export const part1: Record<string, string[]> = {
  "1:1": ["In the name of Allah, Most Gracious, Most Merciful.","পরম করুণাময়, পরম দয়ালু আল্লাহর নামে।"],
  "1:2": ["Praise be to Allah, Lord of the universe.","প্রশংসা আল্লাহর, মহাবিশ্বের প্রভু।"],
  "1:3": ["Most Gracious, Most Merciful.","পরম করুণাময়, পরম দয়ালু।"],
  "1:4": ["Master of the Day of Judgment.","বিচার দিনের মালিক।"],
  "1:5": ["You alone we worship; You alone we ask for help.","আমরা একমাত্র আপনার উপাসনা করি; আমরা একমাত্র আপনার কাছেই সাহায্য চাই।"],
  "1:6": ["Guide us in the right path;","আমাদেরকে সঠিক পথে পরিচালিত করুন;"],
  "1:7": ["the path of those whom You blessed; not of those who have deserved wrath, nor of the strayers.","তাদের পথে যাদের আপনি অনুগ্রহ করেছেন; তাদের পথে নয় যারা আপনার ক্রোধের উপযুক্ত হয়েছে, তাদের পথেও নয় যারা পথভ্রষ্ট হয়েছে।"],
  "2:1": ["A. L. M.","অ. ল. ম."],
  "2:2": ["This scripture is infallible; a beacon for the righteous;","এই ঐশীগ্রন্থটি নির্ভূল; সৎকর্মশীলদের জন্য একটি পথনির্দেশিকা;"],
  "2:3": ["who believe in the unseen, observe the Contact Prayers (Salat), and from our provisions to them, they give to charity.","যারা অদৃশ্যে বিশ্বাস করে,সংযোগ প্রার্থণা (সালাত) পালন করে,এবং আমাদের দেয়া জীবিকা থেকে তারা দান করে।"],
  "2:4": ["And they believe in what was revealed to you, and in what was revealed before you, and with regard to the Hereafter, they are absolutely certain.","এবং তারা বিশ্বাস করে যা তোমার কাছে প্রকাশিত হয়েছে,এবং যা তোমার পূর্বে প্রকাশিত হয়েছে, এবং পরকাল সম্পর্কে তারা সম্পূর্ণ নিশ্চিত।"],
  "2:5": ["These are guided by their Lord; these are the winners.","এরাই তাদের প্রভুর দ্বারা পথ-প্রদর্শিত; এরাই বিজয়ী।"],
  "2:6": ["As for those who disbelieve, it is the same for them; whether you warn them, or not warn them, they cannot believe.","আর যারা অবিশ্বাস করে,তাদেরকে তুমি সতর্ক করো অথবা সতর্ক না করো,তা তাদের জন্য সমান কথা,তারা বিশ্বাস করতে পারে না।"],
  "2:7": ["Allah seals their minds and their hearing, and their eyes are veiled. They have incurred severe retribution.","আল্লাহ তাদের অন্তর এবং শ্রবনশক্তিতে মোহর মেরে দিয়েছেন, এবং তাদের চোখ পর্দাবৃত। তারা নিজেদের উপর টেনে এনেছে কঠিন শাস্তি।"],
  "2:8": ["Then there are those who say, \"We believe in Allah and the Last Day,\" while they are not believers.","এরপর রয়েছে তারা,যারা বলে,“আমরা আল্লাহ এবং শেষ দিনে বিশ্বাস করি,”অথচ তারা বিশ্বাসী নয়।"],
  "2:9": ["In trying to deceive Allah and those who believe, they only deceive themselves without perceiving.","আল্লাহ এবং যারা বিশ্বাস করে তাদেরকে ধোঁকা দেয়ার চেষ্টা করতে গিয়ে,তারা না বুঝে শুধু  নিজেদেরকেই ধোঁকা দেয়।"],
  "2:10": ["In their minds there is a disease. Consequently, Allah augments their disease. They have incurred a painful retribution for their lying.","তাদের অন্তরে রয়েছে ব্যধি। পরিনামে,আল্লাহ তাদের ব্যধি আরো বাড়িয়ে দেন। তারা তাদের মিথ্যাবাদিতার জন্য নিজেদের উপর টেনে এনেছে যন্ত্রণাদায়ক শাস্তি।"],
  "2:11": ["When they are told, \"Do not commit evil,\" they say, \"But we are righteous!\"","যখন তাদেরকে বলা হয়, “মন্দ কাজ করো না,”তারা বলে,“কিন্তু আমরা তো সৎকর্মশীল!”"],
  "2:12": ["In fact, they are evildoers, but they do not perceive.","আসলে,তারা মন্দকর্মী,কিন্তু তারা তা বোঝে না।"],
  "2:13": ["When they are told, \"Believe like the people who believed,\" they say, \"Shall we believe like the fools who believed?\" In fact, it is they who are fools, but they do not know.","যখন তাদের বলা হয়, “বিশ্বাস করো সে লোকদের মতো যারা বিশ্বাস করেছে,”তারা বলে,“যারা বিশ্বাস করেছে,সে বোকাদের মত আমরাও কি বিশ্বাস করবো?” আসলে তারাই বোকা,কিন্তু তারা জানে না।"],
  "2:14": ["When they meet the believers, they say, \"We believe,\" but when alone with their devils, they say, \"We are with you; we were only mocking.\"","যখন তারা বিশ্বাসীদের সাথে সাক্ষাৎ করে,তারা বলে,“আমরা বিশ্বাস করি,”কিন্তু যখন তারা তাদের শয়তানদের সাথে একান্তে হয়, তারা বলে,“আমরা তোমাদের সাথে আছি;আমরা তো কেবল উপহাস করছিলাম।”"],
  "2:15": ["Allah mocks them, and leads them on in their transgressions, blundering.","আল্লাহ তাদের উপহাস করেন, এবং তাদের পরিচালিত করেন তাদের সীমালঙ্ঘনে বিভ্রান্ত অবস্থায়।"],
  "2:16": ["It is they who bought the straying, at the expense of guidance. Such trade never prospers, nor do they receive any guidance.","এরা তারাই যারা পথভ্রষ্টতা কিনেছে পথ-নির্দেশনার মূল্যে। এমন ব্যবসা কখনো উন্নতি করে না,না তারা কোনো পথনির্দেশনা পায়।"],
  "2:17": ["Their example is like those who start a fire, then, as it begins to shed light around them, Allah takes away their light, leaving them in darkness, unable to see.","এদের উদাহরণ হলো তাদের মতো যারা আগুন জ্বালালো,আর যখন তা তাদের চারপাশে আলো ছড়াতে আরম্ভ করলো,আল্লাহ তাদের আলো তুলে নিয়ে তাদের অন্ধকারে ছেঁড়ে দেন, তারা দেখতে পায় না।"],
  "2:18": ["Deaf, dumb, and blind; they fail to return.","বধির, বোবা এবং অন্ধ; তারা ফিরতে ব্যর্থ।"],
  "2:19": ["Another example: a rainstorm from the sky in which there is darkness, thunder, and lightning. They put their fingers in their ears, to evade death. Allah is fully aware of the disbelievers.","আরেকটি উদাহরণঃ আকাশ থেকে কোন ঝড়োবৃষ্টি যাতে আছে অন্ধকার, বজ্র, এবং বিদ্যুত চমক। তারা মৃত্যু এড়াতে তাদের কানে আঙ্গুল দেয়। আল্লাহ অবিশ্বাসীদের সম্পর্কে সম্পূর্ণ অবগত।"],
  "2:20": ["The lightning almost snatches away their eyesight. When it lights for them, they move forward, and when it turns dark, they stand still. If Allah wills, He can take away their hearing and their eyesight. Allah is Omnipotent.","বিদ্যুত চমক তাদের দৃষ্টিশক্তি প্রায় ছিনিয়ে নেয়। যখন তা তাদের জন্য আলো দেয়, তারা সামনে এগোয়, এবং যখন তা অন্ধকা্রে রুপ নেয়, তারা স্থির দাঁড়িয়ে যায়। যদি আল্লাহ চান, তিনি তাদের শ্রবণ ও দৃষ্টিশক্তি তুলে নিতে পারেন। আল্লাহ সর্বশক্তিমান।"],
  "2:21": ["O people, worship only your Lord—the One who created you and those before you—that you may be saved.","হে লোকসকল, একমাত্র তোমাদের প্রভুর উপাসনা করো – সেই একজন যিনি সৃষ্টি করেছেন তোমাদেরকে এবং তাদেরকে যারা তোমাদের পূর্বে ছিল – যাতে তোমরা রক্ষা পেতে পারো।"],
  "2:22": ["The One who made the earth habitable for you, and the sky a structure. He sends down from the sky water, to produce all kinds of fruits for your sustenance. You shall not set up idols to rival Allah, now that you know.","সেই সত্ত্বা,যিনি পৃথিবীকে তোমাদের জন্য বাসযোগ্য করেছেন, এবং আকাশকে করেছেন একটি কাঠামো। তোমাদের জীবিকার জন্য সব ধরণের ফলমূল উৎপন্ন করতে তিনি আকাশ থেকে পানি বর্ষণ করেন। তোমরা আল্লাহর সাথে প্রতিদ্বন্দিতা করতে উপাস্যদের স্থাপন করবে না,এখন যেহেতু তোমরা জানো।"],
  "2:23": ["If you have any doubt regarding what we revealed to our servant, then produce one sura like these, and call upon your own witnesses against Allah, if you are truthful.","যদি তোমাদের কোনো সন্দেহ থাকে সে সম্পর্কে,যা আমরা আমাদের বান্দার কাছে প্রকাশ করেছি,তাহলে এই সুরার মতো একটি সুরা তৈরী করো,এবং ডাকো আল্লাহর বিপক্ষে তোমাদের নিজেদের সাক্ষীদেরকে,যদি তোমরা সত্যবাদী হও।"],
  "2:24": ["If you cannot do this—and you can never do this—then beware of the Hellfire, whose fuel is people and rocks; it awaits the disbelievers.","যদি তোমরা তা করতে না পারো – এবং তোমরা তা কখনোই করতে পারবে না – তাহলে নরকের আগুনের ব্যাপারে সতর্ক হও, যার জ্বালানী হলো মানুষ এবং পাথর; এটা অবিশ্বাসীদের জন্য অপেক্ষা করছে।"],
  "2:25": ["Give good news to those who believe and lead a righteous life that they will have gardens with flowing streams. When provided with a provision of fruits therein, they will say, \"This is what was provided for us previously.\" Thus, they are given allegorical descriptions. They will have pure spouses therein, and they abide therein forever.","সুসংবাদ দাও তাদেরকে,যারা বিশ্বাস করে এবং সৎ জীবনযাপন করে যে,তাদের জন্য থাকবে প্রবাহিত ঝর্নাধারা সহ বাগানসমূহ। যখন সেখানে তাদেরকে কোন ফল খেতে দেয়া হবে,তারা বলবে,“এটা তো তা-ই যা আমাদেরকে পূর্বে দেয়া হয়েছিল।”এভাবে,তাদেরকে রূপকধর্মী বর্ণনা দেয়া হয়েছে। সেখানে তাদের জন্য থাকবে শুদ্ধ সহধর্মী/সহধর্মিণী,এবং সেখানে তারা চিরকাল বসবাস করবে।"],
  "2:26": ["Allah does not shy away from citing any kind of allegory, from the tiny mosquito and greater. As for those who believe, they know that it is the truth from their Lord. As for those who disbelieve, they say, \"What did Allah mean by such an allegory?\" He misleads many thereby, and guides many thereby. But He never misleads thereby except the wicked,","আল্লাহ কোনো ধরণের রূপকের মাধ্যমে উদাহরণ দিতে লজ্জা বোধ করেন না,তা সে হোক ছোট মশা কিংবা এর থেকে বড় কিছু। আর যারা বিশ্বাস করে,তারা জানে যে,এটা তাদের প্রভুর পক্ষ থেকে সত্য। আর যারা অবিশ্বাস করে,তারা বলে,“আল্লাহ এমন রূপক দ্বারা কি বুঝিয়েছেন?”তিনি এর দ্বারা অনেককেই বিপথগামী করেন, এবং এর দ্বারা অনেককেই সঠিক পথে পরিচালিত করেন। কিন্তু,তিনি মন্দ ছাড়া অন্য কাউকে এর দ্বারা বিপথগামী করেন না,"],
  "2:27": ["who violate Allah's covenant after pledging to uphold it, sever what Allah has commanded to be joined, and commit evil. These are the losers.","যারা আল্লাহর চুক্তি ভংগ করে,তা মেনে চলার অঙ্গীকার করার পর, বিচ্ছিন্ন হয় তা থেকে,যাতে আল্লাহ যুক্ত হতে আদেশ দিয়েছেন, এবং মন্দ কাজ করে। এরাই হতভাগ্য।"],
  "2:28": ["How can you disbelieve in Allah when you were dead and He gave you life, then He puts you to death, then He brings you back to life, then to Him you ultimately return?","কিভাবে তোমরা আল্লাহতে অবিশ্বাস করতে পারো যখন তোমরা ছিলে মৃত এবং তিনি তোমাদের জীবন দিয়েছেন, তারপর তিনি তোমাদের মৃত্যু দেন, তারপর তিনি আবার তোমাদের জীবিত করেন, তারপর তাঁরই কাছে তোমরা চুড়ান্তভাবে ফিরে যাও?"],
  "2:29": ["He is the One who created for you everything on earth, then turned to the sky and perfected seven universes therein, and He is fully aware of all things.","তিনিই একজন, যিনি তোমাদের জন্য পৃথিবীতে সবকিছু সৃষ্টি করলেন, তারপর তিনি আকাশের দিকে ফিরলেন আর তাতে সাতটি মহাবিশ্ব সুষম করলেন,  এবং তিনি সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "2:30": ["Recall that your Lord said to the angels, \"I am placing a representative (a temporary god) on Earth.\" They said, \"Will You place therein one who will spread evil therein and shed blood, while we sing Your praises, glorify You, and uphold Your absolute authority?\" He said, \"I know what you do not know.\"","স্মরণ করো যে তোমার প্রভু ফেরেশতাদের বললেন, “আমি পৃথিবীতে একজন প্রতিনিধি (একজন অস্থায়ী উপাস্য) প্রতিষ্ঠা করতে যাচ্ছি।”তারা বলল, “আপনি কি সেখানে এমন কাউকে পাঠাবেন, যে সেখানে মন্দের প্রসার ঘটাবে এবং রক্তপাত করবে,যখন কিনা আমরা আপনার গুণগাণ করছি,আপনার মহিমা ঘোষণা করছি,এবং আপনার পূর্ণ কর্তৃত্ব মেনে চলছি?”তিনি বললেন, “আমি জানি যা তোমরা জানো না।”"],
  "2:31": ["He taught Adam all the names then presented them to the angels, saying, \"Give Me the names of these, if you are right.\"","তিনি আদমকে সবকিছুর নাম শেখালেন তারপর সেগুলোকে ফেরেশতাদের কাছে উপস্থাপন করে বললেন, “আমাকে এগুলোর নাম বল, যদি তোমরা সঠিক হও।”"],
  "2:32": ["They said, \"Be You glorified, we have no knowledge, except that which You have taught us. You are the Omniscient, Most Wise.\"","তারা বলল, “আপনি মহিমান্বিত, যা আপনি আমাদেরকে শিখিয়েছেন তা ছাড়া আমাদের কোনো জ্ঞান নেই। আপনিই সর্বজ্ঞ, পরম জ্ঞানী।”"],
  "2:33": ["He said, \"O Adam, tell them their names.\" When he told them their names, He said, \"Did I not tell you that I know the secrets of the heavens and the earth? I know what you declare, and what you conceal.\"","তিনি বললেন, “হে আদম, তাদেরকে এগুলোর নাম বলে দাও।”যখন সে তাদেরকে সেগুলোর নাম বলে দিলো,তিনি বললেন, “আমি কি তোমাদেরকে বলিনি যে আমি আকাশমন্ডলী এবং পৃথিবীর গোপন বিষয়সমূহ জানি? আমি জানি যা তোমরা প্রকাশ করো,এবং যা তোমরা গোপন করো।”"],
  "2:34": ["When we said to the angels, \"Fall prostrate before Adam,\" they fell prostrate, except Satan; he refused, was too arrogant, and a disbeliever.","যখন আমরা ফেরেশতাদের বললাম, “আদমের সামনে সেজদাবনত হও, ”তারা সেজদাবনত হল, শয়তান ছাড়া; সে প্রত্যাখ্যান করল, সে ছিল অত্যন্ত উদ্ধত এবং এক অবিশ্বাসী।"],
  "2:35": ["We said, \"O Adam, live with your wife in Paradise, and eat therefrom generously, as you please, but do not approach this tree, lest you sin.\"","আমরা বললাম, ”হে আদম, তোমার স্ত্রীর সাথে স্বর্গে বাস করো এবং সেখান থেকে ইচ্ছেমতো খাও, যেমন তোমাদের পছন্দ, কিন্তু এই গাছের কাছে যেও না,পাছে তোমাদের পাপ হয়।"],
  "2:36": ["But the devil duped them, and caused their eviction therefrom. We said, \"Go down as enemies of one another. On Earth shall be your habitation and provision for awhile.\"","কিন্তু শয়তান তাদেরকে ধোঁকা দিল, এবং সেখান থেকে তাদের বহিষ্কারের কারণ হল। আমরা বললাম, “একে অপরের শত্রু হিসেবে নেমে যাও। পৃথিবীতে হবে তোমাদের কিছু সময়ের জন্য বসবাস এবং জীবিকা।”"],
  "2:37": ["Then, Adam received from his Lord words, whereby He redeemed him. He is the Redeemer, Most Merciful.","তারপর, আদম তার প্রভুর কাছ থেকে শব্দাবলী গ্রহন করলো,যার দ্বারা তিনি তাকে উদ্ধার করলেন। তিনিই উদ্ধারকারী,পরম দয়ালু।"],
  "2:38": ["We said, \"Go down therefrom, all of you. When guidance comes to you from Me, those who follow My guidance will have no fear, nor will they grieve.","আমরা বললাম, “এখান থেকে নেমে যাও, তোমরা সবাই। যখন আমার কাছ থেকে তোমাদের কাছে পথনির্দেশনা আসে,তখন যারা আমার পথনির্দেশনা অনুসরণ করে তাদের কোনো ভয় থাকবে না,না তারা শোক করবে।"],
  "2:39": ["As for those who disbelieve and reject our revelations, they will be dwellers of Hell, wherein they abide forever.","“আর যারা অবিশ্বাস করে এবং আমাদের প্রত্যাদেশসমূহ প্রত্যাখ্যান করে,তারা হবে নরকের বাসিন্দা,যেখানে তারা চিরকাল থাকবে।”"],
  "2:40": ["O Children of Israel, remember My favor, which I bestowed upon you, and fulfill your part of the covenant, that I fulfill My part of the covenant, and reverence Me.","হে ইসরাঈলের সন্তানেরা,স্মরণ করো আমার অনুগ্রহ, যা আমি তোমাদের উপর অর্পণ করেছি এবং পূর্ণ করো তোমাদের অঙ্গীকারকৃত অংশ, যাতে আমি পূর্ণ করি আমার অঙ্গীকারকৃত অংশ, এবং আমাকে ভক্তি-শ্রদ্ধা করো।"],
  "2:41": ["You shall believe in what I have revealed herein, confirming what you have; do not be the first to reject it. Do not trade away My revelations for a cheap price, and observe Me.","তোমরা বিশ্বাস করবে তাতে যা আমি এখানে প্রকাশ করেছি,যা তোমাদের কাছে আছে তা সুনিশ্চিত করে; এটাকে প্রত্যাখ্যানে প্রথম হইও না। আমার প্রত্যাদেশনাবলীকে সামান্য মূল্যে বিক্রি করো না এবং আমার প্রতি মনোযোগ দাও।"],
  "2:42": ["Do not confound the truth with falsehood, nor shall you conceal the truth, knowingly.","সত্যকে মিথ্যার সাথে মিশ্রিত করো না,আর জেনে-শুনে সত্যকে গোপন করো না"],
  "2:43": ["You shall observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), and bow down with those who bow down.","তোমরা সংযোগ প্রার্থণা (সালাত) পালন করবে এবং বাধ্যতামূলক দান (যাকাত) প্রদান করবে,এবং অবনত হবে (রুকু করবে) তাদের সাথে যারা অবনত হয় (রুকু করে)।"],
  "2:44": ["Do you exhort the people to be righteous, while forgetting yourselves, though you read the scripture? Do you not understand?","তোমরা কি মানুষকে সৎকর্মশীল হতে উদবুদ্ধ করো,অথচ নিজেদেরকেই ভুলে যাও, যদিও তোমরা ঐশীগ্রন্থ পড়ো? তোমরা কি বুঝো না?"],
  "2:45": ["You shall seek help through steadfastness and the Contact Prayers (Salat). This is difficult indeed, but not so for the reverent,","তোমরা সাহায্য প্রার্থণা করবে ধৈর্য্য এবং সংযোগ প্রার্থণা (সালাতের) মাধ্যমে। এটা প্রকৃতপক্ষে কঠিন, কিন্তু ভক্তদের জন্য নয়।"],
  "2:46": ["who believe that they will meet their Lord; that to Him they ultimately return.","যারা বিশ্বাস করে যে তারা তাদের প্রভুর সাথে সাক্ষাত করবে আর তাঁর কাছে তারা অবশেষে ফিরে যাবে।"],
  "2:47": ["O Children of Israel, remember My favor which I bestowed upon you, and that I blessed you more than any other people.","হে ইসরাইলের সন্তানেরা,স্মরণ করো আমার অনুগ্রহ যা আমি তোমাদের উপর প্রদান করেছি,এবং যে আমি তোমাদেরকে অন্য যেকোন লোকের চেয়ে বেশি সৌভাগ্যশালী করেছি।"],
  "2:48": ["Beware of the day when no soul can avail another soul, no intercession will be accepted, no ransom can be paid, nor can anyone be helped.","সেদিনের ব্যাপারে সাবধান হও যখন না কেউ কারো উপকারে আসতে পারে,না কোনো সুপারিশ গ্রহণ করা হবে,না কোনো মুক্তিপণ দেয়া যাবে,না কেউ সাহায্যপ্রাপ্ত হতে পারবে।"],
  "2:49": ["Recall that we saved you from Pharaoh's people who inflicted upon you the worst persecution, slaying your sons and sparing your daughters. That was an exacting test from your Lord.","স্মরণ করো যে আমরা তোমাদেরকে ফেরাউনের লোকদের থেকে রক্ষা করেছিলাম যারা তোমাদের উপর নির্মম অত্যাচার চালিয়েছিল, তোমাদের পুত্রদের হত্যা করতো আর কন্যাদের ছেড়ে দিতো। তোমাদের প্রভুর পক্ষ থেকে সেটা ছিল এক কঠোর পরীক্ষা।"],
  "2:50": ["Recall that we parted the sea for you; we saved you and drowned Pharaoh's people before your eyes.","স্মরণ করো যে,আমরা তোমাদের জন্য সাগরকে বিভক্ত করেছিলাম; আমরা তোমাদের রক্ষা করেছিলাম এবং তোমাদের চোখের সামনে ফিরাউনের লোকদের ডুবিয়ে দিয়েছিলাম।"],
  "2:51": ["Yet, when we summoned Moses for forty nights, you worshiped the calf in his absence, and turned wicked.","এরপরও, যখন আমরা মুসাকে চল্লিশ রাতের জন্য ডেকেছিলাম, তোমরা তার অনুপস্থিতিতে বাছুর পূজা করেছিলে এবং পাপপূর্ন হয়ে পড়েছিলে।"],
  "2:52": ["Still, we pardoned you thereafter that you may be appreciative.","তবুও, এসবের পরে আমরা তোমাদেরকে ক্ষমা করেছিলাম যাতে তোমরা কৃতজ্ঞ হও।"],
  "2:53": ["Recall that we gave Moses scripture and the statute book, that you may be guided.","স্মরণ করো যে,আমরা মুসাকে দিয়েছিলাম ঐশীগ্রন্থ এবং বিধিবদ্ধ আইনগ্রন্থ, যাতে তোমরা সুপথপ্রাপ্ত হতে পারো।"],
  "2:54": ["Recall that Moses said to his people, \"O my people, you have wronged your souls by worshiping the calf. You must repent to your Creator. You shall kill your egos. This is better for you in the sight of your Creator.\" He did redeem you. He is the Redeemer, Most Merciful.","স্মরণ করো যে,মুসা তার লোকদের বলেছিল, “হে আমার লোকেরা,বাছুর পূজা করে তোমরা তোমাদের আত্মার ক্ষতি করেছ। তোমরা অবশ্যই তোমাদের স্রষ্টার কাছে অনুশোচনা করবে। তোমরা তোমাদের ‘আমিত্ব’কে (অহংবোধকে) হত্যা করবে। তোমাদের স্রষ্টার দৃষ্টিতে এটা তোমাদের জন্য উত্তম।”তিনি  তোমাদের উদ্ধার করেছিলেন। তিনি উদ্ধারকর্তা,পরম দয়ালু।"],
  "2:55": ["Recall that you said, \"O Moses, we will not believe unless we see Allah, physically.\" Consequently, the lightning struck you, as you looked.","স্মরণ করো যে,তোমরা বলেছিলে,“হে মুসা,আমরা বিশ্বাস করবো না যতক্ষণ না আমরা আল্লাহকে স্বশরীরে দেখছি।”ফলস্বরুপ, বজ্র তোমাদের আঘাত করলো,যখন তোমরা তাকিয়েছিলে।"],
  "2:56": ["We then revived you, after you had died, that you may be appreciative.","তারপর, তোমরা মরে যাবার পর, আমরা তোমাদের পূনর্জীবিত করলাম, যাতে তোমরা কৃতজ্ঞ হও।"],
  "2:57": ["We shaded you with clouds (in Sinai), and sent down to you manna and quails: \"Eat from the good things we provided for you.\" They did not hurt us (by rebelling); they only hurt their own souls.","আমরা তোমাদেরকে (সিনাইয়ে) মেঘমালা দিয়ে ছায়া দান করেছিলাম এবং তোমাদের কাছে অবতীর্ণ করেছিলাম ‘মান্না’ এবং কোয়েলঃ “তোমাদের জন্য আমাদের দেয়া ভালো জিনিস থেকে খাও।”তারা (বিদ্রোহ করে) আমাদের ক্ষতি করেনি; তারা শুধু নিজেদের আত্মারই ক্ষতি করেছিল।"],
  "2:58": ["Recall that we said, \"Enter this town, where you will find as many provisions as you like. Just enter the gate humbly, and treat the people nicely. We will then forgive your sins, and increase the reward for the pious.\"","স্মরন করো যে আমরা বলেছিলাম, \"এই শহরে প্রবেশ করো, যেখানে তোমাদের পছন্দমতো অনেক জীবিকা পাবে। শুধু নম্রভাবে দরজা দিয়ে প্রবেশ করো, এবং লোকদের সাথে সুন্দর ব্যবহার করো। তাহলে আমরা তোমাদের পাপসমূহ ক্ষমা করে দেব, এবং সৎকর্মশীলদের জন্য পুরষ্কার বাড়িয়ে দেব।"],
  "2:59": ["But the wicked among them carried out commands other than the commands given to them. Consequently, we sent down upon the transgressors condemnation from the sky, due to their wickedness.","কিন্তু,তাদের মধ্যকার মন্দ লোকেরা তাদেরকে দেয়া নির্দেশ অনুসরণ না করে অন্য নির্দেশ অনুসরন করলো। ফলস্বরূপ, আকাশ থেকে আমরা সীমালঙ্গনকারীদের উপর শাস্তি অবতীর্ণ করলাম, তাদের অপকর্মের জন্য।"],
  "2:60": ["Recall that Moses sought water for his people. We said, \"Strike the rock with your staff.\" Whereupon, twelve springs gushed out therefrom. The members of each tribe knew their own water. Eat and drink from Allah's provisions, and do not roam the earth corruptingly.","স্মরন করো যে,মুসা তার লোকদের জন্য পানি খুঁজেছিল, আমরা বলেছিলাম, \"তোমার লাঠি দিয়ে পাথরটিতে আঘাত করো\"। যার ফলে,সেখান থেকে বারটি ঝর্না প্রবলবেগে বের হয়ে আসলো। প্রত্যেক গোত্রের সদস্যরা তাদের নিজ নিজ পানি চিনতো। আল্লাহর দেয়া জীবিকা থেকে খাও এবং পান করো,এবং পৃথিবীতে দূর্নীতি করে বেড়িও না।"],
  "2:61": ["Recall that you said, \"O Moses, we can no longer tolerate one kind of food. Call upon your Lord to produce for us such earthly crops as beans, cucumbers, garlic, lentils, and onions.\" He said, \"Do you wish to substitute that which is inferior for that which is good? Go down to Egypt, where you can find what you asked for.\" They have incurred condemnation, humiliation, and disgrace, and brought upon themselves wrath from Allah. This is because they rejected Allah's revelations, and killed the prophets unjustly. This is because they disobeyed and transgressed.","স্মরন করো যে তোমরা বলেছিলে,\"হে মুসা,আমরা এক রকমের খাদ্য আর সহ্য করতে পারছি না। তোমার প্রভুর কাছে আহবান করো তিনি যেন আমাদের জন্য ভূমিজাত শস্য যেমন শীম, শসা,রসূন, ডাল এবং পেঁয়াজ উৎপন্ন করেন। সে বলল, \"তোমরা কি ভাল জিনিসের পরিবর্তে এর চেয়ে নিম্নমানের জিনিস চাও? মিশরে গিয়ে অধঃপতিত হও, সেখানে তোমরা যা চাচ্ছ তা পাবে\"। তারা নিজেদের উপর টেনে আনলো নিন্দা,লাঞ্ছনা এবং অসম্মান, এবং নিজেদের উপর নিয়ে আসলো আল্লাহর ক্রোধ। এটা এ কারনে যে তারা আল্লাহর প্রকাশণাবলী প্রত্যাখান করেছিল, এবং নবীদেরকে অন্যায়ভাবে হত্যা করেছিল। এটা এ কারনে যে,তারা অমান্য করেছিল এবং সীমালঙ্ঘন করেছিল।"],
  "2:62": ["Surely, those who believe, those who are Jewish, the Christians, and the converts; anyone who (1) believes in Allah, and (2) believes in the Last Day, and (3) leads a righteous life, will receive their recompense from their Lord. They have nothing to fear, nor will they grieve.","নিশ্চয়ই, যারা বিশ্বাস করে,যারা ইহুদী,খ্রীস্টান, এবং ধর্মান্তরিত; যে কেউই (১) বিশ্বাস করে আল্লাহতে,এবং (২) বিশ্বাস করে শেষ দিনে,এবং (৩) সৎ জীবন-যাপন করে,তারা তাদের প্রভুর কাছ থেকে প্রতিদান পাবে। তাদের ভয়ের কিছু নেই, না তারা শোক করবে।"],
  "2:63": ["We made a covenant with you, as we raised Mount Sinai above you: \"You shall uphold what we have given you strongly, and remember its contents, that you may be saved.\"","আমরা যখন তোমাদের উপর সিনাই পর্বত তুলে ধরে তোমাদের সাথে অঙ্গীকার করেছিলাম যে,“তোমরা দৃঢভাবে মেনে চলবে যা আমরা তোমাদের দিয়েছি,এবং এর বিষয়বস্তু স্মরণ রাখবে,যাতে তোমরা রক্ষা পেতে পার।”"],
  "2:64": ["But you turned away thereafter, and if it were not for Allah's grace towards you and His mercy, you would have been doomed.","কিন্তু তোমরা এরপর মুখ ফিরিয়ে নিলে এবং যদি তোমাদের প্রতি আল্লাহর অনুগ্রহ ও কৃপা না থাকতো,তোমরা ধ্বংস হয়ে যেতে।"],
  "2:65": ["You have known about those among you who desecrated the Sabbath. We said to them, \"Be you as despicable as apes.\"","তোমাদের মধ্যে যারা সাব্বাথকে অপবিত্র করেছিল তোমরা তাদের সম্পর্কে জেনেছো। আমরা তাদেরকে বললাম, “তোমরা বানরের মতো ঘৃণ্য হয়ে যাও।”"],
  "2:66": ["We set them up as an example for their generation, as well as subsequent generations, and an enlightenment for the righteous.","আমরা তাদেরকে তাদের, এবং তাদের পরবর্তী প্রজন্মদের জন্য উদাহরণস্বরুপ করেছি,এবং সৎকর্মশীলদের জন্য করেছি একটি জ্ঞানালোক।"],
  "2:67": ["Moses said to his people, \"Allah commands you to sacrifice a heifer.\" They said, \"Are you mocking us?\" He said, \"Allah forbid, that I should behave like the ignorant ones.\"","মুসা তার লোকদের বলল, “আল্লাহ তোমাদেরকে একটি অপক্ব-গাভী উৎসর্গ করতে আদেশ করেন।” তারা বলল, “তুমি কি আমাদের উপহাস করছো?” সে বলল, “আল্লাহ না করুন, যে আমি অজ্ঞদের মতো আচরণ করি।”"],
  "2:68": ["They said, \"Call upon your Lord to show us which one.\" He said, \"He says that she is a heifer that is neither too old, nor too young; of an intermediate age. Now, carry out what you are commanded to do.\"","তারা বলল, “তোমার প্রভুকে আহবান করো যেন তিনি আমাদের দেখান কোনটি।”সে বলল, “তিনি বলেছেন যে,সেটা একটি বকনা বাছুর যেটা খুব বেশি বয়ষ্ক নয়, কিংবা অল্প বয়ষ্কও নয়; মাঝামাঝি বয়সের। এবার, তোমাদেরকে যা আদেশ করা হয়েছে তা পালন করো।”"],
  "2:69": ["They said, \"Call upon your Lord to show us her color.\" He said, \"He says that she is a yellow heifer, bright colored, pleases the beholders.\"","তারা বলল, “তোমার প্রভুকে আহবান করো আমাদেকে যেন এর রং দেখান।”সে বলল, “তিনি বলেছেন যে,সেটা একটি হলুদ বকনা বাছুর, উজ্জ্বল রংয়ের, দর্শকদের মুগ্ধ করে।”"],
  "2:70": ["They said, \"Call upon your Lord to show us which one. The heifers look alike to us and, Allah willing, we will be guided.\"","তারা বলল, “তোমার প্রভুকে আহবান করো যেন তিনি আমাদের দেখান তা কোনটি। বকনা বাছুরগুলো আমাদের কাছে দেখতে একই রকম মনে হয়, আল্লাহ যদি চান, আমরা সুপথে পরিচালিত হবো।”"],
  "2:71": ["He said, \"He says that she is a heifer that was never humiliated in plowing the land or watering the crops; free from any blemish.\" They said, \"Now you have brought the truth.\" They finally sacrificed her, after this lengthy reluctance.","সে বলল, “তিনি বলেন যে,এটি এমন বকনা বাছুর যেটা কখনো জমি চাষে অথবা শস্য ক্ষেতে পানি দেয়ার কাজে ব্যবহৃত হয়নি; কোনো প্রকার খুঁত মুক্ত।”তারা বলল, “এখন তুমি সত্যটা এনেছ।”তারা অবশেষে এটি উৎসর্গ করলো,এই দীর্ঘ অনীহার পর।"],
  "2:72": ["You had killed a person, then disputed among yourselves. Allah was to expose what you tried to conceal.","তোমরা একজনকে হত্যা করেছিলে,এরপর নিজেদের মধ্যে বিবাদ করলে। আল্লাহ তা প্রকাশ করতে চেয়েছিলেন যা তোমরা গোপন করার চেষ্টা করছিলে।"],
  "2:73": ["We said, \"Strike (the victim) with part (of the heifer).\" That is when Allah brought the victim back to life, and showed you His signs, that you may understand.","আমরা বললাম, “(অপক্ব-গাভীর) অংশ দিয়ে (মৃত ব্যক্তিটিকে) আঘাত করো।”তখনই আল্লাহ মৃত ব্যক্তিটির জীবন ফিরিয়ে দিলেন, এবং তোমাদেরকে তাঁর নিদর্শনসমূহ দেখালেন, যাতে তোমরা বুঝতে পারো।"],
  "2:74": ["Despite this, your hearts hardened like rocks, or even harder. For there are rocks from which rivers gush out. Others crack and release gentle streams, and other rocks cringe out of reverence for Allah. Allah is never unaware of anything you do.","তা সত্ত্বেও, তোমাদের হৃদয় পাথরের মতো কঠিন হয়ে গেল, বা তার চেয়েও কঠিন। কারণ এমন পাথরও আছে যেগুলো থেকে নদী প্রবল বেগে বের হয়ে আসে। অন্যগুলো ফেঁটে যায় এবং শান্ত ঝর্ণা নির্গত হয়, এবং অন্য পাথরগুলো আল্লাহর ভয়ে খসে পড়ে। আল্লাহ কখনোই অসচেতন নন যা কিছু তোমরা করো।"],
  "2:75": ["Do you expect them to believe as you do, when some of them used to hear the word of Allah, then distort it, with full understanding thereof, and deliberately?","তোমরা কি আশা করো যে তারা তোমাদের মতো বিশ্বাস করবে,যখন তাদের মধ্যে কিছু লোক আল্লাহর কথা শুনতো,তারপর তা বিকৃত করতো,সম্পূর্ণ বুঝে-শুনে এবং ইচ্ছাকৃতভাবে?"],
  "2:76": ["And when they meet the believers, they say, \"We believe,\" but when they get together with each other, they say, \"Do not inform (the believers) of the information given to you by Allah, lest you provide them with support for their argument concerning your Lord. Do you not understand?\"","এবং যখন তারা বিশ্বাসীদের সাথে সাক্ষাত করে,তারা বলে,“আমরা বিশ্বাস করি,”কিন্তু যখন তারা একে অপরের সাথে মিলিত হয়, তারা বলে,“তোমাদেরকে দেয়া আল্লাহর তথ্য (বিশ্বাসীদেরকে) জানিয়ে দিয়ো না,পাছে তোমরা তোমাদের প্রভুর সম্পর্কে তাদের যুক্তিতে সমর্থন যোগাবে। তোমরা কি বোঝ না?”"],
  "2:77": ["Do they not know that Allah knows everything they conceal, and everything they declare?","তারা কি জানে না যে,আল্লাহ জানেন যা কিছু তারা গোপন করে,এবং যা কিছু তারা প্রকাশ করে?"],
  "2:78": ["Among them are gentiles who do not know the scripture, except through hearsay, then assume that they know it.","তাদের মধ্যে রয়েছে ঐশীগ্রন্থ অনুসরণ না করা (উম্মী) লোক, যারা ঐশীগ্রন্থ সম্পর্কে জানে না; লোক মুখে শোনা কথা ছাড়া,তারপর তারা ধরে নেয় যে তারা তা জানে।"],
  "2:79": ["Therefore, woe to those who distort the scripture with their own hands, then say, \"This is what Allah has revealed,\" seeking a cheap material gain. Woe to them for such distortion, and woe to them for their illicit gains.","কাজেই, দুর্ভোগ তাদের প্রতি যারা নিজেদের হাতে ঐশীগ্রন্থ বিকৃত করে,এরপর বলে,“এটাই আল্লাহ অবতীর্ণ করেছেন, ”সস্তা পার্থিব মুনাফা খোঁজে। দূর্ভোগ তাদের প্রতি এরুপ বিকৃতির জন্য, এবং দূর্ভোগ তাদের প্রতি তাদের এই অবৈধ অর্জনের জন্য।"],
  "2:80": ["Some have said, \"Hell will not touch us, except for a limited number of days.\" Say, \"Have you taken such a pledge from Allah—Allah never breaks His pledge—or, are you saying about Allah what you do not know?\"","কেউ কেউ বলেছে,“নরক আমাদের স্পর্শ করবে না নির্দিষ্ট সংখ্যক কিছু দিন ছাড়া।”বল, “তোমরা কি আল্লাহর কাছ থেকে এমন কোন অঙ্গীকার নিয়েছ – আল্লাহ কখনোই তাঁর অঙ্গীকার ভঙ্গ করেন না – নাকি তোমরা আল্লাহ সম্পর্কে এমন কিছু বলছো যা তোমরা জানো না?”"],
  "2:81": ["Indeed, those who earn sins and become surrounded by their evil work will be the dwellers of Hell; they abide in it forever.","নিশ্চয়ই, যারা পাপ অর্জন করে এবং তাদের অসৎ কর্ম দ্বারা পরিবেষ্টিত হয়ে যায়, তারাই হবে নরকের বাসিন্দা; তারা সেখানে চিরকাল বসবাস করে।"],
  "2:82": ["As for those who believe, and lead a righteous life, they will be the dwellers of Paradise; they abide in it forever.","আর যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,তারা হবে স্বর্গের বাসিন্দা; তারা সেখানে চিরকাল বসবাস করে।"],
  "2:83": ["We made a covenant with the Children of Israel: \"You shall not worship except Allah. You shall honor your parents and regard the relatives, the orphans, and the poor. You shall treat the people amicably. You shall observe the Contact Prayers (Salat) and give the obligatory charity (Zakat).\" But you turned away, except a few of you, and you became averse.","আমরা ইসরাইলের সন্তানদের সাথে একটি অঙ্গীকার করেছিলামঃ “তোমরা আল্লাহ ছাড়া আর কারো উপাসনা করবে না। তোমরা পিতামাতাকে সম্মান করবে এবং আত্মীয়-স্বজন, এতীম এবং গরীবদের প্রতি খেয়াল রাখবে। তোমরা লোকদের সাথে সুন্দর ব্যবহার করবে। তোমরা সংযোগ প্রার্থণা (সালাত) পালন করবে এবং বাধ্যতামূলক দান (যাকাত) প্রদান করবে।”কিন্তু সামান্য কয়েকজন ছাড়া,তোমরা মুখ ফিরিয়ে নিলে,এবং তোমরা বিরোধী হয়ে পড়লে।"],
  "2:84": ["We made a covenant with you, that you shall not shed your blood, nor shall you evict each other from your homes. You agreed and bore witness.","আমরা তোমাদের সাথে একটি অঙ্গীকার করেছিলাম যে,তোমরা নিজেদের মধ্যে রক্তপাত করবে না,না তোমরা পরস্পরকে তোমাদের ঘর-বাড়ি থেকে উচ্ছেদ করবে। তোমরা সম্মত হয়েছিলে এবং স্বাক্ষ্য দিয়েছিলে।"],
  "2:85": ["Yet, here you are killing each other, and evicting some of you from their homes, banding against them sinfully and maliciously. Even when they surrendered, you demanded ransom from them. Evicting them was prohibited for you in the first place. Do you believe in part of the scripture and disbelieve in part? What should be the retribution for those among you who do this, except humiliation in this life, and a far worse retribution on the Day of Resurrection? Allah is never unaware of anything you do.","এরপরও, তোমরা একে অন্যকে হত্যা করছো এবং তোমাদের কাউকে কাউকে তাদের বাড়ি-ঘর থেকে উচ্ছেদ করছো,তাদের বিরুদ্ধে পাপ এবং বিদ্বেষের সাথে একত্রিত হয়ে। এমনকি তারা আত্ম-সমর্পণ করার পরও তোমরা তাদের কাছে মুক্তিপণ দাবী করেছো। তাদের উচ্ছেদ করাটাই প্রথমত তোমাদের জন্য নিষিদ্ধ ছিল। তোমরা কি ঐশীগ্রন্থের কিছু অংশে বিশ্বাস করো আর কিছু অংশে অবিশ্বাস করো? তোমাদের মধ্যে যারা এরুপ করে তাদের শাস্তি কি হওয়া উচিত, এই জীবনে অপদস্থতা এবং পুনুরুত্থান দিবসে আরোও নিকৃষ্ট শাস্তি ছাড়া? তোমরা যা কিছু করো তা সম্পর্কে আল্লাহ কখনোই অসচেতন নন।"],
  "2:86": ["It is they who bought this lowly life at the expense of the Hereafter. Consequently, the retribution is never commuted for them, nor can they be helped.","এরা তারাই যারা পরকালের বিনিময়ে এই তুচ্ছ জীবন ক্রয় করেছে। ফলস্বরুপ, তাদের জন্য শাস্তি কখনোই কমানো হয় না,না তারা সাহায্যপ্রাপ্ত হতে পারে।"],
  "2:87": ["We gave Moses the scripture, and subsequent to him we sent other messengers, and we gave Jesus, son of Mary, profound miracles and supported him with the Holy Spirit. Is it not a fact that every time a messenger went to you with anything you disliked, your ego caused you to be arrogant? Some of them you rejected, and some of them you killed.","আমরা মুসাকে ঐশীগ্রন্থ দিয়েছিলাম এবং তার পরে আমরা অন্যান্য বার্তাবাহকদের পাঠিয়েছিলাম এবং আমরা মরিয়মের পুত্র যীশুকে সুস্পষ্ট অলৌকিক নিদর্শনাবলি দিয়েছিলাম আর পবিত্র আত্মার মাধ্যমে তাকে সমর্থণ করেছিলাম। এটাই কি বাস্তব সত্য নয় যে,যখনই কোন বার্তাবাহক তোমাদের কাছে যেতো এমন কোনকিছু নিয়ে যা তোমরা অপছন্দ করতে,তোমাদের আমিত্ব তোমাদেরকে উদ্ধত করে তুলতো? তাদের কাউকে তোমরা প্রত্যাখ্যান করতে,এবং কাউকে হত্যা করতে।"],
  "2:88": ["Some would say, \"Our minds are made up!\" Instead, it is a curse from Allah, as a consequence of their disbelief, that keeps them from believing, except for a few of them.","কেউ কেউ বলে, “পূর্ব থেকে আমাদের মন স্থির হয়ে আছে!” বরং,এটা আল্লাহর পক্ষ থেকে এক অভিশাপ, তাদের অবিশ্বাসের ফলে, যা তাদেরকে বিশ্বাস করা থেকে বিরত রাখে, তাদের অল্প কিছু সংখ্যক ছাড়া।"],
  "2:89": ["When this scripture came to them from Allah, and even though it agrees with, and confirms what they have, and even though they used to prophesy its advent when they talked with the disbelievers, when their own prophecy came to pass, they disbelieved therein. Allah's condemnation thus afflicts the disbelievers.","যখন এই ঐশীগ্রন্থ আল্লাহর পক্ষ থেকে তাদের কাছে আসলো, এবং এমনকি যদিও এটি তাদের নিকট যা আছে তার সাথে একমত হয়, এবং তা সুনিশ্চিত করে,এবং এমনকি যদিও অবিশ্বাসীদের সাথে কথা বলার সময় তারা এর আগমনের ভবিষ্যদ্বানী করতো, যখন তাদের নিজেদের ভবিষ্যদ্বানী পূর্ণ হলো, তারা তা অবিশ্বাস করলো। আল্লাহর অভিসম্পাত এভাবেই অবিশ্বাসীদের উপর পতিত হয়।"],
  "2:90": ["Miserable indeed is what they sold their souls for—rejecting these revelations of Allah out of sheer resentment that Allah should bestow His grace upon whomever He chooses from among His servants. Consequently, they incurred wrath upon wrath. The disbelievers have incurred a humiliating retribution.","নিশ্চয়  শোচনীয় যার বিনিময়ে তারা তাদের আত্মা বিক্রি করেছে – আল্লাহর এই প্রকাশণাবলি প্রত্যাখ্যান করে,নিছক এই বিদ্বেষে যে আল্লাহ তাঁর দাসদের মধ্যে যার উপর ইচ্ছা অনুগ্রহ প্রদান করেন। ফলস্বরুপ, তারা ক্রোধের উপর ক্রোধ অর্জন করেছে। অবিশ্বাসীরা নিজেদের উপর টেনে এনেছে লাঞ্ছনাকর শাস্তি।"],
  "2:91": ["When they are told, \"You shall believe in these revelations of Allah,\" they say, \"We believe only in what was sent down to us.\" Thus, they disbelieve in subsequent revelations, even if it is the truth from their Lord, and even though it confirms what they have! Say, \"Why then did you kill Allah's prophets, if you were believers?\"","যখন তাদেরকে বলা হয়, “তোমরা আল্লাহর এই প্রকাশণাবলিতে বিশ্বাস করবে,”তারা বলে,“আমরা শুধু তাতে বিশ্বাস করি যা আমাদের উপর অবতীর্ণ হয়েছে।”এরুপে,তারা অবিশ্বাস করে পরবর্তী প্রকাশণাবলিতে,যদিও এটা তাদের প্রভুর পক্ষ থেকে সত্য এবং যদিও এটা নিশ্চিত করে যা তাদের কাছে আছে! বল, “তাহলে কেন তোমরা আল্লাহর নবীদের হত্যা করেছো,যদি তোমরা বিশ্বাসীই ছিলে?”"],
  "2:92": ["Moses went to you with profound miracles, yet you worshiped the calf in his absence, and you turned wicked.","মুসা তোমাদের কাছে গিয়েছিল সুস্পষ্ট অলৌকিক নিদর্শনবলি নিয়ে, তারপরও তোমরা তার অনুপস্থিতিতে বাছুর পূজা করেছিলে এবং পাপপূর্ন হয়েছিলে।"],
  "2:93": ["We made a covenant with you, as we raised Mount Sinai above you, saying, \"You shall uphold the commandments we have given you, strongly, and listen.\" They said, \"We hear, but we disobey.\" Their hearts became filled with adoration for the calf, due to their disbelief. Say, \"Miserable indeed is what your faith dictates upon you, if you do have any faith.\"","আমরা তোমাদের সাথে একটি অঙ্গীকার করেছিলাম, যখন আমরা তোমাদের উপর সিনাই পর্বত তুলে ধরেছিলাম, এই বলে,“আমরা তোমাদেরকে যে প্রত্যাদেশাবলি দিয়েছি তা মেনে চলবে,দৃঢভাবে এবং মন দিয়ে শোন।”তারা বলল, “আমরা শুনি,কিন্তু অমান্য করি।”তাদের হৃদয় বাছুর পূজায় পূর্ণ ছিল, তাদের অবিশ্বাসের কারণে। বল, “সত্যিই শোচনীয় যা তোমাদের বিশ্বাস তোমাদের নির্দেশ দেয়, যদি আদৌ তোমাদের কোন বিশ্বাস থেকে থাকে।”"],
  "2:94": ["Say, \"If the abode of the Hereafter is reserved for you at Allah, to the exclusion of all other people, then you should long for death, if you are truthful.\"","বল, “যদি আল্লাহর নিকট পরকালের আবাস শুধুমাত্র তোমাদের জন্যই সংরক্ষিত থাকে,অন্য সকল মানুষকে বাদ দিয়ে,তবে তোমাদের মৃত্যু আকাঙ্ক্ষা করা উচিত, যদি তোমরা সত্যবাদী হয়ে থাক।”"],
  "2:95": ["They never long for it, because of what their hands have sent forth. Allah is fully aware of the wicked.","তারা কখনোই তা আকাঙ্ক্ষা করে না,তা-র জন্য যা তাদের হাত ইতিপূর্বে পাঠিয়েছে। আল্লাহ পাপীদের সম্পর্কে পূর্ণ সচেতন।"],
  "2:96": ["In fact, you will find them the most covetous of life; even more so than the idol worshipers. The one of them wishes to live a thousand years. But this will not spare him any retribution, no matter how long he lives. Allah is seer of everything they do.","প্রকৃতপক্ষে,তোমরা দেখবে,তারা জীবনের প্রতি সবচেয়ে বেশি লোভী; এমনকি প্রতিমা উপাসকদের চেয়েও বেশি। তাদের একেক জন হাজার বছর বেঁচে থাকতে চায়। কিন্তু এটা তাদেরকে কোন শাস্তি থেকে রেহাই দেবে না,যত দিনই তারা বাঁচুক না কেন। তারা যা কিছু করে আল্লাহ সবই দেখেন।"],
  "2:97": ["Say, \"Anyone who opposes Gabriel should know that he has brought down this (Quran) into your heart, in accordance with Allah's will, confirming previous scriptures, and providing guidance and good news for the believers.\"","বল, “যে কেউ জিবরাইলের বিরোধীতা করে তার জানা উচিত যে,সে এটি (কুরআন) তোমার হৃদয়ে অবতীর্ণ করেছে আল্লাহর ইচ্ছানুসারে,যা নিশ্চিত করে পুর্ববর্তী ঐশীগ্রন্থসমূহ এবং বিশ্বাসীদের জন্য পথনির্দেশ ও সুসংবাদ দেয়।”"],
  "2:98": ["Anyone who opposes Allah, and His angels, and His messengers, and Gabriel and Michael, should know that Allah opposes the disbelievers.","যে কেউ আল্লাহ, এবং তাঁর ফেরেশতাদের, এবং তাঁর বার্তাবাহকদের, আর জিবরাইল ও মিকাইলের বিরোধিতা করে,তার জানা উচিত যে,আল্লাহ অবিশ্বাসীদের বিরোধিতা করেন।"],
  "2:99": ["We have sent down to you such clear revelations, and only the wicked will reject them.","আমরা তোমার প্রতি অবতীর্ণ করেছি এমন সুস্পষ্ট প্রকাশণাবলি এবং শুধুমাত্র পাপীরাই তা প্রত্যাখ্যান করবে।"],
  "2:100": ["Is it not a fact that when they make a covenant and pledge to keep it, some of them always disregard it? In fact, most of them do not believe.","এটাই কি বাস্তব সত্য নয় যে যখন তারা কোন অঙ্গীকার করে এবং সেটা রক্ষা করার প্রতিজ্ঞা করে,তাদের মধ্যে কেউ কেউ তা সবসময় উপেক্ষা করে? বস্তুত, তাদের অধিকাংশ বিশ্বাস করে না।"],
  "2:101": ["Now that a messenger from Allah has come to them, and even though he proves and confirms their own scripture, some followers of the scripture (Jews, Christians, and Muslims) disregard Allah's scripture behind their backs, as if they never had any scripture.","এখন যেহেতু আল্লাহর পক্ষ থেকে তাদের কাছে একজন বার্তাবাহক এসেছে এবং যদিও সে তাদের নিজেদের ঐশীগ্রন্থটি প্রমাণ করে এবং সুনিশ্চিত করে,ঐশীগ্রন্থের কিছু অনুসারীরা (ইহুদী,খ্রীস্টান এবং মুসলিমরা) তাদের অগোচরে আল্লাহর গ্রন্থ উপেক্ষা করে,যেন তাদের কখনো কোন ঐশীগ্রন্থ ছিল না।"],
  "2:102": ["They pursued what the devils taught concerning Solomon's kingdom. Solomon, however, was not a disbeliever, but the devils were disbelievers. They taught the people sorcery, and that which was sent down through the two angels of Babel, Haroot and Maroot. These two did not divulge such knowledge without pointing out: \"This is a test. You shall not abuse such knowledge.\" But the people used it in such evil schemes as the breaking up of marriages. They can never harm anyone against the will of Allah. They thus learn what hurts them, not what benefits them, and they know full well that whoever practices witchcraft will have no share in the Hereafter. Miserable indeed is what they sell their souls for, if they only knew.","তারা অনুসরণ করলো যা শয়তানরা সোলায়মানের রাজত্ব সম্পর্কে শিখিয়েছিল। তবে,সোলায়মান অবিশ্বাসী ছিল না,অবিশ্বাসী ছিল শয়তানরা। তারা লোকদের শেখাতো কালো যাদু এবং যা বাবেল নগরীর দু’জন ফেরেশতা হারুত ও মারুতের মাধ্যমে অবতীর্ণ হয়েছিল। এই দু’জন এরকম জ্ঞান ফাঁস করতো না,এটা না বলে যেঃ “এটা একটা পরীক্ষা। তোমরা এমন জ্ঞানের অপব্যবহার করবে না।”কিন্তু লোকেরা এটি ব্যবহার করলো বিয়ে ভেঙ্গে দেয়ার মতো মন্দ ষড়যন্ত্রে। তারা কখনো আল্লাহর ইচ্ছার বিরুদ্ধে কারো ক্ষতি করতে পারে না। এভাবে তারা শেখে যা তাদেরকে কষ্ট দেয়, তা নয় যা তাদের উপকার করে এবং তারা খুব ভালোভাবে জানে যে,যেকেউ কালো যাদু চর্চা করে তার জন্য পরকালে কোন অংশ নেই। সত্যিই শোচনীয় যার জন্য তারা তাদের আত্মা বিক্রি করে,যদি শুধু তারা জানতো।"],
  "2:103": ["If they believe and lead a righteous life, the reward from Allah is far better, if they only knew.","যদি তারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,তাহলে আল্লাহর পক্ষ থেকে পুরষ্কার অনেক উত্তম, যদি শুধু তারা জানতো।"],
  "2:104": ["O you who believe, do not say, \"Raa'ena\" (be our shepherd). Instead, you should say, \"Unzurna\" (watch over us), and listen. The disbelievers have incurred a painful retribution.","হে তোমরা যারা বিশ্বাস করো,“রা’য়েনা (আমাদের রাখাল হও)” বলো না। বরং বল, “উনযুরনা (আমাদের প্রতি লক্ষ্য রাখো)”এবং মনোযোগ সহকারে শোনো। অবিশ্বাসীরা নিজেদের উপর কষ্টদায়ক শাস্তি টেনে এনেছে।"],
  "2:105": ["Neither the disbelievers among the followers of the scripture, nor the idol worshipers, wish to see any blessings come down to you from your Lord. However, Allah showers His blessings upon whomever He chooses. Allah possesses infinite grace.","না ঐশীগ্রন্থের অনুসারীদের মধ্যকার অবিশ্বাসীরা,না অংশীদার উপসাকরা,দেখতে চায় যে তোমাদের কাছে তোমাদের প্রভুর পক্ষ থেকে কোন আশীর্বাদ নেমে আসুক। যদিও, আল্লাহ তাঁর আশীর্বাদ তার প্রতি বর্ষণ করেন যাকে তিনি পছন্দ করেন। আল্লাহ অসীম অনুগ্রহের অধিকারী।"],
  "2:106": ["When we abrogate any miracle, or cause it to be forgotten, we produce a better miracle, or at least an equal one. Do you not recognize the fact that Allah is Omnipotent?","যখন আমরা কোন অলৌকিক নিদর্শন রহিত করি কিংবা তা বিস্মৃত করে দেই, আমরা এর চেয়েও উত্তম, বা অন্ততপক্ষে এর সমতুল্য কোন অলৌকিক নিদর্শন উপস্থিত করি। তোমরা কি এই বাস্তব সত্যটা উপলব্ধি করো না যে আল্লাহ সর্বশক্তিমান?"],
  "2:107": ["Do you not recognize the fact that Allah possesses the kingship of the heavens and the earth; that you have none besides Allah as your Lord and Master?","তোমরা কি এই বাস্তব সত্যটা উপলব্ধি করো না যে আল্লাহর অধীনে রয়েছে আকাশমন্ডলী ও পৃথিবীর রাজত্ব; আর আল্লাহ ব্যতীত তোমাদের কোন প্রভু ও মালিক নেই?"],
  "2:108": ["Do you wish to demand of your messenger what was demanded of Moses in the past? Anyone who chooses disbelief, instead of belief, has truly strayed off the right path.","তোমরা কি তোমাদের বার্তাবাহকের কাছে এমন কিছু দাবী করতে চাও যেমন অতীতে মুসার কাছে দাবী করা হয়েছিল? যে কেউ অবিশ্বাসকে বেছে নেয়, বিশ্বাসের পরিবর্তে,সত্যিই সে সঠিক পথ থেকে বিচ্যুত হয়েছে।"],
  "2:109": ["Many followers of the scripture would rather see you revert to disbelief, now that you have believed. This is due to jealousy on their part, after the truth has become evident to them. You shall pardon them, and leave them alone, until Allah issues His judgment. Allah is Omnipotent.","এখন যেহেতু তোমরা বিশ্বাস করেছ, ঐশীগ্রন্থের অনেক অনুসারী দেখতে চাইবে যে তোমরা পুনরায় অবিশ্বাস করো। এটা তাদের পক্ষ থেকে হিংসার ফল, সত্য তাদের কাছে সুস্পষ্ট হবার পর। তোমরা তাদেরকে ক্ষমা করো,তাদেরকে তাদের মতো ছেঁড়ে দাও, যতক্ষণ না আল্লাহ তাঁর রায় দেন। আল্লাহ সর্বশক্তিমান।"],
  "2:110": ["You shall observe the Contact Prayers (Salat) and give the obligatory charity (Zakat). Any good you send forth on behalf of your souls, you will find it at Allah. Allah is seer of everything you do.","তোমরা সংযোগ প্রার্থণা (সালাত) পালন করো এবং বাধ্যতামূলক দান (যাকাত) দাও। তোমাদের আত্মার পক্ষে ভালো যা কিছু তোমরা অগ্রে প্রেরণ করো,তা তোমরা আল্লাহর কাছে পাবে। তোমরা যা কিছু করো আল্লাহ তা দেখেন।"],
  "2:111": ["Some have said, \"No one will enter Paradise except Jews or Christians!\" Such is their wishful thinking. Say, \"Show us your proof, if you are right.\"","কেউ কেউ বলেছে,\"ইহুদী বা খ্রিষ্টান ছাড়া কেউই স্বর্গে প্রবেশ করবে না!”এমনই তাদের মনগড়া চিন্তাধারা। বল, “আমাদেরকে তোমাদের প্রমাণ দেখাও, যদি তোমরা সঠিক হও।”"],
  "2:112": ["Indeed, those who submit themselves absolutely to Allah alone, while leading a righteous life, will receive their recompense from their Lord; they have nothing to fear, nor will they grieve.","নিশ্চয়ই, যারা নিজেদেরকে সম্পূর্ণরুপে শুধুমাত্র আল্লাহর কাছে সমর্পণ করে,সেই সাথে সৎজীবন যাপন করে,তারা তাদের প্রভুর কাছ থেকে প্রতিদান পাবে; তাদের ভয়ের কিছু নেই, না তারা কোন শোক করবে।"],
  "2:113": ["The Jews said, \"The Christians have no basis,\" while the Christians said, \"The Jews have no basis.\" Yet, both of them read the scripture. Such are the utterances of those who possess no knowledge. Allah will judge them on the Day of Resurrection, regarding their disputes.","ইহুদিরা বলল, “খ্রীস্টানদের কোন ভিত্তি নেই, ”আবার অন্যদিকে খ্রীস্টানরা বলল, “ইহুদিদের কোনো ভিত্তি নেই।”অথচ তারা উভয়ই ঐশীগ্রন্থ পাঠ করে। এমন কথাবার্তা তাদেরই হয় যারা কোন জ্ঞান রাখে না। আল্লাহ পুনঃরুত্থান দিবসে তাদের বিচার করবেন, তাদের মতবিরোধ সম্পর্কে।"],
  "2:114": ["Who are more evil than those who boycott Allah's masjids, where His name is commemorated, and contribute to their desertion? These ought not to enter therein except fearfully. They will suffer in this life humiliation, and will suffer in the Hereafter a terrible retribution.","তাদের চেয়ে কারা বেশি মন্দ যারা আল্লাহর মসজিদগুলো বর্জন করে,যেখানে তাঁর নাম স্মরণ করা হয়, এবং সেগুলোকে পরিত্যক্ত করতে ভূমিকা রাখে? ভয়-বিহবল অবস্থায় ছাড়া সেখানে তাদের প্রবেশ কাঙ্খিত নয়। তারা এই জীবনে লাঞ্ছনা ভোগ করবে এবং পরকালে ভোগ করবে এক ভয়ানক প্রতিফল।"],
  "2:115": ["To Allah belongs the east and the west; wherever you go there will be the presence of Allah. Allah is Omnipresent, Omniscient.","পূর্ব ও পশ্চিম আল্লাহরই; তোমরা যেখানেই যাও সেখানেই আল্লাহর উপস্থিতি থাকবে। আল্লাহ সর্বত্র বিরাজমান, সর্বজ্ঞ।"],
  "2:116": ["They said, \"Allah has begotten a son!\" Be He glorified; never! To Him belongs everything in the heavens and the earth; all are subservient to Him.","তারা বলেছে,“আল্লাহ পুত্র জন্ম দিয়েছেন!”তিনি মহিমান্বিত; কখনই নয়! তাঁর অধীনে রয়েছে আকাশমন্ডলী ও পৃথিবীর সবকিছু।; সবাই তাঁর আজ্ঞাধীন।"],
  "2:117": ["The Initiator of the heavens and the earth: to have anything done, He simply says to it, \"Be,\" and it is.","আকাশমন্ডলী ও পৃথিবীর সূচনাকারীঃ কোন কিছু সম্পন্ন করতে তিনি শুধু একে বলেন, “হও”এবং তা হয়ে যায়।"],
  "2:118": ["Those who possess no knowledge say, \"If only Allah could speak to us, or some miracle could come to us!\" Others before them have uttered similar utterances; their minds are similar. We do manifest the miracles for those who have attained certainty.","যারা কোন জ্ঞান রাখে না তারা বলে,“শুধু যদি আল্লাহ আমাদের সাথে কথা বলতেন, অথবা কোন অলৌকিক নিদর্শন আমাদের কাছে আসতো”তাদের পূর্বে অন্যরা একই ধরণের কথা বলেছে; তাদের মানসিকতা একই ধরণের। আমরা তাদের জন্য অলৌকিক নিদর্শন সুস্পষ্ট করি যারা নিশ্চিত বিশ্বাস অর্জন করেছে।"],
  "2:119": ["We have sent you with the truth as a bearer of good news, as well as a warner. You are not answerable for those who incur Hell.","আমরা তোমাকে সত্য সহকারে পাঠিয়েছি সুসংবাদবহনকারী,সেই সাথে সতর্ককারী হিসেবে। তোমাকে তাদের সম্পর্কে জিজ্ঞাসা করা হবে না যারা নিজেদের উপর নরক টেনে এনেছে।"],
  "2:120": ["Neither the Jews, nor the Christians, will accept you, unless you follow their religion. Say, \"Allah's guidance is the true guidance.\" If you acquiesce to their wishes, despite the knowledge you have received, you will find no ally or supporter to help you against Allah.","ইহুদি বা খ্রীস্টানরা তোমাকে গ্রহণ করবে না,যদি না তুমি তাদের ধর্ম অনুসরণ করো। বল, “আল্লাহর পথনির্দেশনাই সত্য পথনির্দেশনা।”তুমি যে জ্ঞান প্রাপ্ত হয়েছো তা সত্ত্বেও যদি তুমি তাদের ইচ্ছায় সম্মত হও, তবে আল্লাহর বিরুদ্ধে তোমাকে সাহায্য করার জন্য তুমি কোন মিত্র বা সমর্থণকারী পাবে না।"],
  "2:121": ["Those who received the scripture, and know it as it should be known, will believe in this. As for those who disbelieve, they are the losers.","যারা ঐশীগ্রন্থ পেয়েছে এবং এটা সম্বন্ধে জানে যেভাবে জানা উচিত, তারা এতে বিশ্বাস করবে। আর যারা অবিশ্বাস করে,তারাই ক্ষতিগ্রস্থ।"],
  "2:122": ["O Children of Israel, remember My favor which I bestowed upon you, and that I blessed you more than any other people.","হে ইসরাঈলের সন্তানেরা,স্মরণ করো আমার অনুগ্রহ যা আমি তোমাদের দান করেছি,এবং আমি তোমাদেরকে অন্য সকল লোকদের চেয়ে বেশি সৌভাগ্যশালী করেছিলাম।"],
  "2:123": ["Beware of the day when no soul will help another soul, no ransom will be accepted, no intercession will be useful, and no one will be helped.","সে দিন সম্পর্কে সতর্ক হও যখন কোন আত্মা অন্য আত্মাকে সাহায্য করবে না,কোন মুক্তিপণ গ্রহণ করা হবে না,কোন সুপারিশ ফলপ্রসু হবে না এবং কেউ সাহায্য পাবে না।"],
  "2:124": ["Recall that Abraham was put to the test by his Lord, through certain commands, and he fulfilled them. (Allah) said, \"I am appointing you an imam for the people.\" He said, \"And also my descendants?\" He said, \"My covenant does not include the transgressors.\"","স্মরণ করো যে,ইব্রাহিম তার প্রভুর দ্বারা নির্দিষ্ট কিছু আদেশের মাধ্যমে পরীক্ষিত হয়েছিল এবং সে সেগুলো পূর্ণ করেছিল। (আল্লাহ) বলেছিলেন, “আমি তোমাকে মানুষের জন্য ইমাম নিযুক্ত করছি।”সে বলেছিল, “আর আমার বংশধর থেকেও কি?”তিনি বলেছিলেন, “আমার অঙ্গীকার সীমালঙ্ঘনকারীদের অন্তর্ভুক্ত করে না”।"],
  "2:125": ["We have rendered the shrine (the Ka'aba) a focal point for the people, and a safe sanctuary. You may use Abraham's shrine as a prayer house. We commissioned Abraham and Ismail: \"You shall purify My house for those who visit, those who live there, and those who bow and prostrate.\"","আমরা পবিত্র ঘর (কাবা)-কে করেছি লোকদের জন্য কেন্দ্রবিন্দুতে এবং একটি নিরাপদ পূন্যস্থানে। তোমরা ইব্রাহিমের অবস্থান স্থলকে প্রার্থণা ঘর হিসেবে ব্যবহার করো। আমরা ইব্রাহিম ও ইসমাঈলকে নিযুক্ত করেছিলামঃ “তোমরা আমার ঘরকে তাদের জন্য পবিত্র রাখবে যারা দর্শন করতে আসে,যারা সেখানে বসবাস করে,এবং যারা রুকু এবং সেজদা করে।”"],
  "2:126": ["Abraham prayed: \"My Lord, make this a peaceful land, and provide its people with fruits. Provide for those who believe in Allah and the Last Day.\" (Allah) said, \"I will also provide for those who disbelieve. I will let them enjoy, temporarily, then commit them to the retribution of Hell, and a miserable destiny.\"","ইব্রাহিম প্রার্থণা করেছিল, “আমার প্রভু,এই স্থানটিকে শান্তিময় করুন এবং এর অধিবাসীদের ফলের যোগান দিন। যোগান দিন তাদের জন্য যারা আল্লাহ এবং শেষ দিবসে বিশ্বাস করে।”(আল্লাহ) বললেন, “আমি তাদের জন্যও যোগান দিব যারা অবিশ্বাস করে। আমি তাদেরকে উপভোগ করতে দেব, সাময়িকভাবে,তারপর তাদেরকে পতিত করবো নরকের শাস্তিতে,এবং এক শোচনীয় নিয়তিতে।”"],
  "2:127": ["As Abraham raised the foundations of the shrine, together with Ismail (they prayed): \"Our Lord, accept this from us. You are the Hearer, the Omniscient.","যখন ইব্রাহিম ইসমাঈলকে সাথে নিয়ে পবিত্র ঘরের ভিত্তি গড়ে তুলেছিল (তারা প্রার্থণা করলো):“আমাদের প্রভু,এটি আমাদের কাছ থেকে গ্রহণ করুন। আপনি সর্বশ্রোতা,সর্বজ্ঞ।"],
  "2:128": ["\"Our Lord, make us submitters to You, and from our descendants let there be a community of submitters to You. Teach us the rites of our religion, and redeem us. You are the Redeemer, Most Merciful.","“আমাদের প্রভু,আমাদেরকে আপনার কাছে আত্ম-সমর্পণকারী করুন এবং আমাদের বংশধর থেকে আপনার কাছে একটি আত্ম-সমর্পণকারী সম্প্রদায় গড়ে তুলুন। আমাদেরকে ধর্মের রীতিনীতি শিক্ষা দিন এবং আমাদের পাপ মোচন করুন। আপনি পাপ মোচনকারী,পরম দয়ালু।"],
  "2:129": ["\"Our Lord, and raise among them a messenger to recite to them Your revelations, teach them the scripture and wisdom, and purify them. You are the Almighty, Most Wise.\"","“আমাদের প্রভু,আর তাদের মধ্য থেকে একজন বার্তাবাহকের উত্থান ঘটান তাদের কাছে আপনার প্রকাশণাবলি পড়ে শোনানোর জন্য, তাদেরকে ঐশীগ্রন্থ ও প্রজ্ঞা শিক্ষা দেবার জন্য এবং তাদেরকে পরিশুদ্ধ করার জন্য। আপনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।”"],
  "2:130": ["Who would forsake the religion of Abraham, except one who fools his own soul? We have chosen him in this world, and in the Hereafter he will be with the righteous.","সে ছাড়া কে ইব্রাহিমের ধর্ম পরিত্যাগ করে,যে তার নিজ আত্মাকেই বোকা বানায়? আমরা এই দুনিয়াতে তাকে পছন্দ করেছি,এবং পরকালে সে সৎকর্মশীলদের সাথে থাকবে।"],
  "2:131": ["When his Lord said to him, \"Submit,\" he said, \"I submit to the Lord of the universe.\"","যখন তার প্রভু তাকে বললেন, \"আত্মসমর্পণ করো\",সে বলল, \"আমি বিশ্বজগতের প্রভুর কাছে আত্মসমর্পণ করলাম।"],
  "2:132": ["Moreover, Abraham exhorted his children to do the same, and so did Jacob: \"O my children, Allah has pointed out the religion for you; do not die except as submitters.\"","উপরন্তু,ইব্রাহিম তার সন্তানদেরও অনুরূপ করতে উপদেশ দিয়েছিল, এবং ইয়াকুবও এমনটি করেছিল: \"হে আমার সন্তানেরা,আল্লাহ তোমাদের জন্য ধর্মকে নির্দিষ্ট করে দিয়েছেন; আত্মসমর্পণকারী না হয়ে মরো না।\""],
  "2:133": ["Had you witnessed Jacob on his death bed; he said to his children, \"What will you worship after I die?\" They said, \"We will worship your god; the god of your fathers Abraham, Ismail, and Isaac; the one god. To Him we are submitters.\"","যদি তোমরা ইয়াকুবকে তার মৃত্যু শয্যায় দেখতে ; সে তার সন্তানদের বলেছিল, \"আমার মৃত্যুর পর তোমরা কিসের উপাসনা করবে?”তারা বলেছিল, \"আমরা উপাসনা করবো আপনার  উপাস্যের; আপনার পিতৃপুরুষ ইব্রাহিম, ইসমাইল, এবং ইসহাকের উপাস্যের; সেই একক উপাস্যের। তাঁর নিকট আমরা আত্ম-সমর্পণকারী।"],
  "2:134": ["Such is a community from the past. They are responsible for what they earned, and you are responsible for what you earned. You are not answerable for anything they have done.","এমনই হচ্ছে অতীতের একটি সম্প্রদায়। তারা যা অর্জন করেছে তার জন্য তারা দায়ী এবং তোমরা যা অর্জন করেছ তার জন্য তোমরা দায়ী। তারা যা কিছু করেছে তার জন্য তোমরা কৈফিয়ত দিবে না।"],
  "2:135": ["They said, \"You have to be Jewish or Christian, to be guided.\" Say, \"We follow the religion of Abraham—monotheism—he never was an idol worshiper.\"","তারা বলে,“পথ-নির্দেশনা পেতে হলে,তোমাদেরকে ইহুদী অথবা খ্রীস্টান হতে হবে।”বল, “আমরা অনুসরণ করি ইব্রাহিমের ধর্ম- একেশ্বরবাদ– সে কখনোই প্রতিমা উপাসক ছিল না”।"],
  "2:136": ["Say, \"We believe in Allah, and in what was sent down to us, and in what was sent down to Abraham, Ismail, Isaac, Jacob, and the Patriarchs; and in what was given to Moses and Jesus, and all the prophets from their Lord. We make no distinction among any of them. To Him alone we are submitters.\"","বল, “আমরা বিশ্বাস করি আল্লাহতে,এবং যা আমাদের উপর অবতীর্ণ হয়েছে,এবং যা অবতীর্ণ হয়েছে ইব্রাহিম, ইসমাঈল, ইসহাক, ইয়াকুব এবং গোত্রপ্রধানদের উপর; এবং যা দেয়া হয়েছে মুসা ও ঈসাকে,এবং সকল নবীদেরকে তাদের প্রভুর কাছ থেকে। আমরা তাদের কারো মধ্যে কোন রকম পার্থক্য করি না। আমরা একমাত্র তাঁর কাছে আত্ম-সমর্পণকারী।”"],
  "2:137": ["If they believe as you do, then they are guided. But if they turn away, then they are in opposition. Allah will spare you their opposition; He is the Hearer, the Omniscient.","যদি তারা তোমাদের মতই বিশ্বাস করে,তাহলে তারা সুপথপ্রাপ্ত। কিন্তু,যদি তারা মুখ ফিরিয়ে নেয়, তাহলে তারা বিপক্ষে অবস্থান নিয়েছে। আল্লাহ তাদের বিরোধিতা থেকে তোমাকে রক্ষা করবেন; তিনি সর্বশ্রোতা,সর্বজ্ঞ।"],
  "2:138": ["Such is Allah's system, and whose system is better than Allah's? \"Him alone we worship.\"","এমনই হচ্ছে আল্লাহর নিয়ম, এবং আল্লাহর নিয়মের চেয়ে কার নিয়ম উত্তম? \"আমরা একমাত্র তাঁরই উপাসনা করি\"।"],
  "2:139": ["Say, \"Do you argue with us about Allah, when He is our Lord and your Lord? We are responsible for our deeds, and you are responsible for your deeds. To Him alone we are devoted.\"","বল, “তোমরা কি আমাদের সাথে আল্লাহ সম্বন্ধে তর্ক করো,যখন তিনি আমাদের প্রভু এবং তোমাদের প্রভু? আমরা আমাদের কাজের জন্য দায়ী এবং তোমরা তোমাদের কাজের জন্য দায়ী। আমরা একমাত্র তাঁর প্রতি নিবেদিত।”"],
  "2:140": ["Do you say that Abraham, Ismail, Isaac, Jacob, and the Patriarchs were Jewish or Christian? Say, \"Do you know better than Allah? Who is more evil than one who conceals a testimony he has learned from Allah? Allah is never unaware of anything you do.\"","তোমরা কি বল যে ইব্রাহিম, ইসমাঈল, ইসহাক, ইয়াকুব, এবং গোত্রপ্রধানরা ইহুদী বা খ্রিষ্টান ছিল? বল, \"তোমরা কি আল্লাহর চেয়ে ভালো জান? কে তার চেয়ে অধিক মন্দ যে আল্লাহ থেকে শেখা এক সাক্ষ্য গোপন করে? তোমরা যা কিছু করো আল্লাহ সে সম্পর্কে কখনোই অসচেতন নন।\""],
  "2:141": ["That was a community from the past. They are responsible for what they earned, and you are responsible for what you earned. You are not answerable for anything they did.","সেটা ছিল অতীতের একটি সম্প্রদায়। তারা যা অর্জন করেছে তার জন্য তারা দায়ী এবং তোমরা যা অর্জন করেছ তার জন্য তোমরা দায়ী। যা কিছু তারা করেছিল তার জন্য তোমরা কৈফিয়ত দিবে না।"],
  "2:142": ["The fools among the people would say, \"Why did they change the direction of their Qiblah?\" Say, \"To Allah belongs the east and the west; He guides whoever wills in a straight path.\"","লোকেদের মধ্যকার নির্বোধরা বলবে, “কেন তারা তাদের ক্বিবলার দিক পরিবর্তন করলো?”বল, “পূর্ব এবং পশ্চিম আল্লাহর; তিনি যাকে ইচ্ছা সরল পথে পরিচালিত করেন।”"],
  "2:143": ["We thus made you an impartial community, that you may serve as witnesses among the people, and the messenger serves as a witness among you. We changed the direction of your original Qiblah only to distinguish those among you who readily follow the messenger from those who would turn back on their heels. It was a difficult test, but not for those who are guided by Allah. Allah never puts your worship to waste. Allah is Compassionate towards the people, Most Merciful.","আমরা এভাবে তোমাদেরকে একটি নিরপেক্ষ সম্প্রদায় করেছি,যাতে তোমরা লোকদের মাঝে সাক্ষী হও এবং বার্তাবাহক তোমাদের মাঝে সাক্ষী হয়। আমরা তোমাদের মূল কিবলার দিক পরিবর্তন করেছিলাম শুধু তোমাদের মধ্যে যারা নির্দ্বিধায় বার্তাবাহকের অনুসরণ করে তাদের থেকে যারা পিছু হটে যায় তাদেরকে আলাদা করার জন্য। এটি একটি কঠিন পরীক্ষা ছিল, কিন্তু তাদের জন্য নয় যারা আল্লাহ দ্বারা পথ প্রদর্শিত। আল্লাহ কখনোই তোমাদের উপাসনা বৃথা যেতে দেন না। আল্লাহ মানুষের প্রতি সহানুভূতিশীল, পরম দয়ালু।"],
  "2:144": ["We have seen you turning your face about the sky (searching for the right direction). We now assign a Qiblah that is pleasing to you. Henceforth, you shall turn your face towards the Sacred Masjid. Wherever you may be, all of you shall turn your faces towards it. Those who received the previous scripture know that this is the truth from their Lord. Allah is never unaware of anything they do.","আমরা তোমাকে দেখেছি (সঠিক দিকের সন্ধানে) আকাশের দিকে ইতঃস্তত মুখ ফেরাতে। আমরা এখন একটি কিবলা নির্দিষ্ট করছি যা তোমাকে সন্তুষ্ট করে। এখন থেকে,তুমি পবিত্র মসজিদের দিকে তোমার মুখ ফেরাবে। তোমরা যেখানে থাক না কেন, তোমরা সকলে তোমাদের মুখ এর দিকে ফেরাবে। যারা পূর্বে ঐশীগ্রন্থ প্রাপ্ত হয়েছিল তারা জানে যে,এটা তাদের প্রভুর পক্ষ থেকে সত্য। তারা যা কিছু করে আল্লাহ সে সম্পর্কে কখনই অসচেতন নন।"],
  "2:145": ["Even if you show the followers of the scripture every kind of miracle, they will not follow your Qiblah. Nor shall you follow their Qiblah. They do not even follow each others' Qiblah. If you acquiesce to their wishes, after the knowledge that has come to you, you will belong with the transgressors.","এমনকি তুমি যদি ঐশীগ্রন্থের অনুসারীদের সব ধরণের অলৌকিক নিদর্শনও দেখা,তারা তোমার কিবলা অনুসরণ করবে না। না তুমি তাদের কিবলা অনুসরণ করবে। এমনকি তারা নিজেরাই একে অন্যের কিবলা অনুসরণ করে না। তোমার কাছে যে জ্ঞান এসেছে,তারপর যদি তুমি তাদের ইচ্ছা মেনে নাও, তুমি সীমালঙ্ঘনকারীদের অন্তর্ভুক্ত হবে।"],
  "2:146": ["Those who received the scripture recognize the truth herein, as they recognize their own children. Yet, some of them conceal the truth, knowingly.","যারা ঐশীগ্রন্থ গ্রহণ করেছে তারা এর মধ্যকার সত্য এমনভাবে চিনে নেয় যেমন তারা আপন সন্তানদের চিনে থাকে। এরপরও, তাদের কেউ কেউ জেনে-শুনে সত্য গোপন করে।"],
  "2:147": ["This is the truth from your Lord; do not harbor any doubt.","এটা তোমার প্রভুর পক্ষ থেকে আসা সত্য; কোন রুপ সন্দেহ পোষণ করো না।"],
  "2:148": ["Each of you chooses the direction to follow; you shall race towards righteousness. Wherever you may be, Allah will summon you all. Allah is Omnipotent.","তোমাদের প্রত্যেকেই অনুসরণের একেক দিক বেছে নাও; তোমাদের উচিত সৎকর্মে প্রতিযোগীতা করা। তোমরা যেখানেই থাক না কেন, আল্লাহ তোমাদের সবাইকে একত্রিত করবেন। আল্লাহ সর্বশক্তিমান।"],
  "2:149": ["Wherever you go, you shall turn your face (during Salat) towards the Sacred Masjid. This is the truth from your Lord. Allah is never unaware of anything you all do.","তুমি যেখানেই যাও, (সালাতের সময়) তুমি তোমার মুখ পবিত্র মসজিদের দিকে ফেরাবে। এটা তোমার প্রভুর পক্ষ থেকে সত্য। তোমরা সবাই যা কিছু করো আল্লাহ সে সম্পর্কে কখনই অসচেতন নন।"],
  "2:150": ["Wherever you go, you shall turn your face (during Salat) towards the Sacred Masjid; wherever you might be, you shall turn your faces (during Salat) towards it. Thus, the people will have no argument against you, except the transgressors among them. Do not fear them, and fear Me instead. I will then perfect My blessings upon you, that you may be guided.","তুমি যেখানেই যাও, (সালাতের সময়) তুমি তোমাদের মুখ পবিত্র মসজিদের দিকে ফেরাবে; তোমরা যেখানেই থাক না কেন, তোমরা (সালাতের সময়) তোমাদের মুখ এর দিকে ফেরাবে। এতে করে তোমাদের বিরুদ্ধে লোকদের কোন তর্ক থাকবে না,শুধু তাদের মধ্যকার সীমালঙ্ঘনকারীদের ছাড়া। তাদেরকে ভয় করো না,বরং আমাকেই ভয় করো। আমি তখন তোমাদের প্রতি আমার আশীর্বাদ সম্পূর্ণ করবো,যাতে তোমরা পথপ্রাপ্ত হতে পার।"],
  "2:151": ["(Blessings) such as the sending of a messenger from among you to recite our revelations to you, purify you, teach you the scripture and wisdom, and to teach you what you never knew.","(আশীর্বাদ) যেমন তোমাদের মধ্য থেকে একজন বার্তাবাহক পাঠানো– তোমাদের কাছে আমাদের প্রকাশণাবলী পাঠ করার জন্য, তোমাদেরকে পরিশুদ্ধ করার জন্য, তোমাদেরকে ঐশীগ্রন্থ ও প্রজ্ঞা শিক্ষা দেবার জন্য, এবং তোমাদেরকে শিক্ষা দেবার জন্য যা তোমরা কখনো জানতে না।"],
  "2:152": ["You shall remember Me, that I may remember you, and be thankful to Me; do not be unappreciative.","তোমরা আমাকে স্মরণ করো,যাতে আমিও তোমাদের স্মরণ করি,এবং আমার প্রতি কৃতজ্ঞ হও; অকৃতজ্ঞ হইও না।"],
  "2:153": ["O you who believe, seek help through steadfastness and the Contact Prayers (Salat). Allah is with those who steadfastly persevere.","হে তোমরা যারা বিশ্বাস করো,দৃঢ়তা ও সংযোগ প্রার্থণা (সালাতের) মাধ্যমে সাহায্য প্রার্থণা করো। আল্লাহ তাদের সাথে আছেন যারা দৃড়তার সাথে অধ্যবসায়ী।"],
  "2:154": ["Do not say of those who are killed in the cause of Allah, \"They are dead.\" They are alive at their Lord, but you do not perceive.","আল্লাহর পথে যারা নিহত হয়, তাদের সম্পর্কে বলো না যে,“তারা মৃত”। তারা তাদের প্রভুর কাছে জীবিত, কিন্তু তোমরা বোঝ না।"],
  "2:155": ["We will surely test you through some fear, hunger, and loss of money, lives, and crops. Give good news to the steadfast.","আমরা অবশ্যই তোমাদেরকে পরীক্ষা করবো কিছু ভয়, ক্ষুধা,এবং অর্থ, জীবন ও শস্যের ক্ষয়-ক্ষতির মাধ্যমে। সুসংবাদ দাও অবিচলদের।"],
  "2:156": ["When an affliction befalls them, they say, \"We belong to Allah, and to Him we are returning.\"","যখন কোন দুঃখ-কষ্ট তাদের উপর আসে,তারা বলে,“আমরা আল্লাহর এবং তাঁর কাছেই আমরা ফিরে যাচ্ছি।”"],
  "2:157": ["These have deserved blessings from their Lord and mercy. These are the guided ones.","এরা তাদের প্রভুর আশীর্বাদ এবং অনুগ্রহের উপযুক্ত হয়েছে। এরাই সুপথপ্রাপ্ত।"],
  "2:158": ["The knolls of Safa and Marwah are among the rites decreed by Allah. Anyone who observes Hajj or 'Umrah commits no error by traversing the distance between them. If one volunteers more righteous works, then Allah is Appreciative, Omniscient.","সাফা ও মারওয়া টিলাগুলো আল্লাহর জারি করা ধর্মীয় অনুষ্ঠানাদির অন্তর্ভূক্ত। যে কেউ হজ্জ অথবা উমরাহ পালন করে,এ দু’য়ের মাঝের দুরত্ব অতিক্রম করাতে তাদের কোন ভুল নেই। যদি কেউ স্বেচ্ছায় অধিক সৎকর্ম করে,তবে আল্লাহ যথার্থ মূল্যায়নকারী,সর্বজ্ঞ।"],
  "2:159": ["Those who conceal our revelations and guidance, after proclaiming them for the people in the scripture, are condemned by Allah; they are condemned by all the condemners.","যারা আমাদের প্রকাশনাবলী এবং পথ-নির্দেশণা গোপন করে,ঐশীগ্রন্থের সেগুলো মানুষের জন্য প্রকাশ করার পর, তারা আল্লাহ কর্তৃক নিন্দিত; তারা সকল বিবেচক দ্বারা নিন্দিত।"],
  "2:160": ["As for those who repent, reform, and proclaim, I redeem them. I am the Redeemer, Most Merciful.","আর যারা অনুশোচনা করে,সংশোধিত হয় এবং ঘোষনা করে,আমি তাদের উদ্ধার করি। আমিই উদ্ধারকারী,পরম দয়ালু।"],
  "2:161": ["Those who disbelieve and die as disbelievers, have incurred the condemnation of Allah, the angels, and all the people (on the Day of Judgment).","যারা অবিশ্বাস করে এবং অবিশ্বাসী অবস্থায় মারা যায়, তারা (বিচার দিবসে) নিজেদের উপর টেনে এনেছে আল্লাহর, ফেরেশতাদের এবং সকল মানুষের নিন্দা।"],
  "2:162": ["Eternally they abide therein. The retribution is never commuted for them, nor are they reprieved.","তারা সেখানে চিরস্থায়ীভাবে বসবাস করে। তাদের জন্য শাস্তি কখনোই কমানো হয় না,না তাদেরকে অবকাশ দেয়া হয়।"],
  "2:163": ["Your god is one god; there is no god but He, Most Gracious, Most Merciful.","তোমাদের উপাস্য এক উপাস্য; তিনি ছাড়া আর কোন উপাস্য নেই, পরম করুণাময়, পরম দয়ালু।"],
  "2:164": ["In the creation of the heavens and the earth, the alternation of night and day, the ships that roam the ocean for the benefit of the people, the water that Allah sends down from the sky to revive dead land and to spread in it all kinds of creatures, the manipulation of the winds, and the clouds that are placed between the sky and the earth, there are sufficient proofs for people who understand.","আকাশমন্ডলী ও পৃথিবীর সৃষ্টি,রাত ও দিনের পালাবদল, জাহাজসমূহ যা মানুষের উপকারার্থে সাগরে ঘুরে বেড়ায়, পানি যা আল্লাহ আকাশ থেকে বর্ষণ করেন মৃত ভূমিকে পূনর্জীবিত করানোর জন্য এবং এতে সব ধরণের জীবের বিস্তার করতে,বায়ূপ্রবাহ নিয়ন্ত্রনে,এবং আকাশ ও পৃথিবীর মাঝে অবস্থিত মেঘমালায়, যথেষ্ট প্রমাণ রয়েছে মানুষের জন্য যারা অনুধাবন করে।"],
  "2:165": ["Yet, some people set up idols to rival Allah, and love them as if they are Allah. Those who believe love Allah the most. If only the transgressors could see themselves when they see the retribution! They will realize then that all power belongs to Allah alone, and that Allah's retribution is awesome.","এরপরও, কিছু লোক আল্লাহর প্রতিদ্বন্দী করতে উপাস্য স্থাপন করে এবং তাদেরকে এমনভাবে ভালবাসে যেন তারা আল্লাহ। যারা বিশ্বাস করে তারা আল্লাহকেই সবচেয়ে বেশি ভালবাসে। শুধু যদি সীমালঙ্ঘনকারীরা নিজেদের দেখতে পেত যখন তারা শাস্তি অবলোকন করে! তখন তারা উপলব্ধি করবে যে সকল ক্ষমতা কেবল আল্লাহর, এবং আল্লাহর শাস্তি ভয়ানক।"],
  "2:166": ["Those who were followed will disown those who followed them. They will see the retribution, and all ties among them will be severed.","যাদেরকে অনুসরণ করা হতো তারা তাদের অনুসারীদের পরিত্যাগ করবে। তারা শাস্তি দেখবে,এবং তাদের মধ্যকার সকল বন্ধন ছিন্ন হবে।"],
  "2:167": ["Those who followed will say, \"If we can get another chance, we will disown them, as they have disowned us now.\" Allah thus shows them the consequences of their works as nothing but remorse; they will never exit Hell.","যারা অনুসরণ করতো তারা বলবে,“যদি আমরা আরেকবার সুযোগ পাই, আমরা তাদেরকে পরিত্যাগ করবো,যেভাবে তারা এখন আমাদের পরিত্যাগ করেছে।”আল্লাহ এভাবে তাদের কর্মফলকে অনুশোচনা ছাড়া অন্য কিছু হিসেবে দেখান না; তারা কখনো নরক থেকে বের হবে না।"],
  "2:168": ["O people, eat from the earth's products all that is lawful and good, and do not follow the steps of Satan; he is your most ardent enemy.","হে লোকসকল, পৃথিবীর উৎপাদিত সকল আইনসম্মত ও ভাল জিনিস হতে খাও এবং শয়তানের পদাঙ্ক অনুসরণ করো না। সে তোমাদের সবচেয়ে ঘোর শত্রু।"],
  "2:169": ["He only commands you to commit evil and vice, and to say about Allah what you do not know.","সে তোমাদের আদেশ দেয় শুধুমাত্র মন্দ ও অধর্ম করতে,এবং আল্লাহ সম্পর্কে এমন কথা বলতে যা তোমরা জানো না।"],
  "2:170": ["When they are told, \"Follow what Allah has revealed herein,\" they say, \"We follow only what we found our parents doing.\" What if their parents did not understand, and were not guided?","যখন তাদেরকে বলা হয়, “অনুসরণ করো যা আল্লাহ এখানে প্রকাশ করেছেন, ”তারা বলে,“আমরা শুধু অনুসরণ করি যা আমাদের পিতামাতাদের করতে দেখেছি।”আর যদি তাদের পিতামাতারা না বুঝে থাকে,এবং সুপথপ্রাপ্ত না হয়?"],
  "2:171": ["The example of such disbelievers is that of parrots who repeat what they hear of sounds and calls, without understanding. Deaf, dumb, and blind; they cannot understand.","এমন অবিশ্বাসীদের উদাহরণ হলো সেই তোতা পাখি,যেগুলো না বুঝে পুনঃরাবৃত্তি করে,যে শব্দ ও ডাক এগুলো শোনে। বধির, বোবা,ও অন্ধ; এরা বুঝতে পারে না।"],
  "2:172": ["O you who believe, eat from the good things we provided for you, and be thankful to Allah, if you do worship Him alone.","হে তোমরা যারা বিশ্বাস করো,তোমাদের জন্য আমাদের দেয়া ভালো জিনিস থেকে খাও এবং আল্লাহর প্রতি কৃতজ্ঞ হও, যদি তোমরা একমাত্র তাঁর উপাসনা করো।"],
  "2:173": ["He only prohibits for you the eating of animals that die of themselves (without human interference), blood, the meat of pigs, and animals dedicated to other than Allah. If one is forced (to eat these), without being malicious or deliberate, he incurs no sin. Allah is Forgiver, Most Merciful.","তিনি তোমাদের খাওয়ার জন্য নিষিদ্ধ করেন শুধু সে সমস্ত প্রানী যেগুলো নিজে নিজেই মারা যায় (মানুষের হস্তক্ষেপ ছাড়া),রক্ত, শুকরের মাংস এবং আল্লাহ ছাড়া অন্য কারো প্রতি উৎসর্গকৃত প্রানী। যদি কেউ (এগুলো খেতে) বাধ্য হয়, দুষ্টবুদ্ধি বা ইচ্ছার বশবর্তী না হয়ে,সে কোন পাপ করে না। আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "2:174": ["Those who conceal Allah's revelations in the scripture, in exchange for a cheap material gain, eat but fire into their bellies. Allah will not speak to them on the Day of Resurrection, nor will He purify them. They have incurred a painful retribution.","যারা আল্লাহর প্রকাশনাবলী গোপন করে,সস্তা পার্থিব অর্জনের বিনিময়ে,তারা আগুন ছাড়া অন্যকিছু দিয়ে তাদের পেট ভরায় না। আল্লাহ পুনঃরুত্থান দিবসে তাদের সাথে কথা বলবেন না,না তিনি তাদের পরিশুদ্ধ করবেন। তারা নিজেদের উপর এক যন্ত্রনাদায়ক শাস্তি টেনে এনেছে।"],
  "2:175": ["It is they who chose the straying instead of guidance, and the retribution instead of forgiveness. Consequently, they will have to endure Hell.","এরা তারা যারা পথ-নির্দেশনার পরিবর্তে পথভ্রষ্টতা,এবং ক্ষমার পরিবর্তে শাস্তি বেছে নিয়েছে। ফলশ্রুতিতে,তাদেরকে সহ্য করতে হবে নরক।"],
  "2:176": ["This is because Allah has revealed this scripture, bearing the truth, and those who dispute the scripture are the most ardent opponents.","এর কারণ এই যে,আল্লাহ এই ঐশীগ্রন্থ প্রকাশ করেছেন, সত্য সহকারে,এবং যারা ঐশীগ্রন্থে বিবাদ করে তারাই ঘোরতম বিরোধী।"],
  "2:177": ["Righteousness is not turning your faces towards the east or the west. Righteous are those who believe in Allah, the Last Day, the angels, the scripture, and the prophets; and they give the money, cheerfully, to the relatives, the orphans, the needy, the traveling alien, the beggars, and to free the slaves; and they observe the Contact Prayers (Salat) and give the obligatory charity (Zakat); and they keep their word whenever they make a promise; and they steadfastly persevere in the face of persecution, hardship, and war. These are the truthful; these are the righteous.","পূর্ব বা পশ্চিমে তোমাদের মুখ ফেরানোই সৎকর্ম নয়। তারা সৎকর্মশীল যারা বিশ্বাস করে আল্লাহতে,শেষ দিনে,ফেরেশতাদের, ঐশীগ্রন্থে এবং নবীদের; এবং তারা সানন্দে অর্থ দান করে আত্মীয়-স্বজনদের, এতীমদের, অভাবীদের, ভ্রমণরত বহিরাগতদের, ভিক্ষুকদের এবং দাস মুক্তির জন্য; এবং তারা সংযোগ প্রার্থণা (সালাত) পালন করে এবং বাধ্যতামূলক দান (যাকাত) দেয়; এবং তারা তাদের কথা রাখে যখন তারা কোন প্রতিশ্রুতি দেয়; এবং তারা নির্যাতন, কষ্ট এবং যুদ্ধের মুখে অবিচলতার সাথে অধ্যবসায়ী থাকে। এরাই সত্যবাদী; এরাই সৎকর্মশীল।"],
  "2:178": ["O you who believe, equivalence is the law decreed for you when dealing with murder—the free for the free, the slave for the slave, the female for the female. If one is pardoned by the victim's kin, an appreciative response is in order, and an equitable compensation shall be paid. This is an alleviation from your Lord and mercy. Anyone who transgresses beyond this incurs a painful retribution.","হে তোমরা যারা বিশ্বাস করো,সমতা হলো আইন যা তোমাদের জন্য জারি করা হলো যখন হত্যার বিচার করো– স্বাধীন ব্যক্তির জন্য স্বাধীন ব্যক্তি,দাসের জন্য দাস, নারীর জন্য নারী। যদি কেউ নিহত ব্যক্তির নিকটতম আত্মীয়ের ক্ষমা পায়, তাদেরকে কৃতজ্ঞতামূলক জবাব দিতে হবে এবং একটি ন্যায্য ক্ষতিপূরণ পরিশোধ করতে হবে। এটি তোমাদের প্রভুর পক্ষ থেকে একটি সহজীকরণ এবং অনুগ্রহ। যে কেউ এর বাইরে সীমালঙ্ঘন করে সে নিজের উপর যন্ত্রণাদায়ক শাস্তি টেনে আনে।"],
  "2:179": ["Equivalence is a life saving law for you, O you who possess intelligence, that you may be righteous.","সমতা হলো তোমাদের জন্য একটি জীবন রক্ষাকারী আইন, হে তোমরা যারা বুদ্ধিমত্তার অধিকারী,যাতে তোমরা সৎকর্মশীল হতে পারো।"],
  "2:180": ["It is decreed that when death approaches, you shall write a will for the benefit of the parents and relatives, equitably. This is a duty upon the righteous.","এই বিধান জারি করা হলো যে যখন মৃত্যু নিকটবর্তী হয়, তখন তোমরা একটি উইল লিখবে তোমাদের পিতামাতা ও আত্মীয়দের উপকারার্থে,ন্যায়সঙ্গতভাবে। এটা সৎকর্মশীলদের উপর দ্বায়িত্ব।"],
  "2:181": ["If anyone alters a will he had heard, the sin of altering befalls those responsible for such altering. Allah is Hearer, Knower.","যদি কেউ কোন উইল পরিবর্তন করে যা সে শুনেছিল, এই পরিবর্তনের পাপ তাদের উপর পড়বে যারা এরুপ পরিবর্তনের জন্য দায়ী। আল্লাহ সর্বশ্রোতা,সবজান্তা।"],
  "2:182": ["If one sees gross injustice or bias on the part of a testator, and takes corrective action to restore justice to the will, he commits no sin. Allah is Forgiver, Most Merciful.","যদি কেউ উইলকারীর দিক থেকে ঘোর অন্যায় কিংবা পক্ষপাত লক্ষ্য করে এবং উইলে ন্যায়বিচার ফিরিয়ে আনার লক্ষ্যে সংশোধনমূলক পদক্ষেপ গ্রহণ করে,তবে সে কোনো পাপ করে না। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "2:183": ["O you who believe, fasting is decreed for you, as it was decreed for those before you, that you may attain salvation.","হে তোমরা যারা বিশ্বাস করো,তোমাদের জন্য উপবাস পালনের বিধান জারি করা হলো,যেরুপ তোমাদের পূর্ববর্তীদের উপর এই বিধান জারি করা হয়েছিল, যাতে তোমরা পরিত্রাণ লাভ করতে পারো।"],
  "2:184": ["Specific days (are designated for fasting); if one is ill or traveling, an equal number of other days may be substituted. Those who can fast, but with great difficulty, may substitute feeding one poor person for each day of breaking the fast. If one volunteers (more righteous works), it is better. But fasting is the best for you, if you only knew.","নির্দিষ্ট দিনসমূহ (উপবাসের জন্য নির্ধারিত); যদি কেউ অসুস্থ হয় কিংবা ভ্রমণে থাকে,তবে সমান সংখ্যক অন্য দিন প্রতিস্থাপন করতে পারে। যাদের জন্য উপবাস করা অত্যন্ত কষ্টকর, তারা উপবাস ভঙ্গের প্রত্যেক দিনের বদলে একজন গরীব লোক খাওয়াবে। যদি কেউ স্বেচ্ছায় কিছু (অধিক সৎকর্ম) করে,এটা উত্তম। কিন্তু উপবাসই তোমাদের জন্য সর্বোত্তম, যদি শুধু তোমরা জানতে।"],
  "2:185": ["Ramadan is the month during which the Quran was revealed, providing guidance for the people, clear teachings, and the statute book. Those of you who witness this month shall fast therein. Those who are ill or traveling may substitute the same number of other days. Allah wishes for you convenience, not hardship, that you may fulfill your obligations, and to glorify Allah for guiding you, and to express your appreciation.","রমজানই হলো সে মাস যখন কুরআন অবতীর্ণ হয়েছিল, যা মানুষের জন্য প্রদান করে পথ-নির্দেশণা,সুস্পষ্ট শিক্ষা,এবং বিধান গ্রন্থ। তোমাদের মধ্যে যারা এই মাস প্রত্যক্ষ করবে তারা তাতে উপবাস পালন করবে। যারা অসুস্থ কিংবা ভ্রমণে থাকে,তারা এর পরিবর্তে সমান সংখ্যক অন্য দিন প্রতিস্থাপন করতে পারে। আল্লাহ তোমাদের জন্য সহজ করতে চান, কঠিন নয়, যাতে তোমরা তোমাদের দ্বায়িত্বসমূহ সম্পন্ন করতে পারো এবং তোমাদের সুপথে পরিচালনার জন্য আল্লাহর মহিমা ঘোষণা করতে পারো,এবং যাতে তোমাদের কৃতজ্ঞতা প্রকাশ করতে পারো।"],
  "2:186": ["When My servants ask you about Me, I am always near. I answer their prayers when they pray to Me. The people shall respond to Me and believe in Me, in order to be guided.","যখন আমার বান্দারা তোমাকে আমার সম্পর্কে জিজ্ঞেস করে,আমি সর্বদাই নিকটে। আমি তাদের প্রার্থণার জবাব দেই যখন তারা আমার কাছে প্রার্থণা করে। লোকেরা আমার প্রতি সাঁড়া দেবে এবং আমাকে বিশ্বাস করবে,সুপথ পাওয়ার জন্য।"],
  "2:187": ["Permitted for you is sexual intercourse with your wives during the nights of fasting. They are the keepers of your secrets, and you are the keepers of their secrets. Allah knew that you used to betray your souls, and He has redeemed you, and has pardoned you. Henceforth, you may have intercourse with them, seeking what Allah has permitted for you. You may eat and drink until the white thread of light becomes distinguishable from the dark thread of night at dawn. Then, you shall fast until sunset. Sexual intercourse is prohibited if you decide to retreat to the masjid (during the last ten days of Ramadan). These are Allah's laws; you shall not transgress them. Allah thus clarifies His revelations for the people, that they may attain salvation.","উপবাসের রাতে তোমাদের জন্য তোমাদের স্ত্রীদের সাথে সহবাস অনুমোদিত। তারা তোমাদের গোপনীয়তা রক্ষাকারী এবং তোমরা তাদের গোপনীয়তা রক্ষাকারী। আল্লাহ জানতেন যে তোমরা তোমাদের আত্মার সাথে প্রতারণা করতে এবং তিনি তোমাদের পাপমোচন করেছেন ও তোমাদেরকে ক্ষমা করেছেন। এখন থেকে,আল্লাহ তোমাদের জন্য যা অনুমোদন করেছেন তা অন্বেষণ করতে তোমরা তাদের সাথে সহবাস করতে পারো। তোমরা পানাহার করতে পারো যতক্ষণ না রাতের কালো রেখা থেকে আলোর সাদা রেখা পৃথক করা যায় ভোর বেলায়। তারপর, তোমরা সূর্যাস্ত পর্যন্ত উপবাস পালন করবে। (রমজানের শেষ দশ দিনে) সহবাস নিষিদ্ধ যদি তোমরা মসজিদে অবস্থানের সিদ্ধান্ত নাও। এগুলো আল্লাহর আইন; তোমরা এগুলোর সীমালঙ্ঘন করবে না। এভাবে আল্লাহ তাঁর প্রকাশনাবলী লোকদের জন্য সুস্পষ্ট করেন, যাতে তারা পরিত্রাণ লাভ করতে পারে।"],
  "2:188": ["You shall not take each others' money illicitly, nor shall you bribe the officials to deprive others of some of their rights illicitly, while you know.","তোমরা একে অপরের অর্থ অনৈতিকভাবে আত্মসাৎ করবে না,না তোমরা কর্মকর্তাদের ঘুষ দেবে অন্যদেরকে তাদের কিছু অধিকার থেকে অনৈতিকভাবে বঞ্চিত করতে,যখন তোমরা জানো।"],
  "2:189": ["They ask you about the phases of the moon! Say, \"They provide a timing device for the people, and determine the time of Hajj.\" It is not righteous to beat around the bush; righteousness is attained by upholding the commandments and by being straightforward. You shall observe Allah, that you may succeed.","তারা তোমাকে চাঁদের পর্যায়সমূহ সম্পর্কে জিজ্ঞেস করে! বল, “এগুলো লোকদের জন্য একটি সময় নিরুপণের পদ্ধতি প্রদান করে এবং হজ্জের সময় নির্ধারণ করে।”কাজের কথায় না এসে কথা ঘুরানোর মধ্যে ন্যায়নিষ্ঠতা নেই,  ন্যায়নিষ্ঠতা অর্জিত হয় ঐশিক আদেশ মেনে চলা এবং সরলতা অবলম্বনের মাধ্যমে। তোমরা আল্লাহকে মান্য করবে,যাতে তোমরা সফল হতে পারো।"],
  "2:190": ["You may fight in the cause of Allah against those who attack you, but do not aggress. Allah does not love the aggressors.","তোমরা আল্লাহর উদ্দেশ্যে যুদ্ধ করতে পারো তাদের বিরুদ্ধে যারা তোমাদের আক্রমণ করে, কিন্তু প্রথম আক্রমণ করো না। আল্লাহ আগ্রাসনকারীদের ভালোবাসেন না।"],
  "2:191": ["You may kill those who wage war against you, and you may evict them whence they evicted you. Oppression is worse than murder. Do not fight them at the Sacred Mosque (Masjid), unless they attack you therein. If they attack you, you may kill them. This is the just retribution for those disbelievers.","তোমরা তাদেরকে হত্যা করতে পারো যারা তোমাদের বিরুদ্ধে যুদ্ধ শুরু করে,এবং তোমরা তাদেরকে উচ্ছেদ করতে পারো,যেখান থেকে তারা তোমাদেরকে উচ্ছেদ করেছিল। অত্যাচার হত্যার চেয়ে অধিকতর মন্দ। পবিত্র মসজিদে (মসজিদ) তাদের সাথে লড়াই করবে না,যদি না তারা তোমাদের সেখানে আক্রমণ করে। যদি তারা তোমাদের আক্রমণ করে,তাদেরকে তোমরা হত্যা করতে পারো। এটা ঐসব অবিশ্বাসীদের জন্য উচিত শাস্তি।"],
  "2:192": ["If they refrain, then Allah is Forgiver, Most Merciful.","যদি তারা বিরত থাকে,তাহলে আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "2:193": ["You may also fight them to eliminate oppression, and to worship Allah freely. If they refrain, you shall not aggress; aggression is permitted only against the aggressors.","এছাড়াও, তোমরা তাদের সাথে লড়াই করতে পারো,অত্যাচার নির্মূল এবং স্বাধীনভাবে আল্লাহর উপাসনা করার জন্য। যদি তারা বিরত থাকে,তোমরা আগ্রাসী হবে না। শুধুমাত্র আগ্রাসনকারীদের বিরুদ্ধে আগ্রাসন অনুমোদিত।"],
  "2:194": ["During the Sacred Months, aggression may be met by an equivalent response. If they attack you, you may retaliate by inflicting an equitable retribution. You shall observe Allah and know that Allah is with the righteous.","পবিত্র মাসগুলোতে,একটি সমতুল্য জবাবের দ্বারা আগ্রসন মোকাবেলা করা যেতে পারে। যদি তারা তোমাদের আক্রমন করে,একটি ন্যায়সঙ্গত শাস্তি আরোপের দ্বারা তার জবাব দিতে পারো। তোমরা আল্লাহকে মান্য করবে এবং জানো যে আল্লাহ সৎকর্মশীলদের সাথে আছেন।"],
  "2:195": ["You shall spend in the cause of Allah; do not throw yourselves with your own hands into destruction. You shall be charitable; Allah loves the charitable.","তোমরা আল্লাহর উদ্দেশ্যে ব্যয় করবে; তোমরা নিজেদের হাতে নিজেদেরকে ধ্বংসের মুখে ঠেলে দিও না। তোমরা দানশীল হবে,আল্লাহ দানশীলদের ভালবাসেন।"],
  "2:196": ["You shall observe the complete rites of Hajj and 'Umrah for Allah. If you are prevented, you shall send an offering, and do not resume cutting your hair until your offering has reached its destination. If you are ill, or suffering a head injury (and you must cut your hair), you shall expiate by fasting, or giving to charity, or some other form of worship. During the normal Hajj, if you break the state of Ihraam (sanctity) between 'Umrah and Hajj, you shall expiate by offering an animal sacrifice. If you cannot afford it, you shall fast three days during Hajj and seven when you return home—this completes ten—provided you do not live at the Sacred Mosque (Masjid). You shall observe Allah, and know that Allah is strict in enforcing retribution.","তোমরা আল্লাহর জন্য হজ্ব এবং ওমরাহের পরিপূর্ণ আনুষ্ঠানিকতা পালন করবে। যদি তোমরা বাধাপ্রাপ্ত হও, তোমরা একটি উৎসর্গ পাঠাবে,এবং তোমাদের উৎসর্গ গন্তব্যে না পৌঁছানো পর্যন্ত মাথা মুন্ডন শুরু করো না। যদি তোমরা অসুস্থ হও, অথবা কোন মাথার আঘাতে ভোগে থাকো (এবং তোমাদের চুল কাটতেই হয়),তোমরা প্রায়শ্চিত্ত করবে উপবাসের মাধ্যমে,অথবা দান করে,অথবা অন্য কোন ধরনের উপাসনার দ্বারা। সাধারণ হজ্বের সময়, তোমরা যদি উমরাহ্‌ এবং হজ্বের মধ্যে ইহরাম (পবিত্রতার) অবস্থা ভঙ্গ করো,তোমরা একটি পশু উৎসর্গের মাধ্যমে প্রায়শ্চিত্ত করবে। যদি তোমাদের এর সামর্থ না থাকে,তাহলে তোমরা হজ্বের সময় তিন (দিন) উপবাস পালন করবে এবং বাড়ি ফিরে সাত (দিন) - এতে দশ (দিন) পূর্ন হয় - যদি না তোমরা পবিত্র মসজিদে বাস করো। তোমরা আল্লাহকে মান্য করবে এবং জানো যে আল্লাহ শাস্তি প্রয়োগে কঠোর।"],
  "2:197": ["Hajj shall be observed in the specified months. Whoever sets out to observe Hajj shall refrain from sexual intercourse, misconduct, and arguments throughout Hajj. Whatever good you do, Allah is fully aware thereof. As you prepare your provisions for the journey, the best provision is righteousness. You shall observe Me, O you who possess intelligence.","হজ্জ তীর্থযাত্রা পালন করতে হবে নির্ধারিত মাসগুলোতে। যে কেউ হজ্ব পালনের উদ্দেশে বের হয়, শারীরিক মিলন, খারাপ ব্যবহার এবং তর্ক করা থেকে বিরত থাকবে,হজ্বের পুরো সময় জুঁড়ে। তোমরা যে পূন্যই করো,আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত। তোমরা যখন (তীর্থ) যাত্রার জন্য পাথেয় প্রস্তুত করো,সবচেয়ে উত্তম পাথেয় হল আল্লাহ ভীতি। তোমরা আমাকে মান্য করবে,ওহে তোমরা যারা জ্ঞানবুদ্ধির অধিকারী।"],
  "2:198": ["You commit no error by seeking provisions from your Lord (through commerce). When you file from 'Arafaat, you shall commemorate Allah at the Sacred Location (of Muzdalifah). You shall commemorate Him for guiding you; before this, you had gone astray.","তোমাদের প্রভুর নিকট থেকে (বাণিজ্যের মাধ্যমে) জীবিকা অন্বেষণ করে তোমরা কোন ভুল করো না। তোমরা যখন আরাফাত থেকে সারিবদ্ধভাবে রওয়ানা হবে,তোমরা পবিত্র স্থানে (মুজদালিফাতে) আল্লাহকে স্মরণ করবে,তোমার তাঁকে স্মরণ করবে তোমাদেরকে পথ প্রদর্শণ করার জন্য; এর আগে তোমরা পথভ্রষ্ট হয়ে গিয়েছিলে।‘"],
  "2:199": ["You shall file together, with the rest of the people who file, and ask Allah for forgiveness. Allah is Forgiver, Most Merciful.","তোমরা একত্রে সারিবদ্ধভাবে রওয়ানা হবে বাকী লোকদের সাথে যারা সারিবদ্ধভাবে রওয়ানা হয়, এবং আল্লাহর কাছে ক্ষমা প্রার্থনা করবে। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "2:200": ["Once you complete your rites, you shall continue to commemorate Allah as you commemorate your own parents, or even better. Some people would say, \"Our Lord, give us of this world,\" while having no share in the Hereafter.","তোমরা তোমাদের আনুষ্ঠানিকতা সম্পূর্ণ করার পর, তোমরা আল্লাহর স্মরণ করতে থাকবে যেভাবে তোমরা তোমাদের নিজেদের পিতামাতাকে স্মরণ করো,বা তার চেয়েও উত্তম রূপে। কিছু লোক বলবে,“আমাদের প্রভু,আমাদেরকে এই দুনিয়াতে দিন\",যখন পরকালে কোন অংশ থাকে না।"],
  "2:201": ["Others would say, \"Our Lord, grant us righteousness in this world, and righteousness in the Hereafter, and spare us the retribution of Hell.\"","অন্যরা বলবে,\"আমাদের প্রভু,আমাদেরকে এই দুনিয়াতে কল্যাণ দান করুন, এবং পরকালেও কল্যাণ দান করুন, এবং আমাদেরকে নরকের শাস্তি থেকে রক্ষা করুন।\""],
  "2:202": ["Each of these will receive the share they have earned. Allah is most efficient in reckoning.","এদের প্রত্যেকেই পাবে সেই অংশ যা তারা অর্জন করেছে। আল্লাহ হিসাব গ্রহণে সবচেয়ে দক্ষ।"],
  "2:203": ["You shall commemorate Allah for a number of days (in Mena); whoever hastens to do this in two days commits no sin, and whoever stays longer commits no sin, so long as righteousness is maintained. You shall observe Allah, and know that before Him you will be gathered.","তোমরা আল্লাহকে স্মরণ করবে কিছু সংখ্যক দিন (মিনাতে); যে কেউ ত্বরা করে তা দুই দিনে সম্পন্ন করে সে কোন পাপ করে না এবং যে কেউ বেশি সময় অবস্থান করে সে কোন পাপ করে না,যতক্ষণ ন্যায়পরায়নতা বজায় রাখা হয়। তোমরা আল্লাহকে মান্য করবে এবং জানো যে তাঁর সামনেই তোমরা একত্রিত হবে।"],
  "2:204": ["Among the people, one may impress you with his utterances concerning this life, and may even call upon Allah to witness his innermost thoughts, while he is a most ardent opponent.","লোকদের মধ্যে,কেউ তোমাকে এই দুনিয়া সম্পর্কে তার কথা দিয়ে মোহিত করতে পারে,এবং এমনকি তার গভীরতম চিন্তার সাক্ষী হবার জন্য আল্লাহকে আহবান করতে পারে,যদিও সে একজন সবচেয়ে ঘোর বিরোধী।"],
  "2:205": ["As soon as he leaves, he roams the earth corruptingly, destroying properties and lives. Allah does not love corruption.","সে প্রস্থান করা মাত্রই, পৃথিবীতে ঘুরে বেড়াঁয় দূর্নীতি করে,সম্পত্তি এবং জীবন ধ্বংস করে। আল্লাহ দূর্নীতিকে ভালবাসেন না।"],
  "2:206": ["When he is told, \"Observe Allah,\" he becomes arrogantly indignant. Consequently, his only destiny is Hell; what a miserable abode.","যখন তাকে বলা হয়, \"আল্লাহকে মেনে চল\",সে ঔদ্ধতের সাথে ক্ষুব্ধ হয়। ফলস্বরুপ, তার একমাত্র গন্তব্য নরক, কতই না দুর্বিষহ আবাস।"],
  "2:207": ["Then there are those who dedicate their lives to serving Allah; Allah is compassionate towards such worshipers.","অতঃপর রয়েছে তারা,যারা আল্লাহর প্রতি দায়িত্ব পালনে নিজেদের জীবন উৎসর্গ করে। আল্লাহ এরকম উপাসনাকারীদের প্রতি মেহেরবান।"],
  "2:208": ["O you who believe, you shall embrace total submission; do not follow the steps of Satan, for he is your most ardent enemy.","হে যারা বিশ্বাস করো,তোমরা পরিপূর্ণভাবে আত্মসমর্পণ করবে; শয়তানের পদাঙ্ক অনুসরণ করো না,কারন সে তোমাদের সবচেয়ে ঘোর শত্রু।"],
  "2:209": ["If you backslide, after the clear proofs have come to you, then know that Allah is Almighty, Most Wise.","যদি তোমরা পিছপা হও, তোমাদের কাছে সুস্পষ্ট প্রমাণ আসার পর, তবে জেনে নাও যে আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "2:210": ["Are they waiting until Allah Himself comes to them in dense clouds, together with the angels? When this happens, the whole matter will be terminated, and to Allah everything will be returned.","তারা কি অপেক্ষা করছে যে কখন আল্লাহ নিজে পুঞ্জিভূত মেঘের মাঝে তাদের কাছে আসবেন, ফেরেশতাদের সাথে? যখন তা ঘটবে,পুরো ব্যাপারটাই শেষ হয়ে যাবে,এবং আল্লাহর নিকট সবকিছু ফিরে যাবে।"],
  "2:211": ["Ask the Children of Israel how many profound miracles have we shown them! For those who disregard the blessings bestowed upon them by Allah, Allah is most strict in retribution.","ইসরাইলের সন্তানদের জিজ্ঞেস করো- তাদেরকে আমরা কতগুলো প্রগাঢ় নিদর্শন দেখিয়েছিলাম! যারা তাদের উপর অর্পিত আল্লাহর আশীর্বাদকে উপেক্ষা করে,আল্লাহ তাদের জন্য শাস্তি আরোপে সবচেয়ে কঠোর।"],
  "2:212": ["This worldly life is adorned in the eyes of the disbelievers, and they ridicule those who believe. However, the righteous will be far above them on the Day of Resurrection. Allah blesses whomever He wills, without limits.","অবিশ্বাসীদের চোখে এই পার্থিব জীবন সুসজ্জিত করে দেয়া হয়েছে,এবং তারা তাদেরকে উপহাস করে যারা বিশ্বাস করে। তবে,পুনরুত্থানের দিন সৎকর্মশীলরা তাদের চেয়ে অনেক উপরে থাকবে। আল্লাহ যাকে ইচ্ছা আশীর্বাদ করেন, সীমাহীন ভাবে।"],
  "2:213": ["The people used to be one community when Allah sent the prophets as bearers of good news, as well as warners. He sent down with them the scripture, bearing the truth, to judge among the people in their disputes. Ironically, those who received the scripture were the ones who rejected any new scripture, despite clear proofs given to them. This is due to jealousy on their part. Allah guides those who believe to the truth that is disputed by all others, in accordance with His will. Allah guides whoever wills in a straight path.","লোকেরা একই সম্প্রদায়ভূক্ত ছিল যখন আল্লাহ নবীদের পাঠালেন সুসংবাদ বহনকারী,একই সাথে সতর্ককারী হিসেবে। তিনি তাদের সাথে অবতীর্ণ করেছিলেন ঐশীগ্রন্থ, যা সত্য বহনকারী,লোকদের মাঝে তাদের বিতর্কের বিচার করার জন্য। দুঃখজনক ভাবে,যারা ঐশীগ্রন্থ গ্রহণ করেছিল তারাই নতুন কোন ঐশীগ্রন্থ প্রত্যাখ্যান করেছে,তাদেরকে দেয়া সুস্পষ্ট প্রমান সত্তেও। এটা তাদের পক্ষ থেকে হিংসার কারনে। আল্লাহ তাদের পথ-প্রদর্শন করেন যারা বিশ্বাস করে সত্যের দিকে যা অন্য সকলের দ্বারা বিতর্কিত, আল্লাহর ইচ্ছানুসারে। আল্লাহ যাকে ইচ্ছা সরল পথে পথ-প্রদর্শন করেন।"],
  "2:214": ["Do you expect to enter Paradise without being tested like those before you? They were tested with hardship and adversity, and were shaken up, until the messenger and those who believed with him said, \"Where is Allah's victory?\" Allah's victory is near.","তোমরা কি স্বর্গে প্রবেশ করার আশা করো পরিক্ষীত হওয়া ছাড়াই যেমন করা হয়েছিল তোমাদের পূর্ববর্তীদের? তারা পরিক্ষীত হয়েছিল কষ্ট এবং প্রতিকূল পরিস্থিতির মধ্য দিয়ে,এবং শিহরিত হয়েছিল/ধাক্কা খেয়েছিল, যতক্ষণ না বার্তাবাহক এবং তার সঙ্গে যারা বিশ্বাস করেছিল তারা বলেছিল, \"কোথায় আল্লাহর বিজয়?”আল্লাহর বিজয় নিকটেই।"],
  "2:215": ["They ask you about giving: say, \"The charity you give shall go to the parents, the relatives, the orphans, the poor, and the traveling alien.\" Any good you do, Allah is fully aware thereof.","তারা তোমাকে জিজ্ঞেস করে দান সম্পর্কে,বল, \"তোমরা যে দান করো তা যাবে পিতা-মাতা,আত্মীয়-স্বজন, এতিম, গরীব এবং ভ্রমণরত ভীনদেশীদের জন্য।”যেকোন ভাল কাজ তোমরা করো,আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "2:216": ["Fighting may be imposed on you, even though you dislike it. But you may dislike something which is good for you, and you may like something which is bad for you. Allah knows while you do not know.","যুদ্ধ তোমাদের উপর আরোপিত হতে পারে,যদিও তোমরা তা অপছন্দ করো। কিন্ত হয়তো তোমরা কোন কিছু অপছন্দ করছো যা তোমাদের জন্য ভাল, এবং হয়তো তোমরা কোন কিছু পছন্দ করছো যা তোমাদের জন্য মন্দ। আল্লাহ জানেন যখন তোমরা জানো না।"],
  "2:217": ["They ask you about the Sacred Months and fighting therein: say, \"Fighting therein is a sacrilege. However, repelling from the path of Allah and disbelieving in Him and in the sanctity of the Sacred Mosque (Masjid), and evicting its people, are greater sacrileges in the sight of Allah. Oppression is worse than murder.\" They will always fight you to revert you from your religion, if they can. Those among you who revert from their religion, and die as disbelievers, have nullified their works in this life and the Hereafter. These are the dwellers of Hell, wherein they abide forever.","তারা তোমাকে পবিত্র মাসসমূহ এবং তাতে যুদ্ধ করা সম্পর্কে জিজ্ঞাসা করে; বল, “তাতে যুদ্ধ করা একটি অপবিত্র কাজ। কিন্ত, আল্লাহর পথে প্রতিবন্ধকতা সৃষ্টি করা,এবং অবিশ্বাস করা তাঁকে ও পবিত্র মসজিদের পবিত্রতায়,এবং এর লোকেদের উচ্ছেদ করা,আল্লাহর দৃষ্টিতে আরও বড় অপবিত্র কাজ। অত্যাচার হত্যা থেকে অধিকতর মন্দ”। তারা সব সময় তোমাদের সাথে লড়াই করবে তোমাদেরকে তোমাদের ধর্ম থেকে ফিরিয়ে দিতে,যদি তারা পারে। তোমাদের মধ্যে যারা তাদের ধর্ম থেকে ফিরে যাবে,এবং অবিশ্বাসী হিসেবে মৃত্যুবরণ করবে,তারা বিনষ্ট করে ফেলেছে তাদের কাজ এই জীবনে এবং পরকালে। এরাই নরকের বাসিন্দা,যেখানে তারা চিরকাল বসবাস করবে।"],
  "2:218": ["Those who believe, and those who emigrate and strive in the cause of Allah, have deserved Allah's mercy. Allah is Forgiver, Most Merciful.","যারা বিশ্বাস করে,এবং যারা দেশান্তরী হয় এবং আল্লাহর উদ্দেশ্য সংগ্রাম করে,তারা আল্লাহর করুণা পাবার যোগ্য হয়েছে। আল্লাহ ক্ষমাশীল, পরম করুণাময়।"],
  "2:219": ["They ask you about intoxicants and gambling: say, \"In them there is a gross sin, and some benefits for the people. But their sinfulness far outweighs their benefit.\" They also ask you what to give to charity: say, \"The excess.\" Allah thus clarifies the revelations for you, that you may reflect,","তারা তোমাকে মাদকদ্রব্য এবং জুয়া সম্পর্কে জিজ্ঞাসা করে; বল, “এগুলোর মধ্যে রয়েছে মহাপাপ এবং লোকেদের জন্য কিছু উপকার। কিন্তু,এগুলোর পাপ উপকার থেকে অনেক বেশি”। তারা তোমাকে আরও জিজ্ঞাসা করে কি দান করবে; বল, “অতিরিক্তটা”। আল্লাহ এভাবে প্রকাশনাবলী তোমাদের জন্য সুস্পষ্ট করেন, যাতে তোমরা অনুধাবন করো,"],
  "2:220": ["upon this life and the Hereafter. And they ask you about the orphans: say, \"Bringing them up as righteous persons is the best you can do for them. If you mix their property with yours, you shall treat them as family members.\" Allah knows the righteous and the wicked. Had Allah willed, He could have imposed harsher rules upon you. Allah is Almighty, Most Wise.","এই জীবন এবং পরকালের বিষয়ে। এবং তারা তোমাকে এতিমদের সম্পর্কে জিজ্ঞেস করেঃ বল, \"তোমরা তাদের জন্য যা করতে পারো তন্মধ্যে তাদেরকে সৎকর্মশীল হিসেবে বড় করাই সর্বোত্তম। তোমরা যদি তাদের সম্পত্তির সাথে তোমাদের সম্পদ মিশিয়ে ফেল, তবে তোমরা তাদের সাথে পরিবারের সদস্যের মতো ব্যবহার করবে”। আল্লাহ সৎকর্মশীল এবং মন্দদের জানেন। আল্লাহ যদি চাইতেন, তবে তিনি তোমাদের উপর কঠোরতর নিয়ম আরোপ করতে পারতেন। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "2:221": ["Do not marry idolatresses unless they believe; a believing woman is better than an idolatress, even if you like her. Nor shall you give your daughters in marriage to idolatrous men, unless they believe. A believing man is better than an idolater, even if you like him. These invite to Hell, while Allah invites to Paradise and forgiveness, as He wills. He clarifies His revelations for the people, that they may take heed.","প্রতিমা উপাসক নারীদের বিয়ে করো না যদি না তারা বিশ্বাস করে; একজন বিশ্বাসী নারী একজন প্রতিমা উপাসক নারীর চেয়ে উত্তম, যদিও তোমরা তাকে পছন্দ করো। না তোমরা তোমাদের কন্যাদের প্রতিমা উপাসক পুরুষের সাথে বিয়ে দেবে,যদি না তারা বিশ্বাস করে। একজন বিশ্বাসী পুরুষ একজন প্রতিমা উপাসক পুরুষের চেয়ে উত্তম যদিও তোমরা তাকে পছন্দ করো। এরা নরকের দিকে আহবান করে,যখন আল্লাহ স্বর্গ এবং ক্ষমাশীলতার দিকে আহবান করেন, যেমন তিনি ইচ্ছা করেন। তিনি লোকদের জন্য তাঁর প্রত্যাদেশাবলী সুস্পষ্ট করেন, যাতে তারা সতর্ক হতে পারে।"],
  "2:222": ["They ask you about menstruation: say, \"It is harmful; you shall avoid sexual intercourse with the women during menstruation; do not approach them until they are rid of it. Once they are rid of it, you may have intercourse with them in the manner designed by Allah. Allah loves the repenters, and He loves those who are clean.\"","তারা তোমাকে রজঃস্রাব সম্পর্কে জিজ্ঞাসা করেঃ বল, “এটা ক্ষতিকারক; তোমরা রজঃস্রাবের সময় স্ত্রীদের সাথে যৌন সহবাস এড়িয়ে চলবে; তাদের সান্নিধ্যে যেও না যতক্ষণ না তারা এটা থেকে মুক্ত হয়। যখন তারা এটা থেকে মুক্ত হয়, তোমরা তাদের সাথে সহবাস করতে পার, আল্লাহর পরিকল্পিত পদ্ধতিতে। আল্লাহ অনুশোচনাকারীদের ভালোবাসেন, এবং তিনি তাদের ভালোবাসেন যারা পরিষ্কার।"],
  "2:223": ["Your women are the bearers of your seed. Thus, you may enjoy this privilege however you like, so long as you maintain righteousness. You shall observe Allah, and know that you will meet Him. Give good news to the believers.","তোমাদের স্ত্রীরা তোমাদের বীজের ধারক। তাই, তোমরা এই বিশেষ সুবিধা উপভোগ করতে পারো যেভাবে তোমরা পছন্দ করো,যতক্ষণ তোমরা ন্যায়পরায়ণতা বজায় রাখো। তোমরা আল্লাহকে মান্য করবে,এবং জেনে রাখো যে তোমরা তাঁর সাথে সাক্ষাৎ করবে। বিশ্বাসীদের সুসংবাদ দাও।"],
  "2:224": ["Do not subject Allah's name to your casual swearing, that you may appear righteous, pious, or to attain credibility among the people. Allah is Hearer, Knower.","তোমাদের নৈমিত্তিক শপথে আল্লাহর নামকে উপলক্ষ্য বানিয়ো না,যাতে তোমরা সৎকর্মশীল, সৎকর্মশীল প্রতীয়মান হতে পারো,অথবা মানুষের মাঝে বিশ্বাসযোগ্যতা অর্জন করতে পারো। আল্লাহ শ্রোতা,জ্ঞাতা।"],
  "2:225": ["Allah does not hold you responsible for the mere utterance of oaths; He holds you responsible for your innermost intentions. Allah is Forgiver, Clement.","শুধুমাত্র শপথ উচ্চারণের কারনে আল্লাহ তোমাদের দায়ী করেন না; তিনি তোমাদের দায়ী করেন তোমাদের গভীরতম অভিপ্রায়ের জন্য। আল্লাহ ক্ষমাশীল, সহিষূ।"],
  "2:226": ["Those who intend to divorce their wives shall wait four months (cooling off); if they change their minds and reconcile, then Allah is Forgiver, Merciful.","যারা তাদের স্ত্রীদের সাথে বিবাহ-বিচ্ছেদ করতে মনস্থ করে তারা চার মাস অপেক্ষা করবে (শান্ত হতে); তারা যদি তাদের মন পরিবর্তন করে এবং পূনঃর্মিলিত হয়, তবে আল্লাহ ক্ষমাশীল, দয়ালু।"],
  "2:227": ["If they go through with the divorce, then Allah is Hearer, Knower.","তারা যদি বিবাহ-বিচ্ছেদের মধ্য দিয়ে যায়, তবে আল্লাহ শ্রোতা,জ্ঞাতা।"],
  "2:228": ["The divorced women shall wait three menstruations (before marrying another man). It is not lawful for them to conceal what Allah creates in their wombs, if they believe in Allah and the Last Day. (In case of pregnancy,) the husband's wishes shall supersede the wife's wishes, if he wants to remarry her. The women have rights, as well as obligations, equitably. Thus, the man's wishes prevail (in case of pregnancy). Allah is Almighty, Most Wise.","বিবাহ-বিচ্ছেদ প্রাপ্ত নারী তিন রজঃস্রাব পর্যন্ত অপেক্ষা করবে (অন্য পুরুষকে বিয়ে করার পূর্বে)। এটা তাদের জন্য আইনসম্মত নয়, যা আল্লাহ তাদের গর্ভে সৃষ্টি করেন তা গোপন করা,যদি তারা আল্লাহ এবং পরকালে বিশ্বাস করে। (গর্ভাবস্থার ক্ষেত্রে) স্বামীর ইচ্ছা স্ত্রীর ইচ্ছার উপর স্থান পাবে,যদি সে তাকে পুনরায় বিয়ে করতে চায়। নারীর অধিকার রয়েছে,পাশাপাশি রয়েছে দায়িত্ব, সমানভাবে। এভাবে,স্বামীর ইচ্ছা প্রাধান্য পায় (গর্ভাবস্থার ক্ষেত্রে)। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "2:229": ["Divorce may be retracted twice. The divorced woman shall be allowed to live in the same home amicably, or leave it amicably. It is not lawful for the husband to take back anything he had given her. However, the couple may fear that they may transgress Allah's law. If there is fear that they may transgress Allah's law, they commit no error if the wife willingly gives back whatever she chooses. These are Allah's laws; do not transgress them. Those who transgress Allah's laws are the unjust.","বিবাহ-বিচ্ছেদ দু’বার বাতিল করা যেতে পারে। বিবাহ-বিচ্ছেদ প্রাপ্ত নারী একই বাড়িতে সৌহার্দ্যপূর্ণভাবে বাস করতে,অথবা সৌহার্দ্যপূর্ণভাবে ছেড়ে চলে যেতে অনুমোদিত হবে। এটা স্বামীর জন্য আইনসম্মত নয় যে যা সে তাকে দিয়েছে এর কোনকিছু ফিরিয়ে নেয়া। কিন্তু,দম্পত্তির আশংকা হতে পারে যে তারা হয়তো আল্লাহর আইনের সীমালঙ্ঘন করবে। যদি কোন আশংকা থাকে যে তারা আল্লাহর আইনের সীমালঙ্ঘন করবে,তারা কোন ভুল করে না যদি স্ত্রী স্বেচ্ছায় ফিরিয়ে দেয় যা কিছু সে পছন্দ করে। এগুলো আল্লাহর আইন, এগুলোর সীমালঙ্ঘন করো না। যারা আল্লাহর আইনের সীমালঙ্ঘন করে তারা অবিবেচক।"],
  "2:230": ["If he divorces her (for the third time), it is unlawful for him to remarry her, unless she marries another man, then he divorces her. The first husband can then remarry her, so long as they observe Allah's laws. These are Allah's laws; He explains them for people who know.","সে যদি তার (স্ত্রীর) সাথে (তৃতীয়বারের মতো) বিবাহ-বিচ্ছেদ করে,তাকে পুনরায় বিয়ে করা তার জন্য বে-আইনি,যদি না সে অন্য পুরুষকে বিয়ে করে নেয়,এরপর সে (পুরুষ) তার সাথে বিবাহ-বিচ্ছেদ করে। প্রথম স্বামী তখন তাকে পুনরায় বিয়ে করতে পারে,যতক্ষণ পর্যন্ত তারা আল্লাহর আইন মান্য করে। এগুলো আল্লাহর আইন; তিনি এগুলো ব্যাখ্যা করেন তাদের জন্য যারা জানে।"],
  "2:231": ["If you divorce the women, once they fulfill their interim (three menstruations), you shall allow them to live in the same home amicably, or let them leave amicably. Do not force them to stay against their will, as a revenge. Anyone who does this wrongs his own soul. Do not take Allah's revelations in vain. Remember Allah's blessings upon you, and that He sent down to you the scripture and wisdom to enlighten you. You shall observe Allah, and know that Allah is aware of all things.","যদি তোমরা স্ত্রীদের সাথে বিবাহ-বিচ্ছেদ করো,যখন তারা অন্তর্বর্তী সময় (তিন রজঃস্রাব) সম্পূর্ণ করে,তোমরা একই বাড়িতে তাদেরকে সৌহার্দ্যপূর্ণভাবে বাস করতে দেবে,অথবা সৌহার্দ্যপূর্ণভাবে তাদেরকে চলে যেতে দেবে। তাদের ইচ্ছার বিরুদ্ধে তাদেরকে থাকার জন্য বল  প্রয়োগ করো না,প্রতিশোধ হিসাবে। যে কেউ এই কাজ করে সে নিজের আত্মার ক্ষতি করে। আল্লাহর প্রকাশনাবলিকে নিরর্থকভাবে নিও না। তোমাদের প্রতি আল্লাহর আশীর্বাদ স্মরণ করো,এবং এটা যে তিনি তোমাদের কাছে অবতীর্ণ করেছেন ঐশীগ্রন্থ এবং জ্ঞান, তোমাদের আলোকিত করার জন্য। তোমরা আল্লাহকে মান্য করবে,এবং জানো যে আল্লাহ সবকিছু সম্পর্কে সচেতন।"],
  "2:232": ["If you divorce the women, once they fulfill their interim, do not prevent them from remarrying their husbands, if they reconcile amicably. This shall be heeded by those among you who believe in Allah and the Last Day. This is purer for you, and more righteous. Allah knows, while you do not know.","যদি তোমরা স্ত্রীদের সাথে বিবাহ-বিচ্ছেদ করো,যখন তারা অন্তর্বর্তী সময় সম্পূর্ণ করে,তাদেরকে তাদের স্বামীদের পুনরায় বিয়ে করতে বাধা দিও না,যদি তারা সৌহার্দ্যপূর্ণভাবে পুনঃর্মিলিত হয়। এটা তোমাদের মধ্যে তাদের দ্বারা মান্য হবে যারা আল্লাহ এবং শেষ দিনে বিশ্বাস করে। এটা তোমাদের জন্য পবিত্র, এবং অধিক ধর্মনিষ্ঠ। আল্লাহ জানেন, যখন তোমরা জানো না।"],
  "2:233": ["Divorced mothers shall nurse their infants two full years, if the father so wishes. The father shall provide the mother's food and clothing equitably. No one shall be burdened beyond his ability. No mother shall be harmed on account of her infant, nor shall the father be harmed because of his infant. (If the father dies), his inheritor shall assume these responsibilities. If the infant's parents mutually agree to part, after due consultation, they commit no error by doing so. You commit no error by hiring nursing mothers, so long as you pay them equitably. You shall observe Allah, and know that Allah is Seer of everything you do.","বিবাহ বিচ্ছেদকৃত মা,তাদের শিশুদের পূর্ণ দুই বছর স্তন্যপান করাবে,যদি পিতা এরকম ইচ্ছা করে। পিতা ন্যায়সঙ্গত ভাবে মায়ের খাদ্য ও বস্ত্রের সংস্থান করবে। কাউকে তার ক্ষমতার অতিরিক্ত দায়িত্ব চাপানো যাবে না। কোন মা তার শিশুর কারণে ক্ষতিগ্রস্ত হবে না,না কোন পিতা ক্ষতিগ্রস্ত হবে তার শিশুর কারণে। (যদি পিতা মারা যায়),তার উত্তরাধিকারী এই দায়িত্বসমূহ গ্রহণ করবে। যদি শিশুর পিতা-মাতা আলাদা হওয়ার ব্যপারে পরস্পর সম্মত হয়, যথোচিত পরামর্শের পর, এরকম করে তারা কোন ভুল করে না। তোমরা দুধ-মা ভাড়া করে কোন ভুল করো না,যতক্ষণ তোমরা তাদেরকে ন্যায়সঙ্গত পারিশ্রমিক দাও। তোমরা আল্লাহকে মান্য করবে,এবং জান যে আল্লাহ সবকিছুর দ্রষ্টা যা তোমরা করো।"],
  "2:234": ["Those who die and leave wives, their widows shall wait four months and ten days (before they remarry). Once they fulfill their interim, you commit no error by letting them do whatever righteous matters they wish to do. Allah is fully Cognizant of everything you do.","যারা মারা যায় এবং স্ত্রীদের ছেঁড়ে যায়,তাদের বিধবারা চার মাস এবং দশ দিন অপেক্ষা করবে (তারা পুনরায় বিয়ে করার আগে)। যখন তারা অন্তর্বর্তী সময় পূর্ণ করে,যে কোন ন্যায়সঙ্গত বিষয় তারা করতে ইচ্ছা করে,তাদেরকে তা করতে দিয়ে তোমরা ভুল করো না। আল্লাহ সম্পূর্ণ জ্ঞাত সে সবকিছু সম্পর্কে যা তোমরা করো।"],
  "2:235": ["You commit no sin by announcing your engagement to the women, or keeping it secret. Allah knows that you will think about them. Do not meet them secretly, unless you have something righteous to discuss. Do not consummate the marriage until their interim is fulfilled. You should know that Allah knows your innermost thoughts, and observe Him. You should know that Allah is Forgiver, Clement.","তোমরা কোন পাপ করো না তোমাদের সাথে সেই নারীদের বিবাহের বাগদান ঘোষণা করে,অথবা তা গোপন রেখে। আল্লাহ জানেন যে তোমরা তাদের ব্যাপারে চিন্তা করবে। তাদের সাথে গোপনে সাক্ষাৎ করো না,যদি না আলোচনা করার জন্য তোমাদের কোন ন্যায়সঙ্গত বিষয় থাকে। বিয়ে সুসম্পূর্ণ করো না যতক্ষণ না তাদের অন্তর্বর্তী সময় পূর্ণ হয়। তোমাদের জানা উচিৎ যে,আল্লাহ জানেন তোমাদের গভীরতম চিন্তা,এবং তাঁকে মান্য করো। তোমাদের জানা উচিৎ যে,আল্লাহ ক্ষমাশীল, সহিষ্ণু।"],
  "2:236": ["You commit no error by divorcing the women before touching them, or before setting the dowry for them. In this case, you shall compensate them—the rich as he can afford and the poor as he can afford —an equitable compensation. This is a duty upon the righteous.","তোমরা কোন ভুল করো না নারীদের সাথে বিবাহ-বিচ্ছেদ করে তাদেরকে স্পর্শ করার আগে,অথবা তাদের জন্য দেন-মোহর নির্ধারণ করার আগে। এক্ষেত্রে,তোমরা তাদেরকে ক্ষতিপূরণ দিবে- ধনিরা তাদের সামর্থ অনুসারে এবং দরিদ্ররা তাদের সামর্থ অনুসারে- একটি ন্যায়সঙ্গত ক্ষতিপূরণ। এটা সৎকর্মশীলদের উপর একটি দায়িত্ব।"],
  "2:237": ["If you divorce them before touching them, but after you had set the dowry for them, the compensation shall be half the dowry, unless they voluntarily forfeit their rights, or the party responsible for causing the divorce chooses to forfeit the dowry. To forfeit is closer to righteousness. You shall maintain the amicable relations among you. Allah is Seer of everything you do.","যদি তোমরা তাদের সাথে বিবাহ-বিচ্ছেদ করো তাদেরকে স্পর্শ করার আগে,কিন্তু তোমরা তাদের জন্য দেন-মোহর নির্ধারণ করার পর, তবে ক্ষতিপূরণটি দেন-মোহরের অর্ধেক হবে,যদি না তারা স্বেচ্ছায় তাদের অধিকার ছেঁড়ে দেয়, অথবা বিবাহ-বিচ্ছেদ হবার জন্য দায়ী পক্ষটি দেন-মোহরটি ছেঁড়ে দিতে পছন্দ করে। ক্ষতিস্বীকার করা সতকর্মশীলতার নিকটবর্তী। তোমরা তোমাদের মধ্যে সৌহার্দ্যপূর্ন সম্পর্ক বজায় রাখবে। তোমরা যা কিছু করো আল্লাহ সবকিছুর দ্রষ্টা।"],
  "2:238": ["You shall consistently observe the Contact Prayers, especially the middle prayer, and devote yourselves totally to Allah.","তোমরা নিয়মিত সংযোগ প্রার্থনাসমূহ পালন করবে,বিশেষ করে মধ্যবর্তী প্রার্থনা,এবং নিজেদেরকে পুরোপুরি আল্লাহর নিকট উৎসর্গ করবে।"],
  "2:239": ["Under unusual circumstances, you may pray while walking or riding. Once you are safe, you shall commemorate Allah as He taught you what you never knew.","অস্বাভাবিক পরিস্থিতিতে,তোমরা প্রার্থনা করতে পারো হাঁটা অথবা আরোহী অবস্থায়। যখন তোমরা নিরাপদ হও, তোমরা আল্লাহকে স্মরন করবে যেভাবে তিনি তোমাদের শিক্ষিয়েছিলেন যা তোমরা কখনোই জানতে না।"],
  "2:240": ["Those who die and leave wives, a will shall provide their wives with support for a year, provided they stay within the same household. If they leave, you commit no sin by letting them do whatever they wish, so long as righteousness is maintained. Allah is Almighty, Most Wise.","যারা মারা যায় এবং স্ত্রীদের ছেড়ে যায়, একটি উইল তাদের স্ত্রীদের জন্য এক বছরের ভরণপোষণের ব্যবস্থা করবে,তাদেরকে একই বাড়িতে থাকতে দিয়ে। যদি তারা চলে যায়, তোমরা কোন পাপ করো না তারা যা করতে চায় তা করতে দিয়ে,যতক্ষন পর্যন্ত ন্যায়পরায়ণতা বজায় রাখা হয়। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "2:241": ["The divorcees also shall be provided for, equitably. This is a duty upon the righteous.","বিবাহ বিচ্ছেদকৃত নারীদেরকেও প্রদান করতে হবে,ন্যায়সঙ্গতভাবে। এটা সৎকর্মশীলদের উপর একটি দায়িত্ব।"],
  "2:242": ["Allah thus explains His revelations for you, that you may understand.","আল্লাহ এভাবে তাঁর প্রকাশনাবলী তোমাদের জন্য ব্যাখ্যা করেন, যাতে তোমরা বুঝতে পারো।"],
  "2:243": ["Have you noted those who fled their homes—though they were in the thousands—fearing death? Allah said to them, \"Die,\" then revived them. Allah showers His grace upon the people, but most people are unappreciative.","তোমরা কি তাদের লক্ষ্য করেছ যারা তাদের ঘর থেকে পালিয়েছিল- যদিও তারা সংখ্যায় ছিল হাজার হাজার– মৃত্যু ভয়ে? আল্লাহ তাদের বললেন, “মরে যাও, ”এরপর তাদেরকে পুনরায় জীবিত করলেন। আল্লাহ মানুষের প্রতি তাঁর অনুগ্রহ বর্ষণ করেন, কিন্তু অধিকাংশ মানুষই অকৃতজ্ঞ।"],
  "2:244": ["You shall fight in the cause of Allah, and know that Allah is Hearer, Knower.","তোমরা আল্লাহর উদ্দেশ্যে যুদ্ধ করবে,এবং জানো যে আল্লাহ শ্রোতা,জ্ঞাতা।"],
  "2:245": ["Who would lend Allah a loan of righteousness, to have it repaid to them multiplied manifold? Allah is the One who provides and withholds, and to Him you will be returned.","কে আল্লাহকে সৎকর্ম ধার দিবে, এর চেয়ে বহুগুন বেশি ফেরত পেতে? আল্লাহ সেই সত্ত্বা  যিনি দেন এবং দেয়া থেকে বিরত থাকেন আর তাঁর কাছেই তোমরা ফিরে যাবে।"],
  "2:246": ["Have you noted the leaders of Israel after Moses? They said to their prophet, \"If you appoint a king to lead us, we will fight in the cause of Allah.\" He said, \"Is it your intention that, if fighting is decreed for you, you will not fight?\" They said, \"Why should we not fight in the cause of Allah, when we have been deprived of our homes, and our children?\" Yet, when fighting was decreed for them, they turned away, except a few. Allah is aware of the transgressors.","তুমি কি মুসার পর ইসরাইলের নেতাদের লক্ষ্য করেছ? তারা তাদের নবীকে/ বলেছিল, \"তুমি যদি আমাদেরকে নেতৃত্ব দেয়ার জন্য একজন রাজা নিযুক্ত করো,আমরা আল্লাহর উদ্দেশ্যে লড়াই করবো। তিনি বলেছিলেন, \"এটাই কি তোমাদের উদ্দেশ্য যে,যদি তোমাদের জন্য লড়াই করার আদেশ জারি করা হয়, তোমরা লড়াই করবে না? তারা বলেছিল, \"কেন আমরা আল্লাহর উদ্দেশ্যে লড়াই করবো না,যখন আমরা আমাদের বাড়ি এবং সন্তানদের থেকে বঞ্চিত হয়েছি? \"এরপরও, যখন তাদের জন্য লড়াই করার আদেশ জারি করা হল, তারা মুখ ফিরিয়ে নিল, অল্প কয়েকজন ছাড়া। আল্লাহ সীমালঙ্ঘনকারীদের সম্পর্কে সচেতন।"],
  "2:247": ["Their prophet said to them, \"Allah has appointed Taloot (Saul) to be your king.\" They said, \"How can he have kingship over us when we are more worthy of kingship than he; he is not even rich?\" He said, \"Allah has chosen him over you, and has blessed him with an abundance in knowledge and in body.\" Allah grants His kingship to whomever He wills. Allah is Bounteous, Omniscient.","তাদের নবী তাদেরকে বলেছিল, \"আল্লাহ তালুতকে তোমাদের রাজা হবার জন্য নির্ধারন করেছেন\"। তারা বলেছিল, কিভাবে সে আমাদের উপর রাজপদ পেতে পারে যখন আমরা তার চেয়ে বেশি রাজপদের যোগ্য; সে এমনকি ধনীও নয়? সে বলেছিল, \"আল্লাহ তোমাদের উপর তাকে পছন্দ করেছেন, এবং তাকে জ্ঞানে ও শারীরিকভাবে বেশি প্রাচুর্যতা দিয়ে সৌভাগ্যশালী করেছেন।”আল্লাহ তাঁর রাজপদ যাকে ইচ্ছা প্রদান করেন। আল্লাহ দানশীল, সর্বজ্ঞ।"],
  "2:248": ["Their prophet said to them, \"The sign of his kingship is that the Ark of the Covenant will be restored to you, bringing assurances from your Lord, and relics left by the people of Moses and the people of Aaron. It will be carried by the angels. This should be a convincing sign for you, if you are really believers.\"","তাদের নবী তাদেরকে বলেছিল, “তার রাজপদের চিহ্ন হলো এই যে,প্রতিশ্রুতির সিন্দুক তোমাদের কাছে ফিরিয়ে দেয়া হবে,বয়ে আনবে তোমাদের প্রভুর কাছ থেকে নিশ্চয়তা,এবং মুসার পরিবারের লোকদের ও হারুনের পরিবারের লোকদের পরিত্যক্ত সংরক্ষিত স্মৃতিচিহ্নসমূহ। এটি ফেরেশতাদের দ্বারা বয়ে আনা হবে। এটি তোমাদের জন্য একটি বিশ্বাসযোগ্য নিদর্শন হওয়া উচিৎ,যদি তোমরা সত্যিই বিশ্বাসী হয়ে থাকো।"],
  "2:249": ["When Saul took command of the troops, he said, \"Allah is putting you to the test by means of a stream. Anyone who drinks from it does not belong with me—only those who do not taste it belong with me—unless it is just a single sip.\" They drank from it, except a few of them. When he crossed it with those who believed, they said, \"Now we lack the strength to face Goliath and his troops.\" Those who were conscious of meeting Allah said, \"Many a small army defeated a large army by Allah's leave. Allah is with those who steadfastly persevere.\"","যখন তালুত সৈন্যবাহিনীর নেতৃত্ব গ্রহন করলো,সে বলেছিল, “আল্লাহ তোমাদের একটি জলপ্রবাহ দ্বারা পরীক্ষা করছেন। যেকেউ এটি থেকে পান করবে সে আমার সাথে নয় – যদি না তা শুধু এক চুমুক হয় -শুধুমাত্র যারা এর স্বাদ নেবে না তারা আমার সাথে আছে”। তারা সেখান থেকে পান করলো,তাদের অল্প কয়েকজন ছাড়া। যখন সে তা পার হল তাদের সাথে যারা বিশ্বাস করেছিল, তারা বলেছিল, “এখন আমরা জালুত এবং তার সৈন্যবাহিনীর মুখোমুখি হওয়ার শক্তি হারিয়েছি”। যারা আল্লাহর সাথে সাক্ষাতের ব্যাপারে সচেতন ছিল তারা বলেছিল, “আল্লাহর সম্মতিক্রমে অনেক ছোট সৈন্যবাহিনী বড় সৈন্যবাহিনীকে পরাজিত করেছে। আল্লাহ তাদের সাথে আছেন যারা দৃড়তার সাথে অধ্যবসায়ী।"],
  "2:250": ["When they faced Goliath and his troops, they prayed, \"Our Lord, grant us steadfastness, strengthen our foothold, and support us against the disbelieving people.\"","যখন তারা জালুত এবং তার সৈন্যবাহিনীর মুখোমুখি হলো,তারা প্রার্থনা করেছিল, “আমাদের প্রভু,আমাদের ধৈর্য্য দান করুন, আমাদের অবস্থানকে সুদৃড় করুন, এবং অবিশ্বাসী লোকদের বিরুদ্ধে আমাদের সহায়তা করুন।"],
  "2:251": ["They defeated them by Allah's leave, and David killed Goliath. Allah gave him kingship and wisdom, and taught him as He willed. If it were not for Allah's support of some people against others, there would be chaos on earth. But Allah showers His grace upon the people.","তারা আল্লাহর সম্মতিক্রমে তাদেরকে পরাজিত করেছিল, এবং দাউদ জালুতকে হত্যা করল। আল্লাহ তাকে রাজপদ এবং জ্ঞান দিলেন, এবং তাকে শেখালেন, যেমন তাঁর ইচ্ছা। কিছু লোকের প্রতি অন্যদের বিরুদ্ধে আল্লাহর সহায়তা যদি না থাকত, পৃথিবীতে বিশৃঙ্খলা ছড়িয়ে পড়ত। কিন্তু আল্লাহ মানুষের প্রতি তাঁর অনুগ্রহ বর্ষণ করেন।"],
  "2:252": ["These are Allah's revelations. We recite them through you, truthfully, for you are one of the messengers.","এগুলো আল্লাহর প্রকাশনাবলী। আমরা এগুলো তোমার মাধ্যমে আবৃত্তি করি,সত্যতার সাথে,কারন তুমি বার্তাবাহকদের একজন।"],
  "2:253": ["These messengers; we blessed some of them more than others. For example, Allah spoke to one, and we raised some of them to higher ranks. And we gave Jesus, son of Mary, profound miracles and supported him with the Holy Spirit. Had Allah willed, their followers would not have fought with each other, after the clear proofs had come to them. Instead, they disputed among themselves; some of them believed, and some disbelieved. Had Allah willed, they would not have fought. Everything is in accordance with Allah's will.","এই বার্তাবাহকরা; আমরা তাদের কয়েকজনকে অন্যদের থেকে বেশি অনুগ্রহ করেছি। উদাহরন স্বরূপ, একজনের সাথে আল্লাহ কথা বলেছিলেন, এবং আমরা তাদের কয়েকজনকে উচ্চতর পদে উন্নিত করেছিলাম। এবং আমরা মরিয়ম পুত্র ঈসাকে দিয়েছিলাম প্রগাঢ় অলৌকিক নিদর্শনসমূহ এবং তাকে পবিত্র আত্মার দ্বারা সহায়তা করেছিলাম। আল্লাহ যদি চাইতেন, তাদের অনুসারীরা পরস্পর লড়াই করত না,তাদের কাছে পরিষ্কার প্রমান এসে যাবার পর। অথচ, তারা নিজেদের মধ্যে বিবাদ করলো,তাদের কেউ কেউ বিশ্বাস করলো,এবং কেউ কেউ অবিশ্বাস করলো। আল্লাহ যদি চাইতেন, তারা লড়াই করতো না। সবকিছুই আল্লাহর ইচ্ছা অনুসারে হয়।"],
  "2:254": ["O you who believe, you shall give to charity from the provisions we have given to you, before a day comes where there is no trade, no nepotism, and no intercession. The disbelievers are the unjust.","হে তোমরা যারা বিশ্বাস করো,তোমাদেরকে দেয়া আমাদের জীবিকা থেকে তোমরা দান করবে,সে দিন আসার আগে যেখানে না আছে কোন বাণিজ্য, না স্বজনপ্রীতি,এবং না কোন সুপারিশ। অবিশ্বাসীরা অবিবেচক।"],
  "2:255": ["Allah: there is no other god besides Him, the Living, the Eternal. Never a moment of unawareness or slumber overtakes Him. To Him belongs everything in the heavens and everything on earth. Who could intercede with Him, except in accordance with His will? He knows their past, and their future. No one attains any knowledge, except as He wills. His dominion encompasses the heavens and the earth, and ruling them never burdens Him. He is the Most High, the Great.","আল্লাহঃ তাঁর পাশে অন্য কোন উপাস্য নেই, জীবিত, চিরস্থায়ী। কখনো ক্ষণিকের অসচেতনতা অথবা তন্দ্রা তাঁকে স্পর্শ করে না। আকাশমন্ডলীতে যা কিছু আছে এবং পৃথিবীতে যা কিছু আছে,সব তাঁর। কে তাঁর কাছে সুপারিশ করতে পারে,তাঁর ইচ্ছানুসারে ছাড়া? তিনি জানেন তাদের অতীত এবং তাদের ভবিষ্যৎ। তিনি যেমন ইচ্ছা করেন তা ব্যতিত, কেউ কোন জ্ঞান অর্জন করে না। তাঁর রাজত্ব পরিবেষ্টন করে আছে আকাশমন্ডলী এবং পৃথিবীকে,এবং এগুলোর পরিচালনা তাঁকে কখনো ভারগ্রস্থ করে না। তিনি সর্বোচ্চ, মহান।"],
  "2:256": ["There shall be no compulsion in religion: the right way is now distinct from the wrong way. Anyone who denounces the devil and believes in Allah has grasped the strongest bond; one that never breaks. Allah is Hearer, Omniscient.","ধর্মে জোর-জবরদস্তি থাকবে না। সঠিক পথ এখন ভুল পথ থেকে আলাদা। যেকেউ শয়তানকে প্রত্যাখ্যান করে এবং আল্লাহতে বিশ্বাস করে,সে আঁকড়ে ধরলো সবচেয়ে শক্তিশালী বন্ধন;যা কখনও ভেঙ্গে যায় না। আল্লাহ শ্রোতা,সর্বজ্ঞ।"],
  "2:257": ["Allah is Lord of those who believe; He leads them out of darkness into the light. As for those who disbelieve, their lords are their idols; they lead them out of the light into darkness—these will be the dwellers of Hell; they abide in it forever.","আল্লাহ তাদের প্রভু যারা বিশ্বাস করে; তিনি তাদেরকে অন্ধকার থেকে বের করে আলোয় পরিচালিত করেন। আর তারা যারা অবিশ্বাস করে,তাদের প্রভুরা হচ্ছে তাদের উপাস্যরা ; তারা তাদেরকে আলো থেকে বের করে অন্ধকারে পরিচালিত করে- এরাই হবে নরকের বাসিন্দা; এতে তারা চিরকাল বাস করবে।"],
  "2:258": ["Have you noted the one who argued with Abraham about his Lord, though Allah had given him kingship? Abraham said, \"My Lord grants life and death.\" He said, \"I grant life and death.\" Abraham said, \"Allah brings the sun from the east, can you bring it from the west?\" The disbeliever was stumped. Allah does not guide the wicked.","তুমি কি তাকে লক্ষ্য করেছ যে ইব্রাহীমের সাথে তর্ক করেছিল তার প্রভুর ব্যাপারে,যদিও আল্লাহ তাকে রাজ পদ দান করেছিলেন? ইব্রাহীম বলল, “আমার প্রভু জীবন ও মৃত্যু প্রদান করেন”। সে বলল, “আমি জীবন ও মৃত্যু প্রদান করি”। ইব্রাহীম বলল, “আল্লাহ সূর্যকে পূর্ব দিক থেকে উদিত করেন, তুমি কি একে পশ্চিম দিক থেকে উদিত করতে পারো”? সেই অবিশ্বাসী হতবুদ্ধ হয়ে গেল। আল্লাহ দুষ্টদেরকে পথ প্রদর্শন করেন না।"],
  "2:259": ["Consider the one who passed by a ghost town and wondered, \"How can Allah revive this after it had died?\" Allah then put him to death for a hundred years, then resurrected him. He said, \"How long have you stayed here?\" He said, \"I have been here a day, or part of the day.\" He said, \"No! You have been here a hundred years. Yet, look at your food and drink; they did not spoil. Look at your donkey—we thus render you a lesson for the people. Now, note how we construct the bones, then cover them with flesh.\" When he realized what had happened, he said, \"Now I know that Allah is Omnipotent.\"","সেই ব্যাক্তির বিষয়ে ভেবে দেখো যে একটি ভূতুড়ে শহরের পাশ দিয়ে যাচ্ছিলো এবং অবাক হলো,“কেমন করে আল্লাহ একে জীবিত করতে পারেন এর মৃত্যু ঘটার পর? আল্লাহ তখন তাকে একশ বছরের জন্য মৃত অবস্থায় রাখলেন, এরপর তাকে পুনর্জীবিত করলেন। তিনি বললেন, “তুমি কতকাল এখানে অবস্থান করেছ?”সে বলল, “আমি এখানে এক দিন, অথবা এক দিনের কিছু অংশ অবস্থান করেছি।”তিনি বললেন, “না! তুমি এখানে একশো বছর ছিলে। তারপরও, তোমার খাদ্য ও পানীয়ের দিকে তাকাও; সেগুলো নষ্ট হয়নি। তোমার গাঁধার দিকে তাকাও- আমরা এভাবে তোমাকে মানুষের জন্য একটি  শিক্ষামূলক উদাহরণ  করেছি। এখন, লক্ষ্য করো,কিভাবে আমরা হাড়গুলোকে নির্মাণ করি,এরপর সেগুলোকে মাংস দিয়ে ঢেকে দেই”। যখন সে উপলব্ধি করলো কি ঘটেছে,সে বলল, “এখন আমি জানি যে আল্লাহ সর্বশক্তিমান”।"],
  "2:260": ["Abraham said, \"My Lord, show me how You revive the dead.\" He said, \"Do you not believe?\" He said, \"Yes, but I wish to reassure my heart.\" He said, \"Take four birds, study their marks, place a piece of each bird on top of a hill, then call them to you. They will come to you in a hurry. You should know that Allah is Almighty, Most Wise.\"","ইব্রাহীম বলল, “আমার প্রভু,আমাকে দেখান কিভাবে আপনি মৃতকে পুনর্জীবিত করেন”। তিনি বললেন, “তুমি কি বিশ্বাস করো না?”সে বলল, “হ্যাঁ,কিন্তু আমি আমার হৃদয়কে পুনরায় আশ্বস্ত করতে চাই”। তিনি বললেন, “চারটি পাখি নাও, তাদের চিহ্নগুলো চিনে নাও, প্রত্যেক পাখির একেক টুকরো একেকটি পাহাড়ের উপর রেখে দাও, এরপর তাদেরকে তোমার কাছে ডাকো। তারা তোমার কাছে ছুটে আসবে। তোমার জানা উচিৎ যে আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী”।"],
  "2:261": ["The example of those who spend their monies in the cause of Allah is that of a grain that produces seven spikes, with a hundred grains in each spike. Allah multiplies this manifold for whomever He wills. Allah is Bounteous, Knower.","যারা তাদের অর্থ আল্লাহর পথে ব্যয় করে তাদের উদাহরন হলো একটি শস্যদানা যা উৎপন্ন করে সাতটি শীষ, যার প্রত্যেকটিতে রয়েছে একশটি শস্যদানা। আল্লাহ যার জন্য ইচ্ছা একে বহুগুণ বৃদ্ধি করে দেন। আল্লাহ দানশীল, সর্বজ্ঞ।"],
  "2:262": ["Those who spend their money in the cause of Allah, then do not follow their charity with insult or harm, will receive their recompense from their Lord; they have nothing to fear, nor will they grieve.","যারা তাদের অর্থ আল্লাহর পথে ব্যয় করে,অতঃপর তাদের দানের পর অপমান বা ক্ষতি করে না,তাদের প্রভুর পক্ষ থেকে তারা প্রতিদান পাবে;তাদের ভয়ের কিছুই নেই, না তারা শোক করবে।"],
  "2:263": ["Kind words and compassion are better than a charity that is followed by insult. Allah is Rich, Clement.","সদয় কথা এবং সহানুভূতি সেই দানের চেয়ে উত্তম যার পর অপমান করা হয়। আল্লাহ সমৃদ্ধ, সহিষ্ণু।"],
  "2:264": ["O you who believe, do not nullify your charities by inflicting reproach and insult, like one who spends his money to show off, while disbelieving in Allah and the Last Day. His example is like a rock covered with a thin layer of soil; as soon as heavy rain falls, it washes off the soil, leaving it a useless rock. They gain nothing from their efforts. Allah does not guide disbelieving people.","হে তোমরা যারা বিশ্বাস করো,তোমাদের দান ভর্ৎসনা ও অপমান দ্বারা নিরর্থক করে দিয়ো না,তার মতো যে লোক-দেখানোর জন্য অর্থ খরচ করে,অথচ সে অবিশ্বাস করে আল্লাহ এবং শেষ দিনে। তার উদাহরণ হলো এমন একটি পাথরের মতো যা একটি পাতলা মাটির স্তর দ্বারা আবৃত; যখনই ভারি বর্ষণ হয়, তা মাটিকে ধুয়ে ফেলে,একে একটি অকার্যকর পাথর় করে দিয়ে যায়। তারা তাদের প্রচেষ্টা থেকে কোন কিছু অর্জন করে না। আল্লাহ অবিশ্বাসী লোকদের পথ প্রদর্শন করেন না।"],
  "2:265": ["The example of those who give their money seeking Allah's pleasure, out of sincere conviction, is that of a garden on high fertile soil; when heavy rain falls, it gives twice as much crop. If heavy rain is not available, a drizzle will suffice. Allah is Seer of everything you do.","যারা তাদের অর্থ, আন্তরিক প্রত্যয়ে,আল্লাহর সন্তুষ্টি অর্জনের জন্য দান করে তাদের উদাহরণ হচ্ছে উঁচু উর্বর ভূমিতে যেন একটি বাগান; যখন ভারী বর্ষণ হয়, এটি দ্বিগুন শস্য দেয়,যদি ভারী বর্ষণ না-ও হয়, গুড়ি গুড়ি বৃষ্টিই যথেষ্ট। আল্লাহ দেখেন সবকিছু যা তোমরা করো।"],
  "2:266": ["Does any of you wish to own a garden of palm trees and grapes, with flowing streams and generous crops, then, just as he grows old, and while his children are still dependent on him, a holocaust strikes and burns up his garden? Allah thus clarifies the revelations for you, that you may reflect.","তোমাদের কেউ কি খেজুর গাছ এবং আঙুর বিশিষ্ট একটি বাগানের মালিক হতে চাও, যার সাথে থাকবে প্রবাহিত ঝর্নাধারা এবং প্রচুর পরিমান ফসল, এরপর, যখনই সে বৃদ্ধ হয়, এবং যখন  তার সন্তানেরা তখনও তার উপর নির্ভরশীল, একটি অগ্নিকান্ড আঘাত করে এবং তার বাগানকে জ্বালিয়ে দেয়? আল্লাহ এভাবে তোমাদের জন্য প্রকাশনাবলি সুস্পষ্ট করেন, যাতে তোমরা অনুধাবন করতে পার।"],
  "2:267": ["O you who believe, you shall give to charity from the good things you earn, and from what we have produced for you from the earth. Do not pick out the bad therein to give away, when you yourselves do not accept it unless your eyes are closed. You should know that Allah is Rich, Praiseworthy.","হে যারা বিশ্বাস করো,তোমরা দান করবে তোমাদের উপার্জন করা ভাল জিনিস থেকে,এবং যা আমরা তোমাদের জন্য পৃথিবী থেকে উৎপন্ন করেছি তা থেকে। তার মধ্য থেকে খারাপটি বেছে নিও না দেয়ার জন্য, যখন তোমরা নিজেরা তা গ্রহণ করো না,যদি না তোমাদের চোখ বন্ধ থাকে। তোমাদের জানা উচিত যে আল্লাহ ধনী,প্রশংসনীয়।"],
  "2:268": ["The devil promises you poverty and commands you to commit evil, while Allah promises you forgiveness from Him and grace. Allah is Bounteous, Omniscient.","শয়তান তোমাদের প্রতিশ্রুতি দেয় দারিদ্র্যতার এবং আদেশ দেয় মন্দ করার, যখন আল্লাহ তোমাদের প্রতিশ্রুতি দেন তার পক্ষ থেকে ক্ষমা এবং অনুগ্রহের। আল্লাহ উদার, সর্বজ্ঞ।"],
  "2:269": ["He bestows wisdom upon whomever He chooses, and whoever attains wisdom, has attained a great bounty. Only those who possess intelligence will take heed.","তিনি প্রজ্ঞা প্রদান করেন যাকে তিনি পছন্দ করেন, এবং যেকেউ প্রজ্ঞা অর্জন করে,অর্জন করেছে এক মহা প্রাচুর্য। তারাই শুধুমাত্র উপদেশ গ্রহণ করবে যারা বুদ্ধিমত্তার অধিকারী।"],
  "2:270": ["Any charity you give, or a charitable pledge you fulfill, Allah is fully aware thereof. As for the wicked, they will have no helpers.","যা কিছু তোমরা দান করো,অথবা দানের অঙ্গীকার তোমরা পরিপূর্ণ করো,আল্লাহ তা সম্পর্কে সম্পূর্ণ অবগত। অন্যায়কারীদের বিষয়ে,তাদের কোন সাহায্যকারী থাকবে না।"],
  "2:271": ["If you declare your charities, they are still good. But if you keep them anonymous, and give them to the poor, it is better for you, and remits more of your sins. Allah is fully Cognizant of everything you do.","তোমরা যদি তোমাদের দান প্রকাশ্যে করো,তখনও তা ভাল। কিন্তু যদি তোমরা তা অপ্রকাশিত রাখো,এবং তা গরিবদের দিয়ে দাও, সেটা তোমাদের জন্য উত্তম, এবং তোমাদের অধিক পাপ মোচন করে। আল্লাহ পরিপূর্ণভাবে জ্ঞাত যা কিছু তোমরা করো।"],
  "2:272": ["You are not responsible for guiding anyone. Allah is the only one who guides whoever chooses (to be guided). Any charity you give is for your own good. Any charity you give shall be for the sake of Allah. Any charity you give will be repaid to you, without the least injustice.","কাউকে পথ-প্রদর্শনের জন্য তুমি দায়ী নও। শুধুমাত্র আল্লাহ সেই সত্ত্বা  যিনি পথ-প্রদর্শন করেন, যেকেউ পছন্দ করে (পথ প্রদর্শিত হতে)। যা কিছু দান তোমরা করো তা তোমাদের নিজেদের ভালোর জন্য। যা কিছু দান তোমরা করো তা হবে আল্লাহর উদ্দেশ্যে। যা কিছু দান তোমরা করো তা তোমাদেরকে পরিশোধ করা হবে,সামান্যতম অবিচার ছাড়াই।"],
  "2:273": ["Charity shall go to the poor who are suffering in the cause of Allah, and cannot emigrate. The unaware may think that they are rich, due to their dignity. But you can recognize them by certain signs; they never beg from the people persistently. Whatever charity you give, Allah is fully aware thereof.","দান হবে গরিবদের জন্য যারা আল্লাহর পথে কষ্ট ভোগ করছে,এবং দেশান্তরিত হতে পারে না। অসচেতনরা ভাবতে পারে যে তারা ধনী,তাদের মর্যাদাপূর্ণ অবস্থানের কারণে। কিন্তু তোমরা তাদের নির্দিষ্ট চিহ্ন দ্বারা চিনতে পারো; তারা কখনোই মানুষের কাছে অনবরত চাইতে থাকে না। তোমরা যা কিছু দান করো,আল্লাহ সে সম্পর্কে সম্পূর্ণ সচেতন।"],
  "2:274": ["Those who give to charity night and day, secretly and publicly, receive their recompense from their Lord; they will have nothing to fear, nor will they grieve.","যারা রাতে এবং দিনে দান করে,গোপনে এবং প্রকাশ্যে,তারা তাদের প্রভুর কাছ থেকে প্রতিদান পায়; তাদের ভয়ের কিছু থাকবে না,আর না তারা শোক করবে।"],
  "2:275": ["Those who charge usury are in the same position as those controlled by the devil's influence. This is because they claim that usury is the same as commerce. However, Allah permits commerce, and prohibits usury. Thus, whoever heeds this commandment from his Lord, and refrains from usury, he may keep his past earnings, and his judgment rests with Allah. As for those who persist in usury, they incur Hell, wherein they abide forever.","যারা চড়া সুদ আদায় করে,তারা সে একই অবস্থানে রয়েছে ওদের মত, যারা শয়তানের প্রভাব দ্বারা নিয়ন্ত্রিত। এটার কারন হচ্ছে তারা দাবী করে চড়া সুদ এবং বাণিজ্য একই। কিন্তু,আল্লাহ বাণিজ্যের অনুমতি দিয়েছেন, এবং চড়া সুদ নিষিদ্ধ করেছেন। এভাবে,যেকেউ তার প্রভুর কাছ থেকে আসা এই প্রত্যাদেশ মান্য করে,এবং চড়া সুদ থেকে বিরত থাকে,সে তার অতীতের উপার্জন রাখতে পারে,এবং তার বিচার রয়েছে আল্লাহর হাতে। তাদের বিষয়ে যারা চড়া সুদে অটল থাকে,তারা তাদের উপর নরক টেনে আনে,যেখানে তারা চিরকাল বসবাস করে।"],
  "2:276": ["Allah condemns usury, and blesses charities. Allah dislikes every disbeliever, guilty.","আল্লাহ চড়া সুদকে অব্যবহার্য বলে ঘোষনা করেন, এবং দানকে আশীর্বাদ করেন। আল্লাহ প্রত্যেক অবিশ্বাসী,অপরাধীকে অপছন্দ করেন।"],
  "2:277": ["Those who believe and lead a righteous life, and observe the Contact Prayers (Salat), and give the obligatory charity (Zakat), they receive their recompense from their Lord; they will have nothing to fear, nor will they grieve.","তারা যারা বিশ্বাস করে এবং সৎ-জীবন যাপন করে,এবং সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করে,এবং বাধ্যতামূলক দান (যাকাত) দেয়, তারা তাদের প্রভুর পক্ষ থেকে তাদের প্রতিদান গ্রহণ করে; তাদের ভয়ের কিছু থাকবে না,আর না তারা শোক করবে।"],
  "2:278": ["O you who believe, you shall observe Allah and refrain from all kinds of usury, if you are believers.","হে যারা বিশ্বাস করো,তোমরা আল্লাহকে মান্য করবে এবং সকল ধরনের চড়া সুদ থেকে বিরত থাকবে,যদি তোমরা বিশ্বাসী হও।"],
  "2:279": ["If you do not, then expect a war from Allah and His messenger. But if you repent, you may keep your capitals, without inflicting injustice, or incurring injustice.","যদি তোমরা না করো,তাহলে আল্লাহ এবং তাঁর রাসূলের পক্ষ থেকে একটি যুদ্ধের আশা করো। কিন্তু যদি তোমরা অনুশোচনা করো,তবে তোমরা তোমাদের মূলধন রাখতে পারো,অবিচার করা বা অবিচার টেনে আনা ছাড়া।"],
  "2:280": ["If the debtor is unable to pay, wait for a better time. If you give up the loan as a charity, it would be better for you, if you only knew.","যদি ঋণগ্রহীতা পরিশোধ করতে অক্ষম হয়, উত্তম সময়ের জন্য অপেক্ষা করো। যদি তোমরা ধারটি দান হিসেবে ছেঁড়ে দাও, এটি তোমাদের জন্য উত্তম, যদি শুধু তোমরা জানতে।"],
  "2:281": ["Beware of the day when you are returned to Allah, and every soul is paid for everything it had done, without the least injustice.","তোমরা আল্লাহর কাছে ফিরে যাওয়ার সেই দিনের ব্যাপারে সতর্ক হও, এবং প্রতিটি আত্মা যা করেছে সে সবকিছুর জন্য প্রতিফল পায়, সামান্যতম অবিচার ছাড়াই।"],
  "2:282": ["O you who believe, when you transact a loan for any period, you shall write it down. An impartial scribe shall do the writing. No scribe shall refuse to perform this service, according to Allah's teachings. He shall write, while the debtor dictates the terms. He shall observe Allah his Lord and never cheat. If the debtor is mentally incapable, or helpless, or cannot dictate, his guardian shall dictate equitably. Two men shall serve as witnesses; if not two men, then a man and two women whose testimony is acceptable to all. Thus, if one woman becomes biased, the other will remind her. It is the obligation of the witnesses to testify when called upon to do so. Do not tire of writing the details, no matter how long, including the time of repayment. This is equitable in the sight of Allah, assures better witnessing, and eliminates any doubts you may have. Business transactions that you execute on the spot, need not be recorded, but have them witnessed. No scribe or witness shall be harmed on account of his services. If you harm them, it would be wickedness on your part. You shall observe Allah, and Allah will teach you. Allah is Omniscient.","হে তোমরা যারা বিশ্বাস করো,যখন তোমরা যেকোন সময়ের জন্য কোন ঋণ আদান প্রদান করো,তোমরা তা লিখে রাখবে। একজন নিরপেক্ষ লেখক তা লিখবে। কোন লেখক এই কাজ করতে অস্বীকার করবে না,আল্লাহর শিক্ষা অনুযায়ী। সে লিখবে,যেভাবে ঋণ গ্রহীতা শর্তাবলী বর্ণনা করবে। সে তার প্রভু,আল্লাহকে মান্য করবে এবং কখনো প্রতারণা করবে না। যদি ঋণ গ্রহীতা মানসিকভাবে অসমর্থ, অথবা অসহায় হয়, অথবা লেখার বিষয় বলে দিতে না পারে,তবে তার অভিভাবক ন্যায়সঙ্গতভাবে লেখার বিষয় বলে দেবে। দু’জন পুরুষ সাক্ষী হিসাবে থাকবে,যদি দুজন পুরুষ না হয়, তবে একজন পুরুষ এবং দু’জন স্ত্রীলোক, যাদের সাক্ষ্য সকলের কাছে গ্রহণযোগ্য হবে। এভাবে,একজন স্ত্রীলোক যদি পক্ষপাতিত্ব করে,অন্যজন তাকে স্মরণ করিয়ে দিবে। যখন সাক্ষ্য দিতে ডাকা হয় তখন সাক্ষ্য দেয়া সাক্ষীদের উপর একটি দায়িত্ব। পরিশোধের সময় সহ, বিস্তারিত বর্ণনা লিখতে ক্লান্ত হইয়ো না,তা যতোই দীর্ঘ হোক না কেন। এটা আল্লাহর দৃষ্টিতে ন্যায়সঙ্গত, নিশ্চিত করে উত্তম সাক্ষ্য, এবং তোমাদের মনে থাকতে পারে,এমন যেকোন সন্দেহ দূর করে দেয়। ব্যবসায়িক লেনদেন যা তোমরা ঘটনাস্থলে সম্পাদন করো,তা নথিভুক্ত করার প্রয়োজন নেই, কিন্তু সেগুলোর সাক্ষী রাখো। কোন লেখক বা সাক্ষিকে তার কাজের কারনে ক্ষতিগ্রস্ত করা যাবে না। যদি তোমরা তাদের ক্ষতি করো,তবে তা হবে তোমাদের পক্ষ থেকে পাপাচার। তোমরা আল্লাহকে মান্য করবে,এবং আল্লাহ তোমাদের শিক্ষা দিবেন, আল্লাহ সর্বজ্ঞ।"],
  "2:283": ["If you are traveling, and no scribe is available, a bond shall be posted to guarantee repayment. If one is trusted in this manner, he shall return the bond when due, and he shall observe Allah his Lord. Do not withhold any testimony by concealing what you had witnessed. Anyone who withholds a testimony is sinful at heart. Allah is fully aware of everything you do.","যদি তোমরা ভ্রমনে থাকো,এবং কোন লেখক না পাওয়া যায়, ঋণ পরিশোধের প্রতিশ্রুতি হিসেবে একটি বন্ধক রাখতে হবে। যদি কাউকে এভাবে বিশ্বাস করা হয়, সে বন্ধক যথাসময়ে ফেরত দেবে,এবং সে তার প্রভু আল্লাহকে মান্য করবে। তুমি যার সাক্ষী হয়েছিলে তা গোপন করে কোন সাক্ষ্য দেয়া থেকে বিরত হইয়ো না। যে কেউ সাক্ষ্য দেয়া থেকে বিরত থাকে তার মন পাপপূর্ণ। তোমরা যা কিছু করো সে সম্পর্কে আল্লাহ পরিপূর্ণভাবে অবগত।"],
  "2:284": ["To Allah belongs everything in the heavens and the earth. Whether you declare your innermost thoughts, or keep them hidden, Allah holds you responsible for them. He forgives whomever He wills, and punishes whomever He wills. Allah is Omnipotent.","আকাশমন্ডলী ও পৃথিবীর সবকিছু আল্লাহর। তুমি তোমার গভীরতম  চিন্তাগুলো প্রকাশ করো,বা সেগুলো গোপন রাখো,আল্লাহ সেগুলোর জন্য তোমাদের দায়ী করবেন। তিনি যাকে ইচ্ছা ক্ষমা করেন, এবং যাকে ইচ্ছা শাস্তি দেন। আল্লাহ সর্বশক্তিমান।"],
  "2:285": ["The messenger has believed in what was sent down to him from his Lord, and so did the believers. They believe in Allah, His angels, His scripture, and His messengers: \"We make no distinction among any of His messengers.\" They say, \"We hear, and we obey. Forgive us, our Lord. To You is the ultimate destiny.\"","বার্তাবাহক তার প্রভুর পক্ষ থেকে যা তার কাছে অবতীর্ণ হয়েছে তাতে বিশ্বাস স্থাপন করেছে, এবং বিশ্বাসীরাও তা-ই করেছে। তারা বিশ্বাস করে আল্লাহতে,তাঁর ফেরেশতাদের, তাঁর ধর্মগ্রন্থে,এবং তাঁর বার্তাবাহকদেরঃ “আমরা তাঁর বার্তাবাহকদের মধ্যে কোন পার্থক্য করি না”। তারা বলে, “আমরা শুনি,এবং আমরা মান্য করি। আমাদের প্রভু,আমাদের ক্ষমা করুন। আপনার কাছেই চূড়ান্ত নিয়তি”।"],
  "2:286": ["Allah never burdens a soul beyond its means: to its credit is what it earns, and against it is what it commits. \"Our Lord, do not condemn us if we forget or make mistakes. Our Lord, and protect us from blaspheming against You, like those before us have done. Our Lord, protect us from sinning until it becomes too late for us to repent. Pardon us, forgive us, and have mercy on us. You are our Lord and Master. Grant us victory over the disbelieving people.\"","আল্লাহ কখনোই কোন আত্মার উপর তার সামর্থের অতিরিক্ত বোঝা চাপান নাঃ যা (ভাল) সে অর্জন করে সেটা তার জন্য জমা থাকবে, এবং যা সে (মন্দ) সম্পাদন করে তা তার বিরুদ্ধে থাকবে। “আমাদের প্রভু,আমাদের দোষী সাব্যস্ত করবেন না,যদি আমরা ভুলে যাই অথবা ভুল করি। আমাদের প্রভু,এবং আমাদের রক্ষা করুন আপনার বিরুদ্ধে মিথ্যাচার করা থেকে,যেভাবে আমাদের পূর্ববর্তীগণ করে গেছেন। আমাদের প্রভু,অনুশোচনার জন্য খুব বেশি দেরি হয়ে যাওয়ার আগে আমাদের পাপ থেকে রক্ষা করুন, আমাদের মার্জনা করুন এবং আমাদের ক্ষমা করুন। আপনি আমাদের প্রভু এবং মনিব। অবিশ্বাসী লোকদের উপর আমাদের জয়ী করুন”।"],
  "3:1": ["A. L. M.","অ.ল.ম."],
  "3:2": ["Allah: there is no god except He; the Living, the Eternal.","আল্লাহ: তিনি ছাড়া আর কোন উপাস্য নেই; জীবিত, চিরস্থায়ী।"],
  "3:3": ["He sent down to you this scripture, truthfully, confirming all previous scriptures, and He sent down the Torah and the Gospel","তিনি তোমাদের কাছে অবতীর্ণ করেছেন এই ঐশীগ্রন্থ, সত্যতার সাথে,যা নিশ্চিত করে সকল পূর্ববর্তী ঐশীগ্রন্থ সমূহকে,এবং তিনি অবতীর্ণ করেছেন তওরাত এবং ইঞ্জীল।"],
  "3:4": ["before that, to guide the people, and He sent down the statute book. Those who disbelieve in Allah's revelations incur severe retribution. Allah is Almighty, Avenger.","তার আগে,মানুষকে পথ প্রদর্শনের জন্য, এবং তিনি অবতীর্ণ করেছেন বিধিবদ্ধ আইনগ্রন্থ, যারা আল্লাহর প্রকাশনাবলীকে অবিশ্বাস করে তারা টেনে আনে কঠোর শাস্তি। আল্লাহ সর্বশক্তিমান, প্রতিশোধ গ্রহণকারী।"],
  "3:5": ["Nothing is hidden from Allah, on earth, or in the heaven.","আল্লাহর কাছে কোনকিছুই লুকানো নেই, পৃথিবীতে,অথবা আসমানে।"],
  "3:6": ["He is the One who shapes you in the wombs as He wills. There is no other god besides Him; the Almighty, Most Wise.","তিনিই একজন যিনি তোমাদের আকৃতি দেন মাতৃগর্ভে,যেমন তিনি ইচ্ছে করেন। তাঁর পাশে অন্য কোন উপাস্য নেই; সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "3:7": ["He sent down to you this scripture, containing straightforward verses—which constitute the essence of the scripture—as well as multiple-meaning or allegorical verses. Those who harbor doubts in their hearts will pursue the multiple-meaning verses to create confusion, and to extricate a certain meaning. None knows the true meaning thereof except Allah and those well founded in knowledge. They say, \"We believe in this—all of it comes from our Lord.\" Only those who possess intelligence will take heed.","তিনি তোমাদের প্রতি এই ঐশীগ্রন্থ অবতীর্ণ করেছেন, যাতে আছে সহজবোধ্য চরণসমূহ - যা এই ঐশীগ্রন্থের মূল বিষয়কে স্থাপন করে - আরো আছে বহু অর্থবোধক বা রুপকধর্মী চরণসমূহ। যারা তাদের হৃদয়ে সন্দেহ পোষন করে,তারা বহু অর্থবোধক চরণসমূহের পিছনে লেগে থাকবে,বিভ্রান্তি সৃষ্টি করতে,এবং বের করতে একটি নির্দিষ্ট অর্থ। এগুলোর প্রকৃত অর্থ কেউ জানে না আল্লাহ এবং যাদের জ্ঞান দৃঢ় ভিত্তির উপর প্রতিষ্ঠিত তারা ছাড়া। তারা বলে,\"আমরা এতে বিশ্বাস করি- এর সবটুকুই আমাদের প্রভু থেকে আসে\"। শুধুমাত্র যারা বুদ্ধিমত্তার অধিকারী তারাই উপদেশ গ্রহণ করবে।"],
  "3:8": ["\"Our Lord, let not our hearts waver, now that You have guided us. Shower us with Your mercy; You are the Grantor.","\"আমাদের প্রভু,আমাদের অন্তরকে দ্বিধান্বিত হতে দিয়েন না,এখন যখন আপনি আমাদের পথ-প্রদর্শন করেছেন। আমাদের উপর আপনার দয়া বর্ষন করুণ; আপনিই দাতা।"],
  "3:9": ["\"Our Lord, You will surely gather the people on a day that is inevitable. Allah never breaks a promise.\"","\"আমাদের প্রভু,নিশ্চয় আপনি লোকদের জড়ো করবেন এক অনিবার্য দিনে। আল্লাহ কখনো প্র্রতিশ্রুতি ভঙ্গ করেন না।\""],
  "3:10": ["Those who disbelieve will never be helped by their money, nor by their children, against Allah. They will be fuel for Hell.","যারা অবিশ্বাস করে তারা কখনো আল্লাহর বিপক্ষে সাহায্য প্রাপ্ত হবে না,তাদের অর্থ দ্বারা,না তাদের সন্তানদের দ্বারা। তারা হবে নরকের জ্বালানী।"],
  "3:11": ["Like Pharaoh's people and those before them, they rejected our revelations and, consequently, Allah punished them for their sins. Allah is strict in enforcing retribution.","ফেরাউনের লোকদের এবং তাদের আগে যারা ছিল তাদের মতো,তারা আমাদের প্রকাশনাবলীকে প্রত্যাখ্যান করেছিল এবং,ফলস্বরূপ, আল্লাহ তাদের পাপের জন্য তাদের শাস্তি দিয়েছিলেন। আল্লাহ প্রতিফল আরোপে কঠোর।"],
  "3:12": ["Say to those who disbelieve, \"You will be defeated, then gathered in Hell; what a miserable abode!\"","যারা অবিশ্বাস করে তাদের বল, “তোমরা পরাজিত হবে,এরপর নরকে একত্রিত হবে; কি এক শোচনীয় বাসস্থান!”"],
  "3:13": ["An example has been set for you by the two armies who clashed— one army was fighting in the cause of Allah, while the other was disbelieving. They saw with their own eyes that they were twice as many. Allah supports with His victory whomever He wills. This should provide an assurance for those who possess vision.","তোমাদের জন্য একটি উদাহরণ স্থাপন করা হয়েছে দুই সেনাদলের দ্বারা,যারা সংঘর্ষে লিপ্ত হয়েছিল- একটি সেনাদল আল্লাহর উদ্দশ্যে যুদ্ধ করছিল, যখন অন্যটি ছিল অবিশ্বাসী। তারা স্বচোখে দেখেছিল যে তারা সংখ্যায় দিগুন। আল্লাহ যাকে ইচ্ছা তাঁর বিজয় দিয়ে সমর্থন করেন। যারা দূরদর্শিতার অধিকারী এটা তাদের জন্য একটি নিশ্চয়তা হওয়া উচিৎ।"],
  "3:14": ["Adorned for the people are the worldly pleasures, such as the women, having children, piles upon piles of gold and silver, trained horses, livestock, and crops. These are the materials of this world. A far better abode is reserved at Allah.","মানুষের জন্য সুশোভিত করা হয়েছে পার্থিব আনন্দ, যেমন নারী,সন্তানাদি,রাশি রাশি স্বর্ণ এবং রৌপ্য, প্রশিক্ষিত ঘোড়া,গবাদিপশু,এবং শস্য। এগুলো পার্থিব উপকরণ। আল্লাহর কাছে সংরক্ষিত রয়েছে একটি অতি উত্তম বাসস্থান।"],
  "3:15": ["Say, \"Let me inform you of a much better deal: for those who lead a righteous life, reserved at their Lord, are gardens with flowing streams, and pure spouses, and joy in Allah's blessings.\" Allah is Seer of His worshipers.","বল, “তোমাদেরকে একটি আরো উত্তম চুক্তির ব্যাপারে আমাকে অবহিত করতে দাওঃ যারা সৎজীবন যাপন করে তাদের জন্য, তাদের প্রভুর কাছে সংরক্ষিত রয়েছে,প্রবাহিত জলস্রোত সহ বাগান, এবং বিশুদ্ধ সহধর্মী/সহধর্মীনি এবং আল্লাহর আশীর্বাদের মাঝে পরমানন্দ”। আল্লাহ তাঁর উপাসনাকারীদের দেখেন।"],
  "3:16": ["They say, \"Our Lord, we have believed, so forgive us our sins, and spare us the agony of the hellfire.\"","তারা বলে,\"আমাদের প্রভু,আমরা বিশ্বাস করেছি,অতএব আমাদের পাপসমূহ ক্ষমা করুণ, এবং নরকাগ্নির তীব্র-যন্ত্রণা থেকে আমাদের নিষ্কৃতি দিন।"],
  "3:17": ["They are steadfast, truthful, submitting, charitable, and meditators at dawn.","তারা অবিচল, সত্যবাদী,আত্মসমর্পণকারী,দানশীল, এবং ভোরে ধ্যানকারী।"],
  "3:18": ["Allah bears witness that there is no god except He, and so do the angels and those who possess knowledge. Truthfully and equitably, He is the absolute god; there is no god but He, the Almighty, Most Wise.","আল্লাহ সাক্ষ্য প্রদান করছেন যে,তিনি ছাড়া কোন উপাস্য নেই, এবং ফেরেশতারা ও যারা জ্ঞানের অধিকারী তারাও একই সাক্ষ্য দেয়। সত্যনিষ্ঠার সঙ্গে এবং ন্যায়সঙ্গত পন্থায়, তিনি পরম আল্লাহ; তিনি ছাড়া কোন আল্লাহ নেই, সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "3:19": ["The only religion approved by Allah is \"Submission.\" Ironically, those who have received the scripture are the ones who dispute this fact, despite the knowledge they have received, due to jealousy. For such rejectors of Allah's revelations, Allah is most strict in reckoning.","আল্লাহর অনুমোদিত একমাত্র ধর্ম \"আত্মসমর্পণ\"। দুঃখজনক ভাবে,যারা ঐশীগ্রন্থ গ্রহণ করেছে তারা-ই এই প্রকৃত বিষয়টি নিয়ে বিবাদে লিপ্ত হয়, তারা যে জ্ঞান অর্জন করেছে তা সত্ত্বেও, ঈর্ষার কারনে। আল্লাহর প্রকাশনাবলীর এরুপ প্রত্যাক্ষানকারীদের জন্য, আল্লাহ হিসাব গ্রহনে সবচেয়ে কঠোর।"],
  "3:20": ["If they argue with you, then say, \"I have simply submitted myself to Allah; I and those who follow me.\" You shall proclaim to those who received the scripture, as well as those who did not, \"Would you submit?\" If they submit, then they have been guided, but if they turn away, your sole mission is to deliver this message. Allah is Seer of all people.","তারা যদি তোমার সাথে বিবাদে লিপ্ত হয়, তবে বল, \"আমি কেবল নিজেকে আল্লাহর কাছে সমর্পন করেছি; আমি এবং তারা যারা আমাকে অনুসরণ করে।”যারা ঐশীগ্রন্থ গ্রহণ করেছে আর যারা করেনি তাদের কাছে তুমি ঘোষনা করবে,\"তোমরা কি আত্মসমর্পণ করবে? “তারা যদি আত্মসমর্পণ করে,তবে তারা পথনির্দেশিত হয়েছে,কিন্তু যদি তারা মুখ ফিরিয়ে নেয়, এই বার্তা পৌঁছে দেয়া তোমার একমাত্র কাজ। আল্লাহ সব মানুষকে দেখেন।"],
  "3:21": ["Those who have rejected Allah's revelations, and killed the prophets unjustly, and killed those who advocated justice among the people, promise them a painful retribution.","যারা আল্লাহর প্রকাশনাবলি প্রত্যাখ্যান করেছে,এবং নবীদের অন্যায়ভাবে হত্যা করেছে,এবং তাদেরকে হত্যা করেছে,যারা মানুষের মাঝে ন্যায়পরায়ণতার সমর্থন করেছে,তাদেরকে একটি যন্ত্রণাদায়ক প্রতিফলের প্রতিশ্রুতি দাও।"],
  "3:22": ["Their works have been nullified, both in this life and in the Hereafter, and they will have no helpers.","তাদের কাজগুলো এই দুনিয়া এবং পরকাল উভয়লোকেই বিনষ্ট হয়ে গেছে,এবং তাদের কোন সাহায্যকারী থাকবে না।"],
  "3:23": ["Have you noted those who were given part of the scripture, and how they are invited to uphold this scripture of Allah, and apply it to their own lives, then some of them turn away in aversion?","তুমি কি তাদেরকে লক্ষ্য করেছ, যাদেরকে ঐশীগ্রন্থের অংশবিশেষ দেওয়া হয়েছিল, এবং কেমন করে তারা আমন্ত্রিত হয়েছিল আল্লাহর এই ঐশীগ্রন্থ মেনে চলতে,এবং একে তাদের নিজেদের জীবনে প্রয়োগ করতে,তারপর তাদের কেউ কেউ বিদ্বেষে মুখ ফিরিয়ে নিল।"],
  "3:24": ["This is because they said, \"The hellfire will not touch us, except for a few days.\" They were thus deceived in their religion by their own fabrications.","এটা এ কারনে যে তারা বলেছিল, “নরকের আগুন আমাদের স্পর্শ করবে না,অল্প কিছু দিন ছাড়া”। এভাবে তারা তাদের ধর্মে প্রতারিত হয়েছিল তাদের নিজেদের মিথ্যা উদ্ভাবনের দ্বারা।"],
  "3:25": ["How will it be for them, when we summon them on that inevitable day? Each soul will be paid for whatever it earned, without the least injustice.","এটা তাদের জন্য কেমন হবে,যখন আমরা তাদেরকে একত্রিত করি সেই অনিবার্য দিনে? প্রত্যেক আত্মা যা কিছু অর্জন করেছে তার জন্য মূল্য প্রদান করা হবে,সামান্যতম অবিচার ছাড়াই।"],
  "3:26": ["Say, \"Our god: possessor of all sovereignty. You grant sovereignty to whomever You choose, You remove sovereignty from whomever You choose. You grant dignity to whomever You choose, and commit to humiliation whomever You choose. In Your hand are all provisions. You are Omnipotent.","বল, \"আমাদের উপাস্য: সকল সার্বভৌমত্বের অধিকারী। আপনি যাকে পছন্দ করেন সার্বভৌমত্ব প্রদান করেন, আপনি যার থেকে পছন্দ করেন সার্বভৌমত্ব নিয়ে নেন। আপনি যাকে পছন্দ করেন মর্যাদা প্রদান করেন, এবং আপনি যাকে পছন্দ করেন অপদস্থতায় পতিত করেন। আপনার হাতেই সব কিছুর বন্দোবস্ত। আপনি সর্বশক্তিমান।"],
  "3:27": ["\"You merge the night into the day, and merge the day into the night. You produce the living from the dead, and produce the dead from the living, and You provide for whomever You choose, without limits.\"","\"আপনি রাতকে দিনের মধ্যে মিলিয়ে দেন, এবং দিনকে রাতের মধ্যে মিলিয়ে দেন। আপনি জীবিতকে মৃত থেকে বের করেন, এবং মৃতকে জীবিত থেকে বের করেন, এবং আপনি যাকে পছন্দ করেন সীমাহীনভাবে প্রদান করেন।"],
  "3:28": ["The believers never ally themselves with the disbelievers, instead of the believers. Whoever does this is exiled from Allah. Exempted are those who are forced to do this to avoid persecution. Allah alerts you that you shall reverence Him alone. To Allah is the ultimate destiny.","বিশ্বাসীরা কখনো নিজেদেরকে অবিশ্বাসীদের মিত্র বানায় না,বিশ্বাসীদের বদলে। যেকেউ তা করে,সে আল্লাহর থেকে নির্বাসিত হয়। তারা দায়মুক্ত, যারা তা করতে বাধ্য হয়, নিপীড়ন এড়াতে। আল্লাহ তোমাদেরকে সতর্ক করেন যে,তোমরা কেবল তাঁর ভক্তি করবে। আল্লাহর কাছেই চূড়ান্ত নিয়তি।"],
  "3:29": ["Say, \"Whether you conceal your innermost thought, or declare it, Allah is fully aware thereof.\" He is fully aware of everything in the heavens and the earth. Allah is Omnipotent.","বল, \"তুমি তোমার গভীরতম  চিন্তাগুলো গোপন রাখো,অথবা তা প্রকাশ করো,আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত।”তিনি আকাশমন্ডলী এবং পৃথিবীর সবকিছু সম্পর্কে পূর্ণ অবগত। আল্লাহ সর্বশক্তিমান।"],
  "3:30": ["The day will come when each soul will find all the good works it had done brought forth. As for the evil works, it will wish that they were far, far removed. Allah alerts you that you shall reverence Him alone. Allah is Compassionate towards the people.","সে দিন আসবে যখন প্রত্যেক আত্মা এর করা সব ভাল কাজ সামনে উত্থাপিত পাবে। আর মন্দ কাজের বেলায়, এটি ইচ্ছা করবে যে এগুলো যদি অনেক অনেক দূরে সরিয়ে নেয়া হত। আল্লাহ তোমাদেরকে সতর্ক করেন যে,তোমরা একমাত্র তাঁকে ভক্তি করবে। আল্লাহ লোকদের প্রতি সবচেয়ে দয়াবান।"],
  "3:31": ["Proclaim: \"If you love Allah, you should follow me.\" Allah will then love you, and forgive your sins. Allah is Forgiver, Most Merciful.","ঘোষণা করোঃ “যদি তোমরা আল্লাহকে ভালোবাস, তোমাদের উচিৎ আমাকে অনুসরন করা”। আল্লাহ তখন তোমাদের ভালবাসবেন, এবং তোমাদের পাপ ক্ষমা করে দেবেন। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "3:32": ["Proclaim: \"You shall obey Allah and the messenger.\" If they turn away, Allah does not love the disbelievers.","ঘোষণা করোঃ “তোমরা আল্লাহ এবং বার্তাবাহকে মান্য করবে”। যদি তারা মুখ ফিরিয়ে নেয়, আল্লাহ অবিশ্বাসীদের ভালবাসেন না।"],
  "3:33": ["Allah has chosen Adam, Noah, the family of Abraham, and the family of Amram (as messengers) to the people.","আল্লাহ আদম, নূহ, ইবরাহীমের পরিবার, এবং ইমরানের পরিবারকে লোকেদের কাছে (বার্তাবাহক হিসাবে) পছন্দ করেছেন।"],
  "3:34": ["They belong in the same progeny. Allah is Hearer, Omniscient.","তারা একই বংশের অন্তর্ভূক্ত। আল্লাহ শ্রবণকারী,সর্বজ্ঞ।"],
  "3:35": ["The wife of Amram said, \"My Lord, I have dedicated (the baby) in my belly to You, totally, so accept from me. You are Hearer, Omniscient.\"","ইমরানের স্ত্রী বলল, “আমার প্রভু,আমি আমার পেটের (শিশুকে) আপনার কাছে উৎসর্গ করছি,পূর্ণরূপে,সুতরাং আমার থেকে গ্রহণ করুণ। আপনি শ্রবণকারী,সর্বজ্ঞ।"],
  "3:36": ["When she gave birth to her, she said, \"My Lord, I have given birth to a girl\"—Allah was fully aware of what she bore—\"The male is not the same as the female. I have named her Mary and I invoke Your protection for her and her descendants from the rejected devil.\"","যখন সে তাকে জন্ম দিল, সে বলল, “আমার প্রভু, আমি একটি কন্যা জন্ম দিয়েছি”-আল্লাহ পরিপূর্ণভাবে অবগত ছিলেন কি সে গর্ভে ধারন করছিল- “পুরুষ একই রকম নয়, নারীর মত। আমি তার নাম দিয়েছি মরিয়ম এবং আমি বিতাড়িত শয়তান থেকে তার এবং তার বংশধরদের জন্য আশ্রয় প্রার্থনা করছি”।"],
  "3:37": ["Her Lord accepted her a gracious acceptance, and brought her up a gracious upbringing, under the guardianship of Zachariah. Whenever Zachariah entered her sanctuary he found provisions with her. He would ask, \"Mary, where did you get this from?\" She would say, \"It is from Allah. Allah provides for whomever He chooses, without limits.\"","তার প্রভু তাকে গ্রহণ করেছিলেন অনুগ্রহময় গ্রহণ, এবং তাকে প্রতিপালন করেছিলেন অনুগ্রহময় প্রতিপালন, জাকারিয়ার অভিভাবকত্বে। যখনি  জাকারিয়া তার উপাসনাস্থলে প্রবেশ করতো সে তার কাছে খাদ্যসম্ভার পেত। সে জিজ্ঞাসা করতো,“মরিয়ম, এগুলো তুমি কোথা থেকে পেয়েছ? সে বলত, ‘এটা আল্লাহর থেকে। আল্লাহ যাকে পছন্দ করেন প্রদান করেন, সীমাহীনভাবে।\""],
  "3:38": ["That is when Zachariah implored his Lord: \"My Lord, grant me such a good child; You are the Hearer of the prayers.\"","তখনই জাকারিয়া তার প্রভুর কাছে মিনতি করলেনঃ “আমার প্রভু,আমাকে এমন একটি সুসন্তান দান করুন; আপনি প্রার্থনা শ্রবণকারী”।"],
  "3:39": ["The angels called him when he was praying in the sanctuary: \"Allah gives you good news of John; a believer in the word of Allah, honorable, moral, and a righteous prophet.\"","ফেরেশতারা তাকে আহবান করেছিল যখন সে উপাসনাস্থলে প্রার্থনা করছিলঃ “আল্লাহ তোমাকে ইয়াহিয়ার শুভ সংবাদ দেন; একজন আল্লাহর বাণীতে বিশ্বাসী,সন্মানিত, ন্যায়পরায়ণ, এবং একজন সৎকর্মশীল নবী”।"],
  "3:40": ["He said, \"How can I have a boy, when I am so old, and my wife is sterile?\" He said, \"Allah does whatever He wills.\"","সে বলেছিল, “কেমন করে আমার পুত্র হতে পারে,যখন আমি এতো বৃদ্ধ, এবং আমার স্ত্রী বন্ধ্যা? সে বলেছিল, “আল্লাহ যা ইচ্ছা করেন”।"],
  "3:41": ["He said, \"My Lord, give me a sign.\" He said, \"Your sign is that you will not speak to the people for three days, except through signals. Commemorate your Lord frequently; and meditate night and day.\"","সে বলেছিল, \"আমার প্রভু,আমাকে একটি নিদর্শন দিন।” তিনি বলেছিলেন, \"তোমার নিদর্শন এটা যে,তুমি ইশারা ব্যতীত লোকদের সাথে তিন দিন কথা বলবে না। বার বার তোমার প্রভুর স্মরণ কর;এবং রাতে ও দিনে ধ্যান করো।\""],
  "3:42": ["The angels said, \"O Mary, Allah has chosen you and purified you. He has chosen you from all the women.","ফেরেশতারা বলেছিল, \"হে মরিয়ম, আল্লাহ তোমাকে পছন্দ করেছেন এবং তোমাকে পরিশুদ্ধ করেছেন। তিনি তোমাকে সকল নারীদের থেকে পছন্দ করেছেন।"],
  "3:43": ["\"O Mary, you shall submit to your Lord, and prostrate and bow down with those who bow down.\"","\"হে মরিয়ম, তুমি তোমার প্রভুর নিকট আত্মসমর্পণ করবে,এবং সেজদা করবে ও অবনত হবে (রুকু করবে) তাদের সাথে যারা অবনত হয় (রুকু করে)।\""],
  "3:44": ["This is news from the past that we reveal to you. You were not there when they drew their raffles to select Mary's guardian. You were not present when they argued with one another.","এটি অতীতের সংবাদ যা আমরা তোমার কাছে প্রকাশ করি। তুমি সেখানে ছিলে না,যখন তারা মরিয়মের অভিভাবক নির্বাচন করতে তাদের ভাগ্য নির্নয় করছিল। তুমি উপস্থিত ছিলে না,যখন তারা একে অন্যের সাথে তর্ক করছিল।"],
  "3:45": ["The angels said, \"O Mary, Allah gives you good news: a Word from Him whose name is 'The Messiah, Jesus the son of Mary.' He will be prominent in this life and in the Hereafter, and one of those closest to Me.","ফেরেশতারা বলেছিল, \"হে মরিয়ম, আল্লাহ তোমাকে সুসংবাদ দেন: তাঁর থেকে একটি বানী যার নাম 'মসিহ, মরিয়মের পুত্র ঈসা।' সে এই জীবনে এবং পরকালে বিশিষ্ট হবে,এবং আমার সবচেয়ে নিকটবর্তীদের একজন হবে।"],
  "3:46": ["\"He will speak to the people from the crib, as well as an adult; he will be one of the righteous.\"","“সে কোলে থেকে লোকদের সাথে কথা বলবে,একই ভাবে পূর্ণবয়স্ক হয়ে; সে সৎকর্মশীলদের একজন হবে”।"],
  "3:47": ["She said, \"My Lord, how can I have a son, when no man has touched me?\" He said, \"Allah thus creates whatever He wills. To have anything done, He simply says to it, 'Be,' and it is.","সে বলেছিল, “আমার প্রভু,কেমন করে আমার একটি পুত্র হতে পারে,যখন কোন পুরুষ আমাকে স্পর্শ করেনি?”তিনি বলেছিলেন, \"আল্লাহ এভাবে সৃষ্টি করেন, যা তিনি ইচ্ছা করেন। কোন কিছু করতে,তিনি শুধু এটাকে বলেন, 'হও',এবং তা হয়ে যায়।"],
  "3:48": ["He will teach him the scripture, wisdom, the Torah, and the Gospel.","\"তিনি তাকে শিক্ষা দিবেন ঐশীগ্রন্থ, জ্ঞান, তওরাত, এবং ইঞ্জিল।\""],
  "3:49": ["As a messenger to the Children of Israel: \"I come to you with a sign from your Lord—I create for you from clay the shape of a bird, then I blow into it, and it becomes a live bird by Allah's leave. I restore vision to the blind, heal the leprous, and I revive the dead by Allah's leave. I can tell you what you eat, and what you store in your homes. This should be a proof for you, if you are believers.","ইসরাইলের সন্তানদের কাছে একজন বার্তাবাহক হিসেবেঃ “আমি তোমাদের কাছে তোমাদের প্রভুর কাছ থেকে একটি নিদর্শন নিয়ে আসি-আমি তোমাদের জন্য কাদা থেকে একটি পাখির আকৃতি তৈরি করি,এরপর আমি এটির মধ্যে ফুঁৎকার দেই, এবং এটি আল্লাহর অনুমতিতে একটি জীবন্ত পাখি হয়ে যায়। আমি আল্লাহর অনুমতিতে অন্ধের দৃষ্টি ফিরিয়ে দেই, কুষ্ঠ ব্যাধিগ্রস্থকে আরোগ্য করি,এবং আমি মৃতকে জীবিত করি। আমি তোমাদের বলতে পারি কি তোমরা খাও, এবং কি তোমরা তোমাদের ঘরে মজুদ করো। এটা তোমাদের জন্য একটি প্রমান হওয়া উচিৎ,যদি তোমরা বিশ্বাসী হয়ে থাকো।"],
  "3:50": ["\"I confirm previous scripture—the Torah—and I revoke certain prohibitions imposed upon you. I come to you with sufficient proof from your Lord. Therefore, you shall observe Allah, and obey me.","“আমি সুনিশ্চিত করি পূর্ববর্তী ঐশীগ্রন্থ-তওরাত-এবং আমি বাতিল করি তোমাদের উপর আরোপিত নির্দিষ্ট নিষেধাজ্ঞা। আমি তোমাদের প্রভুর থেকে যথেষ্ট প্রমান নিয়ে তোমাদের কাছে আসি। সুতরাং,তোমরা আল্লাহতে মনোযোগী হবে,এবং আমাকে মান্য করবে।"],
  "3:51": ["\"Allah is my Lord and your Lord; you shall worship Him alone. This is the right path.\"","\"আল্লাহ আমার প্রভু এবং তোমাদের প্রভু; তোমরা একমাত্র তাঁর উপাসনা করবে। এটাই সঠিক পথ।\""],
  "3:52": ["When Jesus sensed their disbelief, he said, \"Who are my supporters towards Allah?\" The disciples said, \"We are Allah's supporters; we believe in Allah, and bear witness that we are submitters.","যখন ঈসা তাদের অবিশ্বাস টের পেল, সে বলল, \"আল্লাহর পক্ষে () কারা আমার সমর্থক?”অনুসারীরা বলল, \"আমরা আল্লাহর সমর্থক; আমরা আল্লাহতে বিশ্বাস করি,এবং সাক্ষী থাক যে,আমরা আত্মসমর্পণকারী।"],
  "3:53": ["\"Our Lord, we have believed in what You have sent down, and we have followed the messenger; count us among the witnesses.\"","\"আমাদের প্রভু,আমরা বিশ্বাস করেছি যা আপনি অবতীর্ণ করেছেন, এবং আমরা বার্তাবাহককে অনুসরণ করেছি; আমাদের সাক্ষীদের মাঝে গননা করুণ।\""],
  "3:54": ["They plotted and schemed, but so did Allah, and Allah is the best schemer.","তারা চক্রান্ত করেছিল এবং পরিকল্পনা করল, কিন্তু আল্লাহ তা-ই করেছিলেন, এবং আল্লাহ সর্বোত্তম পরিকল্পনাকারী।"],
  "3:55": ["Thus, Allah said, \"O Jesus, I am terminating your life, raising you to Me, and ridding you of the disbelievers. I will exalt those who follow you above those who disbelieve, till the Day of Resurrection. Then to Me is the ultimate destiny of all of you, then I will judge among you regarding your disputes.","এভাবে,আল্লাহ বলেছিলেন, “হে ঈসা,আমি তোমার জীবন সমাপ্ত করছি,তোমাকে আমার কাছে তুলে নিচ্ছি,এবং তোমাকে অবিশ্বাসীদের থেকে নিষ্কৃতি দিচ্ছি। আমি উচ্চে অধিষ্ঠিত রাখব তাদেরকে,যারা তোমাকে অনুসরণ করে,তাদের উপর যারা অবিশ্বাস করে,পুনুরুত্থান দিবস পর্যন্ত। এরপর আমার নিকটে তোমাদের সবার চূড়ান্ত নিয়তি,তখন আমি তোমাদের বিবাদের বিষয়ে তোমাদের মধ্যে বিচার করবো।"],
  "3:56": ["\"As for those who disbelieve, I will commit them to painful retribution in this world, and in the Hereafter. They will have no helpers.\"","“যারা অবিশ্বাস করে,আমি তাদেরকে যন্ত্রণাদায়ক প্রতিফল দেব, এই দুনিয়াতে এবং পরকালে। তাদের কোন সাহায্যকারী থাকবে না”।"],
  "3:57": ["As for those who believe and lead a righteous life, He will fully recompense them. Allah does not love the unjust.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,তিনি তাদের পরিপূর্ণ প্রতিদান দিবেন। আল্লাহ অন্যায়কারীদের ভালবাসেন না।"],
  "3:58": ["These are the revelations that we recite to you, providing a message full of wisdom.","এগুলো প্রকাশনাবলী যা আমরা তোমার কাছে আবৃত্তি করি,যা একটি জ্ঞানে পরিপূর্ণ বার্তা প্রদান করে।"],
  "3:59": ["The example of Jesus, as far as Allah is concerned, is the same as that of Adam; He created him from dust, then said to him, \"Be,\" and he was.","আল্লাহর দৃষ্টিভঙ্গি থেকে,ঈসার উদাহরণ, আদমের মতই; তিনি তাকে ধূলা থেকে সৃষ্টি করেছিলেন, তারপর তাকে বলেছিলেন, “হও, ”এবং সে হয়ে গিয়েছিল।"],
  "3:60": ["This is the truth from your Lord; do not harbor any doubts.","তোমার প্রভু থেকে এটি সত্যতা; কোন সন্দেহ পোষণ করো না।"],
  "3:61": ["If anyone argues with you, despite the knowledge you have received, then say, \"Let us summon our children and your children, our women and your women, ourselves and yourselves, then let us invoke Allah's curse upon the liars.\"","যদি কেউ তোমার সাথে তর্ক করে,তুমি যে জ্ঞান পেয়েছ তা সত্ত্বেও, তাহলে বল, “চল, আমরা আমাদের সন্তান এবং তোমাদের সন্তান, আমাদের নারী এবং তোমাদের নারী,আমাদের নিজেদের এবং তোমাদের নিজেদেরকে ডেকে আনি,তারপর চল মিথ্যাবাদীদের উপর আল্লাহর অভিশাপের জন্য প্রার্থনা করি।\""],
  "3:62": ["Absolutely, this is the narration of the truth. Absolutely, there is no god except Allah. Absolutely, Allah is the Almighty, Most Wise.","নিঃসন্দেহে,এটি সত্য বর্ননা। নিঃসন্দেহে,আল্লাহ ছাড়া কোন উপাস্য নেই। নিঃসন্দেহে,আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "3:63": ["If they turn away, then Allah is fully aware of the evildoers.","যদি তারা মুখ ফিরিয়ে নেয়, তবে আল্লাহ মন্দকর্মীদের সম্পর্কে সম্পূর্ণ অবগত।"],
  "3:64": ["Say, \"O followers of the scripture, let us come to a logical agreement between us and you: that we shall not worship except Allah; that we never set up any idols besides Him, nor set up any human beings as lords beside Allah.\" If they turn away, say, \"Bear witness that we are submitters.\"","বল, \"হে ঐশীগ্রন্থের অনুসারীরা,চল আমরা আমাদের এবং তোমাদের মধ্যে একটি যৌক্তিক সম্মতিতে আসি: যে আমরা আল্লাহ ব্যতীত উপাসনা করবো না; যে আমরা কখনো আল্লাহর পাশে কোন অংশীদার সাব্যস্ত করবো না,না কোন মানুষকে আল্লাহর পাশে প্রভু হিসেবে সাব্যস্ত করবো।”যদি তারা মুখ ফিরিয়ে নেয়, বল, সাক্ষী থাক যে,আমরা আত্মসমর্পণকারী।\""],
  "3:65": ["O followers of the scripture, why do you argue about Abraham, when the Torah and the Gospel were not revealed until after him? Do you not understand?","হে ঐশীগ্রন্থের অনুসারীরা,কেন তোমরা ইব্রাহিম সম্পর্কে তর্ক কর, যখন তওরাত এবং ইঞ্জিল তার পরে অবতীর্ণ হয়েছিল? তোমরা কি বুঝ না?"],
  "3:66": ["You have argued about things you knew; why do you argue about things you do not know? Allah knows, while you do not know.","তোমরা তর্ক করেছ সেই জিনিসের ব্যাপারে যা তোমরা জানতে,কেন তোমরা তর্ক কর সেই জিনিসের ব্যাপারে যা তোমরা জানো না? আল্লাহ জানেন, যখন তোমরা জানো না।"],
  "3:67": ["Abraham was neither Jewish, nor Christian; he was a monotheist submitter. He never was an idol worshiper.","ইবরাহীম না ছিলেন ইহুদী,না ছিলেন খ্রীষ্টান; তিনি ছিলেন একজন একেশ্বরবাদী আত্মসমর্পণকারী। তিনি কখনই একজন অংশীদার সাব্যস্তকারী ছিলেন না।"],
  "3:68": ["The people most worthy of Abraham are those who followed him, and this prophet, and those who believe. Allah is the Lord and Master of the believers.","ইবরাহীমের সবচেয়ে যোগ্য লোক হলো তারা যারা তাকে অনুসরণ করেছিল, এবং এই নবীকে,এবং তারা যারা বিশ্বাস করে। আল্লাহ বিশ্বাসীদের প্রভু এবং অভিভাবক।"],
  "3:69": ["Some followers of the scripture wish to lead you astray, but they only lead themselves astray, without perceiving.","ঐশীগ্রন্থের কিছু অনুসারীরা তোমাদেরকে বিপথগামী করতে চায়, কিন্তু তারা শুধু তাদের নিজেদেরকেই বিপথগামী করে,না বুঝেই।"],
  "3:70": ["O followers of the scripture, why do you reject these revelations of Allah though you bear witness (that this is the truth)?","হে ঐশীগ্রন্থের অনুসারীগন, কেন তোমরা প্রত্যাখ্যান করো আল্লাহর এই প্রকাশনাবলী,যদিও তোমরা সাক্ষী দাও (যে এটাই সত্য)?"],
  "3:71": ["O followers of the scripture, why do you confound the truth with falsehood, and conceal the truth, knowingly?","হে ঐশীগ্রন্থের অনুসারীরা,কেন তোমরা সত্যকে মিথ্যার সাথে মিশ্রিত কর, এবং জেনে-শুনে সত্য গোপন কর?"],
  "3:72": ["Some followers of the scripture say, \"Believe in what was sent down to the believers in the morning, and reject it in the evening; maybe someday they will revert.","ঐশীগ্রন্থের কিছু অনুসারীরা বলে,“যা বিশ্বাসীদের কাছে অবতীর্ণ হয়েছে তা সকালে বিশ্বাস কর, এবং সন্ধায় প্রত্যাক্ষান কর; হতে পারে একদিন তারা ফিরে আসবে।"],
  "3:73": ["\"And do not believe except as those who follow your religion.\" Say, \"The true guidance is Allah's guidance.\" If they claim that they have the same guidance, or argue with you about your Lord, say, \"All grace is in Allah's hand; He bestows it upon whomever He wills.\" Allah is Bounteous, Omniscient.","\"এবং যারা তোমাদের ধর্ম অনুসরণ করে তাদের মত ছাড়া বিশ্বাস কর না।”বল, \"আল্লাহর পথ-নির্দেশনাই সত্য পথ-নির্দেশনা।”যদি তারা দাবি করে যে তাদের একই পথ-নির্দেশনা আছে,অথবা তোমাদের প্রভু সম্পর্কে তোমাদের সাথে তর্ক করে,বল, \"আল্লাহর হাতে সকল অনুগ্রহ; তিনি যার উপর ইচ্ছা তা অর্পণ করেন।”আল্লাহ দানশীল, সর্বজ্ঞ।"],
  "3:74": ["He specifies His mercy for whomever He wills; Allah possesses unlimited grace.","তিনি যার জন্য ইচ্ছা করেন, তাঁর অনুগ্রহ নির্দিষ্ট করেন; আল্লাহ সীমাহীন অনুগ্রহের অধিকারী।"],
  "3:75": ["Some followers of the scripture can be trusted with a whole lot, and they will give it back to you. Others among them cannot be trusted with a single dinar; they will not repay you unless you keep after them. That is because they say, \"We do not have to be honest when dealing with the gentiles!\" Thus, they attribute lies to Allah, knowingly.","ঐশীগ্রন্থের কিছু অনুসারীদের সব কিছু দিয়ে বিশ্বাস করা যেতে পারে,এবং তারা তা তোমাকে ফিরিয়ে দিবে। তাদের মধ্যে বাকিদের এক দিনার দিয়েও বিশ্বাস করা যেতে পারে না; তারা তোমাকে পরিশোধ করবে না,যদি না তুমি তাদের পিছনে লেগে থাক। এর কারন এই যে তারা বলে,\"যারা ঐশীগ্রন্থ অনুসরণ করে না (উম্মী)  তাদের সাথে লেনদেনে আমাদেরকে সৎ হতে হবে না!”এভাবে,তারা জেনে-শুনে আল্লাহর উপর মিথ্যা আরোপ করে।"],
  "3:76": ["Indeed, those who fulfill their obligations and lead a righteous life, Allah loves the righteous.","প্রকৃতপক্ষে,যারা পূর্ণ করে তাদের অঙ্গীকার এবং সৎ জীবন যাপন করে,আল্লাহ সৎকর্মশীলদের ভালবাসেন।"],
  "3:77": ["As for those who trade away Allah's covenant, and their obligations, for a cheap price, they receive no share in the Hereafter. Allah will not speak to them, nor look at them, on the Day of Resurrection, nor will He purify them. They have incurred a painful retribution.","আর তাদের জন্য যারা আল্লাহর চুক্তির বাণিজ্য করে,এবং তাদের বাধ্যবাধকতার, সস্তা মুল্যের জন্য, তারা পরকালে কোন অংশ পায় না। আল্লাহ তাদের সাথে কথা বলবেন না,না তাদের দিকে তাকাবেন, পুনুরুত্থানের দিনে,না তিনি তাদেরকে পরিশুদ্ধ করবেন। তারা টেনে এনেছে একটি যন্ত্রণাদায়ক প্রতিফল।"],
  "3:78": ["Among them are those who twist their tongues to imitate the scripture, that you may think it is from the scripture, when it is not from the scripture, and they claim that it is from Allah, when it is not from Allah. Thus, they utter lies and attribute them to Allah, knowingly.","তাদের মধ্যে রয়েছে তারা যারা তাদের জিহ্বা আওড়ায় ঐশীগ্রন্থের অনুকরণ করতে,যাতে তোমরা ভাব যে এটা ঐশীগ্রন্থ থেকে,যখন এটা ঐশীগ্রন্থ থেকে নয়, এবং তারা দাবী করে যে এটা আল্লাহর থেকে,যখন এটা আল্লাহর থেকে নয়। এভাবে,তারা মিথ্যা বলে এবং সেগুলো আল্লাহর উপর আরোপ করে,জেনে-শুনে।"],
  "3:79": ["Never would a human being whom Allah blessed with the scripture and prophethood say to the people, \"Idolize me beside Allah.\" Instead, (he would say), \"Devote yourselves absolutely to your Lord alone,\" according to the scripture you preach and the teachings you learn.","একজন মানুষ যাকে আল্লাহ ঐশীগ্রন্থ এবং নবীত্ব দিয়ে আশীর্বাদ করেছেন সে কখনই মানুষকে বলবে না,“আল্লাহর পাশে আমার উপাসনা করো”। বরং,(সে বলবে),“তোমাদের নিজেদেরকে সম্পূর্ণরূপে একমাত্র তোমাদের প্রভুর কাছে উৎসর্গ করো,”ঐশীগ্রন্থ যা তোমরা প্রচার করো এবং শিক্ষা যা তোমরা শেখ তা অনুসারে।"],
  "3:80": ["Nor would he command you to idolize the angels and the prophets as lords. Would he exhort you to disbelieve after becoming submitters?","না সে তোমাদেরকে আদেশ করবে প্রভু হিসাবে ফেরেশতাদের এবং নবিদের উপাসনা করতে। আত্মসমর্পণকারী হবার পর সে কি তোমাদের অবিশ্বাস করতে উৎসাহিত করবে?"],
  "3:81": ["Allah took a covenant from the prophets, saying, \"I will give you the scripture and wisdom. Afterwards, a messenger will come to confirm all existing scriptures. You shall believe in him and support him.\" He said, \"Do you agree with this, and pledge to fulfill this covenant?\" They said, \"We agree.\" He said, \"You have thus borne witness, and I bear witness along with you.\"","আল্লাহ নবীদের থেকে একটি প্রতিজ্ঞা নিয়েছিলেন, এই বলে যে,\"আমি তোমাদেরকে ঐশীগ্রন্থ এবং বিজ্ঞতা দিব। পরবর্তীকালে,একজন বার্তাবাহক বিদ্যমান সকল ঐশীগ্রন্থসমূহ সত্যায়ন করতে আসবে। তোমরা তাকে বিশ্বাস করবে এবং তাকে সমর্থন করবে।” তিনি বলেছিলেন, \"তোমরা কি এর সাথে সম্মত হয়েছ, এবং এই চুক্তি পূর্ণ করার অঙ্গীকার করছ?” তারা বলেছিল, \"আমরা সম্মত।” তিনি বলেছিলেন, \"তাহলে তোমরা সাক্ষী রইলে এবং আমি তোমাদের সাথে সাক্ষী রইলাম।"],
  "3:82": ["Those who reject this (Quranic prophecy) are the evil ones.","যারা এটি (কুরআনের ভবিষ্যদ্বাণী) প্রত্যাক্ষান করে তারা মন্দ।"],
  "3:83": ["Are they seeking other than Allah's religion, when everything in the heavens and the earth has submitted to Him, willingly and unwillingly, and to Him they will be returned?","তারা কি আল্লাহর ধর্ম ব্যতীত অন্যকিছু খুজঁছে,যখন আকাশমন্ডলী ও পৃথিবীর সবকিছু তাঁর কাছে আত্মসমর্পণ করেছে, ইচ্ছায় ও অনিচ্ছায়, এবং  তাঁর কাছেই তারা ফিরে যাবে?"],
  "3:84": ["Say, \"We believe in Allah, and in what was sent down to us, and in what was sent down to Abraham, Ismail, Isaac, Jacob, and the Patriarchs, and in what was given to Moses, Jesus, and the prophets from their Lord. We make no distinction among any of them. To Him alone we are submitters.\"","বল, \"আমরা বিশ্বাস করি আল্লাহতে,এবং যা আমাদের কাছে অবতীর্ণ হয়েছিল, এবং যা অবতীর্ণ হয়েছিল ইব্রাহিম, ইসমাইল, ইসহাক, ইয়াকুব, এবং পিতৃপুরুষদের কাছে,এবং যা দেয়া হয়েছিল মূসা,ঈসা,এবং নবীদেরকে তাদের প্রভুর পক্ষ থেকে। আমরা তাদের কারো মধ্যে কোন পার্থক্য করি না। একমাত্র তাঁরই কাছে আমরা আত্মসমর্পণকারী।"],
  "3:85": ["Anyone who accepts other than Submission as his religion, it will not be accepted from him, and in the Hereafter, he will be with the losers.","যেকেউ আত্মসমর্পণ ছাড়া অন্য কিছু তার ধর্ম হিসেবে গ্রহণ করে,এটি তাঁর থেকে গৃহীত হবে না,এবং পরকালে,সে হতভাগাদের সাথে থাকবে।"],
  "3:86": ["Why should Allah guide people who disbelieved after believing, and after witnessing that the messenger is truth, and after solid proofs have been given to them? Allah does not guide the wicked.","কেন আল্লাহর উচিৎ সেসব মানুষকে পথ প্রদর্শন করা যারা বিশ্বাস করার পর অবিশ্বাস করেছে,এবং বার্তাবাহকের সত্যতার সাক্ষী হবার পর, এবং তাদেরকে দৃঢ় প্রমান  দেওয়ার পর? আল্লাহ অন্যায়কারীদের পথ প্রদর্শন করেন না।"],
  "3:87": ["These have incurred condemnation by Allah, and the angels, and all the people.","তারা আল্লাহ, এবং ফেরেশতা,এবং সকল মানুষ থেকে শাস্তি টেনে এনেছে।"],
  "3:88": ["Eternally they abide therein; the retribution is never commuted for them, nor will they be reprieved.","অনন্তকাল তারা সেখানে বাস করবে; তাদের জন্য শাস্তি কখনোই কমানো হবে না,না তারা পরিত্রান পাবে।"],
  "3:89": ["Exempted are those who repent thereafter, and reform. Allah is Forgiver, Most Merciful.","তারা নিষ্কৃতি পাবে যারা এরপর অনুশোচনা করে,এবং সংশোধিত হয়। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "3:90": ["Those who disbelieve after believing, then plunge deeper into disbelief, their repentance will not be accepted from them; they are the real strayers.","যারা বিশ্বাস করার পর অবিশ্বাস করে,তারপর অবিশ্বাসের গভীরে ডুবে যায়, তাদের অনুশোচনা তাদের থেকে গ্রহণ করা হবে না; তারাই আসল পথভ্রষ্ট।"],
  "3:91": ["Those who disbelieve and die as disbelievers, an earthful of gold will not be accepted from any of them, even if such a ransom were possible. They have incurred painful retribution; they will have no helpers.","যারা অবিশ্বাস করে এবং অবিশ্বাসী হিসেবে মারা যায়, একটি স্বর্নে পরিপূর্ণ পৃথিবী তাদের কারো কাছ থেকে গ্রহণ করা হবে না,যদি এরকম মুক্তিপণ সম্ভব হয়। তারা যন্ত্রনাদায়ক শাস্তি টেনে এনেছে; তাদের কোন সাহায্যকারী থাকবে না।"],
  "3:92": ["You cannot attain righteousness until you give to charity from the possessions you love. Whatever you give to charity, Allah is fully aware thereof.","তোমরা সৎকর্মশীলতা অর্জন করতে পার না,যতক্ষন না তোমরা তোমাদের অধিকৃত প্রিয় বস্তু থেকে দান করো। যাকিছু তোমরা দান কর, আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "3:93": ["All food used to be lawful for the Children of Israel, until Israel imposed certain prohibitions on themselves before the Torah was sent down. Say, \"Bring the Torah and read it, if you are truthful.\"","ইসরাইলের সন্তানদের জন্য সকল খাদ্য আইনসম্মত ছিল, যতক্ষন না ইসরাইলীরা তাদের নিজেদের উপর নির্দিষ্ট নিষেধসমূহ আরোপ করেছিল, তওরাত অবতীর্ণ হবার আগে। বল, \"তওরাত আন এবং তা পড়, যদি তোমরা সত্যবাদী হও।"],
  "3:94": ["Those who fabricate false prohibitions after this, and attribute them to Allah, are truly wicked.","যারা এরপর মিথ্যা নিষেধসমূহ উদ্ভাবন করে,এবং সেগুলো আল্লাহর উপর আরোপ করে,তারা প্রকৃতপক্ষে অন্যায়কারী।"],
  "3:95": ["Say, \"Allah has proclaimed the truth: You shall follow Abraham's religion—monotheism. He never was an idolator.\"","বল, \"আল্লাহ সেই সত্য ঘোষনা করেছেন: তোমরা অনুসরণ করবে ইব্রাহিমের ধর্ন- একেশ্বরবাদ। সে কখনো অংশীদার সাব্যস্তকারী ছিল না।"],
  "3:96": ["The most important shrine established for the people is the one in Becca; a blessed beacon for all the people.","মানুষের জন্য সব থেকে গুরুত্বপূর্ণ ঘর হচ্ছে সেটি যা বাক্কায় স্থাপিত; একটি পবিত্র আলোকবর্তিকা,সকল মানুষের জন্য।"],
  "3:97": ["In it are clear signs: the station of Abraham. Anyone who enters it shall be granted safe passage. The people owe it to Allah that they shall observe Hajj to this shrine, when they can afford it. As for those who disbelieve, Allah does not need anyone.","এর মধ্যে রয়েছে স্পষ্ট নিদর্শনসমূহ: ইবরাহীমের অবস্থানস্থল। যে কেউ এতে প্রবেশ করে তাকে প্রদান করা হবে নিরাপদ অবস্থান। আল্লাহর কাছে মানুষ এতে বাধ্য যে তারা এই ঘরে হজ্জ পালন করবে,যখন তারা এর  সামর্থ অর্জন করতে পারে আর যারা অবিশ্বাস করে,আল্লাহর কাউকে প্রয়োজন নেই।"],
  "3:98": ["Say, \"O followers of the scripture, why do you reject these revelations of Allah, when Allah is witnessing everything you do?\"","বল, “হে ঐশীগ্রন্থের অনুসারীরা,কেন তোমরা আল্লাহর এই প্রকাশনাবলী প্রত্যাখ্যান কর, যখন আল্লাহ সবকিছু প্রত্যক্ষ করছেন, যা তোমরা করো।"],
  "3:99": ["Say, \"O followers of the scripture, why do you repel from the path of Allah those who wish to believe, and seek to distort it, even though you are witnesses?\" Allah is never unaware of anything you do.","বল, “হে ঐশীগ্রন্থের অনুসারীরা,কেন তোমরা আল্লাহর পথে বাধা দাও, তাদেরকে যারা বিশ্বাস করতে চায়, এবং তা বিকৃত করার পথ খোঁজ, যদিও তোমরা প্রত্যক্ষ করছ”। তোমরা যা কিছু করো তা সম্পর্কে আল্লাহ কখনই অনবগত নন।"],
  "3:100": ["O you who believe, if you obey some of those who received the scripture, they will revert you, after having believed, into disbelievers.","হে তোমরা যারা বিশ্বাস করো, যারা ঐশীগ্রন্থ গ্রহণ করেছে, তাদের কতককে যদি তোমরা মান্য করো, তারা তোমাদেরকে পিছনে ফিরিয়ে দেবে, বিশ্বাস আনার পর, অবিশ্বাসীতে।"],
  "3:101": ["How can you disbelieve, when these revelations of Allah are being recited to you, and His messenger is in your midst? Whoever holds fast to Allah will be guided in the right path.","কিভাবে তোমরা অবিশ্বাস করতে পার: যখন আল্লাহর এই প্রকাশনাবলি তোমাদের কাছে আবৃতি করা হয়েছে,এবং তার বার্তাবাহক তোমাদের কাছে এসেছে? যেকেউ আল্লাহতে দৃড়ভাবে আঁকড়ে থাকে,সে সঠিক পথে পথ-প্রদর্শিত হবে।"],
  "3:102": ["O you who believe, you shall observe Allah as He should be observed, and do not die except as Submitters.","হে যারা বিশ্বাস কর, তোমরা আল্লাহকে মান্য করবে,যেমন তাকে মান্য করা উচিৎ,এবং আত্মসমর্পণকারী হিসেবে ছাড়া মৃত্যুবরণ করো না।"],
  "3:103": ["You shall hold fast to the rope of Allah, all of you, and do not be divided. Recall Allah's blessings upon you—you used to be enemies and He reconciled your hearts. By His grace, you became brethren. You were at the brink of a pit of fire, and He saved you therefrom. Allah thus explains His revelations for you, that you may be guided.","তোমরা আল্লাহর রশি দৃড়ভাবে আঁকড়ে থাকবে,তোমরা সবাই, এবং বিভক্ত হইও না। স্মরণ কর, তোমাদের উপর আল্লাহর আশীর্বাদ- তোমরা শত্রু হয়ে ছিলে এবং তিনি তোমাদের অন্তরসমূহ পূনর্মিলিত করেছিলেন। তাঁর অনুগ্রহে,তোমরা ভাই হয়ে গিয়েছিলে। তোমরা ছিলে অগ্নিকুন্ডের কিনারে,তিনি তোমাদেরকে সেখান থেকে রক্ষা করেছিলেন। আল্লাহ এভাবে তোমাদের জন্য তাঁর প্রকাশনাবলি ব্যাখ্যা করেন, যাতে তোমরা পথ-প্রদর্শিত হতে পার।"],
  "3:104": ["Let there be a community of you who invite to what is good, advocate righteousness, and forbid evil. These are the winners.","তোমাদের একটি সম্প্রদায় হোক, যারা যাকিছু ভাল তাতে আহবান করে,সৎকর্মশীলতার উপদেশ দেয়, এবং মন্দ করতে নিষেধ করে। এরাই বিজয়ী।"],
  "3:105": ["Do not be like those who became divided and disputed, despite the clear proofs that were given to them. For these have incurred a terrible retribution.","তাদের মত হইও না যারা বিভক্ত এবং বিবাদে লিপ্ত হয়ে পড়েছিল, সুস্পষ্ট প্রমান সত্ত্বেও, যা তাদেরকে দেয়া হয়েছিল। এর জন্য, এরা টেনে এনেছে এক ভয়ানক শাস্তি।"],
  "3:106": ["The day will come when some faces will be brightened (with joy), while other faces will be darkened (with misery). As for those whose faces are darkened, they will be asked, \"Did you not disbelieve after believing? Therefore, suffer the retribution for your disbelief.\"","সে দিন আসবে যখন কিছু মুখ উজ্জল হবে (আনন্দে),যখন অন্য মুখগুলো অন্ধকারাচ্ছন্ন হবে (দুর্দশায়)। তাদের ক্ষেত্রে যাদের মুখসমূহ অন্ধকারাচ্ছন্ন হবে,তারা জিজ্ঞাসিত হবে,”তোমরা কি বিশ্বাস করার পর অবিশ্বাস করনি? কাজেই তোমাদের অবিশ্বাসের জন্য প্রতিফল ভোগ করো।\""],
  "3:107": ["As for those whose faces are brightened, they will rejoice in Allah's mercy; they abide therein forever.","আর তাদের ক্ষেত্রে যাদের মুখসমূহ উজ্জ্বল হবে,তারা আল্লাহর দয়ায় আনন্দ করবে; তারা সেখানে চিরকাল বাস করবে।"],
  "3:108": ["These are Allah's revelations; we recite them to you, truthfully. Allah does not wish any hardship for the people.","এগুলো আল্লাহর প্রকাশনাবলী; আমরা সেগুলো তোমার কাছে আবৃত্তি করি,সত্যতার সাথে। আল্লাহ মানুষের জন্য কোন কষ্ট চান না।"],
  "3:109": ["To Allah belongs everything in the heavens and everything on earth, and all matters are controlled by Allah.","আকাশমন্ডলীর সবকিছু এবং পৃথিবীর উপরের সবকিছু আল্লাহর, এবং সকল বস্তু আল্লাহর দ্বারা নিয়ন্ত্রিত।"],
  "3:110": ["You are the best community ever raised among the people: you advocate righteousness and forbid evil, and you believe in Allah. If the followers of the scripture believed, it would be better for them. Some of them do believe, but the majority of them are wicked.","এযাবতকালে উত্থিত মানুষের মাঝে তোমরা শ্রেষ্ঠ সম্প্রদায়ঃ তোমরা সৎকর্মের উপদেশ দাও এবং মন্দে নিষেধ করো,এবং তোমরা আল্লাহতে বিশ্বাস করো। যদি ঐশীগ্রন্থের অনুসারীরা বিশ্বাস করত, এটা তাদের জন্য উত্তম হত। তাদের কেউ কেউ বিশ্বাস করে,কিন্তু তাদের বেশির ভাগ পাপী।"],
  "3:111": ["They can never harm you, beyond insulting you. If they fight you, they will turn around and flee. They can never win.","তোমাদেরকে অপমান করার অতিরিক্ত, তারা কখনো তোমাদের ক্ষতি করতে পারে না। যদি তারা তোমাদের সাথে লড়াই করে,তারা ঘুরে দাঁড়াবে এবং পালিয়ে যাবে। তারা কখনো জয়ী হতে পারে না।"],
  "3:112": ["They shall be humiliated whenever you encounter them, unless they uphold Allah's covenant, as well as their peace covenants with you. They have incurred wrath from Allah, and, consequently, they are committed to disgrace. This is because they rejected Allah's revelations, and killed the prophets unjustly. This is because they disobeyed and transgressed.","যখনি তোমরা তাদের মোকাবেলা কর, তারা অপদস্থ হবে,যদি না তারা বহাল থাকে আল্লাহর চুক্তিতে, পাশাপাশি তোমাদের সাথে করা তাদের শান্তি চুক্তিতে। তারা আল্লাহর ক্রোধ টেনে এনেছে,এবং,ফলস্বরুপ, তারা অসম্মানে পতিত হয়। এটা এ কারনে যে তারা আল্লাহর প্রকাশনাবলিকে প্রত্যাক্ষান করেছিল, এবং নবীদেরকে অন্যায়ভাবে হত্যা করেছিল। এটা এ কারনে যে তারা অমান্য করেছিল এবং সীমালঙ্ঘন করেছিল।"],
  "3:113": ["They are not all the same; among the followers of the scripture, there are those who are righteous. They recite Allah's revelations through the night, and they fall prostrate.","তারা সবাই একই রকম নয়; ঐশীগ্রন্থের অনুসারীদের মধ্যে রয়েছে তারা যারা সৎকর্মশীল। তারা রাত জুড়ে আল্লাহর প্রকাশনাবলি আবৃতি করে,এবং তারা সেজদায় অবনত হয়।"],
  "3:114": ["They believe in Allah and the Last Day, they advocate righteousness and forbid evil, and they hasten to do righteous works. These are the righteous.","তারা আল্লাহতে এবং শেষ দিবসে বিশ্বাস করে,তারা সৎকর্মশীলতার উপদেশ দেয় এবং মন্দ করতে নিষেধ করে,এবং তারা সৎ কাজ করতে ত্বরা করে। এরাই সৎকর্মশীল।"],
  "3:115": ["Any good they do will not go unrewarded. Allah is fully aware of the righteous.","যেকোন ভাল তারা করে,তা অপুরস্কৃত হবে না। আল্লাহ সৎকর্মশীলদের ব্যপারে সম্পূর্ণ অবগত।"],
  "3:116": ["Those who disbelieved can never be helped by their money or their children against Allah. They have incurred Hell, wherein they abide forever.","যারা অবিশ্বাস করেছে তারা কখনই আল্লাহর বিরুদ্ধে তাদের অর্থ অথবা তাদের সন্তানদের দ্বারা সাহায্য প্রাপ্ত হতে পারে না। তারা নরক টেনে এনেছে,যার মধ্যে তারা চিরকাল বাস করবে।"],
  "3:117": ["The example of their accomplishments in this life is like a violent wind that hits the harvest of people who have wronged their souls, and wipes it out. Allah never wronged them; it is they who wronged themselves.","এই জীবনে তাদের সম্পাদিত কাজের উদাহরন হচ্ছে,প্রবল বাতাসের মতো যা আঘাত করে ঐসব মানুষের ফসলে যারা তাদের আত্মার ক্ষতি করেছে,এবং একে নিশ্চিহ্ন করে ফেলে। আল্লাহ কখনই তাদের ক্ষতি করেননি; তারা নিজেরাই নিজেদের ক্ষতি করেছে।"],
  "3:118": ["O you who believe, do not befriend outsiders who never cease to wish you harm; they even wish to see you suffer. Hatred flows out of their mouths and what they hide in their chests is far worse. We thus clarify the revelations for you, if you understand.","হে তোমরা যারা বিশ্বাস করো, বহিরাগতদের সাথে বন্ধুত্ব করো না যারা কখনই তোমাদের অনিষ্ট কামনা বন্ধ করে না। এমনকি, তারা দেখতে চায়, তোমরা কষ্ট ভোগ করো। তাদের মুখ থেকে ঘৃণা প্রবাহিত হয় এবং যা তারা তাদের বুকে লুকিয়ে রাখে তা আরো মন্দ। এভাবে,আমরা তোমাদের জন্য প্রকাশনাবলী সুস্পষ্ট করি, যেন তোমরা বুঝতে পার।"],
  "3:119": ["Here you are loving them, while they do not love you, and you believe in all the scripture. When they meet you they say, \"We believe,\" but as soon as they leave they bite their fingers out of rage towards you. Say, \"Die in your rage.\" Allah is fully aware of the innermost thoughts.","দেখো, তোমরা তাদেরকে ভালবাস, যখন তারা তোমাদেরকে ভালবাসে না, এবং তোমরা সকল ঐশীগ্রন্থে বিশ্বাস করো। যখন তারা তোমাদের সাথে সাক্ষাৎ করে তারা বলে, “আমরা বিশ্বাস করি,” কিন্তু, যে-মুহূর্তে তারা চলে যায় তারা তোমাদের প্রতি প্রচণ্ড ক্রোধ বসত তাদের আঙ্গুল কামড়াতে থাকে। বল, “মর, তোমাদের প্রচণ্ড ক্রোধে”। আল্লাহ সব থেকে গভীরতম চিন্তাসমূহ সম্পর্কে পরিপূর্ণভাবে অবগত।"],
  "3:120": ["When anything good comes your way they hurt, and when something bad happens to you they rejoice. If you steadfastly persevere, and maintain righteousness, their schemes will never hurt you. Allah is fully aware of everything they do.","যখন তোমাদের পথে ভালো কিছু আসে তারা আঘাত পায়, এবং যখন তোমাদের মন্দ কিছু হয় তারা আনন্দিত হয়। যদি তোমরা দৃড়তার সাথে অধ্যবসায়ী হও, এবং সৎকর্মশীলতা বজায় রাখো, তাদের চক্রান্ত কখনই তোমাদের ক্ষতি করতে পারবে না। তারা যাকিছু করে আল্লাহ সে সম্পর্কে পরিপূর্ণভাবে অবগত।"],
  "3:121": ["Recall that you (Muhammad) were among your people when you set out to assign to the believers their positions for battle. Allah is Hearer, Omniscient.","স্মরণ কর যে,তুমি (মুহাম্মদ) তোমার লোকদের মাঝে ছিলে,যখন তুমি বিশ্বাসীদের জন্য তাদের যুদ্ধের অবস্থান নির্ধারণ করতে গিয়েছিলে। আল্লাহ শ্রোতা,সর্বজ্ঞ।"],
  "3:122": ["Two groups among you almost failed, but Allah was their Lord. In Allah the believers shall trust.","তোমাদের মধ্যে দুই দল প্রায় ব্যর্থ হয়েছিল, কিন্তু আল্লাহ ছিলেন তাদের প্রভু। বিশ্বাসীরা আস্থা রাখবে আল্লাহতে।"],
  "3:123": ["Allah has granted you victory at Badr, despite your weakness. Therefore, you shall observe Allah, to show your appreciation.","আল্লাহ বদরে তোমাদের বিজয় দান করেছেন, তোমাদের দুর্বলতা সত্ত্বেও। অতএব, তোমরা আল্লাহকে মান্য করবে,তোমাদের কৃতজ্ঞতা প্রদর্শনের জন্য।"],
  "3:124": ["You told the believers, \"Is it not enough that your Lord supports you with three thousand angels, sent down?\"","তুমি বিশ্বাসীদের বলেছিলে,\"এটা কি যথেষ্ট নয় যে,তোমাদের প্রভু তোমাদের সমর্থন করেন অবতীর্ণ তিন হাজার ফেরেশতা দিয়ে?\""],
  "3:125": ["Indeed, if you steadfastly persevere and maintain righteousness, then they attack you suddenly, your Lord will support you with five thousand angels, well trained.","নিশ্চয়, যদি তোমরা দৃড়তার সাথে অধ্যবসায়ী হও এবং সৎকর্মশীলতা বজায় রাখ, তারপর তারা তোমাদের অকস্মাৎ আক্রমণ করে, তোমাদের প্রভু তোমাদেরকে সুপ্রশিক্ষিত পাঁচ হাজার ফেরেশতা দিয়ে সমর্থন করবেন।"],
  "3:126": ["Allah thus informs you, in order to give you good news, and to assure your hearts. Victory comes only from Allah, the Almighty, Most Wise.","এভাবে,আল্লাহ তোমাদেরকে অবহিত করেন, তোমাদের সুসংবাদ দেওয়ার জন্য, এবং তোমাদের হৃদয়কে আশ্বস্ত করার জন্য। বিজয় একমাত্র আল্লাহ থেকে আসে,সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "3:127": ["He thus annihilates some disbelievers, or neutralizes them; they always end up the losers.","এভাবে,তিনি কিছু অবিশ্বাসীকে নির্মূল করেন, অথবা তাদেরকে নিষ্ক্রিয় করে দেন, শেষ পর্যন্ত তারা সবসময় পরাজিত হয়।"],
  "3:128": ["It is not up to you; He may redeem them, or He may punish them for their transgressions.","এটা তোমার অধীনে নয়; তিনি হয়তো তাদের উদ্ধার করবেন, অথবা তাদের শাস্তি দিবেন, তাদের সীমালঙ্ঘনের জন্য।"],
  "3:129": ["To Allah belongs everything in the heavens and the earth. He forgives whomever He wills, and punishes whomever He wills. Allah is Forgiver, Most Merciful.","আকাশমন্ডলী ও পৃথিবীর সবকিছু আল্লাহর। তিনি যাকে ইচ্ছা ক্ষমা করেন, এবং যাকে ইচ্ছা শাস্তি দেন। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "3:130": ["O you who believe, you shall not take usury, compounded over and over. Observe Allah, that you may succeed.","হে তোমরা যারা বিশ্বাস করো,তোমরা চড়া সুদ নেবে না,চক্রবৃদ্ধি হারে। আল্লাহকে মান্য করো,যাতে তোমরা সফলকাম হতে পার।"],
  "3:131": ["Beware of the hellfire that awaits the disbelievers.","সতর্ক হও, সেই নরকাগ্নির বিষয়ে যা অবিশ্বাসীদের জন্য অপেক্ষা করে।"],
  "3:132": ["You shall obey Allah and the messenger, that you may attain mercy.","তোমরা আল্লাহ এবং বার্তাবাহককে মান্য করবে,যাতে ঐশরিক দয়া অর্জন করতে পার।"],
  "3:133": ["You should eagerly race towards forgiveness from your Lord and a Paradise whose width encompasses the heavens and the earth; it awaits the righteous,","তোমাদের উচিত আগ্রহের সঙ্গে প্রতিযোগিতা করা,তোমাদের প্রভুর থেকে ক্ষমাপ্রাপ্তির এবং একটি স্বর্গের, যার প্রশস্ততা বেষ্টন করে আকাশমন্ডলী  এবং পৃথিবীকে; এটি সৎকর্মশীলদের জন্য অপেক্ষা করে,"],
  "3:134": ["who give to charity during the good times, as well as the bad times. They are suppressors of anger, and pardoners of the people. Allah loves the charitable.","যারা দান করে ভাল সময়ে,একই সাথে দু:সময়ে। তারা ক্রোধ দমনকারী,এবং লোকদের ক্ষমাকারী। আল্লাহ দানশীলকে ভালবাসেন।"],
  "3:135": ["If they fall in sin or wrong their souls, they remember Allah and ask forgiveness for their sins—and who forgives the sins except Allah—and they do not persist in sins, knowingly.","যদি তারা পাপে পতিত হয় অথবা তাদের আত্মার ক্ষতি করে,তারা আল্লাহকে স্মরণ করে এবং তাদের পাপের জন্য ক্ষমা চায়- এবং কে পাপ ক্ষমা করে আল্লাহ ছাড়া- এবং জেনে-শুনে তারা পাপ করতে থাকে না।"],
  "3:136": ["Their recompense is forgiveness from their Lord, and gardens with flowing streams; they abide therein forever. What a blessed reward for the workers!","তাদের প্রতিদান হল তাদের প্রভুর পক্ষ থেকে ক্ষমা,এবং প্রবাহিত জলস্রোত সহ বাগান; তারা সেখানে চিরকাল বসবাস করে। পরিশ্রমকারীদের জন্য কি এক মনোরম পুরস্কার!"],
  "3:137": ["Precedents have been set for you in the past; roam the earth and note the consequences for the unbelievers.","তোমাদের জন্য অতীতের উদাহরণ স্থাপন করা হয়েছে; পৃথিবীতে ভ্রমন কর এবং লক্ষ্য কর অবিশ্বাসীদের পরিণাম।"],
  "3:138": ["This is a proclamation for the people, and a guidance and enlightenment for the righteous.","এটা মানুষের জন্য একটি ঘোষণা,এবং সৎকর্মশীলদের জন্য একটি পথ নির্দেশনা এবং জ্ঞানালোক।"],
  "3:139": ["You shall not waver, nor shall you grieve, for you are the ultimate victors, if you are believers.","তোমরা দ্বিধাগ্রস্থ হবে না,না তোমরা শোকার্ত হবে,কারন তোমরাই চূড়ান্ত বিজয়ী,যদি তোমরা বিশ্বাসী হয়ে থাকো।"],
  "3:140": ["If you suffer hardship, the enemy also suffers the same hardship. We alternate the days of victory and defeat among the people. Allah thus distinguishes the true believers, and blesses some of you with martyrdom. Allah dislikes injustice.","যদি তোমরা কষ্ট ভোগ কর, শত্রুরাও একই কষ্ট ভোগ করে। আমরা মানুষের মাঝে জয় এবং পরাজয়ের দিনগুলো পালাক্রমে পরিবর্তন করি। আল্লাহ এভাবে পৃথক করেন সত্যিকার বিশ্বাসীদের, এবং তোমাদের কতককে শহীদত্ব দিয়ে আশীর্বাদ করেন। আল্লাহ অবিচার অপছন্দ করেন।"],
  "3:141": ["Allah thus toughens those who believe and humiliates the disbelievers.","এভাবে,আল্লাহ তাদেরকে বলিষ্ঠ করেন, যারা বিশ্বাস করে এবং অপদস্থ করেন, অবিশ্বাসীদের।"],
  "3:142": ["Do you expect to enter Paradise without Allah distinguishing those among you who strive, and without distinguishing those who are steadfast?","তোমরা কি স্বর্গে প্রবেশের আশা কর, তোমাদের মধ্যে তাদেরকে আলাদা করা ব্যতিত, যারা সংগ্রাম করে,এবং তাদেরকে আলাদা করা ব্যতিত, যারা দৃড়?"],
  "3:143": ["You used to long for death before you had to face it. Now you have faced it, right before your eyes.","তোমরা মৃত্যুর জন্য আকাংখা করতে,এর মুখোমুখি হবার আগে। এখন, তোমরা এর মুখোমুখি হয়েছ, ঠিক তোমাদের চোখের সামনে।"],
  "3:144": ["Muhammad was no more than a messenger like the messengers before him. Should he die or get killed, would you turn back on your heels? Anyone who turns back on his heels, does not hurt Allah in the least. Allah rewards those who are appreciative.","মুহাম্মদ তার পূর্বের বার্তাবাহকদের মত, একজন বার্তাবাহকের চেয়ে বেশি কিছু ছিল না। সে মরে গেলে অথবা নিহত হলে,তোমরা কি পূর্বের অবস্থায় ফিরে যেতে? যেকেউ তার পূর্বের অবস্থায় ফিরে যায়, সে আল্লাহর সামান্যতম ক্ষতি করে না। আল্লাহ তাদেরকে পুরস্কৃত করেন, যারা কৃতজ্ঞ।"],
  "3:145": ["No one dies except by Allah's leave, at a predetermined time. Whoever seeks the vanities of this world, we give him therefrom, and whoever seeks the rewards of the Hereafter, we bless him therein. We reward those who are appreciative.","আল্লাহর অনুমতি ছাড়া কেউই মৃত্যুবরণ করে না,এক পূর্বনির্ধারিত সময়ে। যেকেউ এই দুনিয়ার আড়ম্বর খোঁজে,আমরা তাকে সেখান থেকে দেই, এবং যেকেউ পরকালের পুরস্কার খোঁজে,আমরা তাকে সেখানে আশীর্বাদ করি। আমরা তাদেরকে পুরস্কৃত করি,যারা কৃতজ্ঞ।"],
  "3:146": ["Many a prophet had godly people fight along with him, without ever wavering under pressure in the cause of Allah, nor did they hesitate or become discouraged. Allah loves the steadfast.","অনেক নবিদের সাথে আল্লাহপ্রেমী লোকেরা ছিল যুদ্ধ করার জন্য, আল্লাহর উদ্দেশ্যে চাপের মুখে কখনো দিধাগ্রস্থ না হয়ে,না তারা ইতস্তত করতো অথবা নিরুৎসাহিত হয়ে পড়তো। আল্লাহ অবিচলদের ভালবাসেন।"],
  "3:147": ["Their only utterance was, \"Our Lord, forgive us our sins, and our transgressions, strengthen our foothold, and grant us victory over the disbelievers.\"","তাদের একমাত্র উক্তি ছিল, “আমাদের প্রভু,ক্ষমা করুন- আমাদের পাপ, এবং আমাদের সীমালঙ্ঘনসমূহ, আমাদের অবস্থানকে সুদৃঢ় করুন, এবং অবিশ্বাসীদের উপর আমাদের জয় প্রদান করুন। \""],
  "3:148": ["Consequently, Allah granted them the rewards of this world, and the better rewards of the Hereafter. Allah loves the good doers.","ফলস্বরূপ, আল্লাহ তাদেরকে প্রদান করেছিলেন এই দুনিয়ার পুরুস্কার, এবং পরকালের উত্তম পুরুস্কার। আল্লাহ সৎকর্মশীলদের ভালোবাসেন।"],
  "3:149": ["O you who believe, if you obey those who disbelieve, they will turn you back on your heels, then you end up losers.","হে তোমরা যারা বিশ্বাস কর, তোমরা যদি তাদেরকে মান্য কর যারা অবিশ্বাস করে,তারা তোমাদেরকে পূর্বের অবস্থায় ফিরিয়ে দেবে,তখন তোমরা শেষ পর্যন্ত পরাজিত হবে।"],
  "3:150": ["Allah alone is your Lord and Master, and He is the best supporter.","আল্লাহ একমাত্র তোমাদের প্রভু এবং মনিব, এবং তিনিই সর্বোত্তম সমর্থনকারী।"],
  "3:151": ["We will throw terror into the hearts of those who disbelieved, since they set up besides Allah powerless idols. Their destiny is Hell; what a miserable abode for the transgressors!","যারা অবিশ্বাস করেছিল তাদের অন্তরে আমরা আতঙ্ক ছুড়ে দেব, যেহেতু তারা আল্লাহর সাথে ক্ষমতাহীন উপাস্য স্থাপন করেছিল। তাদের নিয়তি হল নরক; কতই না দুর্বিষহ আবাস সীমালঙ্ঘনকারীদের জন্য।"],
  "3:152": ["Allah has fulfilled His promise to you, and you defeated them by His leave. But then you wavered, disputed among yourselves, and disobeyed after He had shown you (the victory) you had longed for. But then, some of you became distracted by the spoils of this world, while others were rightly concerned with the Hereafter. He then diverted you from them to test you. He has pardoned you. Allah showers the believers with His grace.","আল্লাহ তোমাদের প্রতি তাঁর অঙ্গীকার পরিপূর্ণ করেছেন, এবং তোমরা তাঁর সম্মতিক্রমে তাদের পরাজিত করেছিলে। কিন্তু এরপর তোমরা দ্বিধান্বিত হয়ে পড়েছিলে,তোমাদের নিজেদের মধ্যে বিবাদে লিপ্ত হয়েছিলে,এবং অমান্য করেছিলে তিনি তোমাদের আকাংক্ষিত (বিজয়) দেখানোর পর। কিন্তু এরপর, তোমাদের কেউ কেউ এই দুনিয়ার যুদ্ধলব্ধ মালের দ্বারা বিভ্রান্ত হয়ে পড়েছিলে,যখন অন্যান্যরা সঠিকভাবে পরকাল নিয়ে উদ্বিগ্ন ছিল। তিনি তখন তোমাদের পরীক্ষা করতে তাদের থেকে সরিয়ে দিলেন। তিনি তোমাদের মার্জনা করেছেন। আল্লাহ বিশ্বাসীদের উপর তাঁর অনুগ্রহ বর্ষন করেন।"],
  "3:153": ["Recall that you rushed (after the spoils), paying no attention to anyone, even when the messenger was calling from behind you. Consequently, He substituted one misery for another, that you may not grieve over anything you had missed, or agonize over any hardship you had suffered. Allah is Cognizant of everything you do.","স্মরণ কর যে,তোমরা (যুদ্ধলব্ধ মালের পিছনে) হুমড়ি খেয়ে পড়েছিলে,কারো প্রতি কোন দৃষ্টিপাত না করে,এমনকি যখন বার্তাবাহক তোমাদেরকে পিছন থেকে ডাকছিল। ফলস্বরুপ, তিনি একটি দুর্দশাকে অন্যটি দ্বারা প্রতিস্থাপন করেছিলেন, যাতে তোমাদের শোক করতে না হয় তোমাদের হাত-ছাড়া হয়েছিল এমন কোনকিছুর উপর, অথবা যন্ত্রণা না পেতে হয় এমন কোন কষ্টের কারনে যা তোমরা ভোগ করেছিলে। আল্লাহ তোমাদের করা সবকিছু সম্পর্কে অবগত।"],
  "3:154": ["After the setback, He sent down upon you peaceful slumber that pacified some of you. Others among you were selfishly concerned about themselves. They harbored thoughts about Allah that were not right— the same thoughts they had harbored during the days of ignorance. Thus, they said, \"Is anything up to us?\" Say, \"Everything is up to Allah.\" They concealed inside themselves what they did not reveal to you. They said, \"If it was up to us, none of us would have been killed in this battle.\" Say, \"Had you stayed in your homes, those destined to be killed would have crawled into their death beds.\" Allah thus puts you to the test to bring out your true convictions, and to test what is in your hearts. Allah is fully aware of the innermost thoughts.","এই প্রতিবন্ধকতার পর, তিনি তোমাদের উপর শান্তিময় ঘুম অবতীর্ণ করেছিলেন যা তোমাদের কাউকে কাউকে শান্ত করেছিল। তোমাদের মধ্যে অন্যরা সার্থপরভাবে তাদের নিজেদের নিয়ে উদ্বিগ্ন ছিল। তারা আল্লাহ সম্পর্কে এমন চিন্তা পোষণ করেছিল যা সঠিক ছিল না- সে একই চিন্তাসমূহ যা তারা অজ্ঞতার দিনগুলোতে পোষণ করতো। একারনে,তারা বলেছিল, \"আমাদের হাতে কি কোনকিছু আছে? বল, \"সবকিছু আল্লাহর হাতে।”তারা তাদের নিজেদের ভিতরে গোপন করেছিল, যা তারা তোমার কাছে প্রকাশ করেনি। তারা বলেছিল, \"যদি এটা আমাদের হাতে থাকত, আমাদের কেউই এই যুদ্ধে নিহত হত না।” বল, \"তোমরা যদি তোমাদের বাড়িতে অবস্থান করতে,যাদের নিহত হওয়া পূর্বনির্ধারিত ছিল তারা হামাগুড়ি দিত তাদের মৃত্যু শয্যায়।” এভাবে,আল্লাহ তোমাদের পরীক্ষায় ফেলেন তোমাদের প্রকৃত অভিপ্রায়কে প্রকাশ করতে,এবং পরীক্ষা করতে তোমাদের অন্তরে কি আছে। আল্লাহ গভীরতম  চিন্তাসমূহ সম্পর্কে সম্পূর্ণ অবগত।"],
  "3:155": ["Surely, those among you who turned back the day the two armies clashed have been duped by the devil. This reflects some of the (evil) works they had committed. Allah has pardoned them. Allah is Forgiver, Clement.","নিশ্চয়, তোমাদের মধ্যে যারা পিছু হটেছিল দুই সেনাবাহিনীর সংঘর্ষের দিনে,তারা শয়তানের দ্বারা প্রতারিত হয়েছিল। এটা প্রতিফলন করে কিছু (মন্দ) কর্ম, যা তারা করেছিল। আল্লাহ তাদের মার্জনা করেছেন। আল্লাহ ক্ষমাশীল, সহিষ্ণু।"],
  "3:156": ["O you who believe, do not be like those who disbelieved and said of their kinsmen who traveled or mobilized for war, \"Had they stayed with us, they would not have died or gotten killed.\" Allah renders this a source of grief in their hearts. Allah controls life and death. Allah is Seer of everything you do.","হে তোমরা যারা বিশ্বাস কর, তাদের মতো হইয়ো না যারা অবিশ্বাস করেছিল এবং তাদের আত্মীয়দের বলেছিল, যারা যুদ্ধের জন্য ভ্রমন করেছিল অথবা একত্রিত হয়েছিল, “তারা যদি আমাদের সাথে থাকতো,তবে তারা মারা যেত না অথবা নিহত হতো না”। আল্লাহ এটাকে তাদের হৃদয়ে একটি তীব্র শোকের উৎসে পরিণত করেছেন। আল্লাহ জীবন এবং মৃত্যু নিয়ন্ত্রন করেন। আল্লাহ তোমাদের করা সবকিছুর দ্রষ্টা।"],
  "3:157": ["Whether you get killed or die in the cause of Allah, the forgiveness from Allah, and mercy are far better than anything they hoard.","তোমরা আল্লাহর উদ্দেশ্য নিহত হও অথবা মারা যাও, তারা যা কিছু জমা করে তার চেয়ে আল্লাহর ক্ষমা,এবং দয়া অনেক উত্তম।"],
  "3:158": ["Whether you die or get killed, you will be summoned before Allah.","তোমরা মারা যাও অথবা নিহত হও, তোমাদেরকে আল্লাহর সামনে ডাকা হবে।"],
  "3:159": ["It was mercy from Allah that you became compassionate towards them. Had you been harsh and mean-hearted, they would have abandoned you. Therefore, you shall pardon them and ask forgiveness for them, and consult them. Once you make a decision, carry out your plan, and trust in Allah. Allah loves those who trust in Him.","এটা আল্লাহর করুণা ছিল যে তুমি তাদের প্রতি দয়াশীল হয়েছিলে। তুমি যদি কঠোর এবং ছোট মনের হতে,তাহলে তারা তোমাকে পরিত্যাগ করতো। অতএব, তুমি তাদেরকে মার্জনা করবে এবং তাদের জন্য ক্ষমা প্রার্থনা করবে,এবং তাদের সাথে পরামর্শ করবে। তোমরা একবার একটি সিদ্ধান্ত নিলে,তোমাদের পরিকল্পনা সম্পন্ন কর, এবং আল্লাহর প্রতি আস্থা রাখো। আল্লাহ তাদেরকে ভালবাসেন যারা তার প্রতি আস্থা রাখে।"],
  "3:160": ["If Allah supports you, none can defeat you. And if He abandons you, who else can support you? In Allah the believers shall trust.","যদি আল্লাহ তোমাদেরকে সমর্থন করেন, কেউ তোমাদেরকে পরাজিত করতে পারে না। এবং যদি তিনি তোমাদেরকে পরিত্যাগ করেন, আর কে তোমাদেরকে সমর্থন করতে পারে? বিশ্বাসীরা আল্লাহর প্রতি আস্থা রাখবে।"],
  "3:161": ["Even the prophet cannot take more of the spoils of war than he is entitled to. Anyone who takes more than his rightful share will have to account for it on the Day of Resurrection. That is when each soul is paid for whatever it earned, without the least injustice.","এমনকি নবী তার নির্ধারিত অংশের বেশি যুদ্ধলব্ধ সম্পদ নিতে পারে না। যে কেউ তার ন্যায্য অংশের বেশি নেয়, তাকে এর হিসাব দিতে হবে পুনরুত্থান দিবসে। অর্থাৎ,যখন প্রত্যেক আত্মাকে প্রতিফল দেওয়া হয, সেজন্য যা কিছু সে অর্জন করেছে,সামান্যতম অবিচার ছাড়াই।"],
  "3:162": ["Is one who pursues Allah's pleasure the same as one who incurs wrath from Allah and his destiny is Hell, the most miserable abode?","যে ব্যক্তি আল্লাহর সন্তুষ্টি অন্বেষণ করে কি একই, সে ব্যক্তির মত যে আল্লাহর তীব্র ক্রোধ টেনে আনে এবং তার নিয়তি হল নরক, সবচেয়ে দুর্দশাগ্রস্ত আবাস।"],
  "3:163": ["They certainly occupy different ranks at Allah. Allah is Seer of everything they do.","নিশ্চিতভাবে,তারা আল্লাহর কাছে বিভিন্ন পদে অধিষ্ঠিত। আল্লাহ তাদের করা সবকিছুর দ্রষ্টা।"],
  "3:164": ["Allah has blessed the believers by raising in their midst a messenger from among them, to recite for them His revelations, and to purify them, and to teach them the scripture and wisdom. Before this, they had gone totally astray.","আল্লাহ বিশ্বাসীদের আশীর্বাদপুষ্ট করেছেন, তাদের মাঝে তাদের মধ্য থেকে একজন বার্তাবাহক উত্থিত করে,তাদের জন্য তাঁর প্রত্যাদেশসমূহ আবৃত্তি করতে,এবং তাদের পরিশুদ্ধ করতে,এবং তাদেরকে ঐশীগ্রন্থ ও প্রজ্ঞা শিক্ষা দিতে। এর আগে,তারা পুরোপুরি পথভ্রষ্ট হয়ে গিয়েছিল।"],
  "3:165": ["Now that you have suffered a setback, and even though you inflicted twice as much suffering (upon your enemy), you said, \"Why did this happen to us?\" Say, \"This is a consequence of your own deeds.\" Allah is Omnipotent.","এখন তোমরা যে একটি প্রতিবন্ধকতা ভোগ করেছ, এবং এমনকি যদিও তোমরা এর দ্বিগুণ পরিমাণ দুর্ভোগ চাপিয়েছিলে (তোমাদের শত্রুদের উপর),তোমরা বলেছিলে,\"কেন এটা আমাদের প্রতি ঘটেছিল? বল, \"এটা তোমাদের নিজেদের কর্মের একটি প্রতিফল\"। আল্লাহ সর্বশক্তিমান।"],
  "3:166": ["What afflicted you the day the two armies clashed was in accordance with Allah's will, and to distinguish the believers.","দুই সেনাবাহিনীর সংঘর্ষের দিনে যা তোমাদেরকে দুর্দশাগ্রস্ত করেছিল তা আল্লাহর ইচ্ছা অনুযায়ী ছিল, এবং বিশ্বাসীদের পৃথক করার জন্য।"],
  "3:167": ["And to expose the hypocrites who were told, \"Come fight in the cause of Allah, or contribute.\" They said, \"If we knew how to fight, we would have joined you.\" They were closer to disbelief then than they were to belief. They uttered with their mouths what was not in their hearts. Allah knows what they conceal.","এবং ভণ্ডদের প্রকাশ করার জন্য, যাদেরকে বলা হয়েছিল, “আসো,আল্লাহর উদ্দেশ্যে যুদ্ধ কর, অথবা অবদান রাখ”।তারা বলেছিল, “আমরা যদি জানতাম কিভাবে যুদ্ধ করতে হয়, আমরা তোমার সাথে যোগদান করতাম”। তখন তারা বিশ্বাসের চেয়ে অবিশ্বাসের নিকটবর্তী ছিল। তারা তাদের মুখে বলেছিল যা তাদের হৃদয়ে ছিল না। আল্লাহ জানেন যা তারা গোপন করে।"],
  "3:168": ["They said of their kinsmen, as they stayed behind, \"Had they obeyed us, they would not have been killed.\" Say, \"Then prevent your own death, if you are truthful.\"","তারা তাদের আত্মীয়দের ব্যাপারে বলেছিল, যখন তারা পেছনে থেকে গিয়েছিল, “তারা যদি আমাদের কথা মান্য করতো,তারা নিহত হতো না”। বল, “তাহলে তোমাদের নিজেদের মৃত্যুকে প্রতিহত কর, যদি তোমরা সত্যবাদী হয়ে থাকো”।"],
  "3:169": ["Do not think that those who are killed in the cause of Allah are dead; they are alive at their Lord, enjoying His provisions.","এটা ভেবো না যে যারা আল্লাহর উদ্দেশ্যে নিহত হয় তারা মৃত; তারা তাদের প্রভুর নিকট জীবিত, উপভোগ করছে তাঁর জীবিকা।"],
  "3:170": ["They are rejoicing in Allah's grace, and they have good news for their comrades who did not die with them, that they have nothing to fear, nor will they grieve.","তারা আল্লাহর অনুগ্রহে আনন্দ করছে,এবং তাদের কাছে তাদের সে সহযোদ্ধাদের জন্য সুসংবাদ আছে যারা তাদের সাথে মৃত্যুবরণ করেনি,যে তাদের কোন ভয় নেই, না তারা শোক করবে।"],
  "3:171": ["They have good news of Allah's blessings and grace, and that Allah never fails to reward the believers.","তাদের জন্য সুসংবাদ আছে,আল্লাহর আশীর্বাদ এবং অনুগ্রহের, এবং যে আল্লাহ কখনো বিশ্বাসীদের পুরষ্কৃত করতে ব্যর্থ হন না।"],
  "3:172": ["For those who respond to Allah and the messenger, despite the persecution they suffer, and maintain their good works, and lead a righteous life, a great reward.","যারা আল্লাহ এবং বার্তাবাহকের ডাকে সাড়া দেয়, তারা যে নিপীড়ন ভোগ করে তা সত্ত্বেও, এবং তাদের ভাল কাজসমূহ চালিয়ে যায়, এবং একটি ন্যায়নিষ্ঠ জীবন অতিবাহিত করে,তাদের জন্য রয়েছে এক মহা পুরষ্কার।"],
  "3:173": ["When the people say to them, \"People have mobilized against you; you should fear them,\" this only strengthens their faith and they say, \"Allah suffices us; He is the best Protector.\"","যখন লোকেরা তাদেরকে বলে,\"লোকেরা তোমাদের বিরুদ্ধে একত্রিত হয়েছে; তোমাদের উচিত তাদের ভয় করা,”এটা শুধু তাদের বিশ্বাসকে দৃড় করে এবং তারা বলে,\"আল্লাহ আমাদের জন্য যথেষ্ট; তিনি সবচেয়ে উত্তম রক্ষাকারী।"],
  "3:174": ["They have deserved Allah's blessings and grace. No harm ever touches them, for they have attained Allah's approval. Allah possesses infinite grace.","TBD"],
  "3:175": ["It is the devil's system to instill fear into his subjects. Do not fear them and fear Me instead, if you are believers.","এটা শয়তানের পদ্ধতি,তার অধীনস্থদের ভিতরে ধীরে ধীরে ভয়ের সঞ্চার করা। তাদেরকে ভয় করো না এবং পরিবর্তে আমাকে ভয় কর, যদি তোমরা বিশ্বাসী হও।"],
  "3:176": ["Do not be saddened by those who hasten to disbelieve. They never hurt Allah in the least. Instead, Allah has willed that they will have no share in the Hereafter. They have incurred a terrible retribution.","TBD"],
  "3:177": ["Those who choose disbelief, instead of belief, do not hurt Allah in the least; they have incurred a painful retribution.","যারা অবিশ্বাসকে পছন্দ করে,বিশ্বাসের বদলে,তারা আল্লাহর সামান্যতম ক্ষতি করে না; তারা টেনে এনেছে যন্ত্রণাদায়ক শাস্তি।"],
  "3:178": ["Let not the disbelievers think that we lead them on for their own good. We only lead them on to confirm their sinfulness. They have incurred a humiliating retribution.","অবিশ্বাসীরা যেন না ভাবে যে আমরা তাদের নিজেদের ভালোর জন্য তাদের পরিচালনা করবো। আমরা শুধু তাদের পরিচালিত করি তাদের পাপময়তা নিশ্চিত করতে। তারা টেনে এনেছে অপমানজনক শাস্তি।"],
  "3:179": ["Allah is not to leave the believers as you are, without distinguishing the bad from the good. Nor does Allah inform you of the future, but Allah bestows such knowledge upon whomever He chooses from among His messengers. Therefore, you shall believe in Allah and His messengers. If you believe and lead a righteous life, you receive a great recompense.","আল্লাহ বিশ্বাসীদের পরিত্যাগ করেন না যেমন তোমরা করো,ভাল থেকে মন্দকে পৃথক করা ছাড়া। না আল্লাহ তোমাদেরকে ভবিষ্যৎ অবহিত করেন, তবে আল্লাহ এমন জ্ঞান তাঁর বার্তাবাহকদের মধ্যে যাকে তিনি পছন্দ করেন তার উপর অর্পণ করেন। সেজন্য, তোমরা আল্লাহ এবং তাঁর বার্তাবাহকদেরকে বিশ্বাস করবে। যদি তোমরা বিশ্বাস করো এবং সৎজীবন যাপন করো,তোমরা এক মহা প্রতিদান প্রাপ্ত হও।"],
  "3:180": ["Let not those who withhold and hoard Allah's provisions think that this is good for them; it is bad for them. For they will carry their hoardings around their necks on the Day of Resurrection. Allah is the ultimate inheritor of the heavens and the earth. Allah is fully Cognizant of everything you do.","যারা আটকে রাখে এবং মজুত করে আল্লাহর দান, তারা যেন না ভাবে যে এটা তাদের জন্য ভাল; এটা তাদের জন্য মন্দ। কারন পুনুরুত্থানের দিবসে তারা তাদের মজুত তাদের গলায় বেষ্টন করে বহন করবে। আল্লাহ আসমান সমূহ এবং পৃথিবীর চূড়ান্ত উত্তরাধিকারী। আল্লাহ সবকিছু পূর্ণভাবে অবগত যা তোমরা করো।"],
  "3:181": ["Allah has heard the utterances of those who said, \"Allah is poor, while we are rich.\" We will record everything they said, just as we recorded their killing of the prophets unjustly, and we will say, \"Suffer the retribution of Hell.","আল্লাহ তাদের কথা শুনেছেন যারা বলেছিল, \"আল্লাহ গরীব, পক্ষান্তরে আমরা ধনী। “তারা যা বলেছিল আমরা এর সবকিছু রেকর্ড  করবো,ঠিক যেমন আমরা রেকর্ড করেছিলাম, তাদের অন্যায়ভাবে নবীদেরকে হত্যা করা এবং আমরা বলব, \"নরকের শাস্তি ভোগ করো।"],
  "3:182": ["\"This is the consequence of your own works.\" Allah is never unjust towards the people.","\"এটা তোমাদের নিজেদের কর্মসমূহের প্রতিফল।”আল্লাহ লোকদের প্রতি কখনো অন্যায়কারী নন।"],
  "3:183": ["It is they who said, \"Allah has made a covenant with us that we shall not believe in any messenger, unless he produces an offering that gets consumed by fire.\" Say, \"Messengers before me have come to you with clear proofs, including what you just demanded. Why then did you kill them, if you are truthful?\"","এরা তারাই যারা বলেছিল, \"আল্লাহ আমাদের সাথে একটি চুক্তি করেছেন যে,আমরা কোন বার্তাবাহককে বিশ্বাস করবো না,যদি না সে একটি উৎসর্গীকৃত বস্তু উপস্থাপন করে,যা আগুনে গ্রাস হয়ে যায়। বল, “আমার আগে বার্তাবাহকরা তোমাদের কাছে সুস্পষ্ট প্রমানাদি সহ এসেছিল, তোমরা যা এইমাত্র দাবী করলে তা সহ। তাহলে,কেন তোমরা তাদেরকে হত্যা করেছিলে,যদি তোমরা সত্যবাদী হও? \""],
  "3:184": ["If they reject you, messengers before you have been rejected, even though they brought proofs, the Psalms, and the enlightening scripture.","যদি তারা তোমাকে প্রত্যাক্ষান করে,তোমার আগে বার্তাবাহকদের প্রত্যাক্ষান করা হয়েছিল, যদিও তারা নিয়ে এসেছিল প্রমানাদি,যবুর, এবং আলোকময়★  কিতাব।"],
  "3:185": ["Every person tastes death, then you receive your recompense on the Day of Resurrection. Whoever misses Hell, barely, and makes it to Paradise, has attained a great triumph. The life of this world is no more than an illusion.","প্রত্যেক ব্যক্তি মৃত্যুর স্বাদ গ্রহণ করে,এরপর পুনরুত্থান দিবসে তোমরা তোমাদের প্রতিফল গ্রহণ করো। যে কেউ অল্পের জন্য নরক থেকে বাঁচে,এবং স্বর্গে যেতে সফল হয়, সে অর্জন করেছে এক মহা বিজয়। এই দুনিয়ার জীবন একটি বিভ্রমের চেয়ে বেশি কিছু নয়।"],
  "3:186": ["You will certainly be tested, through your money and your lives, and you will hear from those who received the scripture, and from the idol worshipers, a lot of insult. If you steadfastly persevere and lead a righteous life, this will prove the strength of your faith.","তোমরা নিশ্চিতভাবে পরিক্ষিত হবে,তোমাদের অর্থ এবং তোমাদের জীবনের মাধ্যমে,এবং তোমরা শুনবে যারা ঐশীগ্রন্থ গ্রহণ করেছে তাদের থেকে,এবং প্রতিমা উপাসকদের থেকে,অনেক অপমান। যদি তোমরা দৃঢ়তার সাথে অধ্যবসায়ী হও এবং সৎ জীবন যাপন করো,এটা তোমাদের বিশ্বাসের দৃঢ়তা প্রমান করবে।"],
  "3:187": ["Allah took a covenant from those who received the scripture: \"You shall proclaim it to the people, and never conceal it.\" But they disregarded it behind their backs, and traded it away for a cheap price. What a miserable trade.","আল্লাহ একটি অঙ্গীকার নিয়েছিলেন তাদের থেকে যারা ঐশীগ্রন্থ গ্রহণ করেছিলঃ “তোমরা এটি মানুষের কাছে ঘোষনা করবে,এবং কখনো এটি গোপন করবে না”। কিন্তু,তারা এটি উপেক্ষা করেছিল তাদের অগোচরে,এবং এটির বেচা-কেনা করেছিল একটি সস্তা মূল্যের জন্য। কি এক শোচনীয় বাণিজ্য।"],
  "3:188": ["Those who boast about their works, and wish to be praised for something they have not really done, should not think that they can evade the retribution. They have incurred a painful retribution.","যারা তাদের কাজের ব্যাপারে গর্ব করে,এবং এমন কিছুর জন্য প্রশংসিত হওয়ার আকাঙ্ক্ষা করে যা প্রকৃতপক্ষে তারা করে নাই, তাদের চিন্তা করা উচিৎ নয় যে,তারা কৌশলে শাস্তি এড়াতে পারে। তারা টেনে এনেছে একটি যন্ত্রণাদায়ক শাস্তি।"],
  "3:189": ["To Allah belongs the sovereignty of the heavens and the earth. Allah is Omnipotent.","আকাশ সমূহ এবং পৃথিবীর সার্বভৌমত্ব আল্লাহর। আল্লাহ সর্বশক্তিমান।"],
  "3:190": ["In the creation of the heavens and the earth, and the alternation of night and day, there are signs for those who possess intelligence.","আকাশমন্ডলী ও পৃথিবীর সৃষ্টিতে,এবং রাত ও দিনের পালা-বদলে,তাদের জন্য নিদর্শন রয়েছে যারা বুদ্ধিমত্তার অধিকারী।"],
  "3:191": ["They remember Allah while standing, sitting, and on their sides, and they reflect upon the creation of the heavens and the earth: \"Our Lord, You did not create all this in vain. Be You glorified. Save us from the retribution of Hell.","তারা দাঁড়িয়ে, বসে, ও শায়িত অবস্থায় আল্লাহকে স্মরণ করে, এবং তারা আকাশমন্ডলী  ও পৃথিবীর সৃষ্টির বিষয়ে ভাবে: “আমাদের প্রভু, আপনি এই সবকিছু নিরর্থক সৃষ্টি করেননি। আপনি মহিমান্বিত। আমাদেরকে নরকের শাস্তি থেকে রক্ষা করুন।"],
  "3:192": ["\"Our Lord, whomever You commit to Hell are the ones You have forsaken. Such transgressors have no helpers.","\"আমাদের প্রভু,যাদেরকে আপনি নরকে দেন তারা হচ্ছে সেই লোকেরা,যাদেরকে আপনি পরিত্যাগ করেছেন। এরকম সীমালঙ্ঘনকারীদের কোন সাহায্যকারী নেই।"],
  "3:193": ["\"Our Lord, we have heard a caller calling to faith and proclaiming: 'You shall believe in your Lord,' and we have believed. Our Lord, forgive us our transgressions, remit our sins, and let us die as righteous believers.","\"আমাদের প্রভু,আমরা শুনেছি একজন আহবায়ককে বিশ্বাসের দিকে আহবান করতে এবং প্রচার করতে: 'তোমরা তোমাদের প্রভুকে বিশ্বাস করবে,' এবং আমরা বিশ্বাস করেছি। আমাদের প্রভু,আমাদের সীমালঙ্ঘনসমূহ ক্ষমা করুন, আমাদের পাপসমূহ ক্ষমা করুন, এবং আমাদেরকে সৎকর্মশীল বিশ্বাসী হিসেবে মৃত্যু দিন।"],
  "3:194": ["\"Our Lord, shower us with the blessings You promised us through Your messengers, and do not forsake us on the Day of Resurrection. You never break a promise.\"","\"আমাদের প্রভু,আমাদেরকে সেই আশীর্বাদসমূহ বর্ষন করুন, যা আপনি আপনার বার্তাবাহকদের মাধ্যমে আমাদেরকে প্রতিশ্রুতি দিয়েছিলেন, এবং পুনরুত্থান দিবসে আমাদেরকে পরিত্যাগ করবেন না। আপনি কখনো প্রতিশ্রুতি ভঙ্গ করেন না।\""],
  "3:195": ["Their Lord responded to them: \"I never fail to reward any worker among you for any work you do, be you male or female—you are equal to one another. Thus, those who immigrate, and get evicted from their homes, and are persecuted because of Me, and fight and get killed, I will surely remit their sins and admit them into gardens with flowing streams.\" Such is the reward from Allah. Allah possesses the ultimate reward.","তাদের প্রভু তাদের প্রতি সাড়া দিয়েছিলেন: \"আমি কখনো তোমাদের মধ্যে কোন কর্মীকে তোমাদের করা কোন কাজের জন্য প্রতিদান দিতে ব্যর্থ হই না,তোমরা নারী হও অথবা পুরুষ হও- তোমরা একে অন্যের সমান। তাই, যারা দেশান্তরিত হয়, এবং তাদের ঘর-বাড়ি থেকে উচ্ছেদ হয়, এবং আমার কারনে নির্যাতিত হয়, এবং যুদ্ধ করে ও নিহত হয়, আমি অবশ্যই তাদের পাপসমূহ ক্ষমা করবো এবং তাদেরকে প্রবাহিত ঝর্নাসহ বাগানসমূহে প্রবেশ করাব।”এরকমই আল্লাহর পক্ষ থেকে প্রতিদান। আল্লাহ পরম প্রতিদানের অধিকারী।"],
  "3:196": ["Do not be impressed by the apparent success of disbelievers.","অবিশ্বাসীদের আপাত সফলতায় অভিভূত হইও না।"],
  "3:197": ["They only enjoy temporarily, then end up in Hell; what a miserable destiny!","তারা শুধু সাময়িকভাবে উপভোগ করে,তারপর নরকে এসে শেষ হয়; কি এক শোচনীয় নিয়তি!"],
  "3:198": ["As for those who observe their Lord, they have deserved gardens with flowing streams; they abide therein forever. Such is the abode given to them by Allah. What Allah possesses is far better for the righteous.","আর তাদের জন্য যারা তাদের প্রভুকে মান্য করে,তারা প্রবাহিত ঝর্নাসহ বাগানসমূহের যোগ্য হয়েছে; তারা সেখানে চিরকাল বসবাস করে। এরকমই হচ্ছে তাদেরকে আল্লাহর দেয়া আবাস। যাকিছু আল্লাহর কাছে আছে তা সৎকর্মশীলদের জন্য অনেক উত্তম।"],
  "3:199": ["Surely, some followers of the previous scriptures do believe in Allah, and in what was revealed to you, and in what was revealed to them. They reverence Allah, and they never trade away Allah's revelations for a cheap price. These will receive their recompense from their Lord. Allah is the most efficient in reckoning.","নিশ্চিতভাবে,আগের ঐশীগ্রন্থসমূহের কিছু অনুসারীরা বিশ্বাস করে আল্লাহতে,এবং যা তোমার কাছে প্রকাশিত হয়েছিল, এবং যা তাদের কাছে প্রকাশিত হয়েছিল। তারা আল্লাহকে ভক্তি করে,এবং তারা কখনো আল্লাহর প্রত্যাদেশসমূহ সামান্য মূল্যে বিক্রি করে না। এরা তাদের প্রভুর কাছ থেকে প্রতিফল গ্রহণ করবে। আল্লাহ হিসাব গ্রহণে সবচেয়ে দক্ষ।"],
  "3:200": ["O you who believe, you shall be steadfast, you shall persevere, you shall be united, you shall observe Allah, that you may succeed.","হে তোমরা যারা বিশ্বাস কর, তোমরা অবিচল হবে,তোমরা অধ্যবসায়ী হবে,তোমরা ঐক্যবদ্ধ হবে,তোমরা আল্লাহকে মান্য করবে,যাতে তোমরা সফল হতে পার।"],
  "4:1": ["O people, observe your Lord; the One who created you from one being, and created from it its mate, then spread from the two many men and women. You shall regard Allah, by whom you swear, and regard the parents. Allah is watching over you.","হে লোকেরা,তোমাদের প্রভুকে মান্য কর; সেই একজন যিনি তোমাদেরকে এক ব্যক্তি  থেকে সৃষ্টি করেছিলেন, এবং এর থেকে এর সঙ্গিনী সৃষ্টি করেছিলেন, এরপর সেই দুইজন থেকে অনেক পুরুষ ও নারী বিস্তার করেছেন। তোমরা আল্লাহর প্রতি মনোযোগী হবে,যার নামে তোমরা শপথ কর, এবং পিতামাতাকে সন্মান কর। আল্লাহ তোমাদেরকে লক্ষ্য করছেন।"],
  "4:2": ["You shall hand over to the orphans their rightful properties. Do not substitute the bad for the good, and do not consume their properties by combining them with yours. This would be a gross injustice.","তোমরা এতিমদেরকে তাদের ন্যায্য সমত্তিসমুহ হস্তান্তর করবে। ভালটিকে মন্দ দিয়ে প্রতিস্থাপন করো না,এবং তাদের সম্পত্তিগুলো গ্রাস কর না,তাদের গুলোর সাথে তোমাদের গুলো মিশিয়ে। এটা হবে একটি ঘোর অন্যায়।"],
  "4:3": ["If you deem it best for the orphans, you may marry their mothers—you may marry two, three, or four. If you fear lest you become unfair, then you shall be content with only one, or with what you already have. Additionally, you are thus more likely to avoid financial hardship.","যদি তোমরা এটি এতিমদের জন্য সর্বোত্তম মনে কর, তোমরা তাদের মাদেরকে বিয়ে করতে পার - তোমরা বিয়ে করতে পার দুই, তিন অথবা চারটি। যদি তোমরা ভয় করো যে পাছে তোমরা পক্ষপাতদুষ্ট হয়ে পড়বে,তাহলে শুধু একটিতেই, অথবা আগে থেকে তোমাদের যা রয়েছে তা নিয়ে সন্তুষ্ট থাকবে। উপরন্তু,এভাবে  খুব সম্ভবত  তোমরা আর্থিক কষ্ট এড়াতে পার।"],
  "4:4": ["You shall give the women their due dowries, equitably. If they willingly forfeit anything, then you may accept it; it is rightfully yours.","তোমরা নারীদেরকে তাদের নির্ধারিত দেনমহর দিবে,ন্যায়সঙ্গতভাবে। যদি তারা স্বেচ্ছায় কোন কিছু ছেড়ে দেয়, তাহলে তোমরা তা গ্রহন করতে পার; এটি আইনসম্মতভাবে তোমাদের।"],
  "4:5": ["Do not give immature orphans the properties that Allah has entrusted with you as guardians. You shall provide for them therefrom, and clothe them, and treat them kindly.","অপরিনত এতিমদের সে সমত্তিসমুহ দিবে না যা আল্লাহ তোমাদের কাছে  অভিভাবক হিসেবে গচ্ছিত রেখেছেন। তোমরা সেখান থেকে তাদের ব্যয় বহন করবে,এবং তাদেরকে পরিধান করাবে,এবং তাদের সাথে সদাচরণ করবে।"],
  "4:6": ["You shall test the orphans when they reach puberty. As soon as you find them mature enough, give them their property. Do not consume it extravagantly in a hurry, before they grow up. The rich guardian shall not charge any wage, but the poor guardian may charge equitably. When you give them their properties, you shall have witnesses. Allah suffices as Reckoner.","তোমরা এতিমদেরকে পরীক্ষা করবে যখন তারা বয়ঃসন্ধিতে পৌঁছে। যখনি তোমরা তাদেরকে যথেষ্ট পরিণত পাবে,তাদেরকে তাদের সম্পত্তি দিয়ে দাও। তারা বড় হয়ে ওঠার আগে এগুলো তাড়াতাড়ি বেহিসাবিভাবে গ্রাস করে ফেলনা। ধনী অভিভাবক কোন পারিশ্রমিক গ্রহণ করবে না,কিন্তু দরিদ্র অভিভাবক ন্যায়সঙ্গত ভাবে গ্রহণ করতে পারে। যখন তোমরা তাদেরকে তাদের সম্পত্তি দাও, তোমরা সাক্ষী রাখবে। আল্লাহ হিসাব গ্রহণকারী হিসাবে যথেষ্ট।"],
  "4:7": ["The men get a share of what the parents and the relatives leave behind. The women too shall get a share of what the parents and relatives leave behind. Whether it is a small or a large inheritance, (the women must get) a definite share.","পিতামাতা এবং আত্মীয়রা যা রেখে যায় পুরুষরা তার একটি অংশ পায়। নারিরাও তার একটি অংশ পাবে,যা পিতামাতা এবং আত্মীয়রা রেখে যায়। হোক এটি একটি ছোট অথবা একটি বড় উত্তরাধিকার, (নারীরা অবশ্যই পাবে) একটি নির্দিষ্ট অংশ।"],
  "4:8": ["During distribution of the inheritances, if relatives, orphans, and needy persons are present, you shall give them therefrom, and treat them kindly.","উত্তরাধিকারের বণ্টনের সময়, যদি আত্মীয়, এতিম, এবং অভাবগ্রস্ত বাক্তিরা উপস্থিত থাকে,তোমরা তা থেকে তাদেরকে দেবে,এবং তাদের সাথে সদয় আচরণ করবে।"],
  "4:9": ["Those who are concerned about their own children, in case they leave them behind, shall observe Allah and be equitable.","যারা তাদের নিজেদের শিশু-সন্তানদের ব্যাপারে উদ্বিগ্ন, যে যদি তারা তাদেরকে পিছনে ছেড়ে যায়, তারা আল্লাহকে মান্য করবে এবং ন্যায়পরায়ণ হবে ।"],
  "4:10": ["Those who consume the orphans' properties unjustly, eat fire into their bellies, and will suffer in Hell.","যারা এতিমদের সম্পত্তি অন্যায়ভাবে গ্রাস করে,আগুন ভক্ষন করে তাদের পেটে,এবং কষ্টভোগ করবে নরকে।"],
  "4:11": ["Allah decrees a will for the benefit of your children; the male gets twice the share of the female. If the inheritors are only women, more than two, they get two-thirds of what is bequeathed. If only one daughter is left, she gets one-half. The parents of the deceased get one-sixth of the inheritance each, if the deceased has left any children. If he left no children, and his parents are the only inheritors, the mother gets one-third. If he has siblings, then the mother gets one-sixth. All this, after fulfilling any will the deceased has left, and after paying off all debts. When it comes to your parents and your children, you do not know which of them is really the best to you and the most beneficial. This is Allah's law. Allah is Omniscient, Most Wise.","আল্লাহ তোমাদের সন্তানদের সুবিধার জন্য একটি উইল জারি করেন; পুরুষরা নারীর অংশের দ্বিগুণ পায়। যদি উত্তরাধিকারীরা শুধু নারী হয়, দুইয়ের বেশি, তারা দুই-তৃতীয়াংশ পায় যা রেখে যাওয়া হয়। যদি শুধু এক কন্যা রেখে যায়, সে অর্ধেক পাবে। মৃত ব্যক্তির পিতা-মাতাদের প্রত্যেকে উত্তরাধিকারের এক-ষষ্ঠাংশ পাবে, যদি মৃত ব্যক্তি কোন সন্তানাদি রেখে যায়। যদি সে কোন সন্তানাদি রেখে না যায়, এবং তার পিতা-মাতাই শুধু উত্তরাধিকারী হয়, সেই মা এক-তৃতীয়াংশ পাবে। যদি তার ভাই-বোন থাকে, তাহলে মা এক-ষষ্ঠাংশ পাবে। এই সবকিছু, মৃত ব্যক্তির রেখে যাওয়া কোন উইল পরিপূর্ণ করার পর, এবং সকল ঋন পরিশোধ করার পর। যখন এটি তোমাদের পিতামাতা এবং সন্তানদের ক্ষেত্রে হয়, তোমরা জানো না তাদের কারা প্রকৃতপক্ষে তোমাদের কাছে সর্বোত্তম এবং সবচেয়ে উপকারী। এটি আল্লাহর আইন। আল্লাহ সর্বজ্ঞ, পরম জ্ঞানী।"],
  "4:12": ["You get half of what your wives leave behind, if they had no children. If they had children, you get one-fourth of what they leave. All this, after fulfilling any will they had left, and after paying off all debts. They get one-fourth of what you leave behind, if you had no children. If you had children, they get one-eighth of what you bequeath. All this, after fulfilling any will you had left, and after paying off all debts. If the deceased man or woman was a loner, and leaves two siblings, male or female, each of them gets one-sixth of the inheritance. If there are more siblings, then they equally share one-third of the inheritance. All this, after fulfilling any will, and after paying off all debts, so that no one is hurt. This is a will decreed by Allah. Allah is Omniscient, Clement.","তোমরা অর্ধেক পাও যা তোমাদের স্ত্রীরা ফেলে যায়, যদি তাদের কোন সন্তানাদি না থাকে। যদি তাদের সন্তানাদি থাকে,তোমরা এক-চতুর্থাংশ পাও যা তারা ফেলে যায়। এই সবকিছু,তাদের রেখে যাওয়া কোন উইল পরিপূর্ণ করার পর, এবং সকল ঋন পরিশোধ করার পর। তারা এক-চতুর্থাংশ পায় যা তোমরা ফেলে যাও, যদি তোমাদের সন্তানাদি না থাকে। যদি তোমাদের সন্তানাদি থাকে,তারা এক-অষ্টমাংশ পায় যা তোমরা রেখে যাও। এই সবকিছু,তোমাদের রেখে যাওয়া কোন উইল পরিপূর্ণ করার পর, এবং সকল ঋন পরিশোধ করার পর। যদি মৃত পুরুষ অথবা নারী নিঃসঙ্গ হয়, এবং দুইজন ভাই বা বোন রেখে যায়, পুরুষ অথবা নারী,তারা প্রত্যেকেই উত্তরাধিকারের এক-ষষ্ঠাংশ পায়। যদি আরো ভাই-বোন থাকে,তখন তারা সমভাবে উত্তরাধিকারের এক-তৃতীয়াংশ ভাগ করে নেয়। এই সবকিছু,কোন উইল পরিপূর্ণ করার পর, এবং সকল ঋন পরিশোধ করার পর, যাতে কেউই আঘাতপ্রাপ্ত না হয়। এটি আল্লাহর দ্বারা জারীকৃত একটি উইল। আল্লাহ সর্বজ্ঞ, সহিষূ।"],
  "4:13": ["These are Allah's laws. Those who obey Allah and His messenger, He will admit them into gardens with flowing streams, wherein they abide forever. This is the greatest triumph.","এগুলো আল্লাহর আইন। তারা যারা আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করে,তিনি তাদেরকে প্রবেশ করাবেন প্রবাহিত ঝর্নাধারা সহ বাগানসমূহে,যেখানে তারা চিরকাল বসবাস করে। এটি শ্রেষ্ঠ বিজয়।"],
  "4:14": ["As for the one who disobeys Allah and His messenger, and transgresses His laws, He will admit him into Hell, wherein he abides forever. He has incurred a shameful retribution.","আর সে ব্যক্তির জন্য যে আল্লাহ এবং তাঁর বার্তাবাহককে অমান্য করে,এবং তাঁর আইনগুলোর সীমালঙ্ঘন করে,তিনি তাকে নরকে প্রবেশ করাবেন, যেখানে সে চিরকাল বসবাস করে। সে এক লজ্জাকর প্রতিফল টেনে এনেছে।"],
  "4:15": ["Those who commit adultery among your women, you must have four witnesses against them, from among you. If they do bear witness, then you shall keep such women in their homes until they die, or until Allah creates an exit for them.","তোমাদের নারীদের মধ্যে তারা যারা ব্যভিচার করে,তোমাদের কাছে অবশ্যই তোমাদের মধ্য থেকে তাদের বিরুদ্ধে চারজন সাক্ষী থাকতে হবে। যদি তারা সাক্ষ্য প্রদান করে,তাহলে তোমরা এরকম নারীদের তাদের বাড়িতে রাখবে যতক্ষণ না পর্যন্ত তারা মারা যায়, অথবা যতক্ষণ না আল্লাহ তাদের জন্য বের হবার পথ সৃষ্টি করে দেন।"],
  "4:16": ["The couple who commits adultery shall be punished. If they repent and reform, you shall leave them alone. Allah is Redeemer, Most Merciful.","সেই যুগল শাস্তিপ্রাপ্ত হবে যারা ব্যাভিচারে লিপ্ত হয়। যদি তারা অনুতপ্ত হয় এবং সংশোধিত হয়, তোমরা তাদেরকে একা ছেড়ে দেবে। আল্লাহ উদ্ধার কর্তা,পরম দয়ালু।"],
  "4:17": ["Repentance is acceptable by Allah from those who fall in sin out of ignorance, then repent immediately thereafter. Allah redeems them. Allah is Omniscient, Most Wise.","অনুতাপ আল্লাহর দ্বারা গ্রহণযোগ্য তাদের কাছ থেকে যারা অজ্ঞতা থেকে পাপে পতিত হয়, সেক্ষেত্রে এরপর তৎক্ষণাৎ অনুতাপ করে। আল্লাহ তাদের উদ্ধার করেন। আল্লাহ সর্বজ্ঞ, পরম জ্ঞানী।"],
  "4:18": ["Not acceptable is the repentance of those who commit sins until death comes to them, then say, \"Now I repent.\" Nor is it acceptable from those who die as disbelievers. For these, we have prepared a painful retribution.","তাদের অনুশোচনা গ্রহণযোগ্য নয় যারা পাপ করে যতক্ষণ না মৃত্যু তাদের কাছে আসে,তখন বলে,“আমি এখন অনুশোচনা করি”। না এটা গ্রহণযোগ্য তাদের থেকে,যারা অবিশ্বাসী হিসাবে মৃত্যু বরণ করে। এদের জন্য, আমরা এক যন্ত্রণাদায়ক শাস্তি প্রস্তুত করেছি।"],
  "4:19": ["O you who believe, it is not lawful for you to inherit what the women leave behind, against their will. You shall not force them to give up anything you had given them, unless they commit a proven adultery. You shall treat them nicely. If you dislike them, you may dislike something wherein Allah has placed a lot of good.","হে তোমরা যারা বিশ্বাস করো,এটা তোমাদের জন্য আইনসিদ্ধ নয যা নারীরা ছেড়ে যায় তা উত্তরাধিকার করা,তাদের উইলের বিরুদ্ধে। তোমরা তাদেরকে কোন কিছু ছেড়ে দিতে বল প্রয়োগ করবে না /  বল প্রয়োগ করবে না কোন কিছু পরিত্যাগ করতে যা তোমরা তাদেরকে দিয়েছিলে,যদি না তারা একটি প্রমানিত ব্যাভিচার করে। তোমরা তাদের সাথে সুন্দর আচরন করবে। যদি তোমরা তাদেরকে অপছন্দ করো,হয়তো তোমরা কোনকিছুকে অপছন্দ করো যার মধ্যে আল্লাহ অনেক ভাল রেখেছেন।"],
  "4:20": ["If you wish to marry another wife, in place of your present wife, and you had given any of them a great deal, you shall not take back anything you had given her. Would you take it fraudulently, maliciously, and sinfully?","যদি তোমরা অন্য স্ত্রীকে বিয়ে করতে চাও, তোমাদের বর্তমান স্ত্রীর স্থলে,এবং তোমরা তাদের কাউকে প্রচুর দিয়ে থাকো,তোমরা কোনকিছুই ফেরত নেবে না যা তোমরা দিয়েছ। তোমরা কি তা প্রতারণাপূর্ণ ভাবে,বিদ্বেষপরায়ণ ভাবে,এবং পাপপূর্ণ ভাবে নেবে?"],
  "4:21": ["How could you take it back, after you have been intimate with each other, and they had taken from you a solemn pledge?","তোমরা কিভাবে তা ফেরত নিতে পার, যখন তোমরা একে-অন্যের ঘনিষ্ঠ হয়েছ, এবং তারা তোমাদের থেকে একটি সুদৃড় প্রতিজ্ঞা নিয়েছিল?"],
  "4:22": ["Do not marry the women who were previously married to your fathers—existing marriages are exempted and shall not be broken—for it is a gross offense, and an abominable act.","সেই নারীকে বিয়ে কর না,যারা আগে তোমাদের পিতাদের সহিত বিবাহিত ছিল- বিদ্যমান বিবাহসমূহ নিষ্কৃতি প্রাপ্ত এবং ভঙ্গ করবে না- কারণ এটি একটি গুরুতর অপরাধ, এবং ঘৃণ্য কাজ।"],
  "4:23": ["Prohibited for you (in marriage) are your mothers, your daughters, your sisters, the sisters of your fathers, the sisters of your mothers, the daughters of your brother, the daughters of your sister, your nursing mothers, the girls who nursed from the same woman as you, the mothers of your wives, the daughters of your wives with whom you have consummated the marriage—if the marriage has not been consummated, you may marry the daughter. Also prohibited for you are the women who were married to your genetic sons. Also, you shall not be married to two sisters at the same time—but do not break up existing marriages. Allah is Forgiver, Most Merciful.","তোমাদের জন্য নিষিদ্ধ (বিয়ের করার ক্ষেত্রে) তোমাদের মায়েরা,তোমাদের কন্যারা,তোমাদের বোনেরা,তোমাদের পিতাদের বোনেরা,তোমাদের মাতাদের বোনেরা,তোমাদের ভাইয়ের কন্যারা,তোমাদের বোনের কন্যারা,তোমাদের স্তন্য দানকারী মায়েরা,সে বালিকারা যারা স্তন্যপ্রাপ্ত হয়েছিল সে একই নারী থেকে যেমন তোমরা হয়েছিলে,তোমাদের স্ত্রীদের মায়েরা,তোমাদের স্ত্রীদের কন্যারা যাদের সাথে তোমরা বিয়ে পূর্ন করেছ - যদি বিয়ে পূর্নতাপ্রাপ্ত না হয়, তোমরা সে কন্যাকে বিয়ে করতে পার। তোমাদের জন্য আরো নিষিদ্ধ সে নারীরা যারা তোমাদের ঔরসজাত পুত্রদের বিবাহিত ছিল। এছাড়া,তোমরা একই সময়ে দুই বোনের সাথে বিবাহিত  থাকবে না- কিন্তু বিদ্যমান বিয়ে ভেঙো না। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "4:24": ["Also prohibited are the women who are already married, unless they flee their disbelieving husbands who are at war with you. These are Allah's commandments to you. All other categories are permitted for you in marriage, so long as you pay them their due dowries. You shall maintain your morality, by not committing adultery. Thus, whoever you like among them, you shall pay them the dowry decreed for them. You commit no error by mutually agreeing to any adjustments to the dowry. Allah is Omniscient, Most Wise.","আরো নিষিদ্ধ সে নারীরা যারা ইতোমধ্যে বিবাহিত, যদি না তারা তাদের অবিশ্বাসী স্বামীদের কাছ থেকে পালিয়ে আসে যারা তোমাদের সাথে যুদ্ধরত। এগুলো তোমাদের কাছে আল্লাহর প্রত্যাদেশ। অন্য সকল শ্রেনীসমূহ বিয়ে করার ক্ষেত্রে তোমাদের জন্য অনুমোদিত, যে পর্যন্ত তোমরা তাদেরকে তাদের ন্যায্য মোহরানা দাও। তোমরা তোমাদের নৈতিকতা বজায় রাখবে,ব্যভিচার না করে। এভাবে,তাদের মধ্যে যে কাউকে তোমরা পছন্দ কর, তোমরা তাদেরকে তাদের জন্য জারিকৃত মোহরানা পরিশোধ করবে। তোমরা কোন ভুল কর না পারস্পরিক সমঝোতার দ্বারা মোহরানার যেকোন নির্ধারণে। আল্লাহ সর্বজ্ঞ, পরম জ্ঞানী।"],
  "4:25": ["Those among you who cannot afford to marry free believing women, may marry believing slave women. Allah knows best about your belief, and you are equal to one another, as far as belief is concerned. You shall obtain permission from their guardians before you marry them, and pay them their due dowry equitably. They shall maintain moral behavior, by not committing adultery, or having secret lovers. Once they are freed through marriage, if they commit adultery, their punishment shall be half of that for the free women. Marrying a slave shall be a last resort for those unable to wait. To be patient is better for you. Allah is Forgiver, Most Merciful.","তোমাদের মধ্যে যাদের স্বাধীন বিশ্বাসী নারীদেরকে বিয়ে করার সামর্থ্য নেই, তারা বিশ্বাসী দাসী নারীদের বিয়ে করতে পারে। তোমাদের বিশ্বাস সম্পর্কে আল্লাহ সবচেয়ে ভাল জানেন, এবং তোমরা একে-অন্যের সমান, বিশ্বাস যতদূর সম্পর্কিত। তোমারা তাদের বিয়ে করার আগে তাদের অভিভাবকদের কাছ থেকে অনুমতি নিবে,এবং তোমরা ন্যায়সঙ্গতভাবে তাদের ন্যায্য মোহরানা পরিশোধ করবে। তারা নৈতিক আচরণ বজায় রাখবে,ব্যভিচার না করে,অথবা গোপন প্রেমিকদের না রেখে। একবার তারা বিয়ের মাধ্যমে মুক্ত হবার পর, যদি তারা ব্যভিচার করে,তাদের শাস্তি হবে স্বাধীন নারীদের অর্ধেক। দাসী বিয়ে করা হবে তাদের জন্য একটি শেষ অবলম্বন, যারা অপেক্ষা করতে অসমর্থ। ধৈর্যশীল হওয়া তোমাদের জন্য উত্তম। আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "4:26": ["Allah wills to explain things for you, and to guide you through past precedents, and to redeem you. Allah is Omniscient, Most Wise.","আল্লাহ ইচ্ছা করেন তোমাদের জন্য বিষয় সমূহ ব্যাখ্যা করতে,এবং তোমাদের অতীত উদাহরণের সাহায্যে পথ প্রদর্শিত করতে,এবং তোমাদের উদ্ধার করতে। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "4:27": ["Allah wishes to redeem you, while those who pursue their lusts wish that you deviate a great deviation.","আল্লাহ তোমাদের উদ্ধার করতে চান, যখন যারা তাদের লালসার অনুসরণ করে তারা চায় যে,তোমরা বিপথগামী হও এক মহা পথভ্রষ্টতায়।"],
  "4:28": ["Allah wishes to lighten your burden, for the human being is created weak.","আল্লাহ তোমাদের বোঝা হালকা করতে চান, কারন মানুষ সৃষ্টিগতভাবে দুর্বল ।"],
  "4:29": ["O you who believe, do not consume each others' properties illicitly— only mutually acceptable transactions are permitted. You shall not kill yourselves. Allah is Merciful towards you.","হে তোমরা যারা বিশ্বাস করো,একে অন্যের সম্পত্তি অন্যায়ভাবে গ্রাস করো না- শুধুমাত্র পরস্পর গ্রহণযোগ্য লেনদেন অনুমোদিত। তোমরা নিজেদেরকে হত্যা করবে না। আল্লাহ তোমাদের প্রতি দয়াময়।"],
  "4:30": ["Anyone who commits these transgressions, maliciously and deliberately, we will condemn him to Hell. This is easy for Allah to do.","যে কেউ এই সীমালঙ্ঘনগুলো করে,বিদ্বেষপরায়ণভাবে এবং ইচ্ছাকৃত ভাবে,আমরা তাকে নরকের শাস্তি দেব। এটা করা আল্লাহর জন্য সহজ।"],
  "4:31": ["If you refrain from committing the gross sins that are prohibited for you, we will remit your sins, and admit you an honorable admittance.","যদি তোমরা গুরুতর পাপগুলো করা থেকে বিরত থাক যা তোমাদের জন্য নিষিদ্ধ, আমরা তোমাদের পাপসমূহ ক্ষমা করে দিব, এবং তোমাদের প্রবেশ করাব, এক সম্মানিত প্রবেশ।"],
  "4:32": ["You shall not covet the qualities bestowed upon each other by Allah; the men enjoy certain qualities, and the women enjoy certain qualities. You may implore Allah to shower you with His grace. Allah is fully aware of all things.","তোমরা একে-অন্যের উপর আল্লাহ দ্বারা অর্পণ করা গুনাবলির লোভ করবে না; পুরুষরা নির্দিষ্ট গুনাবলি উপভোগ করে,এবং নারীরা নির্দিষ্ট গুনাবলি উপভোগ করে। তোমরা আল্লাহর কাছে মিনতি করতে পার তোমাদেরকে তাঁর অনুগ্রহ বর্ষন করতে। আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "4:33": ["For each of you, we have designated shares from the inheritance left by the parents and the relatives. Also those related to you through marriage, you shall give them their due share. Allah witnesses all things.","তোমাদের প্রত্যেকের জন্য, আমরা নির্ধারিত করেছি,মাতা -পিতা এবং আত্মীয়দের রেখে যাওয়া উত্তরাধিকার থেকে অংশ। আরো যারা বিবাহের মাধ্যমে তোমাদের সাথে সম্পর্কিত, তোমরা তাদেরকে তাদের ন্যায্য অংশ দিবে। আল্লাহ সবকিছু প্রত্যক্ষ করছেন।"],
  "4:34": ["The men are made responsible for the women, and Allah has endowed them with certain qualities, and made them the bread earners. The righteous women will cheerfully accept this arrangement, since it is Allah's commandment, and honor their husbands during their absence. If you experience rebellion from the women, you shall first talk to them, then (you may use negative incentives like) deserting them in bed, then you may (as a last alternative) beat them. If they obey you, you are not permitted to transgress against them. Allah is Most High, Supreme.","পুরুষদের দায়িত্বপূর্ন করা হয়েছে নারীদের জন্য,এবং আল্লাহ তাদের উপর নির্দিষ্ট গুনাবলি আরোপিত করেছেন, এবং তাদেরকে করেছেন রুটি রোজগারকারী। সৎকর্মশীল নারীরা আনন্দের সাথে এই বিন্যাস গ্রহণ করে,যেহেতু এটি আল্লাহর প্রত্যাদেশ, এবং তাদের স্বামীদের সম্মান করে তাদের অনুপস্থিতিতে। যদি তোমরা নারীদের থেকে বিদ্রোহ প্রত্যক্ষ কর, প্রথমে তাদের সাথে কথা বলবে,তারপর (তোমরা ব্যবহার করতে পার নেতিবাচক উদ্দীপক যেমন) বিছানায় তাদের পরিত্যাগ করা,এরপর তোমরা (শেষ বিকল্প হিসেবে) তাদের প্রহার করতে পার। যদি তারা তোমাদের মান্য করে,তোমরা তাদের বিরুদ্ধে সীমালঙ্ঘন করতে অনুমোদিত নও। আল্লাহ সবচেয়ে উচু,সর্বোচ্চ।"],
  "4:35": ["If a couple fears separation, you shall appoint an arbitrator from his family and an arbitrator from her family; if they decide to reconcile, Allah will help them get together. Allah is Omniscient, Cognizant.","যদি একটি দম্পতি বিচ্ছেদের ভয় করে,তোমরা একজন মধ্যস্থতাকারী নিযুক্ত করবে ছেলের পরিবার থেকে এবং একজন মধ্যস্থতাকারী মেয়ের পরিবার থেকে; যদি তারা পূন:র্মিলিত হতে সিদ্ধান্ত নেয়, আল্লাহ তাদেরকে একত্রিত হতে সাহায্য করবেন। আল্লাহ সর্বজ্ঞ, জ্ঞাত।"],
  "4:36": ["You shall worship Allah alone—do not associate anything with Him. You shall regard the parents, the relatives, the orphans, the poor, the related neighbor, the unrelated neighbor, the close associate, the traveling alien, and your servants. Allah does not like the arrogant show-offs.","তোমরা একমাত্র আল্লাহর উপাসনা করবে-কোনকিছুকে তাঁর সাথে যুক্ত করো না। তোমরা পিতামাতা,আত্মীয়, এতিম, দরিদ্র, সম্পর্কযুক্ত প্রতিবেশী,সম্পর্কহীন প্রতিবেশী,ঘনিষ্ঠ সহযোগী,ভ্রমণকারী বিদেশী,এবং তোমাদের ভৃত্যদের প্রতি দৃষ্টি দিবে। আল্লাহ অহংকারী প্রদর্শন পছন্দ করে না।"],
  "4:37": ["The ones who are stingy, exhort the people to be stingy, and conceal what Allah has bestowed upon them from His bounties. We have prepared for the disbelievers a shameful retribution.","সেই ব্যক্তি যে কৃপণ, লোকদের পরামর্শ দেয় কৃপণ হবার, এবং গোপন করে যা আল্লাহ তাদের উপর অর্পণ করেছেন তাঁর দানশীলতা থেকে। আমরা অবিশ্বাসীদের জন্য প্রস্তুত করেছি একটি লজ্জাজনক শাস্তি।"],
  "4:38": ["They give money to charity only to show off, while disbelieving in Allah and the Last Day. If one's companion is the devil, that is the worst companion.","তারা শুধুমাত্র দেখানোর জন্য অর্থ দান করে,যখন আল্লাহ এবং শেষ দিবসে অবিশ্বাসী। যদি কারো সঙ্গী হয় শয়তান, সেই সবচেয়ে মন্দ সঙ্গী।"],
  "4:39": ["Why do they not believe in Allah and the Last Day, and give from Allah's provisions to them? Allah is fully aware of them.","কেন তারা আল্লাহ এবং শেষ দিনে বিশ্বাস করে না,এবং তাদেরকে আল্লাহর দেওয়া  জীবিকা থেকে দেয় না? আল্লাহ তাদের সম্পর্কে সম্পূর্ণ অবগত।"],
  "4:40": ["Allah does not inflict an atom's weight of injustice. On the contrary, He multiplies the reward manifold for the righteous work, and grants from Him a great recompense.","আল্লাহ একটি পরমানুর ভরের অবিচার আরোপ করেন না। পক্ষান্তরে,তিনি সৎ  কর্মের জন্য পুরুস্কার বহুগুনে বাড়িয়ে দেন, এবং তাঁর কাছ থেকে মহান প্রতিদান প্রদান করেন।"],
  "4:41": ["Thus, when the day (of judgment) comes, we will call upon a witness from each community, and you (the messenger) will serve as a witness among these people.","এভাবে,যখন (বিচারের) সে দিন আসবে,আমরা প্রত্যেক সম্প্রদায় থেকে একজন সাক্ষীকে ডাকব, এবং  তুমি (রাসূল) এইসব লোকদের মাঝে একজন সাক্ষী হিসেবে দায়িত্ব পালন করবে।"],
  "4:42": ["On that day, those who disbelieved and disobeyed the messenger will wish that they were level with the ground; not a single utterance will they be able to hide from Allah.","সেই দিন, যারা রাসূলকে অবিশ্বাস করেছিল এবং অমান্য করেছিল তারা ইচ্ছা করবে যে,যদি তারা ভূমির সাথে মিলিয়ে  যেত; না তারা আল্লাহ থেকে একটি কথাও লুকাতে সক্ষম হবে।"],
  "4:43": ["O you who believe, do not observe the Contact Prayers (Salat) while intoxicated, so that you know what you are saying. Nor after sexual orgasm without bathing, unless you are on the road, traveling; if you are ill or traveling, or you had urinary or fecal-related excretion (such as gas), or contacted the women (sexually), and you cannot find water, you shall observe Tayammum (dry ablution) by touching clean dry soil, then wiping your faces and hands therewith. Allah is Pardoner, Forgiver.","হে তোমরা যারা বিশ্বাস কর, মাতাল অবস্থায় সংযোগ প্রার্থনাসমূহ (সালাত) পালন করো না,যাতে তোমরা জান যে,তোমরা কি বলছ। না প্রচন্ড যৌন উত্তেজনার পর গোসল ছাড়া,যদি না তোমরা রাস্তায় থাক, ভ্রমনরত; যদি তোমরা অসুস্থ অথবা ভ্রমনরত থাক, অথবা তোমাদের মূত্র - সংক্রান্ত অথবা মল-সংক্রান্ত নিঃসরন থাকে (যেমন বাতাস),অথবা নারীদের সংস্পর্শে এসে থাক (যৌণ বিচারে),এবং তোমরা পানি খুঁজে না পাও, তোমরা তায়মুম (শুষ্ক ওজু) পালন করবে পরিষ্কার শুকনো মাটি স্পর্শ করে,এরপর তোমাদের মুখ এবং হাতগুলো তা দিয়ে মুছে। আল্লাহ ক্ষমাকারী,মার্জনাকারী।"],
  "4:44": ["Have you noted those who received a portion of the scripture, and how they choose to stray, and wish that you stray from the path?","তুমি কি তাদেরকে লক্ষ্য করেছ, যারা ঐশীগ্রন্থের একটি অংশ গ্রহণ করেছিল, এবং কিভাবে তারা পথভ্রষ্ট হতে পছন্দ করে,এবং চায় যে,তোমরা পথভ্রষ্ট হও?"],
  "4:45": ["Allah knows best who your enemies are. Allah is the only Lord and Master. Allah is the only Supporter.","আল্লাহ সবচেয়ে ভাল জানেন, কারা তোমাদের শত্রু। আল্লাহই একমাত্র প্রভু এবং মনিব। আল্লাহই একমাত্র সমর্থনকারী।"],
  "4:46": ["Among those who are Jewish, some distort the words beyond the truth, and they say, \"We hear, but we disobey,\" and \"Your words are falling on deaf ears,\" and \"Raa'ena (be our shepherd),\" as they twist their tongues to mock the religion. Had they said, \"We hear, and we obey,\" and \"We hear you,\" and \"Unzurna (watch over us),\" it would have been better for them, and more righteous. Instead, they have incurred condemnation from Allah due to their disbelief. Consequently, the majority of them cannot believe.","তাদের মধ্যে যারা ইহুদী,তাদের কেউ কেউ বানীকে সত্য ছাড়িয়ে বিকৃত করে,এবং তারা বলে,“আমরা শুনি,কিন্তু আমরা অমান্য করি”,এবং “তোমার কথা বধির কানে পতিত হচ্ছে,”এবং “রা'য়েনা (আমাদের রাখাল হও)”,যেভাবে তারা তাদের জিহ্বা আওড়ায় ধর্মকে উপহাস করতে। যদি তারা বলত, “আমরা শুনি,এবং আমরা মান্য করি,”এবং “আমরা তোমায় শুনি,”এবং “উনজুরনা (আমাদের প্রতি নজর রাখো),”এটা তাদের জন্য মঙ্গল, এবং অধিক ন্যায়নিষ্ঠ হতো। পরিবর্তে,তারা তাদের অবিশ্বাসের কারনে আল্লাহর থেকে দণ্ডাদেশ টেনে এনেছে। ফলস্বরূপ, তাদের অধিকাংশই বিশ্বাস করতে পারে না।"],
  "4:47": ["O you who received the scripture, you shall believe in what we reveal herein, confirming what you have, before we banish certain faces to exile, or condemn them as we condemned those who desecrated the Sabbath. Allah's command is done.","হে তোমরা যারা ঐশীগ্রন্থ গ্রহণ করেছ, তোমরা বিশ্বাস করবে যা আমরা এখানে প্রকাশ করেছি, যা নিশ্চিত করে তোমাদের যা আছে,আমরা নির্দিষ্ট  মুখগুলো নির্বাসনে বিতাড়িত করার আগে, অথবা তাদের শাস্তি দেয়ার আগে যেমন আমরা শাস্তি দিয়েছিলাম তাদেরকে যারা বিশ্রামের দিনকে অপবিত্র করেছিল। আল্লাহর হুকুম হয়ে গেছে।"],
  "4:48": ["Allah does not forgive idolatry, but He forgives lesser offenses for whomever He wills. Anyone who sets up idols beside Allah, has forged a horrendous offense.","আল্লাহ অংশীদার সাব্যস্ত করাকে ক্ষমা করেন না,কিন্তু তিনি ক্ষমা করেন অপেক্ষাকৃত ছোট অপরাধ, যার জন্য তিনি ইচ্ছা করেন। যে কেউ আল্লাহর পাশে অংশীদার স্থাপন করে,গড়েছে এক ভয়ানক অপরাধ।"],
  "4:49": ["Have you noted those who exalt themselves? Instead, Allah is the One who exalts whomever He wills, without the least injustice.","তুমি কি তাদেরকে লক্ষ্য করেছ যারা তাদের নিজেদের প্রশংসা করে? পরিবর্তে,আল্লাহ সেই একজন যিনি প্রশংসিত করেন যাকে তিনি ইচ্ছা করেন, সামান্যতম অবিচার ছাড়াই।"],
  "4:50": ["Note how they fabricate lies about Allah; what a gross offense this is!","লক্ষ্য করো,কিভাবে তারা আল্লাহ সম্পর্কে মিথ্যা উদ্ভাবন করে,কি এক মহা অপরাধ এটা!"],
  "4:51": ["Have you noted those who received a portion of the scripture, and how they believe in idolatry and false doctrine, then say, \"The disbelievers are better guided than the believers\"?!","তুমি কি তাদেরকে লক্ষ্য করেছ, যারা ঐশীগ্রন্থের একটি অংশ গ্রহণ করেছিল, এবং কিভাবে তারা শিরকীত্বে এবং মিথ্যা মতবাদে বিশ্বাস করে,এরপর বলে,“অবিশ্বাসীরা বিশ্বাসীদের চেয়ে উত্তম পথপ্রাপ্ত\"?!"],
  "4:52": ["It is they who incurred Allah's condemnation, and whomever Allah condemns, you will not find any helper for him.","এরা তারাই যারা আল্লাহর দন্ডাদেশ টেনে এনেছে,এবং যাকে আল্লাহ দন্ডাদেশ দেন, তুমি তার জন্য কোন সাহায্যকারী পাবে না।"],
  "4:53": ["Do they own a share of the sovereignty? If they did, they would not give the people as much as a grain.","তারা কি সার্বভৌমত্বের একটি অংশ অধিকার করেছে? যদি তারা করত, তারা লোকদের একটি শস্যকণা পরিমাণও দিত না।"],
  "4:54": ["Are they envious of the people because Allah has showered them with His blessings? We have given Abraham's family the scripture, and wisdom; we granted them a great authority.","তারা কি সেই লোকদের প্রতি হিংসাপরায়ন, কারণ আল্লাহ তাদেরকে তাঁর অনুগ্রহসমূহ বর্ষন করেছেন? আমরা ইব্রাহিমের পরিবারকে দিয়েছি ঐশীগ্রন্থ, এবং প্রজ্ঞা; আমরা তাদেরকে দান করেছিলাম এক মহান কর্তৃত্ব।"],
  "4:55": ["Some of them believed therein, and some of them repelled therefrom; Hell is the only just retribution for these.","তাদের কেউ কেউ তাতে বিশ্বাস করেছিল, এবং তাদের কেউ কেউ তা থেকে মুখ ফিরিয়ে নিয়েছিল; এইসবের জন্য একমাত্র নরকই যথার্থ শাস্তি।"],
  "4:56": ["Surely, those who disbelieve in our revelations, we will condemn them to the hellfire. Whenever their skins are burnt, we will give them new skins. Thus, they will suffer continuously. Allah is Almighty, Most Wise.","নিশ্চিতরূপে,তারা যারা আমাদের প্রকাশনাসমূহকে অবিশ্বাস করে,আমরা তাদের নরকাগ্নির শাস্তি দেব। যখনই তাদের চামড়া পুড়ে যায়, আমরা তাদেরকে নতুন চামড়া দেব। এভাবে,তারা অবিরত কষ্ট ভোগ করবে। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "4:57": ["As for those who believe and lead a righteous life, we will admit them into gardens with flowing streams; they abide therein forever. They will have pure spouses therein. We will admit them into a blissful shade.","তাদের বিষয়ে যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,আমরা তাদেরকে প্রবাহিত ঝর্নাধারা সহ বাগানসমূহে প্রবেশ করাব, তারা চিরকাল সেখানে বাস করে। সেখানে তাদের বিশুদ্ধ সহধর্মী/সহধর্মীনি থাকবে। আমরা তাদেরকে প্রবেশ করাব একটি স্বর্গীয় ছায়ায়।"],
  "4:58": ["Allah commands you to give back anything the people have entrusted to you. If you judge among the people, you shall judge equitably. The best enlightenment indeed is what Allah recommends for you. Allah is Hearer, Seer.","আল্লাহ তোমাদের হুকুম দেন ফিরিয়ে দিতে যাকিছু লোকেরা তোমাদের কাছে গচ্ছিত রাখে। যদি তোমরা মানুষের মাঝে বিচার করো,তোমরা ন্যায়ভাবে বিচার করবে। প্রকৃতপক্ষে,সর্বোত্তম জ্ঞানালোক হলো যা আল্লাহ তোমাদের জন্য পরামর্শ দেন। আল্লাহ শ্রবণকারী,দর্শনকারী।"],
  "4:59": ["O you who believe, you shall obey Allah, and you shall obey the messenger, and those in charge among you. If you dispute in any matter, you shall refer it to Allah and the messenger, if you do believe in Allah and the Last Day. This is better for you, and provides you with the best solution.","হে তোমরা যারা বিশ্বাস করো,তোমরা আল্লাহকে মান্য করবে,এবং তোমরা মান্য করবে বার্তাবাহককে  এবং তোমাদের মধ্যে যারা দায়িত্বপ্রাপ্ত। যদি তোমরা কোন বিষয়ে বিবাদ করো,তোমরা তা আল্লাহ এবং বার্তাবাহকের প্রতি ন্যস্ত করবে,যদি তোমরা আল্লাহ এবং শেষ দিবসে বিশ্বাস করো। এটা তোমাদের জন্য উত্তম, এবং তোমাদেরকে সর্বোত্তম সমাধান দেয়।"],
  "4:60": ["Have you noted those who claim that they believe in what was revealed to you, and in what was revealed before you, then uphold the unjust laws of their idols? They were commanded to reject such laws. Indeed, it is the devil's wish to lead them far astray.","তুমি কি তাদের লক্ষ্য করেছ, যারা দাবী করে যে,তারা বিশ্বাস করে যা তোমার প্রতি প্রকাশিত হয়েছিল, এবং যা প্রকাশিত হয়েছিল তোমার পূর্বে,তারপর তাদের উপাস্যদের অন্যায্য আইন মেনে চলে? তারা এরূপ আইন প্রত্যাখ্যান করতে আদেশপ্রাপ্ত হয়েছিল। প্রকৃতপক্ষে,এটাই শয়তানের ইচ্ছা,তাদেরকে সুদূরে পথভ্রষ্ট করা।"],
  "4:61": ["When they are told, \"Come to what Allah has revealed, and to the messenger,\" you see the hypocrites shunning you completely.","যখন তাদেরকে বলা হয়েছিল, \"আস সে দিকে যা আল্লাহ প্রকাশ করেছেন, এবং বার্তাবাহকের দিকে,“তুমি দেখ যে ভন্ডরা তোমাকে সম্পূর্ণরূপে পরিত্যাগ করছে।"],
  "4:62": ["How will it be when a disaster hits them, as a consequence of their own works? They will come to you then and swear by Allah: \"Our intentions were good and righteous!\"","এটি কেমন হবে যখন একটি বিপর্যয় তাদেরকে আঘাত করে,তাদের স্বীয় কর্মসমূহের একটি প্রতিফল হিসেবে? তারা এরপরে তোমার কাছে আসবে এবং আল্লাহর নামে শপথ করবে : \"আমাদের উদ্দেশ্য ভাল এবং ন্যায়নিষ্ঠ ছিল! \""],
  "4:63": ["Allah is fully aware of their innermost intentions. You shall ignore them, enlighten them, and give them good advice that may save their souls.","আল্লাহ তাদের গভীরতম  উদ্দেশ্যসমূহ সম্পর্কে সম্পূর্ণ অবগত। তুমি তাদেরকে উপেক্ষা করবে,তাদেরকে আলোকিত করবে,এবং তাদেরকে ভাল উপদেশ দিবে,হয়ত তা তাদের আত্মাকে রক্ষা করবে।"],
  "4:64": ["We did not send any messenger except to be obeyed in accordance with Allah's will. Had they, when they wronged their souls, come to you and prayed to Allah for forgiveness, and the messenger prayed for their forgiveness, they would have found Allah Redeemer, Most Merciful.","আমরা কোন বার্তাবাহককে আল্লাহর ইচ্ছা মান্য করা ব্যতীত পাঠাইনি। যদি তারা,তাদের আত্মার প্রতি অন্যায় করার সময়, তোমার কাছে আসতো এবং আল্লাহর কাছে ক্ষমার জন্য প্রার্থনা করত, এবং বার্তাবাহক তাদের ক্ষমার জন্য প্রার্থনা করত, তারা আল্লাহকে পেতো উদ্ধারকারী,পরম দয়ালু।"],
  "4:65": ["Never indeed, by your Lord; they are not believers unless they come to you to judge in their disputes, then find no hesitation in their hearts whatsoever in accepting your judgment. They must submit a total submission.","বস্তুত কখনোই না,তোমার প্রভুর শপথ; তারা বিশ্বাসী নয় যদি না তারা তোমার কাছে তাদের বিবাদসমূহের বিচারের জন্য  আসে,তারপর তোমার রায় যাই হোক না কেন তা মেনে নিতে তাদের হৃদয়ে কোন দ্বিধা থাকে না।  তারা অবশ্যই আত্মসমর্পণ করবে,একটি পরিপূর্ণ আত্মসমর্পণ।"],
  "4:66": ["Had we decreed for them: \"You must offer your lives,\" or \"Give up your homes,\" they would not have done it, except for a few of them. (Even if such a command was issued,) had they done what they were commanded to do, it would have been better for them, and would prove the strength of their faith.","আমরা যদি তাদের জন্য হুকুম দিতামঃ “তোমরা অবশ্যই তোমাদের প্রান উৎসর্গ করবে,”অথবা “তোমাদের ঘর-বাড়ি পরিত্যাগ করবে,”তারা তা করতো না,তাদের মধ্যে কিছু লোক ব্যতিত। (এমনকি যদি এমন একটি হুকুম জারি হতো),যদি তারা করতো,যা তাদেরকে করতে আদেশ করা হয়েছিল, এটা তাদের জন্য উত্তম হতো,এবং প্রমান করতো তাদের বিশ্বাসের জোর।"],
  "4:67": ["And we would have granted them a great recompense.","এবং আমরা তাদেরকে এক মহা পুরস্কার প্রদান করতাম।"],
  "4:68": ["And we would have guided them in the right path.","এবং আমরা তাদেরকে সঠিক পথ-প্রদর্শন করতাম।"],
  "4:69": ["Those who obey Allah and the messenger belong with those blessed by Allah—the prophets, the saints, the martyrs, and the righteous. These are the best company.","যারা আল্লাহ এবং বার্তাবাহকে মান্য করে,তারা তাদের অন্তর্ভুক্ত যারা আশীর্বাদপ্রাপ্ত হয়েছিল আল্লাহর- নবীদের, সাধুদের, শহীদদের, এবং সৎ কর্মীদের। এরাই সর্বোত্তম সঙ্গী।"],
  "4:70": ["Such is the blessing from Allah; Allah is the best Knower.","এমনই আল্লাহর পক্ষ থেকে আশীর্বাদ; আল্লাহ সবচেয়ে ভালো জানেন।"],
  "4:71": ["O you who believe, you shall remain alert, and mobilize as individuals, or mobilize all together.","হে তোমরা যারা বিশ্বাস কর, তোমরা সতর্ক থাকবে,আর পৃথকভাবে সংগঠিত হও, অথবা সকলে মিলে সংগঠিত হও ।"],
  "4:72": ["Surely, there are those among you who would drag their feet, then, if a setback afflicts you, they would say, \"Allah has blessed me that I was not martyred with them.\"","নিশ্চিতরূপে,তোমাদের মধ্যে রয়েছে তারা যারা গড়িমসি করত, এরপর, যদি কোন প্রতিবন্ধকতা তোমাদের কষ্ট দিত, তারা বলত, \"আল্লাহ আমাকে সৌভাগ্যশীল করেছেন যে,আমি তাদের সাথে শহীদ হইনি।\""],
  "4:73": ["But if you attain a blessing from Allah, they would say, as if no friendship ever existed between you and them, \"I wish I was with them, so I could share in such a great victory.\"","কিন্তু,যদি তুমি আল্লাহ থেকে একটি আশীর্বাদ অর্জন কর, তারা বলবে,যেন তোমাদের ও তাদের মধ্যে কখনোই কোন বন্ধুত্ব বিদ্যমান ছিল না,\"আমি যদি তাদের সাথে থাকতাম, তবে এমন এক মহা-বিজয়ের অংশীদার হতে পারতাম। \""],
  "4:74": ["Those who readily fight in the cause of Allah are those who forsake this world in favor of the Hereafter. Whoever fights in the cause of Allah, then gets killed, or attains victory, we will surely grant him a great recompense.","যারা আল্লাহর উদ্দেশ্যে সানন্দে যুদ্ধ করে,তারা হচ্ছে সে সব লোক যারা পরকালের জন্য এই দুনিয়াকে পরিত্যাগ করে। যেকেউ আল্লাহর উদ্দেশ্যে যুদ্ধ করে,এরপর নিহত হয়, অথবা বিজয় অর্জন করে,আমরা নিশ্চিতরূপে তাকে এক মহা-পুরষ্কার দিব।"],
  "4:75": ["Why should you not fight in the cause of Allah when weak men, women, and children are imploring: \"Our Lord, deliver us from this community whose people are oppressive, and be You our Lord and Master.\"","কেন তোমাদের আল্লাহর উদ্দেশ্যে যুদ্ধ করা উচিৎ নয়, যখন দূর্বল পুরুষরা,নারীরা,এবং শিশুরা মিনতি করছে: \"আমাদের প্রভু,আমাদেরকে এই সম্প্রদায় থেকে মুক্তি দিন যার লোকেরা অত্যাচারী,এবং আপনি হোন আমাদের প্রভু এবং মনিব।\""],
  "4:76": ["Those who believe are fighting for the cause of Allah, while those who disbelieve are fighting for the cause of tyranny. Therefore, you shall fight the devil's allies; the devil's power is nil.","যারা বিশ্বাস করে তারা আল্লাহর উদ্দেশ্যে যুদ্ধ করছে,যখন যারা অবিশ্বাস করে তারা উৎপীড়ন করার উদ্দেশ্যে যুদ্ধ করছে। এই কারনে,তোমরা শয়তানের মিত্রদের বিরুদ্ধে যুদ্ধ করবে; শয়তান শক্তিহীন।"],
  "4:77": ["Have you noted those who were told, \"You do not have to fight; all you need to do is observe the Contact Prayers (Salat) and give the obligatory charity (Zakat),\" then, when fighting was decreed for them, they feared the people as much as they feared Allah, or even more? They said, \"Our Lord, why did You force this fighting on us? If only You respite us for awhile!\" Say, \"The materials of this world are nil, while the Hereafter is far better for the righteous, and you never suffer the slightest injustice.\"","তুমি কি তাদের লক্ষ্য করেছ যাদেরকে বলা হয়েছিল, “তোমাদের যুদ্ধ করতে হবে না;  যে সব তোমাদের করা প্রয়োজন তা হল (সালাত) সংযোগ প্রার্থনাসমূহ প্রতিষ্ঠা করা,এবং বাদ্ধতামূলক দান করা (যাকাত) “এরপর, যখন  তাদের জন্য যুদ্ধ করার আদেশ করা হয়েছিল, তারা লোকদের এমন ভয় করেছিল যেমন তারা আল্লাহকে ভয় করতো,অথবা এমন কি আরও অধিক? তারা বলেছিল, “আমাদের প্রভু,কেন আপনি এই যুদ্ধ আমাদের উপর জোর করে আরোপ করেছিলেন? যদি আপনি শুধু কিছু সময়ের জন্য আমাদের বিরাম দিতেন!”বল, “এই দুনিয়ার বস্তু সামগ্রী কিছুই না,যখন পরকাল সৎকর্মশীলদের জন্য অধিকতর উত্তম, এবং তোমরা কখনই সামান্যতম অবিচার ভোগ করবে না।"],
  "4:78": ["Wherever you are, death will catch up with you, even if you live in formidable castles. When something good happens to them, they say, \"This is from Allah,\" and when something bad afflicts them, they blame you. Say, \"Everything comes from Allah.\" Why do these people misunderstand almost everything?","তোমরা যেখানেই থাকো না কেন, মৃত্যু তোমাদের পাকড়াও করবে,এমনকি যদি তোমরা দুর্ভেদ্য দুর্গেও বাস করো। যখন তাদের ভাল কিছু হয়, তারা বলে,“এটা আল্লাহর পক্ষ থেকে,”এবং যখন কোন মন্দকিছু তাদেরকে পীড়িত করে,তারা তোমার প্রতি দোষারোপ করে। বল, “সবকিছু আল্লাহর থেকে আসে”। কেন এই লোকেরা প্রায় সবকিছুই ভুল বোঝে?"],
  "4:79": ["Anything good that happens to you is from Allah, and anything bad that happens to you is from you. We have sent you as a messenger to the people, and Allah suffices as witness.","যা কিছু ভালো তোমাদের প্রতি ঘটে তা আল্লাহর থেকে,এবং যা কিছু মন্দ তোমাদের প্রতি ঘটে তা তোমাদের পক্ষ থেকে। আমরা লোকদের জন্য তোমাকে  বার্তাবাহক হিসাবে পাঠিয়েছি,এবং আল্লাহ সাক্ষী হিসাবে যথেষ্ট।"],
  "4:80": ["Whoever obeys the messenger is obeying Allah. As for those who turn away, we did not send you as their guardian.","যেকেউ বার্তাবাহককে মান্য করে,সে আল্লাহকে মান্য করছে। তাদের বিষয়ে যারা মুখ ফিরিয়ে নেয়, আমরা তোমাকে তাদের অভিভাবক করে পাঠাইনি।"],
  "4:81": ["They pledge obedience, but as soon as they leave you, some of them harbor intentions contrary to what they say. Allah records their innermost intentions. You shall disregard them, and put your trust in Allah. Allah suffices as an advocate.","তারা আনুগত্যের অঙ্গীকার করে,কিন্তু যখনি তারা তোমাকে ছেড়ে যায়, তাদের কেউ কেউ যা তারা বলে এর বিপরীত ইচ্ছা পোষন করে। আল্লাহ তাদের গভীরতম  ইচ্ছাগুলো রেকর্ড করেন। তোমরা তাদেরকে উপেক্ষা করবে,এবং আল্লাহর প্রতি তোমাদের আস্থা রাখ। আল্লাহ সমর্থক হিসেবে যথেষ্ট।"],
  "4:82": ["Why do they not study the Quran carefully? If it were from other than Allah, they would have found in it numerous contradictions.","কেন তারা যত্নসহকারে কুরআন অধ্যয়ন করে না? যদি এটি আল্লাহ ছাড়া অন্য কারো থেকে হত, তারা এতে অসংখ্য অসংগতি পেত।"],
  "4:83": ["When a rumor that affects security comes their way, they spread it. Had they referred it to the messenger, and those in charge among them, those who understand these matters would have informed them. If it were not for Allah's grace towards you, and His mercy, you would have followed the devil, except a few.","যখন একটি গুজব, তাদের সামনে আসে,যা নিরাপত্তাকে বিঘ্নিত করে,তারা তা ছড়ায়। যদি তারা তা বার্তাবাহক, এবং তাদের মধ্যকার দায়িত্বপ্রাপ্তদের কাছে ন্যস্ত করত, তবে তাদেরকে অবহিত করত তারা যারা এইসব বিষয়গুলো বুঝে। যদি এটি তোমাদের প্রতি আল্লাহর করুনা,এবং তাঁর দয়া না হত, তোমরা শয়তানকে অনুসরণ করতে,অল্পসংখ্যক ছাড়া।"],
  "4:84": ["You shall fight for the cause of Allah; you are responsible only for your own soul, and exhort the believers to do the same. Allah will neutralize the power of those who disbelieve. Allah is much more powerful, and much more effective.","তোমরা আল্লাহর উদ্দেশ্যে যুদ্ধ করবে; তোমরা শুধু তোমাদের নিজেদের আত্মার জন্যই দায়ী,এবং বিশ্বাসীদেরকে তা-ই করতে উপদেশ দিবে। আল্লাহ তাদের ক্ষমতা নিষ্ক্রয় করবেন, যারা অবিশ্বাস করে। আল্লাহ অনেক বেশি ক্ষমতাবান, এবং অনেক বেশি কার্যকরী।"],
  "4:85": ["Whoever mediates a good deed receives a share of the credit thereof, and whoever mediates an evil work, incurs a share thereof. Allah controls all things.","যেকেউ একটি ভাল কাজের মধ্যস্থতা করে,এর কৃতৃত্বের একটি অংশ গ্রহণ করে,এবং যেকেউ একটি মন্দ কাজের মধ্যস্থতা করে,এর একটি অংশ টেনে আনে। আল্লাহ সব কিছু নিয়ন্ত্রণ করেন।"],
  "4:86": ["When greeted with a greeting, you shall respond with a better greeting or at least an equal one. Allah reckons all things.","যখন শুভেচ্ছা প্রাপ্ত হবে কোন অভিবাদন দ্বারা,তোমরা সাড়া দিবে উত্তম অথবা কমপক্ষে একটি সমতুল্য অভিবাদন দিয়ে। আল্লাহ সব কিছুর হিসাব গ্রহণকারী।"],
  "4:87": ["Allah: there is no god except He. He will surely summon you on the Day of Resurrection—the inevitable day. Whose narration is more truthful than Allah's?","ঈশ্বরঃ তিনি ব্যতিত কোন উপাস্য নেই। তিনি অবশ্যই তোমাদের সমবেত করবেন পুরুত্থানের সেই অনিবার্য দিনে। আল্লাহর চেয়ে কার বর্ণনা অধিক সত্য?"],
  "4:88": ["Why should you divide yourselves into two groups regarding hypocrites (among you)? Allah is the one who condemned them because of their own behavior. Do you want to guide those who are sent astray by Allah? Whomever Allah sends astray, you can never find a way to guide them.","(তোমাদের ভিতরের) ভণ্ডদের বিষয়ে কেন তোমাদের উচিত হবে নিজেদের দুই দলে বিভক্ত করা? আল্লাহই তাদেরকে তাদের আচরণের কারনে নিন্দিত করেছেন। তোমরা কি তাদেরকে পথ প্রদর্শন করতে চাও, যারা আল্লাহ দ্বারা পথভ্রষ্ট হয়েছে? যাদেরকে আল্লাহ পথভ্রষ্ট করেন, তুমি কখনই তাদেরকে পথপ্রদর্শন করার উপায় পাবে না।"],
  "4:89": ["They wish that you disbelieve as they have disbelieved, then you become equal. Do not consider them friends, unless they mobilize along with you in the cause of Allah. If they turn against you, you shall fight them, and you may kill them when you encounter them in war. You shall not accept them as friends, or allies.","তারা প্রত্যাশা করে যে,তুমি অবিশ্বাস করো যেমন তারা অবিশ্বাস করেছে,তারপর তোমরা (তাদের) সমান হয়ে যাও। তাদেরকে বন্ধু ভেব না,যদি না তারা আল্লাহর উদ্দেশ্যে তোমাদের সাথে যুদ্ধের জন্য সংগঠিত হয়। যদি তারা তোমাদের শত্রু হয়ে উঠে,তোমরা তাদের বিরুদ্ধে যুদ্ধ করবে,এবং তোমাদেরকে তাদের হত্যা করতে হতে পারে,যখন যুদ্ধে তোমরা তাদের মুখোমুখি হও। তোমরা তাদেরকে বন্ধু অথবা মিত্র হিসাবে গ্রহণ করবে না।"],
  "4:90": ["Exempted are those who join people with whom you have signed a peace treaty, and those who come to you wishing not to fight you, nor fight their relatives. Had Allah willed, He could have permitted them to fight against you. Therefore, if they leave you alone, refrain from fighting you, and offer you peace, then Allah gives you no excuse to fight them.","তারা নিষ্কৃতি প্রাপ্ত যারা সে লোকদের সাথে যোগ দেয় যাদের সাথে তোমরা একটি শান্তি চুক্তি সাক্ষর করেছ, এবং তারা যারা তোমাদের কাছে আসে তোমাদের সাথে যুদ্ধ না করার ইচ্ছা নিয়ে,না তাদের আত্মীয়দের সাথে। আল্লাহ যদি চাইতেন, তিনি তাদেরকে অনুমতি দিতে পারতেন তোমাদের বিরুদ্ধে যুদ্ধ করার। অতএব, যদি তারা তোমাদেরকে একা ছেড়ে দেয়, তোমাদের বিরুদ্ধে যুদ্ধ করা থেকে বিরত থাকে,এবং তোমাদেরকে শান্তি প্রস্তাব দেয়, তখন আল্লাহ তোমাদেরকে তাদের বিরুদ্ধে যুদ্ধের কোন ওজর দেন না।"],
  "4:91": ["You will find others who wish to make peace with you, and also with their people. However, as soon as war erupts, they fight against you. Unless these people leave you alone, offer you peace, and stop fighting you, you may fight them when you encounter them. Against these, we give you a clear authorization.","তোমরা অন্যদেরকে পাবে যারা শান্তি স্থাপন করতে চায় তোমাদের সাথে,এবং তাদের লোকদের সাথেও। কিন্তু,যখনি যুদ্ধ ছড়িয়ে পড়ে,তারা তোমাদের বিরুদ্ধে যুদ্ধ করে। যদি না এইসব লোকেরা তোমাদের থেকে নিবৃত্ত হয়, তোমাদেরকে শান্তি প্রস্তাব দেয়, এবং তোমাদের বিরুদ্ধে যুদ্ধ বন্ধ করে,তোমাদেরকে তাদের বিরুদ্ধে যুদ্ধ করতে হতে পারে যখন তোমরা তাদের মোকাবেলা করো। এইসবের বিপক্ষে,আমরা তোমাদেরকে একটি স্পষ্ট কর্তৃত্ব প্রদান করি।"],
  "4:92": ["No believer shall kill another believer, unless it is an accident. If one kills a believer by accident, he shall atone by freeing a believing slave, and paying a compensation to the victim's family, unless they forfeit such a compensation as a charity. If the victim belonged to people who are at war with you, though he was a believer, you shall atone by freeing a believing slave. If he belonged to people with whom you have signed a peace treaty, you shall pay the compensation in addition to freeing a believing slave. If you cannot find a slave to free, you shall atone by fasting two consecutive months, in order to be redeemed by Allah. Allah is Knower, Most Wise.","কোন বিশ্বাসী অপর বিশ্বাসীকে হত্যা করবে না,যদি না তা একটি দূর্ঘটনা হয়। যদি কেউ কোন বিশ্বাসীকে দূর্ঘটনাবশত হত্যা করে,সে প্রায়শ্চিত্ত করবে একজন বিশ্বাসী দাসকে মুক্ত করে,এবং নিহতের পরিবারকে ক্ষতিপূরণ দিয়ে,যদি না তারা এরকম ক্ষতিপূরণকে দান হিসেবে ছেড়ে দেয়। যদি নিহত ব্যক্তিটি সে লোকদের অন্তর্ভূক্ত হয়, যারা তোমাদের সাথে যুদ্ধে লিপ্ত, যদিও সে একজন বিশ্বাসী ছিল, তোমরা একজন বিশ্বাসী দাসকে মুক্ত করে প্রায়শ্চিত্ত করবে। যদি সে সেই লোকদের অন্তর্ভূক্ত হয়, যাদের সাথে তোমরা একটি শান্তি চুক্তি স্বাক্ষর করেছ, তোমরা ক্ষতিপূরণ করবে সেই সাথে একজন বিশ্বাসী দাসকে মুক্ত করবে। যদি তোমরা মুক্ত করার জন্য একজন দাস খুঁজে না পাও,তোমরা পর পর দুই মাস উপবাস দ্বারা প্রায়শ্চিত্ত করবে,আল্লাহ দ্বারা উদ্ধারপ্রাপ্ত হতে। আল্লাহ জ্ঞাতা,সবচেয়ে জ্ঞানী।"],
  "4:93": ["Anyone who kills a believer on purpose, his retribution is Hell, wherein he abides forever, Allah is angry with him, and condemns him, and has prepared for him a terrible retribution.","যেকেউ একজন বিশ্বাসীকে উদ্দেশ্যমূলকভাবে হত্যা করে,তার শাস্তি নরক, যেখানে সে চিরকাল বসবাস করে,আল্লাহ তার প্রতি রাগান্বিত, এবং তাকে দন্ডাদেশ দেন, এবং তার জন্য প্রস্তুত রেখেছেন এক ভয়ানক শাস্তি।"],
  "4:94": ["O you who believe, if you strike in the cause of Allah, you shall be absolutely sure. Do not say to one who offers you peace, \"You are not a believer,\" seeking the spoils of this world. For Allah possesses infinite spoils. Remember that you used to be like them, and Allah blessed you. Therefore, you shall be absolutely sure (before you strike). Allah is fully Cognizant of everything you do.","হে তোমরা যারা বিশ্বাস কর, যদি তোমরা আল্লাহর উদ্দেশ্যে আঘাত কর, তোমরা সম্পূর্নভাবে নিশ্চিত হবে। তোমাদেরকে শান্তি প্রস্তাব দেয় এমন কাউকে বলবে না যে,\"তুমি বিশ্বাসী নও, ”এই পৃথিবীর যুদ্ধলব্ধ সম্পদের খোঁজে। কারণ, আল্লাহ অফুরন্ত সম্পদের অধিকারী। স্মরণ কর যে,তোমরা তাদের মত ছিলে,এবং আল্লাহ তোমাদেরকে আশীর্বাদপুষ্ট করেছেন। সুতরাং,তোমরা সম্পূর্নভাবে নিশ্চিত হবে (আঘাত করার আগে)। তোমরা যা কিছু কর আল্লাহ সে সম্পর্কে সম্পূর্ন অবগত।"],
  "4:95": ["Not equal are the sedentary among the believers who are not handicapped, and those who strive in the cause of Allah with their money and their lives. Allah exalts the strivers with their money and their lives above the sedentary. For both, Allah promises salvation, but Allah exalts the strivers over the sedentary with a great recompense.","সমান নয় বিশ্বাসীদের মধ্যে বসে থাকা লোকেরা যারা বিকলাঙ্গ নয়, এবং তারা যারা আল্লাহর উদ্দেশ্যে সংগ্রাম করে তাদের অর্থ এবং জীবন দিয়ে। আল্লাহ বসে থাকাদের উপর উন্নীত করেন তাদেরকে যারা তাদের অর্থ এবং তাদের জীবন দিয়ে সংগ্রাম করে। উভয়ের জন্য, আল্লাহ পরিত্রাণের অঙ্গীকার করেন, কিন্তু আল্লাহ বসে থাকাদের উপর সংগ্রামকারীদের এক মহা প্রতিদানের সাথে উন্নীত করেন।"],
  "4:96": ["The higher ranks come from Him, as well as forgiveness and mercy. Allah is Forgiver, Most Merciful.","উচ্চতর পদমর্যাদা তাঁর থেকে আসে,একই ভাবে ক্ষমা এবং করুণা। আল্লাহ ক্ষমাশীল, পরম করুণাময়।"],
  "4:97": ["Those whose lives are terminated by the angels, while in a state of wronging their souls, the angels will ask them, \"What was the matter with you?\" They will say, \"We were oppressed on earth.\" They will say, \"Was Allah's earth not spacious enough for you to emigrate therein?\" For these, the final abode is Hell, and a miserable destiny.","নিজেদের আত্মার উপর অত্যাচার করা কালীন যাদের জীবন ফেরেশতা দ্বারা সমাপ্ত করা হয়, তাদেরকে ফেরেশতারা প্রশ্ন করবে,\"তোমাদের কি সমস্যা ছিল? তারা বলবে যে,“আমরা পৃথিবীতে নিপীড়িত ছিলাম”। তারা বলবে,“স্থান পরিবর্তন করতে আল্লাহর পৃথিবী কি তোমাদের জন্য যথেষ্ট প্রশস্ত ছিল না”? এদের জন্য, চূড়ান্ত বাসস্থান নরক, এবং একটি শোচনীয় নিয়তি।"],
  "4:98": ["Exempted are the weak men, women, and children who do not possess the strength, nor the means to find a way out.","নিষ্কৃতি প্রাপ্ত দুর্বল পুরুষ, নারী,এবং শিশুরা,যারা শক্তি বা সংগতি রাখে না প্রস্থান করার।"],
  "4:99": ["These may be pardoned by Allah. Allah is Pardoner, Forgiver.","হতে পারে এরা আল্লাহ দ্বারা ক্ষমাপ্রাপ্ত হবে,আল্লাহ মার্জনাকারী  ক্ষমাশীল।"],
  "4:100": ["Anyone who emigrates in the cause of Allah will find on earth great bounties and richness. Anyone who gives up his home, emigrating to Allah and His messenger, then death catches up with him, his recompense is reserved with Allah. Allah is Forgiver, Most Merciful.","যে কেউ আল্লাহর উদ্দেশ্যে স্থান পরিবর্তন করে,সে পৃথিবীতে পাবে মহা দান এবং ঐশ্বর্য। যেকেউ আল্লাহ এবং তাঁর বার্তাবাহকের দিকে স্থান পরিবর্তন করতে তার ঘর পরিত্যাগ করে,এরপর মৃত্যু তাকে তুলে নেয়, তার পুরস্কার আল্লাহর কাছে সংরক্ষিত রয়েছে। আল্লাহ ক্ষমাশীল, পরম করুণাময়।"],
  "4:101": ["When you travel, during war, you commit no error by shortening your Contact Prayers (Salat), if you fear that the disbelievers may attack you. Surely, the disbelievers are your ardent enemies.","যখন তোমরা যুদ্ধের সময় ভ্রমণ কর, তখন তোমরা সংযোগ প্রার্থনাসমূহ (সালাত) সংক্ষিপ্ত করে কোন ভুল কর না,যদি তোমরা ভয় পাও যে,অবিশ্বাসীরা তোমাদেরকে আক্রমণ করতে পারে। নিশ্চিতভাবে,অবিশ্বাসীরা তোমাদের ঘোর শত্রু।"],
  "4:102": ["When you are with them, and lead the Contact Prayer (Salat) for them, let some of you stand guard; let them hold their weapons, and let them stand behind you as you prostrate. Then, let the other group that has not prayed take their turn praying with you, while the others stand guard and hold their weapons. Those who disbelieved wish to see you neglect your weapons and your equipment, in order to attack you once and for all. You commit no error, if you are hampered by rain or injury, by putting down your weapons, so long as you remain alert. Allah has prepared for the disbelievers a shameful retribution.","যখন তুমি তাদের সাথে থাক, এবং তাদের জন্য সংযোগ প্রার্থনা (সালাত) পরিচালনা কর, তোমাদের কিছু লোককে পাহারায় নিয়োজিত কর; তারা তাদের অস্ত্রসমূহ ধরে রাখবে,এবং তারা তোমার পিছনে দাঁড়িয়ে থাকবে যখন তুমি সেজদা করো। এরপর, অন্য দলটি,যারা প্রার্থনা করেনি,তোমার সাথে তাদের প্রার্থনার পালা সম্পন্ন করবে,যখন অন্যরা পাহারা দিবে এবং অস্ত্রসমূহ ধরে থাকবে। যারা অবিশ্বাস করে তারা তোমাদেরকে তোমাদের অস্ত্রসমূহ এবং তোমাদের যন্ত্রপাতির প্রতি অবহেলারত অবস্থায় দেখতে চায়, যাতে তোমাদেরকে চুড়ান্তভাবে আক্রমণ করা যায়। তোমরা কোন ভুল করো না তোমাদের অস্ত্রসমূহ নিচে রেখে,যদি তোমরা বৃষ্টি বা আঘাতের দ্বারা বাধাপ্রাপ্ত হও, যতক্ষণ পর্যন্ত তোমরা সতর্ক থাক। আল্লাহ অবিশ্বাসীদের জন্য এক লজ্জাকর প্রতিদান প্রস্তুত রেখেছেন।"],
  "4:103": ["Once you complete your Contact Prayer (Salat), you shall remember Allah while standing, sitting, or lying down. Once the war is over, you shall observe the Contact Prayers (Salat); the Contact Prayers (Salat) are decreed for the believers at specific times.","যখন তোমরা তোমাদের সংযোগ প্রার্থনা (সালাত) সম্পন্ন কর, তোমরা আল্লাহকে স্মরণ করবে দাঁড়ানো,বসা অথবা শায়িত অবস্থায়। যখন যুদ্ধ শেষ হয়, তোমরা সংযোগ প্রার্থনাসমূহ (সালাত) স্থাপন করবে; সংযোগ প্রার্থনাসমূহ (সালাত) বিশ্বাসীদের জন্য নির্দিষ্ট সময়সমূহে (সম্পন্ন করার) আদেশ করা হয়েছে।"],
  "4:104": ["Do not waver in pursuing the enemy. If you suffer, they also suffer. However, you expect from Allah what they never expect. Allah is Omniscient, Most Wise.","শত্রুদের তাড়া করতে দিধান্বিত হইও না।  যদি তোমরা কষ্ট ভোগ কর, তারাও কষ্ট ভোগ করে। কিন্তু,তোমরা আল্লাহ থেকে প্রত্যাশা কর, যা তারা কখনোই প্রত্যাশা করে না। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "4:105": ["We have sent down to you the scripture, truthfully, in order to judge among the people in accordance with what Allah has shown you. You shall not side with the betrayers.","আমরা তোমার কাছে ঐশীগ্রন্থ অবতীর্ণ করেছি,সত্যতার সাথে,আল্লাহ তোমাকে যা দেখিয়েছেন সে অনুসারে লোকদের মাঝে বিচার করতে। তুমি বিশ্বাসঘাতকদের পক্ষ নিবে না।"],
  "4:106": ["You shall implore Allah for forgiveness. Allah is Forgiver, Most Merciful.","তোমরা আল্লাহর কাছে ক্ষমার জন্য মিনতি করবে। আল্লাহ ক্ষমাশীল পরম দয়ালু।"],
  "4:107": ["Do not argue on behalf of those who have wronged their own souls; Allah does not love any betrayer, guilty.","যারা তাদের নিজেদের আত্মার ক্ষতি করেছে তাদের পক্ষ হয়ে তর্ক করো না; আল্লাহ কোন বিশ্বাসঘাতক, অপরাধীকে ভালবাসেন না।"],
  "4:108": ["They hide from the people, and do not care to hide from Allah, though He is with them as they harbor ideas He dislikes. Allah is fully aware of everything they do.","তারা মানুষের কাছ থেকে লুকায়, আর আল্লাহর কাছ থেকে লুকানোকে পরোয়া করে না,যদিও তারা তাঁর অপছন্দনীয় ধারণাগুলো মনে পোষণ করার সময়ও তিনি তাদের সাথেই থাকেন। আল্লাহ তাদের করা সবকিছু সম্পূর্ন অবগত।"],
  "4:109": ["Here you are arguing on their behalf in this world; who is going to argue with Allah on their behalf on the Day of Resurrection? Who is going to be their advocate?","এখানে,এই দুনিয়ায় তুমি তাদের পক্ষে তর্ক করছ; পুনরুত্থানের দিবসে তাদের পক্ষে কে আল্লাহর সাথে তর্ক করতে যাচ্ছে? কে হতে যাচ্ছে তাদের উকিল?"],
  "4:110": ["Anyone who commits evil, or wrongs his soul, then implores Allah for forgiveness, will find Allah Forgiving, Most Merciful.","যে কেউ মন্দ সম্পাদন করে,অথবা তার আত্মার ক্ষতি করে,এরপর ক্ষমার জন্য আল্লাহর কাছে মিনতি করে,সে আল্লাহকে ক্ষমাশীল, পরম দয়ালু পাবে।"],
  "4:111": ["Anyone who earns a sin, earns it to the detriment of his own soul. Allah is Omniscient, Most Wise.","যে কেউ পাপ অর্জন করে,তা তার নিজ আত্মার ক্ষতি করতে অর্জন করে। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "4:112": ["Anyone who earns a sin, then accuses an innocent person thereof, has committed a blasphemy and a gross offense.","যে কেউ পাপ অর্জন করে,এরপর একজন নির্দোষ ব্যক্তিকে এজন্য অভিযুক্ত করে,সে মিথ্যাচার এবং এক গুরুতর অপরাধ করেছে।"],
  "4:113": ["If it were not for Allah's grace towards you, and His mercy, some of them would have misled you. They only mislead themselves, and they can never harm you in the least. Allah has sent down to you the scripture and wisdom, and He has taught you what you never knew. Indeed, Allah's blessings upon you have been great.","যদি এটি তোমার প্রতি আল্লাহর অনুগ্রহ, এবং তাঁর দয়া না হতো,তাদের কেউ কেউ তোমাকে বিপথগামী করত। তারা শুধু তাদের নিজেদেরকে বিপথগামী করে,এবং তারা কখনোই তোমার সামান্যতম ক্ষতি করতে পারে না। আল্লাহ তোমার কাছে ঐশীগ্রন্থ এবং প্রজ্ঞা অবতীর্ণ করেছেন, এবং তিনি তোমাকে শিখিছেন যা তুমি কখনোই জানতে না। প্রকৃতপক্ষে,তোমার উপর আল্লাহর আশীর্বাদসমূহ বিশাল।"],
  "4:114": ["There is nothing good about their private conferences, except for those who advocate charity, or righteous works, or making peace among the people. Anyone who does this, in response to Allah's teachings, we will grant him a great recompense.","তাদের একান্ত সম্মেলনগুলোতে ভাল কিছু নেই, তাদেরটা ব্যতীত যারা দানের, অথবা সৎ কাজের, অথবা লোকদের মাঝে শান্তি আনয়নের উপদেশ দেয়। আল্লাহর শিক্ষাগুলোর প্রতি সাড়া দিয়ে যে কেউ তা করে,আমরা তাকে এক মহা প্রতিদান দিব।"],
  "4:115": ["As for him who opposes the messenger, after the guidance has been pointed out to him, and follows other than the believers' way, we will direct him in the direction he has chosen, and commit him to Hell; what a miserable destiny!","আর যে বার্তাবাহকের বিরোধিতা করে,তাকে পথ-নির্দেশনা দেখানোর পর এবং বিশ্বাসীদের ছাড়া অন্যদের পথ অনুসরণ করে,আমরা তাকে পরিচালিত করবো সে পথে যা সে পছন্দ করেছে,এবং তাকে নরকে নিক্ষিপ্ত করবো; কি এক শোচনীয় নিয়তি!"],
  "4:116": ["Allah does not forgive idol worship (if maintained until death), and He forgives lesser offenses for whomever He wills. Anyone who idolizes any idol beside Allah has strayed far astray.","আল্লাহ অংশীদার সাব্যস্ত করার পাপ ক্ষমা করেন না (যদি মৃত্যু অবধি বজায় রাখা হয়) এবং তিনি যার জন্য ইচ্ছা এর থেকে ছোট অপরাধ ক্ষমা করেন। যে কেউ আল্লাহর পাশে অন্য যে কোন উপাস্যের উপাসনা করে সে বহু দূরে পথভ্রষ্ট হয়েছে।"],
  "4:117": ["They even worship female gods besides Him; as a matter of fact, they only worship a rebellious devil.","তারা এমনকি তাঁর পাশে নারী উপাস্যের উপাসনা করে; বস্তুত, তারা শুধু এক বিদ্রোহী শয়তানের উপাসনা করে।"],
  "4:118": ["Allah has condemned him, and he said, \"I will surely recruit a definite share of Your worshipers.","আল্লাহ তাকে নিন্দিত করেছেন, এবং সে বলেছিল, “আমি অবশ্যই তোমার উপাসনাকারিদের একটি নির্দিষ্ট অংশকে নিয়োজিত করবো।"],
  "4:119": ["\"I will mislead them, I will entice them, I will command them to (forbid the eating of certain meats by) marking the ears of livestock, and I will command them to distort the creation of Allah.\" Anyone who accepts the devil as a lord, instead of Allah, has incurred a profound loss.","“আমি তাদেরকে পথভ্রষ্ট করবো,আমি তাদেরকে প্রলুব্ধ করবো,আমি তাদেরকে হুকুম করবো (নির্দিষ্ট কিছুর মাংস খাওয়া নিষিদ্ধ করতে) গবাদি পশুর কানে চিহ্ন প্রদানের দ্বারা,এবং আমি তাদেরকে হুকুম করবো ঈশরের সৃষ্টিকে বিকৃত করতে”। যে কেউ শয়তানকে একজন প্রভু হিসাবে গ্রহণ করে,আল্লাহর বদলে,সে টেনে এনেছে এক গভীর ক্ষতি।"],
  "4:120": ["He promises them and entices them; what the devil promises is no more than an illusion.","সে তাদেরকে প্রতিশ্রুতি দেয় এবং তাদেরকে প্রলুব্ধ করে; শয়তান যা প্রতিশ্রুতি দেয় তা বিভ্রম ছাড়া কিছুই নয়।"],
  "4:121": ["These have incurred Hell as their final abode, and can never evade it.","এরা টেনে এনেছে নরক তাদের চুড়ান্ত আবাস হিসেবে,এবং কখনো এটি এড়াতে পারে না।"],
  "4:122": ["As for those who believe and lead a righteous life, we will admit them into gardens with flowing streams, wherein they live forever. Such is the truthful promise of Allah. Whose utterances are more truthful than Allah's?","আর তারা যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন-যাপন করে,আমরা তাদেরকে প্রবেশ করাব প্রবাহিত ঝর্নাসহ বাগানসমূহে,যেখানে তারা চিরকাল বসবাস করে। এরকমই আল্লাহর সত্য অঙ্গীকার। আল্লাহর চেয়ে কার কথা অধিক সত্য?"],
  "4:123": ["It is not in accordance with your wishes, or the wishes of the people of the scripture: anyone who commits evil pays for it, and will have no helper or supporter, against Allah.","এটি তোমাদের, অথবা ঐশীগ্রন্থের লোকদের ইচ্ছানুযায়ী নয়ঃ যেকেউ মন্দ করে এর জন্য ক্ষতিপূরণ দেয়, এবং আল্লাহর বিপক্ষে তার কোন সাহায্যকারী অথবা সমর্থক থাকবে না।"],
  "4:124": ["As for those who lead a righteous life, male or female, while believing, they enter Paradise; without the slightest injustice.","আর তারা যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন-যাপন করে বিশ্বাসী অবস্থায়, পুরুষ হোক অথবা নারী,তারা স্বর্গোদ্যানে প্রবেশ করে; সামান্যতম অবিচার ছাড়াই।"],
  "4:125": ["Who is better guided in his religion than one who submits totally to Allah, leads a righteous life, according to the creed of Abraham: monotheism? Allah has chosen Abraham as a beloved friend.","কে তার ধর্মে উত্তম পথপ্রাপ্ত সে ব্যক্তির চেয়ে যে আল্লাহর কাছে পরিপূর্নভাবে আত্মসমর্পন করে,সৎকর্মশীল জীবন-যাপন করে,ইব্রাহিমের ধর্মবিশ্বাস অনুসারেঃ একেশ্বরবাদ? আল্লাহ ইব্রাহিমকে অতিশয় প্রিয় বন্ধু হিসেবে পছন্দ করেছেন।"],
  "4:126": ["To Allah belongs everything in the heavens and the earth. Allah is in full control of all things.","আকাশমন্ডলী এবং পৃথিবীর সবকিছু আল্লাহর। আল্লাহ সকল বস্তুর পরিপূর্ণ নিয়ন্ত্রণে আছেন।"],
  "4:127": ["They consult you concerning women: say, \"Allah enlightens you regarding them, as recited for you in the scripture. You shall restore the rights of orphaned girls whom you cheat out of their due dowries when you wish to marry them: you shall not take advantage of them. The rights of orphaned boys must also be protected as well. You shall treat the orphans equitably. Whatever good you do, Allah is fully aware thereof.\"","তারা নারীদের ব্যাপারে তোমার সাথে পরামর্শ করেঃ বল, “আল্লাহ তাদের ব্যাপারে তোমাদের জ্ঞান দান করেন, যেমনটি ঐশীগ্রন্থে তোমাদের জন্য আবৃত্তি করা হয়। তোমরা এতিম মেয়েদের অধিকার ফিরিয়ে দেবে যাদেরকে তোমরা তাদের প্রাপ্য দেনমোহর হতে ঠকাও, যখন তোমরা তাদেরকে বিয়ে করার ইচ্ছা করঃ তোমরা তাদের সুবিধা নেবে না। এতিম বালকদের অধিকারসমূহও অবশ্যই একই ভাবে সংরক্ষন করতে হবে। তোমরা এতিমদের সাথে ন্যায়সঙ্গত ব্যবহার করবে। যা কিছু ভালো তোমরা করো,আল্লাহ সেসব সম্পর্কে সম্পূর্ণ জ্ঞাত।"],
  "4:128": ["If a woman senses oppression or desertion from her husband, the couple shall try to reconcile their differences, for conciliation is best for them. Selfishness is a human trait, and if you do good and lead a righteous life, Allah is fully Cognizant of everything you do.","যদি কোন নারী তার স্বামী থেকে নিপীড়ন অথবা উপেক্ষার আশঙ্কা করে,দম্পতিটি তাদের বিবাদগুলো মিটিয়ে ফেলার চেষ্টা করবে,কারন বিবাদ মিটিয়ে ফেলা তাদের জন্য সর্বোত্তম। স্বার্থপরতা একটি মানব বৈশিষ্ট্য, এবং যদি তুমি ভালো করো এবং সৎ জীবন-যাপন করো,তোমাদের করা সবকিছু সম্পর্কে আল্লাহ সম্পূর্ন জ্ঞাত।"],
  "4:129": ["You can never be equitable in dealing with more than one wife, no matter how hard you try. Therefore, do not be so biased as to leave one of them hanging (neither enjoying marriage, nor left to marry someone else). If you correct this situation and maintain righteousness, Allah is Forgiver, Most Merciful.","তোমরা একের অধিক স্ত্রীর সাথে আচরনের বেলায কখনই ন্যায়পরায়ণ হতে পারবে না,যত কঠিন চেষ্টাই তোমরা করো না কেন। সে জন্য, এতো পক্ষপাতদুষ্ট হয়ো না যে তাদের যে কোন একজন কে ঝুলিয়ে রাখো (না বিয়ে উপভোগ করতে দিয়ে,না অন্যকাউকে বিয়ে করতে দিয়ে)। যদি তোমরা এই অবস্থা সংশোধন করো এবং সততা বজায় রাখো,আল্লাহ ক্ষমাশীল, পরম করুণাময়।"],
  "4:130": ["If the couple must decide to part, Allah will provide for each of them from His bounties. Allah is Bounteous, Most Wise.","যদি দম্পতিটি পৃথক হওয়ারই সিদ্ধান্ত নেয়, আল্লাহ তাদের প্রত্যেকের জন্যই তাঁর অনুগ্রহসমূহ থেকে দেবেন। আল্লাহ অনুগ্রহশীল, সবচেয়ে জ্ঞানী।"],
  "4:131": ["To Allah belongs everything in the heavens and the earth, and we have enjoined on those who received the scripture before you, and enjoined on you, that you shall reverence Allah. If you disbelieve, then to Allah belongs everything in the heavens and the earth. Allah is in no need, Praiseworthy.","আকাশমন্ডলী ও পৃথিবীর সবকিছু আল্লাহর, এবং আমরা আদেশ করেছি তাদের প্রতি যারা তোমাদের আগে ঐশীগ্রন্থ গ্রহন করেছিল, এবং আদেশ করেছি তোমাদেরকে যে,তোমরা আল্লাহকে ভক্তি করবে। যদি তোমরা অবিশ্বাস কর, তবে আকাশমন্ডলী ও পৃথিবীর সবকিছু আল্লাহর। আল্লাহ কোন প্রয়োজনের অধীন নন, প্রশংসনীয়।"],
  "4:132": ["To Allah belongs everything in the heavens and the earth, and Allah is the only Protector.","আকাশমন্ডলী এবং পৃথিবীর সবকিছু আল্লাহর, এবং আল্লাহই একমাত্র রক্ষাকারী।"],
  "4:133": ["If He wills, He can annihilate you, O people, and substitute others in your place. Allah is certainly able to do this.","যদি তিনি ইচ্ছা করেন, তিনি তোমাদের নিশ্চিহ্ন করতে পারেন, হে মানুষ, এবং তোমাদের জায়গায় অন্যদের বসাতে পারেন। আল্লাহ নিশ্চিতভাবে এটি করতে সক্ষম।"],
  "4:134": ["Anyone who seeks the materials of this world should know that Allah possesses both the materials of this world and the Hereafter. Allah is Hearer, Seer.","যে কেউ এই দুনিয়ার পার্থিব বস্তুসামগ্রী খোঁজে তার জানা উচিত যে,আল্লাহ এই দুনিয়া এবং পরকাল, উভয়লোকের বস্তুসামগ্রীর অধিকারী। আল্লাহ শ্রোতা,দ্রষ্টা।"],
  "4:135": ["O you who believe, you shall be absolutely equitable, and observe Allah, when you serve as witnesses, even against yourselves, or your parents, or your relatives. Whether the accused is rich or poor, Allah takes care of both. Therefore, do not be biased by your personal wishes. If you deviate or disregard (this commandment), then Allah is fully Cognizant of everything you do.","হে তোমরা যারা বিশ্বাস কর, তোমরা সম্পূর্নরুপে ন্যয়পরায়ন হবে,এবং আল্লাহকে মান্য করবে,যখন তোমরা সাক্ষী হিসেবে দায়িত্ব পালন কর, এমনকি তোমাদের নিজেদের বিরুদ্ধে,অথবা তোমাদের পিতা-মাতার, অথবা তোমাদের আত্মীয়দের। অভিযুক্ত ব্যক্তিটি ধনী অথবা গরীব হোক, আল্লাহ উভয়কে গুরুত্ব দেন। সেজন্য, তোমাদের ব্যক্তিগত কামনার দ্বারা পক্ষপাতদুষ্ট হইও না। যদি তোমরা বিচ্যুত হও অথবা উপেক্ষা কর (এই প্রত্যাদেশ), তবে আল্লাহ তোমাদের করা সবকিছু সম্পর্কে সম্পূর্ন অবগত।"],
  "4:136": ["O you who believe, you shall believe in Allah and His messenger, and the scripture He has revealed through His messenger, and the scripture He has revealed before that. Anyone who refuses to believe in Allah, and His angels, and His scriptures, and His messengers, and the Last Day, has indeed strayed far astray.","হে তোমরা যারা বিশ্বাস করো,তোমরা বিশ্বাস করবে আল্লাহ এবং তাঁর বার্তাবাহককে,এবং সেই ঐশীগ্রন্থে যা তিনি তাঁর বার্তাবাহকের মাধ্যমে প্রকাশ করেছেন, এবং সেই ঐশীগ্রন্থে যা তিনি এর আগে প্রকাশ করেছেন। যে কেউ আল্লাহকে,এবং তাঁর স্বর্গ দূতদের, এবং তাঁর ঐশীগ্রন্থে,এবং তাঁর বার্তা বাহকে,এবং শেষ দিনে বিশ্বাস করতে প্রত্যাখ্যান করে,নিশ্চয়ই সে বহু দূর পথভ্রষ্ট হয়েছে।"],
  "4:137": ["Surely, those who believe, then disbelieve, then believe, then disbelieve, then plunge deeper into disbelief, Allah will not forgive them, nor will He guide them in any way.","নিশ্চয়ই, যারা বিশ্বাস করে,এরপর অবিশ্বাস করে,এরপর আবার বিশ্বাস করে,এরপর আবার অবিশ্বাস করে,তারপর অবিশ্বাসের গভীরে নিমজ্জিত হয়, তাদেরকে আল্লাহ ক্ষমা করবেন না,না তিনি তাদেরকে কোন ভাবে পথ প্রদর্শন করবেন।"],
  "4:138": ["Inform the hypocrites that they have incurred painful retribution.","ভণ্ডদের জানাও যে তারা যন্ত্রণাদায়ক শাস্তি টেনে এনেছে।"],
  "4:139": ["They are the ones who ally themselves with disbelievers instead of believers. Are they seeking dignity with them? All dignity belongs with Allah alone.","তারা সে সব লোক যারা বিশ্বাসীদের বদলে অবিশ্বাসীদেরকে নিজেদের মিত্র বানায়। তারা কি তাদের সাথে থেকে মর্যাদা খোঁজ করেছে? সকল মর্যাদা একমাত্র আল্লাহর।"],
  "4:140": ["He has instructed you in the scripture that: if you hear Allah's revelations being mocked and ridiculed, you shall not sit with them, unless they delve into another subject. Otherwise, you will be as guilty as they are. Allah will gather the hypocrites and the disbelievers together in Hell.","তিনি তোমাদের ঐশীগ্রন্থে নির্দেশ দিয়েছেন যেঃ যদি তোমরা শোন যে আল্লাহর প্রকাশনাবলিকে উপহাস এবং ব্যঙ্গ করা হচ্ছে,তোমরা তাদের সাথে বসবে না,যদি না তারা অন্য বিষয়ে চলে যায়। অন্যথায়, তোমরাও তাদের মত দোষী হবে। আল্লাহ ভণ্ডদের এবং অবিশ্বাসীদের একত্রে নরকে জড় করবেন।"],
  "4:141": ["They watch you and wait; if you attain victory from Allah, they say (to you), \"Were we not with you?\" But if the disbelievers get a turn, they say (to them), \"Did we not side with you, and protect you from the believers?\" Allah will judge between you on the Day of Resurrection. Allah will never permit the disbelievers to prevail over the believers.","তারা তোমাদের প্রতি নজর রাখে এবং অপেক্ষা করে; যদি তোমরা আল্লাহর থেকে বিজয় অর্জন কর, তারা বলে (তোমাদেরকে), “আমরা কি তোমাদের সাথে ছিলাম না?”কিন্তু যদি অবিশ্বাসীরা একটি সুযোগ পায়, তারা (তাদেরকে) বলে,“আমরা কি তোমাদের পক্ষ নেই নি,এবং তোমাদেরকে বিশ্বাসীদের থেকে রক্ষা করিনি?”আল্লাহ পূনঃরুত্থান দিবসে তোমাদের মাঝে বিচার করবেন। আল্লাহ অবিশ্বাসীদের কখনোই বিশ্বাসীদের উপর জয়ী হতে দিবেন না।"],
  "4:142": ["The hypocrites think that they are deceiving Allah, but He is the One who leads them on. When they get up for the Contact Prayer (Salat), they get up lazily. That is because they only show off in front of the people, and rarely do they think of Allah.","ভন্ডরা মনে করে যে তারা আল্লাহকে প্রতারিত করছে,কিন্তু তিনিই তাদেরকে ছেড়ে দিয়ে রাখেন। তারা যখন সংযোগ প্রার্থনার (সালাত) জন্য প্রস্তুতি নেয়, তারা অলসভাবে প্রস্তুতি নেয়। এটা এ কারনে যে তারা শুধু লোকদের সামনে প্রদর্শন করে,এবং তারা সামান্যই আল্লাহর চিন্তা করে।"],
  "4:143": ["They waver in between, neither belonging to this group, nor that group. Whomever Allah sends astray, you will never find a way to guide him.","তারা দুইয়ের মধ্যে দ্বিধাগ্রস্থ থাকে,না আছে এই দলে,না ঐ দলে। আল্লাহ যাকে পথভ্রষ্ট করেন, তুমি তাকে পথ-প্রদর্শিত করতে কখনোই কোন পথ খুঁজে পাবে না।"],
  "4:144": ["O you who believe, you shall not ally yourselves with the disbelievers, instead of the believers. Do you wish to provide Allah with a clear proof against you?","হে তোমরা যারা বিশ্বাস কর, তোমরা নিজেদেরকে অবিশ্বাসীদের মিত্র করবে না,বিশ্বাসীদের পরিবর্তে। তোমরা কি নিজেদের বিরুদ্ধে আল্লাহকে সুস্পষ্ট প্রমান দিতে চাও?"],
  "4:145": ["The hypocrites will be committed to the lowest pit of Hell, and you will find no one to help them.","ভন্ডদের স্থান হবে নরকের সর্বনিম্ন খাঁদ, এবং তুমি তাদেরকে সাহায্য করতে কাউকে পাবে না।"],
  "4:146": ["Only those who repent, reform, hold fast to Allah, and devote their religion absolutely to Allah alone, will be counted with the believers. Allah will bless the believers with a great recompense.","শুধু যারা অনুশোচনা করে,সংশোধিত হয়, আল্লাহকে দৃঢ় ভাবে আকড়েঁ থাকে,এবং তাদের ধর্মকে পরিপূর্ণ ভাবে শুধু আল্লাহর প্রতি উৎসর্গ করে,তাদেরকে বিশ্বাসীদের সাথে গননা করা হবে। আল্লাহ বিশ্বাসীদের মহা প্রতিদান দিয়ে আশীর্বাদ করবেন।"],
  "4:147": ["What will Allah gain from punishing you, if you became appreciative and believed? Allah is Appreciative, Omniscient.","তোমাদের শাস্তি দিয়ে আল্লাহ কি অর্জন করবেন, যদি তোমরা কৃতজ্ঞ হয়ে বিশ্বাস কর? আল্লাহ সুবিবেচক, সর্বজ্ঞ।"],
  "4:148": ["Allah does not like the utterance of bad language, unless one is treated with gross injustice. Allah is Hearer, Knower.","আল্লাহ মন্দ ভাষা উচ্চারণ করা পছন্দ করেন না,যদি না কারো সাথে মহা অন্যায় করা হয়। আল্লাহ শ্রোতা,জ্ঞাতা।"],
  "4:149": ["If you work righteousness—either declared or concealed—or pardon a transgression, Allah is Pardoner, Omnipotent.","যদি তোমরা সৎ কাজ করো- হোক তা প্রকাশ্য অথবা গোপন- অথবা কোন সীমালঙ্ঘন ক্ষমা করো,আল্লাহ ক্ষমাশীল, সর্বশক্তিমান।"],
  "4:150": ["Those who disbelieve in Allah and His messengers, and seek to make distinction among Allah and His messengers, and say, \"We believe in some and reject some,\" and wish to follow a path in between;","যারা আল্লাহ এবং তাঁর বার্তাবাহদের অবিশ্বাস করে,এবং আল্লাহ ও তাঁর বার্তাবাহকদের মাঝে পার্থক্য করতে চায়, এবং বলে,“আমরা কাউকে বিশ্বাস করি এবং কাউকে প্রত্যাখ্যান করি,”এবং মধ্যবর্তী একটি পথ অনুসরণ করতে চায়।"],
  "4:151": ["these are the real disbelievers. We have prepared for the disbelievers a shameful retribution.","এরাই হচ্ছে প্রকৃত অবিশ্বাসী। আমরা অবিশ্বাসীদের জন্য প্রস্তত রেখেছি এক লজ্জাকর শাস্তি।"],
  "4:152": ["As for those who believe in Allah and His messengers, and make no distinction among them, He will grant them their recompense. Allah is Forgiver, Most Merciful.","আর তাদের জন্য যারা আল্লাহ এবং তাঁর বার্তাবাহকদের বিশ্বাস করে,এবং তাদের মধ্যে কোন পার্থক্য করে না,তিনি তাদেরকে  প্রতিদান দিবেন। আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "4:153": ["The people of the scripture challenge you to bring down to them a book from the sky! They have asked Moses for more than that, saying, \"Show us Allah, physically.\" Consequently, the lightning struck them, as a consequence of their audacity. Additionally, they worshiped the calf, after all the miracles they had seen. Yet, we pardoned all this. We supported Moses with profound miracles.","ঐশীগ্রন্থের লোকেরা তোমাকে আকাশ থেকে তাদের কাছে একটি গ্রন্থ আনার চ্যালেঞ্জ করে! তারা মূসার কাছে এর চেয়ে বেশি চেয়েছিল, এই বলে যে,\"আমাদেরকে আল্লাহ দেখাও, স্বশরীরে। “ফলস্বরুপ, বিদ্যুৎ চমক তাদের আঘাত করেছিল, তাদের দু:সাহসের একটি ফলস্বরুপ। উপরন্তু,তারা সকল অলৌকিকতা দেখার পর বাছুর পূজা করেছিল। এরপরও, আমরা এই সব ক্ষমা করেছিলাম। আমরা মূসাকে প্রগাঢ় অলৌকিকতাসমূহ দিয়ে সমর্থন করেছিলাম।"],
  "4:154": ["And we raised Mount Sinai above them, as we took their covenant. And we said to them, \"Enter the gate humbly.\" And we said to them, \"Do not desecrate the Sabbath.\" Indeed, we took from them a solemn covenant.","এবং আমরা তাদের উপর সিনাই পর্বতকে তুলে ধরেছিলাম, যখন আমরা তাদের অঙ্গীকার নিয়েছিলাম। এবং আমারা তাদেরকে বলেছিলাম, \"বিনীতভাবে দরজায় প্রবেশ কর\"। এবং আমারা তাদেরকে বলেছিলাম, \"সাব্বাথ (বিশ্রামের দিন) কে অপবিত্র করো না।”প্রকৃতপক্ষে,আমরা তাদের থেকে একটি সুদৃঢ় অঙ্গীকার নিয়েছিলাম।"],
  "4:155": ["(They incurred condemnation) for violating their covenant, rejecting Allah's revelations, killing the prophets unjustly, and for saying, \"Our minds are made up!\" In fact, Allah is the One who sealed their minds, due to their disbelief, and this is why they fail to believe, except rarely.","(তারা শাস্তি টেনে এনেছে) তাদের অঙ্গীকার লঙ্ঘন করার জন্য, আল্লাহর প্রত্যাদেশসমূহ প্রত্যাক্ষান করার জন্য, নবীদেরকে অন্যায়ভাবে হত্যা করার জন্য, এবং বলার জন্য যে,“আমাদের সিদ্ধান্ত স্থির হয়ে গেছে!”প্রকৃতপক্ষে,আল্লাহই তিনি যিনি তাদের অন্তরে মোহর এটে দিয়েছেন, তাদের অবিশ্বাসের দরুন, এবং এ কারনেই তারা বিশ্বাস করতে ব্যর্থ হয়, খুব কম সংখ্যক ছাড়া।"],
  "4:156": ["(They are condemned) for disbelieving and uttering about Mary a gross lie.","(তারা নিন্দিত) অবিশ্বাস করার জন্য এবং মরিয়ম সম্পর্কে এক স্পষ্ট মিথ্যা বলার জন্য।"],
  "4:157": ["And for claiming that they killed the Messiah, Jesus, son of Mary, the messenger of Allah. In fact, they never killed him, they never crucified him—they were made to think that they did. All factions who are disputing in this matter are full of doubt concerning this issue. They possess no knowledge; they only conjecture. For certain, they never killed him.","এবং দাবী করার জন্য যে তারা আল্লাহর বার্তাবাহক, মরিয়মের পুত্র, ঈসা,মসিহকে হত্যা করেছে। প্রকৃত পক্ষে,তারা কখনোই তাকে হত্যা করেনি,তারা কখনোই তাকে ক্রুশ বিদ্ধ করেনি- তাদেরকে মনে করানো হয়েছিল যে তারা করেছিল। সকল বিরোধী দল যারা এই নিয়ে বিবাদ করছে,তারা এই সংক্রান্ত বিষয়ে পূর্ণ সন্দেহে রয়েছে। তাদের কোন জ্ঞান নেই, তারা শুধু অনুমান করে। নিশ্চিতই, তারা কখনই তাকে হত্যা করেনি।"],
  "4:158": ["Instead, Allah raised him to Him; Allah is Almighty, Most Wise.","বরং, আল্লাহ তাঁর কাছে তাকে উঠিয়ে নিয়েছেন; আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "4:159": ["Everyone among the people of the scripture was required to believe in him before his death. On the Day of Resurrection, he will be a witness against them.","ঐশীগ্রন্থধারীদের সকলকে তার মৃত্যুর পূর্বে তার প্রতি বিশ্বাস আনা আবশ্যক ছিল। পুনরুত্থান দিবসে,সে তাদের বিরুদ্ধে সাক্ষী হবে।"],
  "4:160": ["Due to their transgressions, we prohibited for the Jews good foods that used to be lawful for them; also for consistently repelling from the path of Allah.","তাদের সীমাতিক্রমের কারনে,আমরা ইহুদীদের জন্য ভালো খাদ্য নিষিদ্ধ করেছিলাম যা তাদের জন্য আইনসিদ্ধ ছিল; অধিকন্তু অনবরত আল্লাহর পথে  বাধা প্রদান করার জন্য।"],
  "4:161": ["And for practicing usury, which was forbidden, and for consuming the people's money illicitly. We have prepared for the disbelievers among them painful retribution.","এবং চড়া সুদ অনুশীলনের জন্য, যা নিষিদ্ধ ছিল এবং লোকেদের অর্থ অন্যায়ভাবে ভোগ করার জন্য। আমরা তাদের মধ্যকার অবিশ্বাসীদের জন্য প্রস্তুত রেখেছি যন্ত্রনাদায়ক শাস্তি।"],
  "4:162": ["As for those among them who are well founded in knowledge, and the believers, they believe in what was revealed to you, and in what was revealed before you. They are observers of the Contact Prayers (Salat), and givers of the obligatory charity (Zakat); they are believers in Allah and the Last Day. We grant these a great recompense.","আর তাদের মধ্যে যাদের জ্ঞান দৃঢ় ভিত্তির উপর প্রতিষ্ঠিত এবং বিশ্বাসীরা,তারা বিশ্বাস করে যা তোমার প্রতি অবতীর্ণ হয়েছিল এবং যা তোমার পূর্বে অবতীর্ণ হয়েছিল। তারা সংযোগ প্রার্থনাসমূহ (সালাত) পালনকারী,এবং বাধ্যতামূলক দান (যাকাত) প্রদানকারী ; তারা আল্লাহতে এবং শেয দিবসে বিশ্বাসকারী। আমরা তাদেরকে এক মহা প্রতিদান প্রদান করি।"],
  "4:163": ["We have inspired you, as we inspired Noah and the prophets after him. And we inspired Abraham, Ismail, Isaac, Jacob, the Patriarchs, Jesus, Job, Jonah, Aaron, and Solomon. And we gave David the Psalms.","আমরা তোমাকে অনুপ্রানিত করেছি,যেমন অনুপ্রানিত করেছিলাম নুহ এবং তার পরের নবীদেরকে। এবং আমরা অনুপ্রানিত করেছিলাম ইব্রাহিম, ইসমাইল, ইসহাক, ইয়াকুব, গোত্রপ্রধানদের, ঈসা,আয়ুব, ইউনুস, হারুন, এবং সোলাইমানকে। এবং আমরা দাউদকে যবুর দিয়েছিলাম।"],
  "4:164": ["Messengers we have told you about, and messengers we never told you about. And Allah spoke to Moses directly.","বার্তাবাহকরা,যাদের সম্পর্কে আমরা তোমাকে বলেছি,এবং বার্তাবাহকেরা,যাদের সম্পর্কে আমরা তোমাকে কখনো বলিনি। এবং আল্লাহ মুসার সাথে সরাসরি কথা বলেছিলেন।"],
  "4:165": ["Messengers to deliver good news, as well as warnings. Thus, the people will have no excuse when they face Allah, after all these messengers have come to them. Allah is Almighty, Most Wise.","বার্তাবাহকেরা সুসংবাদ, একই সাথে সতর্কতা প্রদান করতে আসে। এভাবে,লোকদের কোন অজুহাত থাকবে না যখন তারা আল্লাহর সম্মুখীন হয়, তাদের কাছে এই সকল বার্তাবাহকদের আসার পর। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "4:166": ["But Allah bears witness concerning what He has revealed to you; He has revealed it with His knowledge. And the angels bear witness as well, but Allah suffices as witness.","কিন্তু আল্লাহ সাক্ষ্য দেন, সে সম্বন্ধে,যা তিনি তোমার কাছে প্রকাশ করেছেন; তিনি তাঁর জ্ঞান থেকে তা প্রকাশ করেছেন। এবং ফেরেশতারা একই রকম সাক্ষ্য দেয়, কিন্তু সাক্ষী হিসেবে আল্লাহই যথেষ্ট।"],
  "4:167": ["Surely, those who disbelieve and repel from the way of Allah have strayed far astray.","নিশ্চিতভাবে,যারা অবিশ্বাস করে এবং আল্লাহর পথে বাধা দেয়, তারা বহুদূর পথভ্রষ্ট হয়েছে।"],
  "4:168": ["Those who disbelieve and transgress, Allah will not forgive them, nor will He guide them in any way;","যারা অবিশ্বাস করে এবং সীমাতিক্রম করে,আল্লাহ তাদেরকে ক্ষমা করবেন না,না তিনি তাদেরকে কোন ভাবে পথপ্রদর্শন করবেন;"],
  "4:169": ["except the way to Hell, wherein they abide forever. This is easy for Allah to do.","নরকের পথে ছাড়া,যেখানে তারা চিরকাল বসবাস করে। এটা আল্লাহর জন্য করা সহজ।"],
  "4:170": ["O people, the messenger has come to you with the truth from your Lord. Therefore, you shall believe for your own good. If you disbelieve, then to Allah belongs everything in the heavens and the earth. Allah is Omniscient, Most Wise.","হে লোকেরা,বার্তাবাহক তোমাদের কাছে তোমাদের প্রভুর পক্ষ থেকে সত্য সহকারে এসেছে। সুতরাং,তোমারা তোমাদের নিজেদের ভালোর জন্য বিশ্বাস করবে। যদি তোমরা অবিশ্বাস করো; তবে আকাশ এবং পৃথিবীর সবকিছু আল্লাহর। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "4:171": ["O people of the scripture, do not transgress the limits of your religion, and do not say about Allah except the truth. The Messiah, Jesus, the son of Mary, was a messenger of Allah, and His word that He had sent to Mary, and a revelation from Him. Therefore, you shall believe in Allah and His messengers. You shall not say, \"Trinity.\" You shall refrain from this for your own good. Allah is only one god. Be He glorified; He is much too glorious to have a son. To Him belongs everything in the heavens and everything on earth. Allah suffices as Lord and Master.","হে ঐশীগ্রন্থের লোকেরা,তোমাদের ধর্মের সীমা অতিক্রম করো না,এবং আল্লাহ সম্পর্কে সত্য ছাড়া বলবে না। মরিয়মের পুত্র, ঈসা,মসিহ ছিল আল্লাহর বার্তাবাহক, এবং তাঁর বানী যা তিনি মরিয়মের কাছে পাঠিয়েছিলেন, এবং তাঁর থেকে একটি প্রকাশনা। সুতরাং,তোমরা আল্লাহ এবং তাঁর বার্তাবাহকদের বিশ্বাস করবে। তোমরা \"ত্রিত্ব”বলবে না। তোমরা তোমাদের নিজেদের ভালোর জন্য এটি থেকে বিরত থাকবে। আল্লাহই শুধুমাত্র একক উপাস্য। তিনি মহিমান্বিত;পুত্র থাকার চেয়ে তিনি অনেক বেশি মহিমান্বিত। আসমান সমূহে যা কিছু আছে এবং পৃথিবীতে যা কিছু আছে,সব তাঁর। আল্লাহ প্রভু এবং মনিব হিসেবে যথেষ্ট।"],
  "4:172": ["The Messiah would never disdain from being a servant of Allah, nor would the closest angels. Those who disdain from worshiping Him, and are too arrogant to submit, He will summon them all before Him.","মসিহ আল্লাহর একজন দাস হওয়াকে কখনোই ঘৃণা করত না,না করত নিকটতম ফেরেশতারা। যারা তাকে উপাসনা করতে ঘৃণা করে,এবং আত্মসমর্পণ করতে খুব অহংকারী,তিনি তাদের সবাইকে  তাঁর সামনে তলব করবেন।"],
  "4:173": ["As for those who believe and lead a righteous life, He will fully recompense them, and shower them with His grace. As for those who disdain and turn arrogant, He will commit them to painful retribution. They will find no lord beside Allah, nor a savior.","আর যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,তিনি তাদেরকে পরিপূর্ণ প্রতিদান দিবেন, এবং তাদেরকে তাঁর করুনা বর্ষন করবেন। আর যারা ঘৃণা করে এবং অহংকারী হয়, তিনি তাদেরকে যন্ত্রনাদায়ক শাস্তি দিবেন। তারা আল্লাহর পাশে না পাবে কোন প্রভু,না কোন রক্ষাকারী।"],
  "4:174": ["O people, a proof has come to you from your Lord; we have sent down to you a profound beacon.","হে লোকেরা,তোমাদের প্রভু হতে তোমাদের কাছে একটি প্রমান এসেছে ; আমরা তোমাদের কাছে এক প্রগাঢ় আলোকবর্তিকা অবতীর্ণ করেছি।"],
  "4:175": ["Those who believe in Allah, and hold fast to Him, He will admit them into mercy from Him, and grace, and will guide them to Him in a straight path.","তারা যারা আল্লাহকে বিশ্বাস করে,এবং তাকে আঁকড়ে ধরে থাকে,তিনি তাদেরকে তাঁর পক্ষ থেকে করুনা,এবং দয়া মঞ্জুর করবেন, এবং তাদেরকে তাঁর দিকে পথ-প্রদর্শিত করবেন, এক সরল পথে।"],
  "4:176": ["They consult you; say, \"Allah advises you concerning the single person. If one dies and leaves no children, and he had a sister, she gets half the inheritance. If she dies first, he inherits from her, if she left no children. If there were two sisters, they get two-thirds of the inheritance. If the siblings are men and women, the male gets twice the share of the female.\" Allah thus clarifies for you, lest you go astray. Allah is fully aware of all things.","তারা তোমার সাথে পরামর্শ করে; বল, “আল্লাহ অবিবাহিত ব্যক্তির বিষয়ে তোমাদেরকে উপদেশ দেন। যদি কেউ মৃত্যু বরণ করে এবং কোন সন্তান রেখে না যায়, এবং তার একজন বোন  থাকে,সে উত্তরাধিকারের অর্ধেক পাবে। যদি সে (বোন) পূর্বে মৃত্যুবরন করে,সে (ভাই) তার থেকে উত্তরাধিকার প্রাপ্ত হবে,যদি সে কোন সন্তান রেখে না যায়। যদি দুই বোন হয়, তারা উত্তরাধিকারের দুই তৃতীয়াংশ পাবে। যদি সহোদর পুরুষ এবং নারী হয়, পুরুষ নারীর দিগুন পাবে”। আল্লাহ এভাবে তোমাদের জন্য পরিষ্কার বর্ণনা করেন, পাছে তোমরা পথভ্রষ্ট হও। আল্লাহ সবকিছু সম্পর্কে পূর্ণ অবগত।"],
  "5:1": ["O you who believe, you shall fulfill your covenants. Permitted for you to eat are the livestock, except those specifically prohibited herein. You shall not permit hunting throughout Hajj pilgrimage. Allah decrees whatever He wills.","হে তোমরা যারা বিশ্বাস কর, তোমরা তোমাদের অঙ্গীকারসমূহ পরিপূর্ন করবে। তোমাদের জন্য পশু খাওয়া অনুমোদিত, সেগুলো ছাড়া যেগুলো এখানে নির্দিষ্টভাবে নিষেধ করা হয়েছে। তোমরা পুরো হজ্ব তীর্থযাত্রা জুড়ে শিকার করাকে অনুমোদন করবে না। আল্লাহ যা ইচ্ছা জারি করেন।"],
  "5:2": ["O you who believe, do not violate the rites instituted by Allah, nor the Sacred Months, nor the animals to be offered, nor the garlands marking them, nor the people who head for the Sacred Shrine (Ka'bah) seeking blessings from their Lord and approval. Once you complete the pilgrimage, you may hunt. Do not be provoked into aggression by your hatred of people who once prevented you from going to the Sacred Masjid. You shall cooperate in matters of righteousness and piety; do not cooperate in matters that are sinful and evil. You shall observe Allah. Allah is strict in enforcing retribution.","হে যারা বিশ্বাস কর, না লঙ্ঘন করবে আল্লাহর দ্বারা প্রতিষ্ঠিত ধর্মানুষ্ঠানসমূহ, না পবিত্র মাসসমূহ, না সে পশু যেগুলো উৎসর্গ করা হবে,না মালাগুলো যা তাদের চিহ্নিত করছে,না সে লোকদেরকে যারা পবিত্র তীর্থস্থান (কাবার) অভিমুখে যায, খুঁজতে তাদের প্রভুর পক্ষ থেকে  দান এবং অনুমোদন। যখন তোমরা তীর্থযাত্রা সম্পন্ন কর, তোমরা শিকার করতে পার। আগ্রাসনে  প্ররোচিত হয়ো না,সে লোকদের প্রতি তোমাদের ঘৃনার দ্বারা,যারা এক সময় তোমাদেরকে পবিত্র মসজিদে যেতে বাধা দিয়েছিল। তোমরা সৎকর্মশীলতা এবং সৎকর্মশীলতার বিষয়ে সহযোগিতা করবে;সহযোগিতা করবে না সে বিষয়সমূহে যেগুলো পাপপূর্ন এবং মন্দ। তোমরা আল্লাহকে মান্য করবে। শাস্তি প্রয়োগে আল্লাহ কঠোর।"],
  "5:3": ["Prohibited for you are animals that die of themselves, blood, the meat of pigs, and animals dedicated to other than Allah. (Animals that die of themselves include those) strangled, struck with an object, fallen from a height, gored, attacked by a wild animal—unless you save your animal before it dies—and animals sacrificed on altars. Also prohibited is dividing the meat through a game of chance; this is an abomination. Today, the disbelievers have given up concerning (the eradication of) your religion; do not fear them and fear Me instead. Today, I have completed your religion, perfected My blessing upon you, and I have decreed Submission as the religion for you. If one is forced by famine (to eat prohibited food), without being deliberately sinful, then Allah is Forgiver, Merciful.","তোমাদের জন্য নিষিদ্ধ সেসব পশু যেগুলো নিজে নিজে মারা যায়, রক্ত, শুকরের মাংস,এবং সেসব পশু যেগুলো আল্লাহ ছাড়া অন্য কারো প্রতি উৎসর্গীকৃত। (যেসব পশু নিজে নিজে মারা যায় অন্তর্ভূক্ত হয় সেগুলোর যেগুলো) শ্বাসরোধকৃত, কোন বস্তু দ্বারা আঘাতপ্রাপ্ত, উপর থেকে পতিত, তীক্ষ্ণ বস্তু দ্বারা বিদ্ধ, বন্য পশু দ্বারা আক্রান্ত - যদি না তোমরা তোমাদের পশুকে এটি মরার পূর্বে রক্ষা কর- এবং বেদীতে উৎসর্গীকৃত পশু। আরো নিষিদ্ধ ভাগ্যের খেলার মাধ্যমে মাংস বন্টন করা ; এটি একটি ঘৃণ্য কাজ। আজ, বিশ্বাসীরা তোমাদের ধর্ম (সমূলে উৎপাটনের) বিষয়ে আশা ছেড়ে দিয়েছে; তাদেরকে ভয় করো না এবং বদলে আমাকে ভয় করো। আজ, আমি তোমাদের ধর্ম সম্পূর্ন করেছি, তোমাদের উপর আমার আশীর্বাদ যথার্থ করেছি, এবং আমি আত্মসমর্পণকে তোমাদের জন্য ধর্ম হিসেবে নিয়ম করেছি। যদি কেউ দুর্ভিক্ষের জন্য বাধ্য হয় (নিষিদ্ধ খাদ্য খেতে), ইচ্ছাকৃতভাবে পাপপূর্ন না হয়ে, তবে আল্লাহ ক্ষমাকারী, দয়ালু।"],
  "5:4": ["They consult you concerning what is lawful for them; say, \"Lawful for you are all good things, including what trained dogs and falcons catch for you.\" You train them according to Allah's teachings. You may eat what they catch for you, and mention Allah's name thereupon. You shall observe Allah. Allah is most efficient in reckoning.","তারা তোমার সাথে পরামর্শ করে,কি তাদের জন্য আইনসম্মত সে বিষয়ে; বল, “তোমাদের জন্য সকল ভালো জিনিস আইনসম্মত, এর মধ্যে আছে সেগুলো যা প্রশিক্ষণ প্রাপ্ত কুকুর এবং বাজপাখি তোমাদের জন্য ধরে আনে,”তোমরা তাদেরকে আল্লাহর শিক্ষা অনুসারে প্রশিক্ষণ দাও। তোমরা খেতে পারো যা তারা তোমাদের জন্য ধরে আনে,এবং সেগুলোর উপর আল্লাহর নাম বল। তোমরা আল্লাহকে মান্য করবে। আল্লাহ হিসাব গ্রহনে সবচেয়ে দক্ষ।"],
  "5:5": ["Today, all good food is made lawful for you. The food of the people of the scripture is lawful for you. Also, you may marry the chaste women among the believers, as well as the chaste women among the followers of previous scripture, provided you pay them their due dowries. You shall maintain chastity, not committing adultery, nor taking secret lovers. Anyone who rejects faith, all his work will be in vain, and in the Hereafter he will be with the losers.","আজ, সকল ভালো খাদ্য তোমাদের জন্য আইনসম্মত করা হলো। ঐশীগ্রন্থের লোকদের খাদ্য তোমাদের জন্য আইনসম্মত। আরও, তোমরা বিশ্বাসীদের মধ্যে চরিত্রবান নারিদের বিয়ে করতে পারো,একই ভাবে পূর্ববর্তী ঐশীগ্রন্থের অনুসারিদের মধ্যে চরিত্রবান নারিদের, এই শর্তে যে তোমরা তাদেরকে তাদের প্রাপ্য মোহর প্রদান করবে। তোমরা (যৌণ) শুদ্ধতা বজায় রাখবে,ব্যভিচারে লিপ্ত না হয়ে,না গোপন প্রেমিক/প্রেমিকা রেখে। যে কেউ বিশ্বাস প্রত্যাখ্যান করে,তার সকল কর্ম নিষ্ফল হবে,এবং পরকালে সে ক্ষতিগ্রস্থদের সাথে থাকবে।"],
  "5:6": ["O you who believe, when you observe the Contact Prayers (Salat), you shall: (1) wash your faces, (2) wash your arms to the elbows, (3) wipe your heads, and (4) wash your feet to the ankles. If you were unclean due to sexual orgasm, you shall bathe. If you are ill, or traveling, or had any digestive excretion (urinary, fecal, or gas), or had (sexual) contact with the women, and you cannot find water, you shall observe the dry ablution (Tayammum) by touching clean dry soil, then rubbing your faces and hands. Allah does not wish to make the religion difficult for you; He wishes to cleanse you and to perfect His blessing upon you, that you may be appreciative.","হে তোমরা যারা বিশ্বাস করো,যখন তোমরা সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করো,তোমরাঃ (১) তোমাদের মুখমণ্ডল ধোবে,(২) তোমাদের হাত কনুই পর্যন্ত ধোবে,(৩) তোমাদের মাথা মুছবে,এবং (৪) তোমাদের পায়ের পাতা গোড়ালি পর্যন্ত ধোবে। যদি তোমরা যৌন উত্তেজনার কারনে অপরিষ্কার থাকো,তোমরা গোসল করবে। যদি তোমরা অসুস্থ থাকো,অথবা ভ্রমনে থাকো,অথবা কোন পরিপাক ঘটিত নি:সরন থেকে থাকে (মূত্রজনিত, মলজনিত, অথবা বায়ু),অথবা নারিদের সাথে (যৌন) সংস্পর্শে এসে থাকো,এবং তোমরা পানি না পাও, তখন তোমরা শুষ্ক অজু (তায়াম্মুম) করবে পরিষ্কার শুষ্ক মাটি স্পর্শে করে,এরপর তোমাদের মুখমণ্ডল এবং হাত মুছার দ্বারা। আল্লাহ তোমাদের জন্য ধর্মকে কঠিন করতে চান না; তিনি তোমাদের পরিষ্কার করতে চান এবং তোমাদের প্রতি তাঁর আশীর্বাদ পূর্ণ করতে চান, যাতে তোমরা কৃতজ্ঞ হতে পার।"],
  "5:7": ["Remember Allah's blessing upon you, and His covenant that He covenanted with you: you said, \"We hear and we obey.\" You shall observe Allah; Allah is fully aware of the innermost thoughts.","তোমাদের প্রতি আল্লাহর আশীর্বাদকে স্মরণ করো,এবং তাঁর অঙ্গীকার যাতে তিনি তোমাদের সাথে অঙ্গীকারাবদ্ধঃ তোমরা বলেছিলে,“আমরা শুনি এবং আমরা মান্য করি।”তোমরা আল্লাহকে মান্য করবে; আল্লাহ অন্তরের গভীরতম চিন্তা সম্পর্কে পরিপূর্ণ অবগত।"],
  "5:8": ["O you who believe, you shall be absolutely equitable, and observe Allah, when you serve as witnesses. Do not be provoked by your conflicts with some people into committing injustice. You shall be absolutely equitable, for it is more righteous. You shall observe Allah. Allah is fully Cognizant of everything you do.","হে তোমরা যারা বিশ্বাস করো,তোমরা সম্পূর্ণরূপে ন্যায়পরায়ণ হবে,এবং আল্লাহকে মান্য করবে,যখন তোমরা সাক্ষী হিসাবে দায়িত্ব পালন করো। কিছু লোকের সাথে তোমাদের কলহের দরুন অবিচার করতে প্ররোচিত হইও না। তোমরা সম্পূর্ণরূপে ন্যায়পরায়ণ হবে,কারন এটা অধিকতর ন্যায়নিষ্ঠ। তোমরা আল্লাহকে মান্য করবে। আল্লাহ তোমাদের করা সবকিছু সম্পর্কে পরিপূর্ণ অবগত।"],
  "5:9": ["Allah promises those who believe and lead a righteous life forgiveness and a great recompense.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে তাদেরকে আল্লাহ ক্ষমা এবং এক মহা প্রতিদানের অঙ্গীকার করেন।"],
  "5:10": ["As for those who disbelieve and reject our revelations, they are the dwellers of Hell.","তাদের জন্য যারা অবিশ্বাস করে এবং আমাদের প্রকাশনাসমূহ প্রত্যাখ্যান করে, তারা নরকের অধিবাসী।"],
  "5:11": ["O you who believe, remember Allah's blessings upon you; when some people extended their hands to aggress against you, He protected you and withheld their hands. You shall observe Allah; in Allah the believers shall trust.","হে তোমরা যারা বিশ্বাস কর, তোমাদের উপর আল্লাহর আশীর্বাদকে স্মরণ কর; যখন কিছু লোক তোমাদের বিরুদ্ধে হামলা করতে হাত বাড়িয়েছিল, তিনি তোমাদেরকে রক্ষা করেছিলেন এবং তাদের হাতগুলো আটকে রেখেছিলেন। তোমরা আল্লাহককে মান্য করবে ; বিশ্বাসীরা আল্লাহতে আস্থা রাখবে।"],
  "5:12": ["Allah had taken a covenant from the Children of Israel, and we raised among them twelve patriarchs. And Allah said, \"I am with you, so long as you observe the Contact Prayers (Salat), give the obligatory charity (Zakat), and believe in My messengers and respect them, and continue to lend Allah a loan of righteousness. I will then remit your sins, and admit you into gardens with flowing streams. Anyone who disbelieves after this, has indeed strayed off the right path.\"","আল্লাহ ইসরাইলের সন্তানদের থেকে একটি অঙ্গীকার নিয়েছিলেন, এবং আমরা তাদের মধ্যে বার জন গোত্রপতির উত্থান করেছিলাম। এবং আল্লাহ বলেছিলেন, \"আমি তোমাদের সাথে আছি,যতক্ষণ তোমরা সংযোগ প্রার্থনাসমূহ (সালাত) পালন কর, বাধ্যতামূলক দান (যাকাত) দাও, এবং আমার বার্তাবাহকদের বিশ্বাস কর এবং তাদেরকে সম্মান কর, এবং আল্লাহকে সৎকর্মশীলতার ঋন দেয়া অব্যাহত রাখ। তাহলে আমি তোমাদের পাপসমূহ ক্ষমা করবো, এবং তোমাদেরকে প্রবাহিত ঝর্নাসহ বাগানসমূহে প্রবেশ করাব। যেকেউ এরপর অবিশ্বাস করে, অবশ্যই সঠিক পথ থেকে বিচ্যুত হয়েছে।\""],
  "5:13": ["It was a consequence of their violating the covenant that we condemned them, and we caused their hearts to become hardened. Consequently, they took the words out of context, and disregarded some of the commandments given to them. You will continue to witness betrayal from them, excepting a few of them. You shall pardon them, and disregard them. Allah loves those who are benevolent.","এটি ছিল তাদের সে অঙ্গীকার ভঙ্গের ফল যা আমরা তাদেরকে নিষেধ করেছিলাম, এবং আমরা তাদের অন্তরকে কঠিন হতে দিয়েছিলাম। ফলস্বরুপ, তারা কথাগুলো প্রসঙ্গের বাইরে নিয়েছিল, এবং তাদেরকে দেয়া কিছু আদেশকে অবহেলা করেছিল। তুমি অনবরত তাদের থেকে বিশ্বাসঘাতকতা প্রত্যক্ষ করবে,তাদের কিছু সংখ্যক ছাড়া। তুমি তাদেরকে মাফ করবে,এবং তাদেরকে উপেক্ষা করবে। আল্লাহ তাদেরকে ভালবাসেন যারা হিতৈষী।"],
  "5:14": ["Also from those who said, \"We are Christian,\" we took their covenant. But they disregarded some of the commandments given to them. Consequently, we condemned them to animosity and hatred among themselves, until the Day of Resurrection. Allah will then inform them of everything they had done.","আরো তাদের থেকে যারা বলেছিল, \"আমরা খ্রিষ্টান\",আমরা তাদের অঙ্গীকার নিয়েছিলাম। কিন্তু তারা তাদেরকে দেয়া কিছু হুকুম উপেক্ষা করেছিল। ফলস্বরুপ, আমরা শাস্তি হিসেবে দিয়েছিলাম তাদের নিজেদের মধ্যে শত্রুতা এবং ঘৃণা,পুনরুত্থান দিন পর্যন্ত।  আল্লাহ এরপর তাদেরকে জানাবেন সবকিছু যা তারা করেছিল।"],
  "5:15": ["O people of the scripture, our messenger has come to you to proclaim for you many things you have concealed in the scripture, and to pardon many other transgressions you have committed. A beacon has come to you from Allah, and a profound scripture.","হে ঐশীগ্রন্থের লোকেরা,আমাদের বার্তাবাহক তোমাদের কাছে এসেছে তোমাদের জন্য ঘোষনা করতে অনেক বিষয় যা তোমরা ঐশীগ্রন্থে গোপন করেছ, এবং ক্ষমা করতে আরো অনেক সীমালঙ্ঘন যা তোমরা করেছ। আল্লাহ থেকে তোমাদের কাছে এক আলোকবর্তিকা এসেছে,এবং একটি  জ্ঞানগর্ভ ঐশীগ্রন্থ।"],
  "5:16": ["With it, Allah guides those who seek His approval. He guides them to the paths of peace, leads them out of darkness into the light by His leave, and guides them in a straight path.","এটা দিয়ে,আল্লাহ তাদেরকে পথপ্রদর্শন করেন যারা তাঁর সম্মতি খোজ করে। তিনি তাদেরকে শান্তির পথে পথপ্রদর্শন করেন, তাঁর সম্মতিতে অন্ধকার থেকে আলোর দিকে পরিচালিত করেন, এবং একটি সরল পথে পথপ্রদর্শন করেন।"],
  "5:17": ["Pagans indeed are those who say that Allah is the Messiah, the son of Mary. Say, \"Who could oppose Allah if He willed to annihilate the Messiah, son of Mary, and his mother, and everyone on earth?\" To Allah belongs the sovereignty of the heavens and the earth, and everything between them. He creates whatever He wills. Allah is Omnipotent.","নিশ্চয়ই তারা অংশীদার সাব্যস্তকারী যারা বলে যে,মরিয়মের পুত্র, মসিহ হচ্ছে আল্লাহ, বল, “কে আল্লাহর বিরোধিতা করতে পারে,যদি তিনি নিশ্চিহ্ন করতে চান মরিয়মের পুত্র মসিহ এবং তার মাকে,এবং পৃথিবীর উপরের সকলকে?”আকাশমন্ডলী  এবং পৃথিবীর, এবং তাদের মধ্যকার সবকিছুর সার্বভৌমত্ব আল্লাহর। তিনি সৃষ্টি করেন, যা কিছু তিনি ইচ্ছা করেন। আল্লাহ সর্বশক্তিমান।"],
  "5:18": ["The Jews and the Christians said, \"We are Allah's children and His beloved.\" Say, \"Why then does He punish you for your sins? You are just humans like the other humans He created.\" He forgives whomever He wills and punishes whomever He wills. To Allah belongs the sovereignty of the heavens and the earth, and everything between them, and to Him is the final destiny.","ঈহুদি এবং খ্রিষ্টানরা বলেছিল, “আমরা আল্লাহর সন্তান এবং তাঁর অতিশয় প্রিয়।”বল, “তবে কেন তিনি তোমাদেরকে তোমাদের পাপের জন্য শাস্তি দেন? তোমরা শুধু তাঁর সৃষ্ট অন্যান্য মানুষদের মতই মানুষ”। তিনি যাকে ইচ্ছা ক্ষমা করেন এবং যাকে ইচ্ছা শাস্তি দেন। আকাশমন্ডলী  এবং পৃথিবীর, এবং তাদের মধ্যকার সবকিছুর সার্বভৌমত্ব আল্লাহর, এবং তাঁরই নিকট চূড়ান্ত নিয়তি।"],
  "5:19": ["O people of the scripture, our messenger has come to you, to explain things to you, after a period of time without messengers, lest you say, \"We did not receive any preacher or warner.\" A preacher and warner has now come to you. Allah is Omnipotent.","হে ঐশীগ্রন্থের লোকেরা,আমাদের বার্তাবাহক তোমাদের কাছে এসেছে,তোমাদের কাছে বিষয়সমূহ ব্যাখ্যা করতে,বার্তাবাহকহীন একটি সময়কালের পর, পাছে তোমরা বল, “আমরা কোন ধর্মপ্রচারক অথবা সতর্ককারী পাই নি”। একজন ধর্মপ্রচারক এবং সতর্ককারী এখন তোমাদের কাছে এসেছে। আল্লাহ সর্বশক্তিমান।"],
  "5:20": ["Recall that Moses said to his people, \"O my people, remember Allah's blessings upon you: He appointed prophets from among you, made you kings, and granted you what He never granted any other people.","স্মরণ করো, মুসা তার লোকদের বলেছিল, “হে আমার লোকেরা,তোমাদের উপর আল্লাহর আশীর্বাদকে স্মরণ করোঃ তিনি তোমাদের মধ্যে থেকে নবীদেরকে নিযুক্ত করেছিলেন, তোমাদেরকে রাজা বানিয়েছিলেন, এবং তোমাদেরকে দিয়েছিলেন, যা তিনি অন্য কোন লোকদের কখনো দেননি।"],
  "5:21": ["\"O my people, enter the holy land that Allah has decreed for you, and do not rebel, lest you become losers.\"","\"হে আমার লোকেরা,সে পবিত্র ভূমিতে প্রবেশ কর, যা আল্লাহ তোমাদের জন্য জারি করেছেন, এবং বিদ্রোহ করো না,পাছে তোমরা ক্ষতিগ্রস্ত হও\"।"],
  "5:22": ["They said, \"O Moses, there are powerful people in it, and we will not enter it, unless they get out of it. If they get out, we are entering.\"","তারা বলেছিল, \"হে মুসা,এতে শক্তিশালী লোকেরা আছে,এবং আমরা এতে প্রবেশ করবো না,যদি না তারা তা থেকে বেড়িয়ে আসে। যদি তারা বের হয়, আমরা প্রবেশ করছি।\""],
  "5:23": ["Two men who were reverent and blessed by Allah said, \"Just enter the gate. If you just enter it, you will surely prevail. You must trust in Allah, if you are believers.\"","দু'জন পুরুষ, যারা ছিল সশ্রদ্ধ এবং আল্লাহর আশীর্বাদপ্রাপ্ত, বলেছিল, \"শুধু দরজা দিয়ে প্রবেশ করো। যদি তোমরা শুধু এতে প্রবেশ কর, তোমরা নিশ্চিতভাবে জয়লাভ করবে। তোমরা অবশ্যই আল্লাহতে আস্থা রাখবে,যদি তোমরা বিশ্বাসী হও।\""],
  "5:24": ["They said, \"O Moses, we will never enter it, so long as they are in it. Therefore, go—you and your Lord —and fight. We are sitting right here.\"","তারা বলেছিল, \"হে মুসা,আমরা কখনো এতে প্রবেশ করবো না,যতক্ষণ তারা এতে রয়েছে। সেজন্য, যাও- তুমি এবং তোমার প্রভু - এবং যুদ্ধ করো। আমরা ঠিক এখানে বসে থাকছি।\""],
  "5:25": ["He said, \"My Lord, I can only control myself and my brother. So allow us to part company with the wicked people.\"","সে বলেছিল, \"আমার প্রভু,আমি শুধু আমাকে এবং আমার ভাইকে নিয়ন্ত্রণ করতে পারি। তাই আমাদেরকে মন্দ লোকদের সঙ্গ পরিত্যাগের অনুমতি দিন।\""],
  "5:26": ["He said, \"Henceforth, it is forbidden them for forty years, during which they will roam the earth aimlessly. Do not grieve over such wicked people.\"","তিনি বলেছিলেন, “এখন থেকে,এটা তাদেরকে চল্লিশ বছরের জন্য নিষিদ্ধ করা হলো,যে সময় তারা উদ্দেশ্যহীনভাবে পৃথিবীতে ঘুরে বেড়াবে।\""],
  "5:27": ["Recite for them the true history of Adam's two sons. They made an offering, and it was accepted from one of them, but not from the other. He said, \"I will surely kill you.\" He said, \"Allah accepts only from the righteous.","তাদের জন্য আদমের দুই পুত্রের সত্য ইতিহাস আবৃত্তি করো। তারা একটি উৎসর্গ নিবেদন করেছিল, এবং এটি তাদের একজন থেকে গ্রহণ করা হয়েছিল, কিন্তু অন্যজন থেকে হয়নি। সে বলেছিল, “আমি অবশ্যই তোমাকে হত্যা করবো”। সে বলেছিল, “আল্লাহ শুধুমাত্র সৎকর্মশীলদের থেকে গ্রহণ করেন।"],
  "5:28": ["\"If you extend your hand to kill me, I am not extending my hand to kill you. For I reverence Allah, Lord of the universe.","“যদি তুমি আমাকে হত্যা করতে তোমার হাত বাড়াও, আমি তোমাকে হত্যা করতে আমার হাত বাড়াচ্ছি না। কারন আমি মহাবিশ্বের প্রভু,আল্লাহকে ভক্তি করি।"],
  "5:29": ["\"I want you, not me, to bear my sin and your sin, then you end up with the dwellers of Hell. Such is the requital for the transgressors.\"","\"আমি চাই তুমি,আমি নয়, আমার পাপ এবং তোমার পাপ বহন করো,তারপর শেষ পর্যন্ত নরকের বাসিন্দাদের সাথে অন্তর্ভুক্ত হও। সীমাতিক্রমকারীদের জন্য এমনই শাস্তি”।"],
  "5:30": ["His ego provoked him into killing his brother. He killed him, and ended up with the losers.","তার অহমবোধ তার ভাইকে হত্যা করতে তাকে প্ররোচিত করলো। সে তাকে হত্যা করেছিল, এবং শেষ পর্যন্ত ক্ষতিগ্রস্থদের সাথে অন্তর্ভুক্ত হয়েছিল।"],
  "5:31": ["Allah then sent a raven to scratch the soil, to teach him how to bury his brother's corpse. He said, \"Woe to me; I failed to be as intelligent as this raven, and bury my brother's corpse.\" He became ridden with remorse.","আল্লাহ তখন একটি দাড় কাক পাঠিয়েছিলেন মাটি খুড়তে,তাকে শেখাতে কিভাবে তার ভাইয়ের মৃতদেহ সমাহিত করতে হবে। সে বলেছিল, \"দু:খ আমার; আমি ব্যর্থ হয়েছি এই দাড় কাকের মত বুদ্ধিমান হতে,এবং আমার ভাইয়ের মৃতদেহ সমাহিত করতে। \""],
  "5:32": ["Because of this, we decreed for the Children of Israel that anyone who murders any person who had not committed murder or horrendous crimes, it shall be as if he murdered all the people. And anyone who spares a life it shall be as if he spared the lives of all the people. Our messengers went to them with clear proofs and revelations, but most of them, after all this, are still transgressing.","এ কারনে,আমরা ইসরাইলের সন্তানদের জন্য জারি করেছিলাম যে,যেকেউ হত্যা করে এমন কোন ব্যক্তিকে যে হত্যা বা গুরুতর অপরাধ করেনি,এটা এমন হবে যেন সে সকল লোককে হত্যা করল। এবং যেকেউ একটি জীবন বাচায়, এটা এমন হবে যেন সে সকল লোকের জীবন বাচাল। আমাদের বার্তাবাহকরা তাদের কাছে স্পট প্রমান এবং প্রকাশনাসমূহ নিয়ে গিয়েছিল, কিন্তু তাদের অধিকাংশই, এই সবকিছুর পর, এখনও সীমালঙ্ঘন করছে।"],
  "5:33": ["The just retribution for those who fight Allah and His messenger, and commit horrendous crimes, is to be killed, or crucified, or to have their hands and feet cut off on alternate sides, or to be banished from the land. This is to humiliate them in this life, then they suffer a far worse retribution in the Hereafter.","যারা আল্লাহ এবং তাঁর বার্তাবাহকের বিরুদ্ধে যুদ্ধ করে,এবং ভয়ংকর অপরাধসমূহ করে,তাদের জন্য হত্যা হওয়া,অথবা ক্রুশবিদ্ধ হওয়া,অথবা তাদের হাত এবং পাগুলো বিপরীত দিক থেকে কেটে ফেলে দেয়া,অথবা জনগন থেকে নির্বাসিত হওয়াই হবে উচিত শাস্তি। এটি তাদেরকে এই জীবনে অপদস্থ করতে,এরপর তারা পরকালে আরো অধিক মন্দ শাস্তি ভোগ করে।"],
  "5:34": ["Exempted are those who repent before you overcome them. You should know that Allah is Forgiver, Most Merciful.","তারা নিষ্কৃতপ্রাপ্ত যারা অনুশোচনা করে,তোমরা তাদেরকে পরাস্ত করার পূর্বে। তোমাদের জানা উচিত যে,আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "5:35": ["O you who believe, you shall reverence Allah and seek the ways and means to Him, and strive in His cause, that you may succeed.","হে তোমরা যারা বিশ্বাস কর, তোমরা আল্লাহকে ভক্তি-শ্রদ্ধা করবে এবং তাঁর সান্নিধ্যের রাস্তা এবং উপায় খুজবে,এবং তাঁর উদ্দেশ্যে সংগ্রাম করবে,যাতে তোমরা সফল হতে পার।"],
  "5:36": ["Certainly, those who disbelieved, if they possessed everything on earth, even twice as much, and offered it as ransom to spare them the retribution on the Day of Resurrection, it would not be accepted from them; they have incurred a painful retribution.","অবশ্যই, তারা যারা অবিশ্বাস করে,যদি তারা পৃথিবীর সবকিছুর, এমনকি এর দিগুন পরিমান অধিকার করে, এবং পুনুরুত্থান দিবসে শাস্তি থেকে তারা নিষ্কৃতি পেতে তা মুক্তিপন হিসেবে দিতে চায়, এটা তাদের থেকে গ্রহণ করা হবে না; তারা টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "5:37": ["They will want to exit Hell, but alas, they can never exit therefrom; their retribution is eternal.","তারা নরক থেকে বের হতে চাইবে,কিন্ত হায়, তারা কখনোই সেখান থেকে বের হতে পারবে না; তাদের শাস্তি চিরস্থায়ী।"],
  "5:38": ["The thief, male or female, you shall mark their hands as a punishment for their crime, and to serve as an example from Allah. Allah is Almighty, Most Wise.","চোর, নারী হোক অথবা পুরুষ, তোমরা তাদের হাত চিহ্নিত করে দিবে তাদের অপরাধের শাস্তি হিসাবে,এবং আল্লাহ থেকে একটি উদাহরণ দিতে। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "5:39": ["If one repents after committing this crime, and reforms, Allah redeems him. Allah is Forgiver, Most Merciful.","যদি কেউ এই অপরাধ করার পর অনুশোচনা করে,এবং সংশোধিত হয়, আল্লাহ তাকে মুক্ত করেন। আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "5:40": ["Do you not know that Allah possesses the sovereignty of the heavens and the earth? He punishes whomever He wills, and forgives whomever He wills. Allah is Omnipotent.","তুমি কি জানো না যে,আল্লাহ আকাশমন্ডলী ও পৃথিবীর সার্বভৌমত্বের অধিকারী? তিনি যাকে ইচ্ছা শাস্তি দেন, এবং যাকে ইচ্ছা ক্ষমা করেন। আল্লাহ সর্বশক্তিমান।"],
  "5:41": ["O you messenger, do not be saddened by those who hasten to disbelieve among those who say, \"We believe,\" with their mouths, while their hearts do not believe. Among the Jews, some listened to lies. They listened to people who never met you, and who distorted the words out of context, then said, \"If you are given this, accept it, but if you are given anything different, beware.\" Whomever Allah wills to divert, you can do nothing to help him against Allah. Allah does not wish to cleanse their hearts. They have incurred humiliation in this world, and in the Hereafter, they will suffer a terrible retribution.","হে তুমি বার্তাবাহক, যারা দ্রুত অবিশ্বাস করে তাদের মধ্যে যারা বলে,তাদের মুখ দিয়ে \"আমরা বিশ্বাস করি,\",যখন তাদের অন্তর বিশ্বাস করে না,তাদের দ্বারা দুঃখিত হইও না। ইহুদীদের মধ্যে,কেউ কেউ মিথ্যা শুনেছিল। তারা সে লোকদের কথা শুনেছিল যারা তোমার সাথে কখনো সাক্ষাত করেনি,এবং তারা বানীগুলোকে প্রসঙ্গের বাইরে বিকৃত করেছিল, এরপর বলেছিল, \"যদি তোমাদেরকে এটি দেয়া হয়, তোমরা তা গ্রহণ করবে,কিন্তু যদি তোমাদেরকে ভিন্ন কিছু দেয়া হয়, সতর্ক হবে।\"  আল্লাহ যাকে বিমুখ করতে চান, তুমি আল্লাহর বিরুদ্ধে তাকে সাহায্য করতে কিছুই করতে পার না। আল্লাহ তাদের অন্তরকে পরিশুদ্ধ করতে চান না। তারা এই দুনিয়ায় টেনে এনেছে লাঞ্চনা,এবং পরকালে,তারা এক ভয়ানক শাস্তি ভোগ করবে।"],
  "5:42": ["They are upholders of lies, and eaters of illicit earnings. If they come to you to judge among them, you may judge among them, or you may disregard them. If you choose to disregard them, they cannot harm you in the least. But if you judge among them, you shall judge equitably. Allah loves those who are equitable.","তারা মিথ্যা মান্যকারী,এবং অবৈধ উপার্জনসমূহের ভক্ষণকারী। যদি তারা তোমার কাছে আসে তাদের মধ্যে বিচার করে দিতে,তুমি তাদের মধ্যে বিচার করতে পার, অথবা তুমি তাদেরকে উপেক্ষা করতে পার। যদি তুমি তাদেরকে উপেক্ষা করা পছন্দ কর, তারা তোমার সামান্যতম ক্ষতিও করতে পারে না। কিন্তু যদি তুমি তাদের মধ্যে বিচার কর, তুমি ন্যায়সঙ্গতভাবে বিচার করবে। আল্লাহ তাদেরকে ভালবাসেন যারা ন্যায়পরায়ণ।"],
  "5:43": ["Why do they ask you to judge among them, when they have the Torah, containing Allah's law, and they chose to disregard it? They are not believers.","কেন তারা তোমার কাছে বিচার চাইতে আসে,যখন তাদের রয়েছে তওরাত, আল্লাহর আইন সম্বলিত, এবং তারা তা উপেক্ষা করা পছন্দ করে? তারা বিশ্বাসী নয়।"],
  "5:44": ["We have sent down the Torah, containing guidance and light. Ruling in accordance with it were the Jewish prophets, as well as the rabbis and the priests, as dictated to them in Allah's scripture, and as witnessed by them. Therefore, do not reverence human beings; you shall reverence Me instead. And do not trade away My revelations for a cheap price. Those who do not rule in accordance with Allah's revelations, are the disbelievers.","আমরা তওরাত অবতীর্ণ করেছি,পথ-নির্দেশনা এবং আলো সম্বলিত। তদনুযায়ী রায় দিত ইহুদী নবীরা,একই সাথে রাবাইরা এবং পন্ডিতরা/ধর্মযাজকরা,যেভাবে আল্লাহর গ্রন্থে তাদেরকে নির্দেশ দেয়া হয়েছিল, এবং যেভাবে তারা প্রত্যক্ষ করেছিল। সেজন্য, মানব জাতিকে ভক্তি-শ্রদ্ধা করো না; বদলে আমাকে ভক্তি-শ্রদ্ধা করবে। এবং সস্তা মূল্যে আমার প্রকাশনাবলি বেচা-কেনা কর না। যার আল্লাহর প্রকাশনাবলি অনুসারে রায় দেয় না,তারা অবিশ্বাসী।"],
  "5:45": ["And we decreed for them in it that: the life for the life, the eye for the eye, the nose for the nose, the ear for the ear, the tooth for the tooth, and an equivalent injury for any injury. If one forfeits what is due to him as a charity, it will atone for his sins. Those who do not rule in accordance with Allah's revelations are the unjust.","এবং আমরা তাদের জন্য এর মধ্যে জারি করেছিলাম যে: প্রানের বিনিময়ে প্রাণ, চোখের বিনিময়ে চোখ, নাকের বিনিময়ে নাক, কানের বিনিময়ে  কান, দাতের বিনিময়ে  দাত, এবং যেকোন আঘাতের বিনিময়ে একটি সমতুল্য আঘাত। যদি কেউ একটি দান হিসেবে তার প্রাপ্য স্বেচ্ছায় দিয়ে দেয়, এটি তার পাপসমূহের জন্য প্রায়শ্চিত্ত হবে। যারা আল্লাহর প্রকাশনাবলি অনুসারে রায় দেয় না তারা অন্যায়কারী।"],
  "5:46": ["Subsequent to them, we sent Jesus, the son of Mary, confirming the previous scripture, the Torah. We gave him the Gospel, containing guidance and light, and confirming the previous scriptures, the Torah, and augmenting its guidance and light, and to enlighten the righteous.","তাদের পরবর্তীতে, আমরা মরিয়ম পুত্র ঈসাকে পাঠিয়েছিলাম, নিশ্চিত করতে পূর্ববর্তী ঐশীগ্রন্থ, তওরাত। আমরা তাকে দিয়েছিলাম ইঞ্জিল, পথ নির্দেশনা এবং আলো সংবলিত, এবং নিশ্চিত করতে পূর্ববর্তী ঐশীগ্রন্থসমূহ, তওরাত, এবং এর পথনির্দেশনা এবং আলো বৃদ্ধি করতে, এবং সৎকর্মশীলদের আলোকিত করতে।"],
  "5:47": ["The people of the Gospel shall rule in accordance with Allah's revelations therein. Those who do not rule in accordance with Allah's revelations are the wicked.","ইঞ্জিলের অধিকারী লোকেরা তন্মধ্যে বিদ্যমান আল্লাহর প্রকাশনাবলি অনুসারে রায় দিবে। যারা আল্লাহর প্রকাশনাবলি অনুসারে রায় না দেয়, তারাই মন্দ।"],
  "5:48": ["Then we revealed to you this scripture, truthfully, confirming previous scriptures, and superseding them. You shall rule among them in accordance with Allah's revelations, and do not follow their wishes if they differ from the truth that came to you. For each of you, we have decreed laws and different rites. Had Allah willed, He could have made you one congregation. But He thus puts you to the test through the revelations He has given each of you. You shall compete in righteousness. To Allah is your final destiny—all of you—then He will inform you of everything you had disputed.","এরপর আমরা তোমার কাছে এই ঐশীগ্রন্থ প্রকাশ করেছি, সত্যপূর্ণভাবে, যা পূর্ববর্তী ঐশীগ্রন্থসমূহ নিশ্চিত করে, এবং সেগুলোকে স্থলাভিষিক্ত হয়/ অতিক্রম করে। তুমি তাদের মাঝে রায় দিবে আল্লাহর প্রকাশনাবলি অনুসারে,এবং তাদের ইচ্ছার অনুসরণ করো না যদি তারা মতভেদ করে সেই সত্যে যা তোমার কাছে এসেছিল। তোমাদের প্রত্যেকের জন্য, আমরা আইন এবং পৃথক ধর্মীয় রীতিনীতিসমূহ জারি করেছি। আল্লাহ যদি চাইতেন, তিনি তোমাদেরকে এক ধর্মগোষ্ঠী করে দিতে পারতেন। কিন্তু তিনি এভাবে তোমাদেরকে পরীক্ষা করেন সেই প্রকাশনাবলির মাধ্যমে,যা তিনি তোমাদের প্রত্যেককে দিয়েছেন। তোমরা সৎকর্মে প্রতিযোগিতা করবে। আল্লাহর নিকট তোমাদের চূড়ান্ত নিয়তি-তোমাদের সকলের- এরপর তিনি তোমাদেরকে জানাবেন সবকিছু, যে বিষয়ে তোমরা বিতর্ক করেছিলে।"],
  "5:49": ["You shall rule among them in accordance with Allah's revelations to you. Do not follow their wishes, and beware lest they divert you from some of Allah's revelations to you. If they turn away, then know that Allah wills to punish them for some of their sins. Indeed, many people are wicked.","তুমি তাদের মাঝে রায় দিবে তোমার কাছে আল্লাহর প্রকাশনাবলি অনুসারে। তাদের ইচ্ছার অনুসরণ করো না,এবং সতর্ক হও পাছে তারা তোমাকে সরিয়ে দেয় তোমার প্রতি আল্লাহর কিছু প্রকাশনাবলি থেকে। যদি তারা বিমুখ হয়, তবে জানো যে আল্লাহ তাদেরকে তাদের কিছু পাপের জন্য শাস্তি দিতে চান। প্রকৃতপক্ষে,অনেক লোক পাপী।"],
  "5:50": ["Is it the law of the days of ignorance that they seek to uphold? Whose law is better than Allah's for those who have attained certainty?","এটা কি অজ্ঞতার দিনের আইন যা তারা মেনে চলতে চায়? যারা নিশ্চয়তা অর্জন করেছে তাদের জন্য আল্লাহর আইনের চেয়ে কার আইন উত্তম?"],
  "5:51": ["O you who believe, do not take certain Jews and Christians as allies; these are allies of one another. Those among you who ally themselves with these belong with them. Allah does not guide the transgressors.","হে তোমরা যারা বিশ্বাস কর, নির্দিষ্ট ইহুদী এবং খ্রিষ্টানদের মিত্র হিসেবে নিও না; এরা একে অন্যের মিত্র। তোমাদের মধ্যে যারা নিজেদেরকে তাদের মিত্র করে,তারা তাদের অন্তর্ভূক্ত। আল্লাহ সীমালঙ্ঘনকারীদের পথ-প্রদর্শন করেন না।"],
  "5:52": ["You will see those who harbor doubt in their hearts hasten to join them, saying, \"We fear lest we may be defeated.\" May Allah bring victory, or a command from Him, that causes them to regret their secret thoughts.","তুমি দেখবে যারা তাদের অন্তরে সন্দেহ পোষন করে,তারা তাদের সাথে যুক্ত হতে তাড়াহুড়ো করে,এই বলে যে,\"আমাদের ভয় হয় পাছে যদি আমরা পরাজিত হই।”আল্লাহ যেন তার পক্ষ থেকে বিজয়, অথবা একটি নির্দেশ আনেন, যা তাদেরকে তাদের গোপন চিন্তাসমূহের জন্য অনুশোচনা করাবে।"],
  "5:53": ["The believers will then say, \"Are these the same people who swore by Allah solemnly that they were with you?\" Their works have been nullified; they are the losers.","বিশ্বাসীরা তখন বলবে,\"এরাই কি সেই লোক যারা আল্লাহর নামে দৃড়ভাবে শপথ করেছিল যে তারা তোমাদের সাথে আছে?”তাদের কাজসমূহ বাতিল হয়েছে;তারাই ক্ষতিগ্রস্থ।"],
  "5:54": ["O you who believe, if you revert from your religion, then Allah will substitute in your place people whom He loves and who love Him. They will be kind with the believers, stern with the disbelievers, and will strive in the cause of Allah without fear of any blame. Such is Allah's blessing; He bestows it upon whomever He wills. Allah is Bounteous, Omniscient.","হে তোমরা যারা বিশ্বাস কর, যদি তোমরা তোমাদের ধর্ম থেকে প্রত্যাবর্তন কর, তবে আল্লাহ তোমাদের জায়গায় লোকদের আনবেন যাদেরকে তিনি ভালবাসেন এবং যারা তাকে ভালবাসে। তারা বিশ্বাসীদের সাথে দয়ালু হবে,অবিশ্বাসীদের সাথে কঠোর হবে,এবং কোন ধরনের দোষী হবার ভয় ছাড়া আল্লাহর উদ্দেশ্যে সংগ্রাম করবে। এরকমই আল্লাহর আশীর্বাদ; তিনি যাকে ইচ্ছা তা প্রদান করেন। আল্লাহ উদার, সর্বজ্ঞ।"],
  "5:55": ["Your real allies are Allah and His messenger, and the believers who observe the Contact Prayers (Salat), and give the obligatory charity (Zakat), and they bow down.","তোমাদের সত্যিকার মিত্র হচ্ছে আল্লাহ এবং তাঁর বার্তাবাহক, এবং বিশ্বাসীরা যারা সংযোগ প্রার্থনাসমূহ (সালাত) পালন করে,এবং বাধ্যতামূলক দান (যাকাত) দেয়, এবং তারা অবনত হয়।"],
  "5:56": ["Those who ally themselves with Allah and His messenger, and those who believed, belong in the party of Allah; absolutely, they are the victors.","যারা নিজেদেরকে আল্লাহ এবং তাঁর বার্তাবাহকের মিত্র করে,এবং যারা বিশ্বাস করে,তারা আল্লাহর দলের অন্তর্গত; সম্পূর্ণরূপে,তারাই বিজয়ী।"],
  "5:57": ["O you who believe, do not befriend those among the recipients of previous scripture who mock and ridicule your religion, nor shall you befriend the disbelievers. You shall reverence Allah, if you are really believers.","হে তোমরা যারা বিশ্বাস করো,পূর্ববর্তী ঐশীগ্রন্থ গ্রহণকারীদের মধ্যে তাদের সাথে বন্ধুত্ব করো না যারা তোমাদের ধর্মকে উপহাস এবং বিদ্রূপ করে,না তোমরা বন্ধুত্ব করবে অবিশ্বাসীদের সাথে। তোমরা আল্লাহকে ভক্তিশ্রদ্ধা করবে,যদি তোমরা সত্যি বিশ্বাসী হও।"],
  "5:58": ["When you call to the Contact Prayers (Salat), they mock and ridicule it. This is because they are people who do not understand.","যখন তোমরা সংযোগ প্রার্থনার (সালাতের) জন্য আহবান করো,তারা একে উপহাস এবং বিদ্রূপ করে। এটা এ কারনে যে তারা এমন লোক যারা বোঝে না।"],
  "5:59": ["Say, \"O people of the scripture, do you not hate us because we believe in Allah, and in what was revealed to us, and in what was revealed before us, and because most of you are not righteous?\"","বল, “হে ঐশীগ্রন্থের লোকেরা,তোমরা কি আমাদের এ কারনে ঘৃণা করো না যে,আমরা বিশ্বাস করি আল্লাহকে,এবং যা আমাদের কাছে প্রকাশিত হয়েছিল, এবং যা আমাদের পূর্বে প্রকাশিত হয়েছিল, এবং এ কারনে যে তোমাদের মাঝে বেশির ভাগই সৎকর্মশীল নও?”"],
  "5:60": ["Say, \"Let me tell you who are worse in the sight of Allah: those who are condemned by Allah after incurring His wrath until He made them (as despicable as) monkeys and pigs, and the idol worshipers. These are far worse, and farther from the right path.\"","বল, “আমি তোমাদেরকে বলি কারা আল্লাহর দৃষ্টিতে অধিক মন্দঃ তারা যারা আল্লাহর দ্বারা নিন্দিত হয়েছিল তার ক্রোধ টেনে আনার পর যতক্ষণ না তিনি তাদেরকে বানর এবং শুকরের মতো (ঘৃণ্য)  করে দিয়েছিলেন, এবং প্রতিমা উপাসকরা। এরা অনেক মন্দ, এবং সঠিক পথ থেকে অধিকতর দূরে।"],
  "5:61": ["When they come to you, they say, \"We believe,\" even though they were full of disbelief when they entered, and they are full of disbelief when they leave. Allah is fully aware of everything they conceal.","তারা যখন তোমার কাছে আসে,তারা বলে,\"আমরা বিশ্বাস করি,”যদিও তারা ছিল অবিশ্বাসে পূর্ন যখন তারা প্রবেশ করেছিল, এবং তারা অবিশ্বাসে পূর্ন যখন তারা চলে যায়। আল্লাহ সম্পূর্ন অবগত তাদের লুকানো সবকিছু সম্পর্কে।"],
  "5:62": ["You see many of them readily committing evil and transgression, and eating from illicit earnings. Miserable indeed is what they do.","তুমি তাদের অনেককে দেখো নির্দ্বিধায় মন্দ এবং সীমালঙ্ঘন করতে,আর অবৈধ উপার্জনসমূহ ভক্ষন করতে। সত্যিই দু:খজনক যা তারা করে।"],
  "5:63": ["If only the rabbis and the priests enjoin them from their sinful utterances and illicit earnings! Miserable indeed is what they commit.","যদি  রাবাই এবং পন্ডিতরা তাদেরকে পাপপূর্ন কথাবার্তা এবং অবৈধ উপার্জনসমূহ থেকে শুধু নিষেধ করত! সত্যিই দু:খজনক যা তারা করে।"],
  "5:64": ["The Jews even said, \"Allah's hand is tied down!\" It is their hands that are tied down. They are condemned for uttering such a blasphemy. Instead, His hands are wide open, spending as He wills. For certain, your Lord's revelations to you will cause many of them to plunge deeper into transgression and disbelief. Consequently, we have committed them to animosity and hatred among themselves until the Day of Resurrection. Whenever they ignite the flames of war, Allah puts them out. They roam the earth wickedly, and Allah dislikes the evildoers.","ইহুদীরা এমনকি বলেছিল, \"আল্লাহর হাত বাধা!”তাদের হাতই বাধা। তারা এরকম একটি মিথ্যাচার উচ্চারণ করার জন্য নিন্দিত। বরং,তাঁর হাত সম্পূর্ন উন্মুক্ত, ব্যয় করছেন যেমন তাঁর ইচ্ছা। নিশ্চিতভাবে,তোমার প্রতি তোমার আল্লাহর প্রকাশনাবলি তাদের অনেককে সীমালঙ্ঘন এবং অবিশ্বাসের আরো গভীরে নিমজ্জিত করাবে। ফলস্বরুপ, আমরা তাদেরকে দিয়েছিলাম তাদের নিজেদের মধ্যে শত্রুতা এবং ঘৃণা,পুনরুত্থান দিন পর্যন্ত। যখনই তারা যুদ্ধের অগ্নিশিখা প্রজ্জ্বলিত করে,আল্লাহ তা নিভিয়ে দেন। তারা মন্দভাবে পৃথিবীতে ঘুরে বেড়ায়, এবং আল্লাহ মন্দকর্মীদের অপছন্দ করেন।"],
  "5:65": ["If only the people of the scripture believe and lead a righteous life, we will then remit their sins, and admit them into gardens of bliss.","যদি শুধু ঐশীগ্রন্থের লোকেরা বিশ্বাস করে এবং একটি সৎকর্মশীল জীবন-যাপন করে,তবে আমরা তাদের পাপসমূহ ক্ষমা করবো,এবং তাদেরকে পরম সুখের বাগানে প্রবেশ করাব।"],
  "5:66": ["If only they would uphold the Torah and the Gospel, and what is sent down to them herein from their Lord, they would be showered with blessings from above them and from beneath their feet. Some of them are righteous, but many of them are evildoers.","যদি শুধু তারা  মেনে চলতো তওরাত ও ইঞ্জিল, এবং যা তাদের কাছে এখানে অবতীর্ণ করা হয়েছে তাদের প্রভুর পক্ষ থেকে,তাদের প্রতি আশীর্বাদ বর্ষণ করা হতো তাদের উপর থেকে এবং তাদের পায়ের নিচ থেকে। তাদের কেউ কেউ সৎ কর্মী,কিন্তু তাদের অনেকেই মন্দ কর্মী।"],
  "5:67": ["O you messenger, deliver what is revealed to you from your Lord— until you do, you have not delivered His message—and Allah will protect you from the people. Allah does not guide the disbelieving people.","হে তুমি বার্তাবাহক, পৌঁছে দাও যা তোমার কাছে প্রকাশ করা হয়েছে তোমার প্রভুর পক্ষ থেকে- যে পর্যন্ত তুমি তা না করো,তুমি তাঁর বার্তা পৌঁছে দাওনি- এবং আল্লাহ তোমাকে লোকদের থেকে রক্ষা করবেন। আল্লাহ অবিশ্বাসী লোকদেরকে পথপ্রদর্শন করেন না।"],
  "5:68": ["Say, \"O people of the scripture, you have no basis until you uphold the Torah, and the Gospel, and what is sent down to you herein from your Lord.\" For sure, these revelations from your Lord will cause many of them to plunge deeper into transgression and disbelief. Therefore, do not feel sorry for the disbelieving people.","বল, “হে ঐশীগ্রন্থের লোকেরা,তোমাদের কোন ভিত্তি নেই যতক্ষণ না তোমরা তওরাত, এবং ইঞ্জিল, এবং এখানে তোমাদের প্রভুর পক্ষ থেকে তোমাদের কাছে যা অবতীর্ণ হয়েছে তা মেনে চলো। “অবশ্যই, তোমার প্রভুর পক্ষ থেকে এই প্রকাশনাবলি তাদের অনেককেই সীমালঙ্ঘন এবং অবিশ্বাসের গভীরে নিমজ্জিত করাবে। সুতরাং,অবিশ্বাসী লোকদের জন্য দুঃখ অনুভব করো না।"],
  "5:69": ["Surely, those who believe, those who are Jewish, the converts, and the Christians; any of them who (1) believe in Allah and (2) believe in the Last Day, and (3) lead a righteous life, have nothing to fear, nor will they grieve.","অবশ্যই, তারা যারা বিশ্বাস করে,তারা যারা ইহুদী,ধর্মান্তরিত, এবং খ্রিষ্টান; তাদের যে কেউ (১) আল্লাহতে বিশ্বাস করে এবং (২) শেষ দিনে বিশ্বাস করে,এবং (৩) সৎ জীবন যাপন করে,তাদের ভয় পাবার কিছু নেই, না তারা শোক করবে।"],
  "5:70": ["We have taken a covenant from the Children of Israel, and we sent to them messengers. Whenever a messenger went to them with anything they disliked, some of them they rejected, and some they killed.","আমরা ইসরাইলের সন্তানদের থেকে একটি অঙ্গীকার নিয়েছিলাম, এবং আমরা তাদের কাছে বার্তাবাহকদের পাঠিয়েছিলাম। যখনি তাদের কাছে কোন বার্তাবাহক গিয়েছিলো এমনকিছু নিয়ে যা তাদের অপছন্দ, তারা তাদের কাউকে কাউকে প্রত্যাখ্যান করেছিল, এবং তাদের কাউকে কাউকে তারা হত্যা করেছিল।"],
  "5:71": ["They thought that they would not be tested, so they turned blind and deaf, then Allah redeemed them, but then many of them turned blind and deaf again. Allah is Seer of everything they do.","তারা ভেবেছিল যে তাদেরকে পরীক্ষা করা হবে না,তাই তারা অন্ধ এবং বধির হয়ে পড়েছিল, এরপর আল্লাহ তাদেরকে পূনরুদ্ধার করেছিলেন, কিন্তু এরপর তাদের অনেকে আবারো অন্ধ এবং বধির হয়ে পড়েছিল। আল্লাহ তাদের করা সবকিছুর দ্রষ্টা।"],
  "5:72": ["Pagans indeed are those who say that Allah is the Messiah, son of Mary. The Messiah himself said, \"O Children of Israel, you shall worship Allah; my Lord and your Lord.\" Anyone who sets up any idol beside Allah, Allah has forbidden Paradise for him, and his destiny is Hell. The wicked have no helpers.","প্রকৃতপক্ষে তারাই অংশীদার সাব্যস্তকারী যারা বলে যে মরিয়ম পুত্র, মসিহ-ই আল্লাহ। মসিহ নিজেই বলেছিল, \"হে ইসরাইলের সন্তানেরা,তোমরা আল্লাহর উপাসনা করবে; আমার প্রভু এবং তোমাদের প্রভু।”যেকেউ আল্লাহর পাশে কোন উপাস্য স্থাপন করে,আল্লাহ তার জন্য স্বর্গ নিষিদ্ধ করেছেন, এবং তার নিয়তি নরক। মন্দদের কোন সাহায্যকারী নেই।"],
  "5:73": ["Pagans indeed are those who say that Allah is a third in a trinity. There is no god except the one god. Unless they refrain from saying this, those who disbelieve among them will incur a painful retribution.","প্রকৃতপক্ষে তারাই অংশীদার সাব্যস্তকারী যারা বলে যে আল্লাহ ত্রিত্বের তৃতীয় (তিনের তৃতীয়)। এক উপাস্য ছাড়া কোন উপাস্য নেই। তারা যদি এটা বলা থেকে বিরত না থাকে,তাদের মধ্যে যারা অবিশ্বাস করে টেনে আনবে এক যন্ত্রনাদায়ক শাস্তি।"],
  "5:74": ["Would they not repent to Allah, and ask His forgiveness? Allah is Forgiver, Most Merciful.","তারা কি আল্লাহর কাছে অনুশোচনা,এবং তাঁর ক্ষমা প্রার্থনা করবে না? আল্লাহ ক্ষমাকারী,পরম দয়ালু।"],
  "5:75": ["The Messiah, son of Mary, is no more than a messenger like the messengers before him, and his mother was a saint. Both of them used to eat the food. Note how we explain the revelations for them, and note how they still deviate!","মরিয়ম পুত্র, মসিহ তার আগের বার্তাবাহকদের মত একজন বার্তাবাহকের চেয়ে বেশি কিছু নয়, এবং তার মা ছিল একজন সাধু। তাদের উভয়েই খাবার খেত। লক্ষ্য কর কিভাবে আমরা তাদের জন্য প্রকাশনাবলি ব্যাখ্যা করি,এবং লক্ষ্য কর কিভাবে তারা এরপরও পথভ্রষ্ট হয়।"],
  "5:76": ["Say, \"Would you worship beside Allah powerless idols who can neither harm you, nor benefit you? Allah is Hearer, Omniscient.\"","বল, “তোমরা কি আল্লাহর পাশে শক্তিহীন উপাস্যদের স্থাপন করবে যারা না তোমাদের ক্ষতি করতে পারে,না উপকার করতে পারে? আল্লাহ শ্রবণকারী,সর্বজ্ঞ”।"],
  "5:77": ["Say, \"O people of the scripture, do not transgress the limits of your religion beyond the truth, and do not follow the opinions of people who have gone astray, and have misled multitudes of people; they are far astray from the right path.\"","বল, “হে ঐশীগ্রন্থের লোকেরা,সত্যকে ছাড়িয়ে তোমাদের ধর্মের সীমাতিক্রম করো না,এবং সে সব লোকদের মতামতসমূহ অনুসরণ করো না যারা পথভ্রষ্ট হয়েছে,এবং বহু সংখ্যক লোককে পথভ্রষ্ট করেছে; তারা সঠিক পথ থেকে বহু দূরে পথভ্রষ্ট”।"],
  "5:78": ["Condemned are those who disbelieved among the Children of Israel, by the tongue of David and Jesus, the son of Mary. This is because they disobeyed and transgressed.","ইসরাইলের সন্তানদের মধ্যে যারা অবিশ্বাস করেছিল তারা দাউদ এবং মরিয়মের পুত্র ঈসার মুখে নিন্দিত। এটা এ কারনে যে তারা অমান্য করেছিল এবং সীমা অতিক্রম করেছিল।"],
  "5:79": ["They did not enjoin one another from committing evil. Miserable indeed is what they did.","তারা একে অন্যকে মন্দ করতে নিষেধ করেনি। তারা যা করেছিল তা সত্যিই শোচনীয়।"],
  "5:80": ["You would see many of them allying themselves with those who disbelieve. Miserable indeed is what their hands have sent forth on behalf of their souls. Allah is angry with them and, consequently, they will abide forever in retribution.","তুমি তাদের অনেককে দেখবে নিজেদের মিত্র করতে তাদেরকে যারা অবিশ্বাস করে। সত্যিই শোচনীয় তাদের  হাত তাদের আত্মার পক্ষ থেকে যা পূর্বে পাঠিয়েছে। আল্লাহ তাদের প্রতি রাগান্বিত এবং,ফলস্বরূপ, তারা চিরকাল শাস্তির মধ্যে বসবাস করবে।"],
  "5:81": ["Had they believed in Allah, and the prophet, and in what was revealed to him herein, they would not have befriended them. But many of them are evil.","যদি তারা বিশ্বাস করত আল্লাহতে,এবং নবীকে,এবং তাতে যা এখানে তার কাছে প্রকাশ করা হয়েছিল, তবে তারা তাদেরকে বন্ধু করত না। কিন্তু তাদের অনেকেই মন্দ।"],
  "5:82": ["You will find that the worst enemies of the believers are the Jews and the idol worshipers. And you will find that the closest people in friendship to the believers are those who say, \"We are Christian.\" This is because they have priests and monks among them, and they are not arrogant.","তুমি পাবে যে বিশ্বাসীদের নিকৃষ্ট শত্রু হচ্ছে ইহুদীরা এবং প্রতিমা উপাসকেরা। এবং তুমি বন্ধুত্বে বিশ্বাসীদের সবচেয়ে কাছের লোক পাবে তাদেরকে যারা বলে,\"আমরা খ্রিস্টান।”এই কারনে যে,তাদের মধ্যে রয়েছে পন্ডিতরা এবং সন্ন্যাসীরা,এবং তারা উদ্ধত নয়।"],
  "5:83": ["When they hear what was revealed to the messenger, you see their eyes flooding with tears as they recognize the truth therein, and they say, \"Our Lord, we have believed, so count us among the witnesses.","যখন তারা শোনে যা বার্তাবাহকের কাছে প্রকাশ করা হয়েছিল, তুমি দেখতে পাও তাদের চোখগুলো অশ্রুতে ভাসছে যেহেতু তারা এর মধ্যে সত্য চিনতে পারে,এবং তারা বলে,\"আমাদের প্রভু,আমরা বিশ্বাস করেছি,তাই আমাদেরকে সাক্ষীদের মাঝে গননা করুন।"],
  "5:84": ["Why should we not believe in Allah, and in the truth that has come to us, and hope that our Lord may admit us with the righteous people?","\"কেন আমাদের বিশ্বাস করা উচিত হবে না আল্লাহকে,এবং সে সত্যে যা আমাদের কাছে এসেছে,এবং আশা করা যে আমাদের প্রভু হয়তো সৎকর্মশীল লোকদের সাথে আমাদেরকে প্রবেশ করাবেন?\""],
  "5:85": ["Allah has rewarded them for saying this; He will admit them into gardens with flowing streams. They abide therein forever. Such is the reward for the righteous.","আল্লাহ তাদেরকে পুরষ্কৃত করেছেন এটা বলার জন্য; তিনি তাদেরকে প্রবেশ করাবেন প্রবাহিত ঝর্নাসহ বাগানসমূহে। তারা সেখানে চিরকাল বসবাস করে। এরকমই বিশ্বাসীদের জন্য পুরষ্কার।"],
  "5:86": ["As for those who disbelieve and reject our revelations, they are the dwellers of Hell.","আর তারা যারা অবিশ্বাস করে এবং আমাদের প্রকাশনাবলি প্রত্যাক্ষান করে,তারা নরকের অধিবাসী।"],
  "5:87": ["O you who believe, do not prohibit good things that are made lawful by Allah, and do not aggress; Allah dislikes the aggressors.","হে তোমরা যারা বিশ্বাস করো,আল্লাহ দ্বারা আইনসম্মত ভালো জিনিশগুলো নিষিদ্ধ করো না,এবং আক্রমন করো না; আল্লাহ আক্রমণকারীদের অপছন্দ করেন।"],
  "5:88": ["And eat from the good and lawful things that Allah has provided for you. You shall reverence Allah, in whom you are believers.","এবং ভালো ও আইনসম্মত বস্তুসমুহ থেকে খাও যা আল্লাহ তোমাদের জন্য দিয়েছেন। তোমরা আল্লাহকে ভক্তি শ্রদ্ধা করবে,যার প্রতি তোমরা বিশ্বাসী।"],
  "5:89": ["Allah does not hold you responsible for the mere utterance of oaths; He holds you responsible for your actual intentions. If you violate an oath, you shall atone by feeding ten poor people from the same food you offer to your own family, or clothing them, or by freeing a slave. If you cannot afford this, then you shall fast three days. This is the atonement for violating the oaths that you swore to keep. You shall fulfill your oaths. Allah thus explains His revelations to you, that you may be appreciative.","শুধু শপথ উচ্চারনের জন্য আল্লাহ তোমাদের দায়বদ্ধ করেন না; তিনি তোমাদের প্রকৃত অভিপ্রায় সমূহের জন্য তোমাদেরকে দায়বদ্ধ করেন। যদি তোমরা একটি শপথ ভঙ্গ করো,তোমরা প্রায়শ্চিত্ত করবে দশজন গরীব লোককে একই খাবার থেকে  খাওয়ানোর দ্বারা যা তোমরা তোমাদের পরিবারকে দিয়ে থাকো,অথবা তাদেরকে বস্ত্র প্রদানের দ্বারা,অথবা একজন দাস মুক্ত করার মাধ্যমে। যদি তোমরা এগুলো করতে সমর্থ না হও, তাহলে তোমরা তিন দিন রোজা রাখবে। এটাই হচ্ছে শপথ সমূহ ভঙ্গ করার প্রায়শ্চিত্ত  যা তোমরা বজায় রাখার অঙ্গীকার করেছিলে। তোমরা তোমাদের শপথ সমূহ পূর্ণ করবে। আল্লাহ এভাবে তোমাদের কাছে তাঁর প্রকাশনা বলী ব্যখ্যা করেন, যাতে তোমরা কৃতজ্ঞ হতে পারো।"],
  "5:90": ["O you who believe, intoxicants, and gambling, and the altars of idols, and the games of chance are abominations of the devil; you shall avoid them, that you may succeed.","হে তোমরা যারা বিশ্বাস করো,মাদকদ্রব্য, এবং জুয়া,এবং উপাস্যের বেদি,এবং ভাগ্যের খেলাগুলো শয়তানের ঘৃণ্য কাজ; তোমরা এগুলো এড়িয়ে চলবে,যাতে তোমরা সফল হতে পারো।"],
  "5:91": ["The devil wants to provoke animosity and hatred among you through intoxicants and gambling, and to distract you from remembering Allah, and from observing the Contact Prayers (Salat). Will you then refrain?","শয়তান চায় মাদকদ্রব্য এবং জুয়ার মাধ্যমে তোমাদের মাঝে শত্রুতা এবং ঘৃণার উদ্রেক করতে,এবং আল্লাহর স্মরণ থেকে,ও সংযোগ প্রার্থনাসমূহ (সালাত) পালন করা থেকে তোমাদের মনোযোগ সরিয়ে দিতে। তবে কি তোমরা বিরত হবে?"],
  "5:92": ["You shall obey Allah, and you shall obey the messenger, and beware. If you turn away, then know that the sole duty of our messenger is to deliver the message efficiently.","তোমরা আল্লাহকে মান্য করবে,এবং তোমরা বার্তাবাহককে মান্য করবে,এবং সতর্ক থাক। যদি তোমরা বিমুখ হও, তবে জেনো যে আমাদের বার্তাবাহকের একমাত্র দায়িত্ব হচ্ছে বার্তা পৌঁছে দেয়া।"],
  "5:93": ["Those who believe and lead a righteous life bear no guilt by eating any food, so long as they observe the commandments, believe and lead a righteous life, then maintain their piety and faith, and continue to observe piety and righteousness. Allah loves the righteous.","যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন যাপন করে তারা কোন খাদ্য খাওয়ার দ্বারা অপরাধ বহন করে না,যতক্ষণ তারা প্রত্যাদেশাবলি মেনে চলে,বিশ্বাস করে এবং একটি সৎ জীবন-যাপন করে,এরপর তাদের সৎকর্মশীলতা এবং আস্থা বজায় রাখে,এবং সৎকর্মশীলতা ও সৎকর্মশীলতা পালন অব্যাহত রাখে। আল্লাহ সৎকর্মশীলদের ভালবাসেন।"],
  "5:94": ["O you who believe, Allah will test you with some game within reach of your hands and your arrows (during pilgrimage). Allah thus distinguishes those among you who observe Him in their privacy. Those who transgress after this have incurred a painful retribution.","হে তোমরা যারা বিশ্বাস কর, আল্লাহ তোমাদের হাতের নাগালে মধ্যে কিছু শিকার এবং তোমাদের তীরগুলো দ্বারা তোমাদের পরীক্ষা করবেন (হজ্বের সময়)। আল্লাহ এভাবে তোমাদের মধ্যে তাদেরকে আলাদা করেন যারা তাঁকে তাদের একান্তে মেনে চলে। যারা এরপরে সীমালঙ্ঘন করে তারা এক যন্ত্রনাদায়ক শাস্তি টেনে এনেছে।"],
  "5:95": ["O you who believe, do not kill any game during pilgrimage. Anyone who kills any game on purpose, his fine shall be a number of livestock animals that is equivalent to the game animals he killed. The judgment shall be set by two equitable people among you. They shall make sure that the offerings reach the Ka'bah. Otherwise, he may expiate by feeding poor people, or by an equivalent fast to atone for his offense. Allah has pardoned past offenses. But if anyone returns to such an offense, Allah will avenge it. Allah is Almighty, Avenger.","হে তোমরা যারা বিশ্বাস কর, তীর্থযাত্রার সময় কোন শিকারকে বধ করো না। যেকেউ ইচ্ছাকৃতভাবে কোন শিকার বধ করে,তার জরিমানা হবে সে সংখ্যক গৃহপালিত পশু যা তার বধকৃত শিকার প্রানীগুলোর সমতুল্য। (বিচারের) রায়টি তোমাদের মধ্যে দুইজন ন্যায়পরায়ন লোকের দ্বারা ধার্য হবে। তারা নিশ্চিত করবে যে উৎসর্গগুলো কা'বায় পৌঁছায়। অন্যথায়, সে প্রায়শ্চিত্ত করতে পারে গরীব লোকদের খাওয়ানোর দ্বারা,অথবা তার অপরাধের প্রায়শ্চিত্ত করতে একটি সমতুল্য উপবাস দ্বারা। আল্লাহ অতীত অপরাধসমূহ ক্ষমা করেছেন। কিন্তু,যদি কেউ এরকম একটি অপরাধে করে বেড়ায়, আল্লাহ এর প্রতিশোধ নিবেন। আল্লাহ সর্বশক্তিমান, প্রতিশোধ গ্রহণকারী।"],
  "5:96": ["All fish of the sea are made lawful for you to eat. During pilgrimage, this may provide for you during your journey. You shall not hunt throughout the pilgrimage. You shall reverence Allah, before whom you will be summoned.","সমুদ্রের সকল মাছ তোমাদের খাওয়ার জন্য আইনসম্মত করা হল। তীর্থ যাত্রার সময়, এগুলো তোমাদের জন্য খাদ্যের যোগান হতে পারে। তোমরা তীর্থযাত্রা জুড়ে শিকার করবে না। তোমরা আল্লাহকে ভক্তি শ্রদ্ধা করবে,যার সামনে তোমাদের ডাকা হবে।"],
  "5:97": ["Allah has appointed the Ka'bah, the Sacred Masjid, to be a sanctuary for the people, and also the Sacred Months, the offerings (to the Sacred Masjid), and the garlands marking them. You should know that Allah knows everything in the heavens and the earth, and that Allah is Omniscient.","আল্লাহ নির্ধারণ করেছেন পবিত্র মসজিদ কা'বাকে লোকদের জন্য একটি উপাসনার স্থান হিসেবে,এবং পবিত্র মাসগুলোও, (পবিত্র মসজিদের প্রতি) উৎসর্গগুলো,এবং  মালাগুলো যা এগুলোকে চিহ্নিত করে। তোমাদের জানা উচিৎ যে আল্লাহ আকাশমন্ডলী ও পৃথিবীর সবকিছু জানেন, এবং যে আল্লাহ সর্বশক্তিমান।"],
  "5:98": ["Know that Allah is strict in enforcing retribution, and that Allah is Forgiving, Most Merciful.","জানো যে আল্লাহ শাস্তি প্রয়োগে কঠোর, এবং যে আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "5:99": ["The sole duty of the messenger is to deliver the message, and Allah knows everything you declare and everything you conceal.","বার্তাবাহকের একমাত্র দায়িত্ব হচ্ছে বার্তা পৌঁছে দেয়া,এবং আল্লাহ  জানেন সবকিছু যা তোমরা প্রকাশ কর এবং সবকিছু যা তোমরা গোপন করো।"],
  "5:100": ["Proclaim: \"The bad and the good are not the same, even if the abundance of the bad may impress you. You shall reverence Allah, (even if you are in the minority,) O you who possess intelligence, that you may succeed.\"","ঘোষণা করঃ “মন্দ এবং ভালো এক নয়, যদিও মন্দের আধিক্য তোমাকে প্রভাবিত করতে পারে। তুমি আল্লাহকে ভক্তি শ্রদ্ধা করবে,(এমনকি যদিও তুমি সংখ্যালঘুদের মধ্যে) হে তোমরা যারা বুদ্ধিমত্তার অধিকারী,যাতে তোমরা সফল হতে পারো।"],
  "5:101": ["O you who believe, do not ask about matters which, if revealed to you prematurely, would hurt you. If you ask about them in light of the Quran, they will become obvious to you. Allah has deliberately overlooked them. Allah is Forgiver, Clement.","হে তোমরা যারা বিশ্বাস কর, জিজ্ঞেস করো না সেসব ব্যাপারসমূহ সম্পর্কে যা,যদি তোমাদের কাছে অকালেই প্রকাশিত হয়, তোমাদের আঘাত করতে পারে। যদি তোমরা কুরআনের আলোকে সেগুলো সম্পর্কে জিজ্ঞেস কর, সেগুলো তোমাদের কাছে স্পষ্ট হয়ে উঠবে। আল্লাহ উদ্দেশ্যপ্রনোদিতভাবে সেগুলো উপেক্ষা করেছেন। আল্লাহ ক্ষমাকারী,দয়াদ্র।"],
  "5:102": ["Others before you have asked the same questions, then became disbelievers therein.","তোমাদের আগে অন্যরা একই প্রশ্নসমূহ জিজ্ঞেস করেছিল, এরপর তাতে অবিশ্বাসী হয়ে পড়েছিল।"],
  "5:103": ["Allah did not prohibit livestock that begets certain combinations of males and females, nor livestock liberated by an oath, nor the one that begets two males in a row, nor the bull that fathers ten. It is the disbelievers who invented such lies about Allah. Most of them do not understand.","আল্লাহ নিষিদ্ধ করেননি গৃহপালিত পশু যা জন্ম দেয় পুরুষ জাতীয় ও নারী জাতীয় নির্দিষ্ট মিশ্রণসমূহ, না কোন শপথের দ্বারা মুক্তকৃত গৃহপালিত পশু,না সেটি যা জন্ম দেয় পর পর দুটি পুরুষ জাতীয়, না সেই ষাড় যেটি দশটির পিতা। অবিশ্বাসীরাই আল্লাহ সম্বন্ধে এরকম মিথ্যা উদ্ভাবন করেছিল। তাদের বেশির ভাগই বোঝে না।"],
  "5:104": ["When they are told, \"Come to what Allah has revealed, and to the messenger,\" they say, \"What we found our parents doing is sufficient for us.\" What if their parents knew nothing, and were not guided?","যখন তাদের বলা হল, \"আস তাতে যা আল্লাহ প্রকাশ করেছেন, এবং বার্তাবাহকের দিকে,”তারা বলে,\"আমাদের জন্য যথেষ্ট যা আমরা আমাদের পিতা-মাতাদের করতে দেখেছিলাম।”যদি এমন হয় যে তাদের পিতা-মাতারা কিছুই না জানত, এবং না ছিল পথপ্রাপ্ত?"],
  "5:105": ["O you who believe, you should worry only about your own necks. If the others go astray, they cannot hurt you, as long as you are guided. To Allah is your ultimate destiny, all of you, then He will inform you of everything you had done.","হে তোমরা যারা বিশ্বাস কর, তোমাদের উচিত শুধু তোমাদের নিজেদের ব্যপারে ভয় করা। যদি অন্যরা পথভ্রষ্ট হয়, তারা তোমাদের আঘাত করতে পারে না,যতক্ষণ তোমরা পথপ্রাপ্ত আছ। আল্লাহর কাছে তোমাদের চুড়ান্ত নিয়তি,তোমাদের সবার, তখন তিনি তোমাদেরকে অবগত করবেন যা কিছু তোমরা করেছিল।"],
  "5:106": ["O you who believe, witnessing a will when one of you is dying shall be done by two equitable people among you. If you are traveling, then two others may do the witnessing. After observing the Contact Prayer (Salat), let the witnesses swear by Allah, to alleviate your doubts: \"We will not use this to attain personal gains, even if the testator is related to us. Nor will we conceal Allah's testimony. Otherwise, we would be sinners.\"","হে তোমরা যারা বিশ্বাস করো,তোমাদের কেউ যখন মারা যাচ্ছে,তখন অছিয়তনামার সাক্ষী হওয়ার কাজ সম্পন্ন হবে তোমাদের মাঝে দুজন ন্যায়পরায়ণ লোক দ্বারা। যদি তোমরা ভ্রমণরত থাকো,তখন অন্য দুজন সাক্ষী হওয়ার কাজ করতে পারে। সংযোগ প্রার্থনা (সালাত) সম্পন্ন করার পর, তোমাদের সন্দেহ দূর করার জন্য সাক্ষীরা আল্লাহর নামে শপথ করবেঃ “আমরা ব্যক্তিগত লাভ প্রাপ্তির জন্য এটি ব্যবহার করবো না,এমন কি যদিও অছিয়তকারী আমাদের সাথে সম্পর্কযুক্ত হয়। না আমরা আল্লাহর সাক্ষ্য গোপন করবো। অন্যথায়, আমরা পাপী হবো”।"],
  "5:107": ["If the witnesses are found to be guilty of bias, then two others shall be asked to take their places. Choose two persons who were victimized by the first witnesses, and let them swear by Allah: \"Our testimony is more truthful than theirs; we will not be biased. Otherwise, we will be transgressors.\"","যদি সাক্ষীগনের মধ্যে পক্ষপাতগ্রস্থ হওয়ার অপরাধ পাওয়া যায়, তখন অন্য দু'জনকে তাদের স্থান নেয়ার জন্য অনুরোধ করা হবে। পছন্দ করো দুজন ব্যক্তি যারা প্রথম সাক্ষীগনের দ্বারা ক্ষতির শিকার, এবং তাদেরকে আল্লাহর নামে শপথ করতে দাওঃ “আমাদের সাক্ষ্য তাদের চেয়ে অধিক সত্যপূর্ন;আমরা পক্ষপাতদুষ্ট হবো না। অন্যথায়, আমরা সীমাতিক্রমকারী হবো।\""],
  "5:108": ["This is more apt to encourage an honest testimony on their part, fearing that their oath may be disregarded like that of the previous witnesses. You shall observe Allah and listen. Allah does not guide the wicked.","তাদেরকে সৎ সাক্ষ্য দিতে উৎসাহিত করা অধিক সঙ্গত, ভয় করে যে তাদের শপথ হয়তো পূর্বের সাক্ষিদের মতো অবিবেচিত হবে। তোমরা আল্লাহকে মান্য করবে এবং শোন। আল্লাহ মন্দদের পথ প্রদর্শন করেন না।"],
  "5:109": ["The day will come when Allah will summon the messengers and ask them, \"How was the response to you?\" They will say, \"We have no knowledge. You are the Knower of all secrets.\"","সে দিন আসবে যখন আল্লাহ বার্তাবাহকদের আহবান করবেন এবং তাদের জিজ্ঞেস করবেন, \"তোমাদের প্রতি কেমন সাড়া দেয়া হয়েছিল?” তারা বলবে,“আমাদের কোন জ্ঞান নেই। আপনি সকল গোপন বিষয়ের জ্ঞাতা”।"],
  "5:110": ["Allah will say, \"O Jesus, son of Mary, remember My blessings upon you and your mother. I supported you with the Holy Spirit, to enable you to speak to the people from the crib, as well as an adult. I taught you the scripture, wisdom, the Torah, and the Gospel. Recall that you created from clay the shape of a bird by My leave, then blew into it, and it became a live bird by My leave. You healed the blind and the leprous by My leave, and revived the dead by My leave. Recall that I protected you from the Children of Israel who wanted to hurt you, despite the profound miracles you had shown them. The disbelievers among them said, 'This is obviously magic.'","আল্লাহ বলবেন, “হে মরিয়ম পুত্র- ঈসা,তোমার এবং তোমার মাতার প্রতি আমার অনুগ্রহ স্মরণ করো। আমি পবিত্র আত্মার দ্বারা তোমাকে সহায়তা করেছিলাম, কোলে থাকা অবস্থায় সেই সাথে একজন পূর্ন বয়স্ক অবস্থায় লোকদের সাথে কথা বলায় সক্ষম করতে। আমি তোমাকে শিখিয়েছিলাম ঐশীগ্রন্থ, প্রজ্ঞা,তওরাত, ও ইঞ্জিল। স্মরণ করো,তুমি কাদা থেকে পাখির আকৃতি তৈরি করেছিলে আমার অনুমতিতে,এরপর তাতে ফু দিয়েছিলে,এবং তা একটি জীবন্ত পাখি হয়ে গিয়েছিল আমার অনুমতিতে। তুমি অন্ধ ও কুষ্ঠ রোগীকে নিরাময় করেছিলে আমার অনুমতিতে,এবং মৃতকে পুনরুজ্জীবিত করেছিলে আমার অনুমতিতে। স্মরণ করো,আমি তোমাকে ইসরাইলের সন্তানদের থেকে রক্ষা করেছিলাম যারা তোমার ক্ষতি করতে চেয়েছিল, প্রগাড় অলৌকিকতা সত্ত্বেও যা তুমি তাদেরকে দেখিয়েছিলে। তাদের মধ্যকার অবিশ্বাসীরা বলেছিল, ‘এটি সুস্পষ্ট জাদু”।"],
  "5:111": ["\"Recall that I inspired the disciples: 'You shall believe in Me and My messenger.' They said, 'We have believed, and bear witness that we are submitters.' \"","\"স্মরণ কর যে আমি অনুসারীদের অনুপ্রাণিত করেছিলাম: 'তোমরা আমাকে ও আমার বার্তাবাহককে বিশ্বাস করবে।'তারা বলেছিল, 'আমরা বিশ্বাস করেছি,এবং সাক্ষী থাকুন যে আমরা আত্মসমর্পণকারী।' \""],
  "5:112": ["Recall that the disciples said, \"O Jesus, son of Mary, can your Lord send down to us a feast from the sky?\" He said, \"You should reverence Allah, if you are believers.\"","স্মরণ কর যে অনুসারীরা বলেছিল, \"হে মরিয়ম পুত্র-ঈসা,তোমার প্রভু কি আকাশ থেকে আমাদের কাছে কোন ভোজ পাঠাতে পারেন?”সে বলেছিল, \"তোমাদের উচিত আল্লাহকে ভক্তি-শ্রদ্ধা করা,যদি তোমরা বিশ্বাসী হও।"],
  "5:113": ["They said, \"We wish to eat from it, and to reassure our hearts, and to know for sure that you have told us the truth. We will serve as witnesses thereof.\"","তারা বলেছিল, \"আমরা চাই এর থেকে খেতে,এবং আমাদের অন্তরকে আশ্বস্ত করতে,এবং নিশ্চিত জানতে যে তুমি আমাদের সত্য বলেছ। আমরা এর সাক্ষী হিসেবে কাজ করবো।\""],
  "5:114": ["Said Jesus, the son of Mary, \"Our god, our Lord, send down to us a feast from the sky. Let it bring plenty for each and every one of us, and a sign from You. Provide for us; You are the best Provider.\"","মরিয়ম পুত্র ঈসা বলেছিল, \"আমাদের উপাস্য, আমাদের প্রভু,আমাদের কাছে আকাশ হতে একটি ভোজ অবতীর্ণ করুন। এটি যেন আমাদের প্রত্যেকের জন্য প্রচুর হয়, এবং আপনার পক্ষ থেকে একটি নিদর্শন হয়। আমাদের জন্য প্রদান করুন; আপনি সর্বোত্তম দাতা।\""],
  "5:115": ["Allah said, \"I am sending it down. Anyone among you who disbelieves after this, I will punish him as I never punished anyone else.\"","আল্লাহ বলেছিলেন, \"আমি তা অবতীর্ণ করছি। তোমাদের মধ্যে যেকেউ এরপর অবিশ্বাস করে,আমি তাকে শাস্তি দিব যা আমি কখনো কাউকে দেইনি।\""],
  "5:116": ["Allah will say, “O Jesus, son of Mary, did you say to the people, ‘Make me and my mother idols beside Allah’?” He will say, “Be You glorified. I could not utter what was not right. Had I said it, You already would have known it. You know my thoughts, and I do not know Your thoughts. You know all the secrets.","আল্লাহ বলবেন, “হে মরিয়ম পুত্র-ঈসা,তুমি কি লোকদের বলেছিলে যে,‘আমাকে আর আমার মাকে আল্লাহর পাশে উপাস্য বানাও?’ সে বলবে,“আপনি মহিমান্বিত। আমি বলতে পারতাম না, যা সঠিক না। আমি যদি তা বলে থাকতাম, আপনি ইতোমধ্যে তা জেনে যেতেন। আপনি আমার চিন্তাগুলো জানেন, এবং আমি আপনার চিন্তাগুলো জানি না। আপনি সকল রহস্য জানেন।"],
  "5:117": ["\"I told them only what You commanded me to say, that: 'You shall worship Allah, my Lord and your Lord.' I was a witness among them for as long as I lived with them. When You terminated my life on earth, You became the Watcher over them. You witness all things.","আমি তাদেরকে  শুধুমাত্র তা-ই বলেছিলাম যা আপনি আমাকে বলতে হুকুম করেছিলেন, যেঃ ‘তোমরা আল্লাহর উপাসনা করবে,আমার প্রভু এবং তোমাদের প্রভু”। আমি তাদের মাঝে একজন সাক্ষী ছিলাম, যতো দিন আমি তাদের সাথে বেঁচে ছিলাম। যখন আপনি পৃথিবীতে আমার জীবন সমাপ্ত করেছিলেন, আপনি তাদের উপর পর্যবেক্ষক হলেন। আপনি সবকিছুর দ্রষ্টা।"],
  "5:118": ["\"If You punish them, they are Your constituents. If You forgive them, You are the Almighty, Most Wise.\"","“যদি আপনি তাদের শাস্তি দেন, তারা আপনার দাস। যদি আপনি তাদের ক্ষমা করেন, আপনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী’।"],
  "5:119": ["Allah will proclaim, \"This is a day when the truthful will be saved by their truthfulness.\" They have deserved gardens with flowing streams. They abide therein forever. Allah is pleased with them, and they are pleased with Him. This is the greatest triumph.","আল্লাহ ঘোষণা করবেন, ‘এটি এমনি এক দিন যখন সত্যবাদীরা তাদের সত্যবাদিতার দ্বারা রক্ষা পাবে’। তারা প্রবাহিত ঝর্নাসহ বাগানের উপযুক্ত হয়েছে। তারা সেখানে চিরকাল বাস করে। আল্লাহ তাদের প্রতি সন্তুষ্ট, এবং তারা তাঁর প্রতি সন্তুষ্ট। এটাই সর্বোচ্চ বিজয়।"],
  "5:120": ["To Allah belongs the sovereignty of the heavens and the earth, and everything in them, and He is Omnipotent.","আকাশমন্ডলী ও পৃথিবীর, এবং এদের মধ্যকার সবকিছুর সার্বভৌম ক্ষমতা আল্লাহর, এবং তিনি সর্বশক্তিমান।"],
  "6:1": ["Praise be to Allah, who created the heavens and the earth, and made the darkness and the light. Yet, those who disbelieve in their Lord continue to deviate.","প্রশংসা আল্লাহর, যিনি আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছেন, এবং বানিয়েছেন অন্ধকার ও আলো। এরপরেও, যারা তাদের রবকে অবিশ্বাস করে তারা পথচ্যুতিতেই রয়েছে।"],
  "6:2": ["He is the One who created you from mud, then predetermined your life span, a life span that is known only to Him. Yet, you continue to doubt.","তিনিই একজন যিনি কাঁদামাটি থেকে তোমাদের সৃষ্টি করেছেন, এরপর পূর্বনির্ধারণ করেছেন তোমাদের জীবনকাল, জীবনকাল যা শুধু তাঁরই জানা। এরপরও, তোমরা সন্দেহের মধ্যেই রয়েছ।"],
  "6:3": ["He is the one Allah in the heavens and the earth. He knows your secrets and your declarations, and He knows everything you earn.","আকাশমণ্ডলী ও পৃথিবীতে তিনিই একমাত্র আল্লাহ। তিনি তোমাদের গোপন ও তোমাদের প্রকাশ্য বিষয়াদি জানেন, এবং তিনি সবকিছু জানেন যা তোমরা উপার্জন করো।"],
  "6:4": ["No matter what kind of proof comes to them from their Lord, they turn away from it, in aversion.","যে ধরনের প্রমানই তাদের প্রভুর পক্ষ থেকে তাদের কাছে আসুক না কেন, তারা তা থেকে মুখ ফিরিয়ে নেয়, বিদ্বেষে।"],
  "6:5": ["Since they rejected the truth when it came to them, they have incurred the consequences of their heedlessness.","যেহেতু তারা প্রত্যাক্ষান করেছে সত্য যখন তা তাদের কাছে এসেছিল, তারা তাদের অমনোযোগিতার প্রতিফলসমূহ টেনে এনেছে।"],
  "6:6": ["Have they not seen how many generations before them we have annihilated? We established them on earth more than we did for you, and we showered them with blessings, generously, and we provided them with flowing streams. We then annihilated them because of their sins, and we substituted another generation in their place.","তারা কি দেখেনি, তাদের আগে আমরা কত প্রজন্মকে ধ্বংস করেছি? আমরা তাদেরকে পৃথিবীতে প্রতিষ্ঠিত করেছিলাম তোমাদেরকে যতোটা করেছিলাম তার চেয়ে বেশি,এবং আমরা তাদের প্রতি আশীর্বাদ বর্ষণ করেছিলাম, উদারভাবে,এবং আমরা তাদের দিয়েছিলাম প্রবাহিত ঝর্নাসমূহ। আমরা এরপর তাদেরকে ধ্বংস করেছিলাম তাদের পাপের কারনে,এবং আমরা প্রতিস্থাপিত করেছিলাম তাদের স্থানে অন্য প্রজন্মকে।"],
  "6:7": ["Even if we sent down to them a physical book, written on paper, and they touched it with their hands, those who disbelieved would have said, \"This is no more than clever magic.\"","এমনকি যদি আমরা তাদের প্রতি একটি বাস্তব গ্রন্থ অবতীর্ণ করতাম, কাগজে লিখিত, আর তারা তাদের হাত দিয়ে তা স্পর্শ করত, যারা অবিশ্বাস করেছে তারা বলত, “এটা সুনিপুন জাদুর চেয়ে বেশি কিছু নয়।\""],
  "6:8": ["They also said, \"If only an angel could come down with him!\" Had we sent an angel, the whole matter would have been terminated, and they would no longer be respited.","তারা আরও বলেছিল, “শুধু যদি তার সাথে একজন ফেরেশতা অবতরণ করতো!” যদি আমরা কোন ফেরেশতা পাঠাতাম, পুরো ব্যাপারটির পরিসমাপ্তি ঘটতো,এবং তারা আর কোন অবকাশ পেতো না।"],
  "6:9": ["Had we sent an angel, we would have sent him in the form of a man, and we would have kept them just as confused as they are confused now.","আমরা যদি একজন ফেরেশতা পাঠাতাম, আমরা তাকে একজন মানুষের আকারে পাঠাতাম, এবং আমরা তাদেরকে একই রকম বিভ্রান্তিতে রাখতাম এখন তারা যেরকম বিভ্রান্তিতে আছে।"],
  "6:10": ["Messengers before you have been ridiculed. It is those who mocked them who suffered the consequences of their ridiculing.","তোমার পূর্বের বার্তাবাহকদের উপহাস করা হয়েছে,যারাই তাদের উপহাস করেছিল তারা তাদের উপহাস করার প্রতিফলসমূহ ভোগ করেছিল।"],
  "6:11": ["Say, \"Roam the earth and note the consequences for the rejectors.\"","বল, \"পৃথিবীতে ভ্রমন কর এবং লক্ষ্য কর প্রত্যাক্ষানকারীদের পরিণামসমূহ।\""],
  "6:12": ["Say, \"To whom belongs everything in the heavens and the earth?\" Say, \"To Allah.\" He has decreed that mercy is His attribute. He will surely summon you all on the Day of Resurrection, which is inevitable. The ones who lose their souls are those who disbelieve.","বল, \"আকাশমন্ডলী ও পৃথিবীর সবকিছু কার?”বল, \"আল্লাহর।” দয়া হচ্ছে তাঁর গুন, যা তিনি নিয়মে পরিণত করেছেন । তিনি নিশ্চিতভাবে তোমাদের সবাইকে পুনরুত্থান দিনে ডাকবেন, যা অনিবার্য। যারাই অবিশ্বাস করে তারাই তাদের আত্মা হারায়।"],
  "6:13": ["To Him belongs everything that dwells in the night and the day. He is the Hearer, the Knower.","তাঁর অধীনেই রয়েছে সবকিছু যা বাস করে রাতে ও দিনে। তিনি শ্রোতা,জ্ঞাতা।"],
  "6:14": ["Say, \"Shall I accept other than Allah as a Lord and Master, when He is the Initiator of the heavens and the earth, and He feeds but is not fed?\" Say, \"I am commanded to be the most devoted submitter, and, 'Do not be an idol worshiper.' \"","বল, \"আমি কি প্রভু ও মনিব হিসেবে আল্লাহ ছাড়া অন্য কাউকে গ্রহন করবো,যখন তিনি আকাশমন্ডলী  ও পৃথিবীর সূচনাকারী,এবং তিনি খাওয়ান কিন্তু খান না?\" বল, \"আমি সবচেয়ে অনুগত আত্মসমর্পণকারী হতে আদেশপ্রাপ্ত হয়েছি,এবং,'প্রতিমা উপাসক হইও না।'\""],
  "6:15": ["Say, \"I fear, if I disobeyed my Lord, the retribution of an awesome day.","বল, \"যদি আমি আমার প্রভুকে অমান্য করে থাকি,আমি ভয় করি- এক ভয়ংকর দিনের শাস্তির।"],
  "6:16": ["\"Whoever is spared (the retribution), on that day, has attained His mercy. And this is the greatest triumph.\"","“যে কেউ সেদিন, (শাস্তি থেকে) নিষ্কৃতি পায়, তাঁর করুণা লাভ করেছে। আর, এটিই শ্রেষ্ঠ বিজয়।\""],
  "6:17": ["If Allah touches you with adversity, none can relieve it except He. And if He touches you with a blessing, He is Omnipotent.","যদি আল্লাহ তোমাদের দুর্দশা দেন, তিনি ব্যতিত অন্য কেউ তা লাঘব করতে পারে না। এবং তিনি যদি তোমাদেরকে সৌভাগ্য দেন, তিনি সর্বশক্তিমান।"],
  "6:18": ["He is Supreme over His creatures. He is the Most Wise, the Cognizant.","তিনি তাঁর সৃষ্টির উপর পরাক্রান্ত। তিনি সবচেয়ে জ্ঞানী,জ্ঞাত।"],
  "6:19": ["Say, \"Whose testimony is the greatest?\" Say, \"Allah's. He is the witness between me and you that this Quran has been inspired to me, to preach it to you and whomever it reaches. Indeed, you bear witness that there are other gods beside Allah.\" Say, \"I do not testify as you do; there is only one god, and I disown your idolatry.\"","বল, “কার সাক্ষ্য সর্বশ্রেষ্ঠ?” বল, “আল্লাহর। তিনি আমার ও তোমাদের মাঝে  সাক্ষী যে এই কুরআন আমার প্রতি প্রত্যাদিষ্ট হয়েছে, এর প্রচার করতে তোমাদের কাছে এবং যার কাছে এটি পৌঁছে। নিশ্চয়, তোমরা সাক্ষ্য দাও যে আল্লাহর পাশে অন্য উপাস্যরা আছে।” বল, “যেরকম তোমরা সাক্ষ্য দাও, আমি তেমন দেই না;উপাস্য তো কেবল একজনই রয়েছেন, এবং আমি তোমাদের অংশিবাদিতা অস্বীকার করি।\""],
  "6:20": ["Those to whom we have given the scripture recognize this as they recognize their own children. The ones who lose their souls are those who do not believe.","যাদেরকে আমরা ঐশীগ্রন্থ প্রদান করেছি তারা তা চেনে যেমন তারা তাদের নিজেদের সন্তানদের চেনে। যারা বিশ্বাস করে না তারাই তাদের আত্মা হারায়।"],
  "6:21": ["Who is more evil than one who lies about Allah, or rejects His revelations? The transgressors never succeed.","তার চেয়ে কে বেশি মন্দ যে আল্লাহ সম্পর্কে মিথ্যা বলে,অথবা তাঁর প্রকাশনাবলি প্রত্যাক্ষান করে? সীমালঙ্ঘনকারীরা কখনো সফল হয় না।"],
  "6:22": ["On the day when we summon them all, we will ask the idol worshipers, \"Where are the idols you set up?\"","সে দিন আমরা যখন তাদের সকলকে ডাকব, আমরা প্রতিমা উপাসকদের জিজ্ঞেস করবো,\"তোমাদের স্থাপন করা উপাস্যরা কোথায়?\""],
  "6:23": ["Their disastrous response will be, \"By Allah our Lord, we never were idol worshipers.\"","তাদের দুর্ভাগ্যমূলক উত্তর হবে,\"আমাদের প্রভু আল্লাহর নামে শপথ, আমরা কখনো প্রতিমা উপাসক ছিলাম না।\""],
  "6:24": ["Note how they lied to themselves, and how the idols they had invented have abandoned them.","লক্ষ্য কর কিভাবে তারা নিজেদের সাথে মিথ্যা বলেছিল, এবং কিভাবে তাদেরকে তাদের উদ্ভাবিত উপাস্যরা পরিত্যাগ করেছে।"],
  "6:25": ["Some of them listen to you, but we place veils on their hearts to prevent them from understanding, and deafness in their ears. Thus, no matter what kind of proof they see, they cannot believe. Thus, when they come to argue with you, the disbelievers say, \"These are tales from the past.\"","তাদের কেউ কেউ তোমাকে শোনে,কিন্তু আমরা তাদের অন্তরে পর্দা দিয়ে দেই যাতে তারা বুঝতে না পারে,এবং তাদের কানে বধিরতা দেই। সুতরাং,তারা যে ধরনের প্রমানই দেখুক না কেন, তারা বিশ্বাস করতে পারে না। সুতরাং যখন তারা তোমার সাথে তর্ক করতে আসে,অবিশ্বাসীরা বলে,\"এগুলো অতীতের গল্প-গুজব।\""],
  "6:26": ["They repel others from this (Quran), as they themselves stay away from it, and thus, they only destroy themselves without perceiving.","তারা অন্যদের এটি (কুরআন) থেকে বাধাঁ দেয়, যেমন তারা নিজেরা এটি থেকে দূরে থাকে,আর তাই, তারা না বুঝে শুধু নিজেদের ধ্বংস করে।"],
  "6:27": ["If only you could see them when they face the hellfire! They would say then, \"Woe to us. Oh, we wish if we could go back, and never reject our Lord's revelations, and join the believers.\"","যদি শুধু তোমরা তাদের দেখতে পারতে যখন তারা নরকাগ্নির মুখোমুখি হয়! তারা তখন বলবে,“আমাদের কি দুঃখ। ইশ, আমরা  যদি পিছনে ফিরে যেতে পারতাম, এবং আমাদের প্রভুর প্রকাশনাবলি কখনো প্রত্যাখ্যান না করতাম, এবং বিশ্বাসীদের সাথে যোগ দিতাম। \""],
  "6:28": ["As a matter of fact, (they only say this because) their secrets have been exposed. If they go back, they will commit exactly the same crimes. They are liars.","বাস্তবিকপক্ষে,(তারা শুধু তা বলে যেহেতু) তাদের গোপন বিষয়গুলো প্রকাশিত হয়েছে। যদি তারা ফিরে যায়, তারা ঠিক একই অপরাধসমূহ করবে। তারা মিথ্যাবাদী।"],
  "6:29": ["They say (subconsciously), \"We live only this life; we will not be resurrected.\"","তারা বলে (অবচেতনভাবে),“আমরা শুধু এই জীবনেই বাঁচি;আমরা পুনরুত্থিত হবো না”।"],
  "6:30": ["If you could only see them when they stand before their Lord! He would say, \"Is this not the truth?\" They would say, \"Yes, by our Lord.\" He would say, \"You have incurred the retribution by your disbelief.\"","যদি শুধু তুমি তাদের দেখতে পেতে যখন তারা তাদের প্রভুর সামনে দাঁড়ায়! তিনি বলবেন, “এটা কি সত্য নয়?”তারা বলবে,“হ্যাঁ,আমাদের প্রভুর শপথ।” তিনি বলবেন, “তোমরা তোমাদের অবিশ্বাসে কারণে শাস্তি টেনে এনেছ”।"],
  "6:31": ["Losers indeed are those who disbelieve in meeting Allah, until the Hour comes to them suddenly then say, \"We deeply regret wasting our lives in this world.\" They will carry loads of their sins on their backs; what a miserable load!","প্রকৃতপক্ষে তারাই ক্ষতিগ্রস্ত যারা আল্লাহর সাথে সাক্ষাতে অবিশ্বাস করে,যতক্ষণ না আকষ্মিকভাবে তাদের কাছে সেই সময় যায়, তখন বলে,\"আমরা এই দুনিয়ায় আমাদের জীবনকে অপচয় করার জন্য গভীর দু:খ প্রকাশ করি।\" তারা তাদের পাপের বোঝা তাদের পিঠে বইবে;কতই না দুর্বিষহ বোঝা!"],
  "6:32": ["The life of this world is no more than illusion and vanity, while the abode of the Hereafter is far better for the righteous. Do you not understand?!","এই দুনিয়ার জীবন বিভ্রম এবং অন্তঃসারশূন্যতা ছাড়া বেশি কিছু নয়, যখন সৎকর্মশীলদের জন্য পরকালের আবাস অনেক উত্তম। তোমরা কি বুঝ না?"],
  "6:33": ["We know that you may be saddened by what they say. You should know that it is not you that they reject; it is Allah's revelations that the wicked disregard.","আমরা জানি যে তারা যা বলে তাতে তুমি দু:খ পেতে পার। তোমার জানা উচিত যে, এ তো তুমি নও যাকে তারা প্রত্যাক্ষান করে; এ তো আল্লাহর প্রকাশনাবলি যা মন্দরা উপেক্ষা করে।"],
  "6:34": ["Messengers before you have been rejected, and they steadfastly persevered in the face of rejection. They were persecuted until our victory came to them. Such is Allah's system that will never change. The history of My messengers thus sets the precedents for you.","তোমার পূর্বের বার্তাবাহকদের প্রত্যাক্ষান করা হয়েছে,এবং তারা প্রত্যাক্ষানের মুখে দৃড়তার সাথে অবিচল ছিল। তারা নিপীড়িত হয়েছিল, যে পর্যন্ত না তাদের কাছে আমাদের বিজয় এসেছিল। এরকমই আল্লাহর পদ্ধতি, যার কখনো পরিবর্তন হবে না। আমার বার্তাবাহকদের ইতিহাস এভাবে তোমাদের জন্য দৃষ্টান্ত সৃষ্টি করে।"],
  "6:35": ["If their rejection gets to be too much for you, you should know that even if you dug a tunnel through the earth, or climbed a ladder into the sky, and produced a miracle for them (they still would not believe). Had Allah willed, He could have guided them, unanimously. Therefore, do not behave like the ignorant ones.","যদি তাদের প্রত্যাক্ষান তোমার জন্য অসহনীয় হয়ে যায়, তোমার জানা উচিত যে এমনকি যদি তুমি ভূমির মধ্য দিয়ে কোন সুরঙ্গ খুড়ঁতে,অথবা আকাশের ভিতর সিঁড়ি দিয়ে আরোহনও করতে,এবং তাদের জন্য কোন অলৌকিকতা তৈরী করতে (এরপরও তারা বিশ্বাস করতো না)। আল্লাহ যদি চাইতেন, তিনি তাদের পথ দেখাতে পারতেন, সর্বসম্মতভাবে। সেজন্য, অজ্ঞদের মতো আচরণ করো না।"],
  "6:36": ["The only ones to respond are those who listen. Allah resurrects the dead; they ultimately return to Him.","শুধুমাত্র তারা সাড়া দেবে,যারা শোনে। আল্লাহ মৃতকে পুনর্জীবিত করেন;তারা শেষ পর্যন্ত তাঁর কাছে ফিরে আসে।"],
  "6:37": ["They said, \"If only a certain sign could come down to him from his Lord!\" Say, \"Allah is able to send down a sign, but most of them do not know.\"","তারা বলেছিল, ‘যদি শুধু একটি বিশ্বাসযোগ্য নিদর্শন তার কাছে তার প্রভুর পক্ষ থেকে আসতো!” বল, “আল্লাহ একটি নিদর্শন অবতীর্ণ করতে সক্ষম, কিন্ত তাদের বেশিরভাগ জানে না”।"],
  "6:38": ["All the creatures on earth, and all the birds that fly with wings, are communities like you. We did not leave anything out of this book. To their Lord, all these creatures will be summoned.","পৃথিবীর সকল সৃষ্টি,এবং সকল পাখি যা পাখা মেলে উড়ে,তোমাদের মতো সম্প্রদায়। আমরা কোন কিছুই এই গ্রন্থের বাইরে রাখিনি। তাদের প্রভুর কাছে,এই সকল সৃষ্টিকে তলব করা হবে।"],
  "6:39": ["Those who reject our proofs are deaf and dumb, in total darkness. Whomever Allah wills, He sends astray, and whomever He wills, He leads in a straight path.","যারা আমাদের প্রমানাদি প্রত্যাক্ষান করে তারা বধির ও বোবা,পুরোপুরি অন্ধকারে। যাকে আল্লাহ চান, বিপথে পাঠান, এবং যাকে তিনি চান, এক সরল পথে পরিচালিত করেন।"],
  "6:40": ["Say, \"What if Allah's retribution came to you, or the Hour came to you: would you implore other than Allah, if you are truthful?\"","বল, “কি হবে যদি আল্লাহর শাস্তি তোমাদের কাছে এসে যায়, অথবা সে ঘণ্টা তোমাদের কাছে এসে যায়ঃ তোমরা কি আল্লাহ ছাড়া অন্যকারো কাছে মিনতি করবে,যদি তোমরা সত্যবাদী হও?”"],
  "6:41": ["The fact is: only Him you implore, and He answers your prayer, if He so wills, and you forget your idols.","বাস্তবতা হলো: শুধু তাঁর কাছেই তোমরা মিনতি করো,এবং তিনি তোমাদের প্রার্থনার উত্তর দেন, যদি তিনি এমনই চান, এবং তোমরা তোমাদের উপাস্যদের ভুলে যাও।"],
  "6:42": ["We have sent (messengers) to communities before you, and we put them to the test through adversity and hardship, that they may implore.","আমরা তোমাদের আগের সম্প্রদায়গুলোর কাছে (বার্তাবাহকদের) পাঠিয়েছি,এবং আমরা তাদেরকে প্রতিকূলতা ও কষ্ট দিয়ে পরীক্ষায় ফেলেছিলাম, যাতে তারা মিনতি করে।"],
  "6:43": ["If only they implored when our test afflicted them! Instead, their hearts were hardened, and the devil adorned their works in their eyes.","যদি শুধু তারা মিনতি করতো আমাদের পরীক্ষা যখন তাদের পীড়া দিয়েছিল! উল্টো,তাদের অন্তর কঠিন হয়ে পড়েছিল, এবং শয়তান তাদের কাজগুলোকে তাদের চোখে সুশোভিত করে রেখেছিল।"],
  "6:44": ["When they thus disregard the message given to them, we open for them the gates of everything. Then, just as they rejoice in what was given to them, we punish them suddenly; they become utterly stunned.","যখন তারা এভাবে তাদেরকে দেয়া বার্তা উপেক্ষা করে,আমরা তাদের জন্য সবকিছুর দরজা খুলে দেই। এরপর, যখনই তারা তা নিয়ে আনন্দ করে যা তাদের দেয়া হয়েছিল, আমরা অকস্মাত তাদেরকে শাস্তি দেই;তারা একেবারে হতবম্ভ হয়ে পড়ে।"],
  "6:45": ["The wicked are thus annihilated. Praise be to Allah, Lord of the universe.","মন্দরা এভাবে নিশ্চিহ্ন হয়। প্রশংসা আল্লাহর, মহাবিশ্বের প্রভু।"],
  "6:46": ["Say, \"What if Allah took away your hearing and your eyesight, and sealed your minds; which god, other than Allah, can restore these for you?\" Note how we explain the revelations, and note how they still deviate!","বল, “কি হবে যদি আল্লাহ তোমাদের শ্রবণ ও দৃষ্টিশক্তি নিয়ে নেন, এবং তোমাদের অন্তরে মোহর এঁটে দেন, আল্লাহ ছাড়া কোন উপাস্য তোমাদের জন্য এগুলো ফিরিয়ে দিতে পারে?” লক্ষ্য করো কিভাবে আমরা প্রকাশনাবলি ব্যাখ্যা করি,এবং লক্ষ্য করো কিভাবে তারা এরপরেও বিপথগামী হয়।"],
  "6:47": ["Say, \"What if Allah's retribution came to you suddenly, or after an announcement, is it not the wicked who incur annihilation?\"","বল, “কি হতো যদি আল্লাহর শাস্তি হঠাৎ করে তোমাদের কাছে আসতো,অথবা কোন ঘোষণার পর, এরা কি পাপীরা নয় যারা ধ্বংস টেনে আনে?"],
  "6:48": ["We do not send the messengers except as deliverers of good news, as well as warners. Those who believe and reform have nothing to fear, nor will they grieve.","আমরা বার্তাবাহকদের একজন সুসংবাদদাতা, আর সতর্ককারী হিসেবে ছাড়া পাঠাই না। যারা বিশ্বাস করে এবং সংশোধিত হয় তাদের ভয়ের কিছু নেই, না তারা শোক করবে।"],
  "6:49": ["As for those who reject our revelations, they incur the retribution for their wickedness.","তাদের জন্য যারা আমাদের প্রকাশনাবলি প্রত্যাক্ষান করে,তারা তাদের পাপের জন্য শাস্তি টেনে আনে।"],
  "6:50": ["Say, “I do not say to you that I possess the treasures of Allah. Nor do I know the future. Nor do I say to you that I am an angel. I simply follow what is revealed to me.\" Say, \"Is the blind the same as the seer? Do you not reflect?\"","বল, “আমি তোমাদেরকে বলি না যে আমি আল্লাহর ধনভাণ্ডারগুলোর মালিক। না আমি ভবিষ্যৎ জানি। না আমি তোমাদের বলি যে,আমি একজন ফেরেশতা। আমি কেবল তা অনুসরণ করি, যা আমার কাছে প্রকাশ করা হয়। বল, “অন্ধ কি  চক্ষুষ্মানের সমান? তোমরা কি অনুধাবন করবে না?"],
  "6:51": ["And preach with this (Quran) to those who reverence the summoning before their Lord—they have none beside Him as a Lord and Master, nor an intercessor—that they may attain salvation.","এবং এটি (কুরআন) দিয়ে প্রচার করো তাদের কাছে যারা তাদের প্রভুর সামনে সমবেত হবার ভয় করে - তাদের প্রভু এবং মনিব হিসেবে তাঁর পাশে আর কেউ নেই, না কোন সুপারিশকারী - যাতে তারা পরিত্রাণ পেতে পারে।"],
  "6:52": ["And do not dismiss those who implore their Lord day and night, devoting themselves to Him alone. You are not responsible for their reckoning, nor are they responsible for your reckoning. If you dismiss them, you will be a transgressor.","এবং তাদেরকে অগ্রাহ্য করো না যারা দিনে ও রাতে তাদের প্রভুর কাছে মিনতি করে, নিজেদেরকে একমাত্র তাঁর কাছে উৎসর্গ করে। তাদের হিসাবের জন্য তুমি দায়ী নও, না তারা তোমার হিসাবের জন্য দায়ী। যদি তুমি তাদের অগ্রাহ্য করো,তুমি একজন সীমালঙ্ঘনকারী হবে।"],
  "6:53": ["We thus test the people by each other, to let them say (mockingly), \"Are these the people among us who are blessed by Allah?\" Is Allah not aware of the appreciative ones?","আমরা লোকদের এভাবে একের দ্বারা অন্যকে পরীক্ষা করি,তাদেরকে (উপহাস করে) বলতে দিতে,\"এরাই কি আমাদের মধ্যকার সেসব লোক যারা আল্লাহর  আশীর্বাদপ্রাপ্ত?” আল্লাহ কি কৃতজ্ঞ ব্যক্তিদের সম্পর্কে অবগত নন?"],
  "6:54": ["When those who believe in our revelations come to you, you shall say, \"Salãmun 'Alaykum (Peace be upon you). Your Lord has decreed that mercy is His attribute. Thus, anyone among you who commits a transgression out of ignorance, and repents thereafter and reforms, then He is Forgiving, Most Merciful.\"","যখন তারা তোমার কাছে আসে,যারা আমাদের প্রকাশনাবলি বিশ্বাস করে,তুমি বলবে,\"সালামুন আলাইকুম (আপনার উপর শান্তি বর্ষিত হোক)। এটা তোমার প্রভুর নিয়ম যে, দয়া করা তাঁর গুন। তাই, তোমাদের মধ্যে যেকেউ অজ্ঞতাবশত একটি সীমালঙ্ঘন করে,এবং এরপরে অনুশোচনা করে এবং সংশোধিত হয়, তবে তিনি ক্ষমাশীল, পরম দয়ালু। \""],
  "6:55": ["We thus explain the revelations, and point out the ways of the wicked.","আমরা এভাবে প্রকাশনাবলি ব্যাখ্যা করি,আর পাপীদের পথগুলো দেখিয়ে দেই।"],
  "6:56": ["Say, \"I am forbidden from worshiping what you worship besides Allah.\" Say, \"I will not follow your opinions. Otherwise, I will go astray, and not be guided.\"","বল, “তোমরা আল্লাহর পাশে যার উপাসনা করো আমাকে তার উপাসনা করতে নিষেধ করা হয়”। বল, “আমি তোমাদের মতের অনুসরণ করবো না। অন্যথায়, আমি বিপথে যাব, এবং পথপ্রাপ্ত হবো না”।"],
  "6:57": ["Say, \"I have solid proof from my Lord, and you have rejected it. I do not control the retribution you challenge me to bring. Judgment belongs with Allah alone. He narrates the truth, and He is the best judge.\"","বল, “আমার কাছে আমার প্রভুর পক্ষ থেকে দৃঢ় প্রমান আছে,এবং তোমরা তা প্রত্যাক্ষান করেছ। তোমরা আমাকে যে শাস্তি আনতে চ্যালেঞ্জ করো, সে শাস্তির নিয়ন্ত্রন আমি করি না। বিচার একমাত্র আল্লাহর অধীনে। তিনি সত্য বর্ণনা করেন, এবং তিনি সর্বোত্তম বিচারক।"],
  "6:58": ["Say, \"If I controlled the retribution you challenge me to bring, the whole matter would have been terminated long ago. Allah knows best who the wicked are.\"","বল, “ তোমরা আমাকে যে শাস্তি আনার চ্যালেঞ্জ করো আমি যদি সে শাস্তির নিয়ন্ত্রন করতাম, পুরো ব্যাপারটি বহু আগেই সমাপ্ত হতো। আল্লাহ সবচেয়ে ভালো জানেন কারা সেই পাপী”।"],
  "6:59": ["With Him are the keys to all secrets; none knows them except He. He knows everything on land and in the sea. Not a leaf falls without His knowledge. Nor is there a grain in the depths of the soil. Nor is there anything wet or dry, that is not recorded in a profound record.","তাঁর কাছে সকল রহস্যের চাবি আছে;তিনি ছাড়া সেগুলো কেউ জানে না। তিনি ভূমির উপরের এবং সাগরের ভেতরের সবকিছু জানেন। তাঁর জ্ঞানের বাইরে একটি পাতাও পড়ে না। না আছে মাটির গভীরে কোন শস্যকনা। না আছে কোন আদ্র বা শুকনো কিছু,যা একটি প্রগাঢ় নথিতে নথিভুক্ত নেই।"],
  "6:60": ["He is the One who puts you to death during the night, and knows even the smallest of your actions during the day. He resurrects you every morning, until your life span is fulfilled, then to Him is your ultimate return. He will then inform you of everything you had done.","তিনিই সে সত্ত্বা যিনি তোমাদেরকে রাতের বেলায় মৃত করেন, এবং দিনের বেলায় তোমাদের করা ক্ষুদ্রতম কাজগুলোও জানেন। তিনি প্রত্যেক সকালে তোমাদের পুনুরুত্থিত করেন, যতক্ষণ না তোমাদের জীবনকাল পূর্ণ হয়, এরপর তার কাছে তোমাদের চুড়ান্ত প্রত্যাবর্তন। তখন তিনি তোমাদের সবকিছু জানাবেন যা তোমরা করেছিলে।"],
  "6:61": ["He is Supreme over His creatures, and He appoints guards to protect you. When the appointed time of death comes to any of you, our messengers put him to death without delay.","তিনি তাঁর সৃষ্টিজগতের  উপর সর্বপ্রধান, এবং তিনি তোমাদের রক্ষা করতে প্রহরী নিযুক্ত করেন। যখন মৃত্যুর নির্ধারিত সময় তোমাদের কারো কাছে আসে,আমাদের বার্তাবাহকেরা অনতিবিলম্বে তার মৃত্যু ঘটায়।"],
  "6:62": ["Then everyone is returned to Allah, their rightful Lord and Master. Absolutely, He is the ultimate judge; He is the most accurate reckoner.","তাদের ন্যয়সঙ্গত প্রভু ও মনিব, আল্লাহর কাছে প্রত্যেকে এরপর ফিরে আসে। নি:সন্দেহে,তিনি চুড়ান্ত বিচারক;তিনি সবচেয়ে নির্ভুল হিসাব গ্রহনকারী।"],
  "6:63": ["Say, \"Who can save you from the darkness of the land or the sea?\" You implore Him loudly and secretly: \"If He saves us this time, we will be eternally appreciative.\"","বল, \"স্থল বা সাগরের অন্ধকার থেকে কে তোমাদের রক্ষা করতে পারে?” তোমরা তাঁর কাছে মিনতি করো উচ্চস্বরে এবং গোপনে: \"যদি তিনি এবারের মতো আমাদের রক্ষা করেন, আমরা চিরদিন কৃতজ্ঞ থাকব।\""],
  "6:64": ["Say, \"Allah does save you this time, and other times as well, then you still set up idols besides Him.\"","বল, \"আল্লাহ এবারের মতো তোমাদের রক্ষা করেন, এবং সাথে সাথে অন্যবারও, তা সত্তেও তোমরা এরপরে তাঁর পাশে উপাস্যদের স্থাপন করো।\""],
  "6:65": ["Say, \"He is certainly able to pour upon you retribution from above you, or from beneath your feet. Or He can divide you into factions and have you taste each others' tyranny. Note how we explain the revelations, that they may understand.\"","বল, \"তিনি নি:সন্দেহে তোমাদেরকে শাস্তি দিতে সক্ষম তোমাদের উপর থেকে,অথবা তোমাদের পায়ের নিচ থেকে। অথবা তিনি তোমাদেরকে দলে-উপদলে বিভক্ত করে একে অন্যের নিপীড়ন আস্বাদন করাতে পারেন। লক্ষ্য করো কিভাবে আমরা প্রকাশনাবলি ব্যাখ্যা করি,যাতে তারা বুঝতে পারে।\""],
  "6:66": ["Your people have rejected this, even though it is the truth. Say, \"I am not a guardian over you.\"","তোমার লোকেরা এটা প্রত্যাক্ষান করেছে,যদিও এটা সত্য। বল, “আমি তোমাদের অভিভাবক নই”"],
  "6:67": ["Every prophecy herein will come to pass, and you will surely find out.","এর মধ্যকার প্রত্যেকটি ভবিষ্যদ্বাণী ঘটবে,এবং তোমরা অবশ্যই দেখতে পাবে।"],
  "6:68": ["If you see those who mock our revelations, you shall avoid them until they delve into another subject. If the devil causes you to forget, then, as soon as you remember, do not sit with such evil people.","তুমি যদি তাদেরকে দেখ যারা আমাদের প্রকাশনাবলীকে উপহাস করে,তুমি তাদেরকে এড়িয়ে যাবে যতক্ষণ না তারা অন্য বিষয়ে প্রবৃত্ত হয়। যদি শয়তান তোমাকে ভুলিয়ে দেয়, এরপর, তোমার স্মরণ হওয়া মাত্র, এমন মন্দ লোকদের সাথে বসো না।"],
  "6:69": ["The righteous are not responsible for the utterances of those people, but it may help to remind them; perhaps they may be saved.","ঐসব লোকদের কথার জন্য সৎকর্মশীলরা দায়ী নয়, তবে এটা তাদেরকে স্মরণ করিয়ে দিতে সাহায্য করতে পারে; হয়তো তারা রক্ষা পাবে ।"],
  "6:70": ["You shall disregard those who take their religion in vain, as if it is a social function, and are totally absorbed in this worldly life. Remind with this (Quran), lest a soul may suffer the consequences of its evil earnings. It has none beside Allah as a Lord and Master, nor an intercessor. If it could offer any kind of ransom, it would not be accepted. They suffer the consequences of the evil works they earn; they have incurred hellish drinks, and a painful retribution because of their disbelief.","তুমি তাদেরকে উপেক্ষা করবে যারা তাদের ধর্মকে নিরর্থক নেয়, যেন এটি কোন সামাজিক অনুষ্ঠান, এবং এই দুনিয়ার জীবনে সম্পূর্ণ নিমগ্ন। স্মরণ করিয়ে দাও এই (কুরআন) দিয়ে,পাছে কোন আত্মা এর মন্দ অর্জনের পরিণাম ভোগ করতে পারে। প্রভু এবং মনিব হিসাবে আল্লাহর পাশে এর আর কেউ নেই, না কোন সুপারিশকারি। যদি এটি কোন প্রকারের মুক্তিপন প্রদান করতে চায়, তা গ্রহণ করা হবেনা। তারা ভোগ করে তাদের অর্জন করা মন্দ কাজের ফল;তারা অর্জন করেছে নারকীয় পানীয়, এবং এক যন্ত্রণাদায়ক শাস্তি তাদের অবিশ্বাসের কারনে।"],
  "6:71": ["Say, \"Shall we implore, beside Allah, what possesses no power to benefit us or hurt us, and turn back on our heels after Allah has guided us? In that case, we would join those possessed by the devils, and rendered utterly confused, while their friends try to save them: 'Stay with us on the right path.'\" Say, \"Allah's guidance is the right guidance. We are commanded to submit to the Lord of the universe.","বল, \"আমরা কি তার কাছে মিনতি করবো,আল্লাহর পাশে, যার ক্ষমতা নেই আমাদের উপকার করার অথবা আমাদের ক্ষতি করার, এবং আল্লাহ আমাদের পথ দেখানোর পর আমরা পূর্বের অবস্থায় ফিরে যাব? সেক্ষেত্রে,আমরা তাদের সাথে যোগ দিবো যারা শয়তানদের দ্বারা আবিষ্ট, এবং একেবারে বিভ্রান্ত হয়ে পড়েছে,যখন তাদের বন্ধুরা তাদেরকে রক্ষা করার চেষ্টা করে বলে: “আমাদের সাথে সঠিক পথে থাকো।\" বলো,\"আল্লাহর পথ-প্রদর্শনই সঠিক। আমরা আদিষ্ট হই মহাবিশ্বের প্রভুর নিকট আত্মসমর্পণ করতে।"],
  "6:72": ["\"And to observe the Contact Prayers (Salat), and to reverence Him—He is the One before whom you will be summoned (for the reckoning).\"","\"এবং সংযোগ প্রার্থনাসমূহ (সালাত) পালন করতে,এবং তাঁকে ভয়-শ্রদ্ধা করতে। তিনিই সে সত্ত্বা যাঁর সামনে তোমাদের ডাকা হবে (বিচারের জন্য)।\""],
  "6:73": ["He is the One who created the heavens and the earth, truthfully. Whenever He says, \"Be,\" it is. His word is the absolute truth. All sovereignty belongs to Him the day the horn is blown. Knower of all secrets and declarations, He is the Most Wise, the Cognizant.","তিনিই সে সত্ত্বা যিনি আকাশমন্ডলী  ও পৃথিবী সৃষ্টি করেছিলেন, সত্যতার সাথে। যখনই তিনি বলেন, \"হও, ” তা হয়ে যায়। তাঁর বানী পরম সত্য। সে দিন সকল সার্বভৌমত্ব তাঁর, যখন শিঙ্গাঁয় ফুঁ দেয়া হয়। সকল গোপন ও প্রকাশ্য বিষয়ের জ্ঞাতা,তিনি পরম জ্ঞানী,জ্ঞাত।"],
  "6:74": ["Recall that Abraham said to his father Ãzer, \"How could you worship statues as gods? I see that you and your people have gone far astray.\"","স্মরণ করো যে ইব্রাহিম তার পিতা আযরকে বলেছিল, \"কেমন করে তুমি প্রতিমূর্তিগুলোকে উপাস্য হিসেবে উপাসনা করো? আমি দেখি যে তুমি এবং তোমার লোকেরা অনেক পথভ্রষ্ট হয়েছ।\""],
  "6:75": ["We showed Abraham the marvels of the heavens and the earth, and blessed him with certainty:","আমরা ইব্রাহীমকে আকাশমন্ডলী ও পৃথিবীর বিস্ময়সমূহ দেখিয়েছিলাম, এবং তাকে নিশ্চিতভাবে ধন্য করেছিলাম।"],
  "6:76": ["When the night fell, he saw a shining planet. \"Maybe this is my Lord,\" he said. When it disappeared, he said, \"I do not like (gods) that disappear.\"","যখন রাত নেমেছিল, সে একটি জ্বলজ্বলে গ্রহ দেখলো। “হতে পারে এটি আমার প্রভু,” সে বলেছিল। যখন এটি অদৃশ্য হলো,সে বললো, “আমি পছন্দ করি না (উপাস্যদের) যারা অদৃশ্য হয়ে যায়”।"],
  "6:77": ["When he saw the moon rising, he said, \"Maybe this is my Lord!\" When it disappeared, he said, \"Unless my Lord guides me, I will be with the strayers.\"","যখন সে চাঁদকে উদীয়মান দেখেছিল, সে বলেছিল, “হতে পারে এটাই আমার প্রভু!”যখন এটি অদৃশ্য হয়েছিল, সে বলেছিল, “যদি না আমার প্রভু আমাকে পথপ্রদর্শন করেন, আমি পথভ্রষ্টদের আন্তরগত হবো”।"],
  "6:78": ["When he saw the sun rising, he said, \"This must be my Lord. This is the biggest.\" But when it set, he said, \"O my people, I denounce your idolatry.","যখন সে সূর্যকে উদীয়মান দেখেছিল, সে বলেছিল, “এটি অবশ্যই আমার প্রভু হবে। এটাই সবচেয়ে বড়”। কিন্তু যখন এটি অস্ত গেল, সে বলেছিল, “হে আমার লোকেরা,আমি তোমাদের শিরককে নিন্দা করি।"],
  "6:79": ["\"I have devoted myself absolutely to the One who initiated the heavens and the earth; I will never be an idol worshiper.\"","“আমি আমার নিজেকে পুরোপুরি উৎসর্গ করেছি সে সত্ত্বার কাছে যিনি আকাশমন্ডলী ও পৃথিবীর সূচনা করেছিলেন; আমি কখনো একজন প্রতিমা উপাসক হবো না”।"],
  "6:80": ["His people argued with him. He said, \"Do you argue with me about Allah, after He has guided me? I have no fear of the idols you set up. Nothing can happen to me, unless my Lord wills it. My Lord's knowledge encompasses all things. Would you not take heed?","তার লোকেরা তার সাথে তর্ক করেছিল। সে বলেছিল, “তোমরা কি আমার সাথে আল্লাহ সম্পর্কে তর্ক করো,তিনি আমাকে পথপ্রদর্শনের পর? তোমাদের স্থাপন করা উপাস্যদের আমি ভয় করি না। আমার কিছুই হতে পারে না,যদি না আমার প্রভু তা ইচ্ছা করেন। আমার প্রভুর জ্ঞান সবকিছু পরিবেষ্টন করে আছে। তোমরা কি সতর্ক হবে না?”"],
  "6:81": ["\"Why should I fear your idols? It is you who should be afraid, since you worship instead of Allah idols that are utterly powerless to help you. Which side is more deserving of security, if you know?\"","\"আমার কেন তোমাদের অংশীদারদের ভয় পাওয়া উচিত? তোমাদেরই তো ভয় পাওয়া উচিত, যেহেতু তোমরা আল্লাহর পরিবর্তে অংশীদারদের উপাসনা করো যেগুলো তোমাদেরকে সাহায্য করতে একদম ক্ষমতাহীন। কোন দল নিরাপত্তা পাবার অধিক যোগ্য, যদি তোমরা জানতে?\""],
  "6:82": ["Those who believe, and do not pollute their belief with idol worship, have deserved the perfect security, and they are truly guided.","যারা বিশ্বাস করে,এবং তাদের বিশ্বাসকে অংশীদার উপাসনা দ্বারা কলূষিত করে না,তারা নিশ্ছিদ্র নিরাপত্তা পাবার যোগ্য, এবং তারা সত্যিকারের পথ-প্রদর্শিত।"],
  "6:83": ["Such was our argument, with which we supported Abraham against his people. We exalt whomever we will to higher ranks. Your Lord is Most Wise, Omniscient.","এরকমই ছিল আমাদের যুক্তি,যা দিয়ে আমরা ইব্রাহীমকে তার লোকদের বিপক্ষে সমর্থন করেছিলাম। আমরা উচ্চতর পদসমূহে অধিষ্ঠিত করি,যাকেই আমরা চাই। তোমার প্রভু সবচেয়ে জ্ঞানী,সর্বজ্ঞ।"],
  "6:84": ["And we granted him Isaac and Jacob, and we guided both of them. Similarly, we guided Noah before that, and from his descendants (we guided) David, Solomon, Job, Joseph, Moses, and Aaron. We thus reward the righteous.","\"এবং আমরা তাকে দিয়েছিলাম ইসহাক ও ইয়াকুব, এবং আমরা তাদের উভয়কে পথ-প্রদর্শন করেছিলাম। একইভাবে,আমরা এর আগে নুহকে পথ-প্রদর্শন করেছিলাম, এবং তার বংশধরদের থেকে (আমরা পথ-প্রদর্শন করেছিলাম) দাউদ, সোলাইমান, আইয়ুব,"],
  "6:85": ["Also, Zachariah, John, Jesus, and Elias; all were righteous.","এছাড়াও, জাকারিয়া,ইয়াহিয়া,ঈসা,এবং ইলিয়াস;সকলে ছিল সৎকর্মশীল।"],
  "6:86": ["And Ismail, Elisha, Jonah, and Lot; each of these we distinguished over all the people.","এবং ইসমাইল, আল-ইয়াসা,ইউনুস ও লুত;এদের প্রত্যেককে আমরা সকল অন্য লোকদের থেকে আলাদা করেছিলাম।"],
  "6:87": ["From among their ancestors, their descendants, and their siblings, we chose many, and we guided them in a straight path.","তাদের পূর্বপুরুষ, তাদের বংশধর, এবং তাদের সহোদরদের মধ্যে থেকে আমরা অনেককে পছন্দ করেছিলাম, এবং আমরা তাদেরকে একটি সরল পথ প্রদর্শন করেছিলাম।"],
  "6:88": ["Such is Allah's guidance, with which He guides whomever He chooses from among His servants. Had any of them fallen into idolatry, their works would have been nullified.","এমনই আল্লাহর পথনির্দেশনা,যা দিয়ে তিনি পথপ্রদর্শন করেন তাঁর দাসদের মধ্যে থেকে যাকে তিনি পছন্দ করেন। তাদের কেউ যদি শিরকীত্বে পতিত হতো,তাদের কাজগুলো বাতিল হয়ে  যেতো।"],
  "6:89": ["Those were the ones to whom we have given the scripture, wisdom, and prophethood. If these people disbelieve, we will substitute others in their place, and the new people will not be disbelievers.","তারাই ছিল সে লোক যাদেরকে আমরা ঐশীগ্রন্থ, প্রজ্ঞা এবং নবুওয়ত দিয়েছিলাম।  যদি এইসব লোকেরা অবিশ্বাস করে,আমরা তাদের স্থানে অন্যদের প্রতিস্থাপিত করবো,এবং নতুন লোকেরা অবিশ্বাসী হবে না।"],
  "6:90": ["These are the ones guided by Allah; you shall be guided in their footsteps. Say, \"I do not ask you for any wage. This is but a message for all the people.\"","এরাই হলো আল্লাহর দ্বারা পথপ্রদর্শিত; তোমরা তাদের পদচিহ্ন অনুসরণ করবে। বল, “আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না। এটা সকল লোকদের জন্যে একটি বার্তা মাত্র।"],
  "6:91": ["They never valued Allah as He should be valued. Thus, they said, \"Allah does not reveal anything to any human being.\" Say, \"Who then revealed the scripture that Moses brought, with light and guidance for the people?\" You put it down on paper to proclaim it, while concealing a lot of it. You were taught what you never knew—you and your parents. Say, \"Allah (is the One who revealed it),\" then leave them in their heedlessness, playing.","তারা কখনো আল্লাহকে মূল্য দেয়নি যেমন তাঁকে মূল্য দেয়া উচিত। তাই, তারা বলেছিল, \"আল্লাহ কোন মানুষের কাছে কোনকিছু প্রকাশ করেন না।\" বল, \"কে তাহলে সে ঐশীগ্রন্থ প্রকাশ করেছিলেন যা মুসা এনেছিল, লোকদের জন্য আলো এবং পথ-প্রদর্শন নিয়ে?\" তোমরা কাগজে লিখে রাখো তার কিছু ঘোষনা করতে,যখন এর অনেক কিছুই গোপন করো। তোমাদের শেখানো হয়েছিল যা তোমরা কখনো জানতে না- তোমাদের এবং তোমাদের পিতা-মাতাদের। বল, \"আল্লাহই (সে সত্ত্বা যিনি এটা প্রকাশ করেছিলেন),”এরপর তাদেরকে তাদের অমনোযোগিতায় ছেড়ে দেন, খেলাছলে।"],
  "6:92": ["This too is a blessed scripture that we have revealed, confirming the previous scriptures, that you may warn the most important community and all those around it. Those who believe in the Hereafter will believe in this (scripture), and will observe the Contact Prayers (Salat).","এটিও একটি পবিত্র ঐশীগ্রন্থ যা আমরা প্রকাশ করেছি,যা পূর্ববর্তী ঐশীগ্রন্থসমূহ নিশ্চিত করছে,যাতে তুমি সতর্ক করতে পারো সবচেয়ে গুরুত্বপূর্ণ সম্প্রদায়কে এবং এর চারপাশের সকলকে। যারা পরকালে বিশ্বাস করে তারা এই (ঐশীগ্রন্থে) বিশ্বাস করবে,এবং সংযোগ প্রার্থনাসমূহ (সালাত) পালন করবে।"],
  "6:93": ["Who is more evil than one who fabricates lies and attributes them to Allah, or says, \"I have received divine inspiration,\" when no such inspiration was given to him, or says, \"I can write the same as Allah's revelations\"? If only you could see the transgressors at the time of death! The angels extend their hands to them, saying, \"Let go of your souls. Today, you have incurred a shameful retribution for saying about Allah other than the truth, and for being too arrogant to accept His revelations.","তার চেয়ে কে বেশি মন্দ যে মিথ্যা উদ্ভাবন করে এবং সেগুলো আল্লাহর প্রতি আরোপ করে,অথবা বলে,\"আমি ঐশ্বরিক অনুপ্রেরণা পেয়েছি,” যখন এরকম কোন অনুপ্রেরণা তাকে দেয়া হয়নি,অথবা বলে,\"আমি আল্লাহর প্রকাশনাবলির মতো লিখতে পারি\"? যদি শুধু তুমি সীমালঙ্ঘনকারীদের দেখতে পেতে মৃত্যুর সময়! ফেরেশতারা তাদের নিকট হাত বাড়ায়, এই বলে যে,\"তোমাদের আত্মাগুলোকে যেতে দাও। আজ, তোমরা আল্লাহ সম্পর্কে সত্য ব্যতীত অন্যকিছু বলে,এবং তাঁর প্রকাশনাবলি গ্রহন করতে অত্যধিক উদ্ধত হয়ে এক লজ্জাকর শাস্তি টেনে এনেছ।"],
  "6:94": ["\"You have come back to us as individuals, just as we created you the first time, and you have left behind what we provided for you. We do not see with you the intercessors that you idolized and claimed that they will help you. All ties among you have been severed; the idols you set up have abandoned you.\"","\"তোমরা আমাদের কাছে ফিরে এসেছো একাকী,ঠিক যেরকম আমরা তোমাদের প্রথমবার সৃষ্টি করেছিলাম, এবং তোমরা পিছনে ফেলে এসেছ যা আমরা তোমাদের জন্য দিয়েছিলাম। আমরা তোমাদের সাথে সুপারিশকারীদের দেখি না যাদের তোমরা উপাস্যসম করেছিলে এবং দাবী করেছিলে যে তারা তোমাদের সাহায্য করবে। তোমাদের মধ্যকার সকল বাঁধন ছিন্ন হয়েছে; তোমাদের স্থাপন করা উপাস্যরা তোমাদের পরিত্যাগ করেছে।\""],
  "6:95": ["Allah is the One who causes the grains and the seeds to crack and germinate. He produces the living from the dead, and the dead from the living. Such is Allah; how could you deviate!","আল্লাহই সে সত্ত্বা যিনি শস্যকণা ও বীজগুলোতে ফাটল এবং অঙ্কুরোদ্গম ঘটান। তিনি মৃত থেকে জীবিতকে,এবং জীবিত থেকে মৃতকে উৎপন্ন করেন। এমনই আল্লাহ;কিভাবে তোমরা বিচ্যুত হতে পারো!"],
  "6:96": ["At the crack of dawn, He causes the morning to emerge. He made the night still, and He rendered the sun and the moon to serve as calculation devices. Such is the design of the Almighty, the Omniscient.","দিনের সূচনায়, তিনি প্রভাত আবির্ভূত হতে দেন। তিনি রাতকে করেছেন প্রশান্ত, এবং তিনি সূর্য ও চাঁদকে গননা যন্ত্র হিসেবে কাজ করতে নিয়োজিত করেছেন। সর্বশক্তিমান, সর্বজ্ঞের এমনই নকশা।"],
  "6:97": ["And He is the One who made the stars to guide you during the darkness, on land and on sea. We thus clarify the revelations for people who know.","এবং তিনিই সে সত্ত্বা যিনি তৈরি করেছিলেন নক্ষত্ররাজি অন্ধকারে তোমাদেরকে পথ দেখাতে, স্থলে এবং সাগরে। আমরা এভাবে লোকদের জন্য প্রকাশনাবলী সুস্পষ্ট করি,যারা জানে।"],
  "6:98": ["He initiated you from one person, and decided your path, as well as your final destiny. We thus clarify the revelations for people who understand.","তিনি তোমাদের সূচনা করেছেন এক ব্যক্তি থেকে,এবং নির্ধারণ করেছেন তোমাদের পথ, সেই সাথে তোমাদের চূড়ান্ত নিয়তি। আমরা এভাবে লোকদের জন্য প্রকাশনাবলী সুস্পষ্ট করি,যারা বুঝে।"],
  "6:99": ["He is the One who sends down from the sky water, whereby we produce all kinds of plants. We produce from the green material multitudes of complex grains, palm trees with hanging clusters, and gardens of grapes, olives and pomegranate; fruits that are similar, yet dissimilar. Note their fruits as they grow and ripen. These are signs for people who believe.","তিনিই সে সত্ত্বা যিনি আকাশ থেকে পানি বর্ষণ করেন, যার দ্বারা আমরা সকল প্রকার উদ্ভিদ জন্মাই। আমরা সবুজ অংশ থেকে উৎপন্ন করি জটিল শস্যের সমাহার, ঝুলন্ত থোকা বিশিষ্ট খেঁজুর গাছ, এবং আঙুরের বাগান, জলপাই এবং আনার; ফল যেগুলো সাদৃশ্যযুক্ত, তথাপি সাদৃশ্যহীন। লক্ষ্য করো সেগুলোর ফল যখন তারা বড় হয় এবং পরিপক্ক হয়। এগুলো লোকদের জন্য নিদর্শন যারা বিশ্বাস করে।"],
  "6:100": ["Yet, they set up besides Allah idols from among the jinns, though He is the One who created them. They even attribute to Him sons and daughters, without any knowledge. Be He glorified. He is the Most High, far above their claims.","এরপরও, তারা আল্লাহর পাশে অংশীদারদের স্থাপন করে জীনদের মধ্যে থেকে,যদিও তিনিই সে সত্ত্বা যিনি তাদের সৃষ্টি করেছিলেন। তারা এমনকি পুত্র ও কন্যা থাকাকে তাঁর গুন হিসেবে চালায়, কোন জ্ঞান ছাড়াই। মহিমা তো তাঁরই। তিনি সর্বাধিক উচ্চ, তাদের দাবীর অনেক উর্ধ্বে।"],
  "6:101": ["The Initiator of the heavens and the earth. How can He have a son, when He never had a mate? He created all things, and He is fully aware of all things.","আকাশমন্ডলী ও পৃথিবীর সূচনাকারী। কি করে তাঁর কোন পুত্র থাকতে পারে,যখন তাঁর কখনো কোন সঙ্গী ছিল না? তিনি সবকিছু সৃষ্টি করেছিলেন, এবং তিনি সবকিছু সম্পর্কে সম্পূর্ন সচেতন।"],
  "6:102": ["Such is Allah your Lord, there is no god except He, the Creator of all things. You shall worship Him alone. He is in control of all things.","এরকমই তোমাদের প্রভু আল্লাহ, তিনি ছাড়া কোন উপাস্য নেই, সবকিছুর সৃষ্টিকর্তা। তোমরা একমাত্র তাঁরই উপাসনা করবে। তিনি সবকিছুর নিয়ন্ত্রন করেন।"],
  "6:103": ["No visions can encompass Him, but He encompasses all visions. He is the Compassionate, the Cognizant.","কোন দৃষ্টি তাকে পরিবেষ্টন করতে পারে না,কিন্তু তিনি সকল দৃষ্টি পরিবেষ্টন করেন। তিনি করুনাময়, জ্ঞাত।"],
  "6:104": ["Enlightenments have come to you from your Lord. As for those who can see, they do so for their own good, and those who turn blind, do so to their own detriment. I am not your guardian.","তোমাদের প্রভুর কাছ থেকে তোমাদের কাছে জ্ঞানালোক এসেছে। যারা দেখতে পারে তাদের ক্ষেত্রে,তারা তাদের নিজের ভালোর জন্যই দেখে,এবং যারা অন্ধত্বে ফিরে যায়, তারা তাদের নিজের ক্ষতির জন্যই তা করে। আমি তোমাদের অভিভাবক নই।"],
  "6:105": ["We thus explain the revelations, to prove that you have received knowledge, and to clarify them for people who know.","আমরা এভাবে প্রকাশনাবলি ব্যাখ্যা করি,প্রমান করতে যে, তোমরা জ্ঞান পেয়েছ, এবং সেগুলো লোকদের জন্য সুস্পষ্ট করতে,যারা জানে।"],
  "6:106": ["Follow what is revealed to you from your Lord, there is no god except He, and disregard the idol worshipers.","অনুসরণ করো যা তোমার প্রভুর পক্ষ থেকে তোমার কাছে প্রকাশ করা হয়, তিনি ব্যতিত কোন উপাস্য নেই, এবং প্রতিমা উপাসকদের উপেক্ষা করো।"],
  "6:107": ["Had Allah willed, they would not have worshiped idols. We did not appoint you as their guardian, nor are you their advocate.","আল্লাহ যদি চাইতেন, তারা অংশীদার উপাসনা করতো না। আমরা তোমাকে তাদের অভিভাবক নিযুক্ত করিনি,না তুমি তদের উকিল।"],
  "6:108": ["Do not curse the idols they set up beside Allah, lest they blaspheme and curse Allah, out of ignorance. We have adorned the works of every group in their eyes. Ultimately, they return to their Lord, then He informs them of everything they had done.","আল্লাহর পাশে তাদের স্থাপন করা অংশীদারদের অভিশাপ দিওনা,পাছে তারা অজ্ঞতাবশত আল্লাহকে গালমন্দ করবে এবং অভিশাপ দেবে। আমরা প্রত্যেক দলের কাজকে তাদের চোখে সুশোভিত করে দিয়েছি। অবশেষে,তারা তাদের প্রভুর কাছে ফিরে যায়, তখন তিনি তাদেরকে জানান সবকিছু যা তারা করেছিল।"],
  "6:109": ["They swore by Allah, solemnly, that if a miracle came to them, they would surely believe. Say, \"Miracles come only from Allah.\" For all you know, if a miracle did come to them, they would continue to disbelieve.","তারা আল্লাহর নামে শপথ করেছিল, দৃড়ভাবে যে, যদি একটি অলৌকিকতা তাদের কাছে আসতো,তারা অবশ্যই বিশ্বাস করতো। বল, “অলৌকিকতা শুধু আল্লাহ থেকে আসে”। যতদূর তোমরা জানো,যদি একটি অলৌকিকতা তাদের কাছে আসত, তারা অবিশ্বাসই রইতো”।"],
  "6:110": ["We control their minds and their hearts. Thus, since their decision is to disbelieve, we leave them in their transgressions, blundering.","আমরা তাদের মন এবং তাদের হৃদয় নিয়ন্ত্রন করি। এভাবে,যেহেতু অবিশ্বাস করাই তাদের সিদ্ধান্ত, আমরা তাদেরকে তাদের সীমালঙ্ঘনে, বিভ্রান্তিতে ছেড়ে দেই।"],
  "6:111": ["Even if we sent down the angels to them; even if the dead spoke to them; even if we summoned every miracle before them; they cannot believe unless Allah wills it. Indeed, most of them are ignorant.","এমনকি যদি আমরা তাদের নিকট ফেরেশতাদের পাঠাতাম; এমনকি যদি মৃতরা তাদের সাথে কথা বলত; এমনকি যদি তাদের সামনে আমরা প্রত্যেক অলৌকিকতা একত্রিত করতাম; তারা বিশ্বাস করতে পারে না যদি না আল্লাহ তা ইচ্ছা করেন। প্রকৃতপক্ষে,তাদের বেশির ভাগই অজ্ঞ।"],
  "6:112": ["We have permitted the enemies of every prophet—human and jinn devils—to inspire in each other fancy words, in order to deceive. Had your Lord willed, they would not have done it. You shall disregard them and their fabrications.","আমরা অনুমোদন দিয়েছি প্রত্যেক নবীর শত্রু- মানুষ এবং জীন শয়তানদের- একে অন্যকে কল্পিত কথা দিয়ে অনুপ্রানিত করতে,প্রতারিত করার জন্য। যদি তোমার প্রভু ইচ্ছা করতেন, তারা এটা করত না। তুমি তাদেরকে এবং তাদের মিথ্যা উদ্ভাবনসমূহকে উপেক্ষা করবে।"],
  "6:113": ["This is to let the minds of those who do not believe in the Hereafter listen to such fabrications, and accept them, and thus expose their real convictions.","এটা একারনে যে, যারা পরকালে বিশ্বাস করে না, তাদের মনকে এরকম মিথ্যা উদ্ভাবন শুনানো,এবং সেগুলো গ্রহন করানো,এবং এভাবে তাদের প্রকৃত অভিপ্রায়কে প্রকাশ করানো হয়।"],
  "6:114": ["Shall I seek other than Allah as a source of law, when He has revealed to you this book fully detailed? Those who received the scripture recognize that it has been revealed from your Lord, truthfully. You shall not harbor any doubt.","আমি কি আল্লাহ ছাড়া অন্য কাউকে আইনের উৎস হিসেবে খুজঁবো,যখন তিনি তোমাদের কাছে এই গ্রন্থ পূর্ণ বিস্তারিতরুপে প্রকাশ করেছেন? যারা এই ঐশীগ্রন্থ গ্রহন করেছিল, তারা চিনতে পারে যে,এটি তোমার প্রভুর কাছ থেকে প্রকাশিত হয়েছে,সত্যতার সাথে। তোমরা কোন সন্দেহ পোষন করবে না।"],
  "6:115": ["The word of your Lord is complete, in truth and justice. Nothing shall abrogate His words. He is the Hearer, the Omniscient.","তোমার প্রভুর বানী পরিপূর্ণ, সত্যে এবং সুবিচারে। কোন কিছুই তাঁর বানী রহিত করবে না। তিনি শ্রবণকারী,সর্বজ্ঞ।"],
  "6:116": ["If you obey the majority of people on earth, they will divert you from the path of Allah. They follow only conjecture; they only guess.","যদি তুমি পৃথিবীর বেশিরভাগ মানুষকে মান্য করো,তারা তোমাকে আল্লাহর পথ থেকে সরিয়ে দেবে। তারা শুধু মিথ্যা ধারনার অনুসরন করে; তারা শুধু অনুমান করে।"],
  "6:117": ["Your Lord is fully aware of those who stray off His path, and He is fully aware of those who are guided.","তোমার প্রভু তাদের ব্যাপারে সম্পূর্ণ সচেতন  যারা তাঁর পথ থেকে বিপথগামী হয়, এবং তিনি তাদের ব্যপারে সম্পূর্ণ অবগত, যারা সুপথপ্রাপ্ত।"],
  "6:118": ["You shall eat from that upon which Allah's name has been pronounced, if you truly believe in His revelations.","তুমি খাবে তা থেকে, যেটার উপর আল্লাহর নাম উচ্চারণ করা হয়েছে,যদি তুমি সত্যই তাঁর প্রকাশনাবলিতে বিশ্বাস করো।"],
  "6:119": ["Why should you not eat from that upon which Allah's name has been mentioned? He has detailed for you what is prohibited for you, unless you are forced. Indeed, many people mislead others with their personal opinions, without knowledge. Your Lord is fully aware of the transgressors.","কেন তোমারা খাবেনা তা থেকে, যাতে আল্লাহর নাম উচ্চারণ করা হয়েছে? তিনি তোমাদের জন্য বিশদ বর্ণনা করেছেন যা তোমাদের জন্য নিষিদ্ধ, যদি না তোমাদেরকে জোর করা হয়। প্রকৃতপক্ষে, অনেক লোক অন্যদের বিপথগামী করে তাদের ব্যক্তিগত মতামত দিয়ে, জ্ঞান ছাড়াই। তোমার প্রভু সীমাতিক্রমকারীদের ব্যাপারে পূর্ণ অবগত।"],
  "6:120": ["You shall avoid obvious sins, as well as the hidden ones. Those who have earned sins will surely pay for their transgressions.","তোমরা প্রকাশ্য পাপ পরিহার করবে,সেই সাথে গোপনগুলো। যারা পাপ উপার্জন করেছে,তারা অবশ্যই তাদের সীমাতিক্রমের জন্য মূল্য দেবে।"],
  "6:121": ["Do not eat from that upon which the name of Allah has not been mentioned, for it is an abomination. The devils inspire their allies to argue with you; if you obey them, you will be idol worshipers.","আল্লাহর নাম যেটাতে নেয়া হয়নি তা থেকে খেও না,কারণ এটি অত্যন্ত ঘৃণ্য কাজ। তোমাদের সাথে তর্ক করতে শয়তানরা তাদের মিত্রদের অনুপ্রানিত করে;যদি তোমরা তাদের মান্য করো,তোমরা প্রতিমা উপাসক হবে।"],
  "6:122": ["Is one who was dead and we granted him life, and provided him with light that enables him to move among the people, equal to one in total darkness from which he can never exit? The works of the disbelievers are thus adorned in their eyes.","যে লোক ছিল মৃত, তারপর আমরা তাকে জীবন দিলাম, এবং তাকে আলো দিলাম, যা লোকদের মাঝে তাকে চলতে সক্ষম করে, কি সেই লোকের সমান যে সম্পূর্ন অন্ধকারে রয়েছে যা থেকে সে কখনো বের হতে পারে না? অবিশ্বাসীদের কাজগুলোকে এভাবেই তাদের চোখে সুসজ্জিত করা হয়।"],
  "6:123": ["We allow the leading criminals of every community to plot and scheme. But they only plot and scheme against their own souls, without perceiving.","আমরা প্রত্যেক সম্প্রদায়ের নেতৃত্বস্থানীয় অপরাধীদেরকে চক্রান্ত এবং পরিকল্পনা করতে দেই। কিন্তু তারা কেবল তাদের নিজেদের আত্মার বিরুদ্ধে চক্রান্ত এবং পরিকল্পনা করে,অনুধাবন না করে।"],
  "6:124": ["When a powerful proof comes to them, they say, \"We will not believe, unless we are given what is given to Allah's messengers!\" Allah knows exactly who is best qualified to deliver His message. Such criminals will suffer debasement at Allah, and terrible retribution as a consequence of their evil scheming.","যখন একটি শক্তিশালী প্রমান তাদের কাছে আসে,তারা বলে,\"আমরা বিশ্বাস করবো না,যদি না আমাদের তা দেয়া হয় যা আল্লাহর বার্তাবাহকদের দেয়া হয়!”আল্লাহ যথাযথভাবে জানেন, কে তাঁর বার্তা পৌঁছে দিতে সর্বোত্তম যোগ্য। এরকম অপরাধীরা তাদের মন্দ পরিকল্পনার একটি ফল হিসেবে আল্লাহর কাছে লাঞ্চনা,এবং ভয়ানক শাস্তি ভোগ করবে।"],
  "6:125": ["Whomever Allah wills to guide, He renders his chest wide open to Submission. And whomever He wills to send astray, He renders his chest intolerant and straitened, like one who climbs towards the sky. Allah thus places a curse upon those who refuse to believe.","যাকেই আল্লাহ পথ-প্রদর্শন করতে চান, তিনি তার বক্ষকে আত্মসমর্পণে সুপ্রসারিত উন্মুক্ত করেন। এবং যাকেই তিনি পথভ্রষ্ট করতে চান, তিনি তার বক্ষকে অসহিষ্ণু এবং সংকীর্ণ করেন, সে লোকের মতো যে আকাশের দিকে আরোহন করে। আল্লাহ এভাবে তাদের উপর অভিশাপ ন্যস্ত করেন, যারা বিশ্বাস করতে অসম্মত।"],
  "6:126": ["This is the straight path to your Lord. We have explained the revelations for people who take heed.","এটাই তোমার প্রভুর দিকে সরল পথ। আমরা প্রকাশনাবলি ব্যাখ্যা করেছি লোকদের জন্য যারা মনোযোগী হয়।"],
  "6:127": ["They have deserved the abode of peace at their Lord; He is their Lord and Master, as a reward for their works.","তারা তাদের প্রভুর কাছে শান্তিময় আবাসের যোগ্য; তিনি তাদের প্রভু এবং মনিব, তাদের কাজের পুরুস্কার হিসাবে।"],
  "6:128": ["The day will come when He summons all of them (and says): \"O you jinns, you have claimed multitudes of humans.\" Their human companions will say, \"Our Lord, we enjoyed each others' company until we wasted the life span You had set for us.\" He will say, \"Hell is your destiny.\" They abide therein forever, in accordance with Allah's will. Your Lord is Wise, Omniscient.","সেদিন আসবে যখন তিনি তাদের সকলকে ডাকেন (এবং বলেন) “হে তোমরা জীন, তোমরা বহুসংখ্যক মানুষকে দাবী করেছ”। তাদের মানব সঙ্গীরা বলবে,“আমাদের প্রভু,আমরা একে অন্যের সঙ্গ উপভোগ করেছিলাম, যতক্ষণ না আমরা সে জীবনকাল অপচয় করেছিলাম যা আপনি আমাদের জন্য স্থির করেছিলেন”।  তিনি বলবেন, “তোমাদের নিয়তি নরক”। তারা সেখানে চিরকাল বাস করে,আল্লাহর ইচ্ছা অনুযায়ী। তোমার প্রভু বিজ্ঞ, সর্বজ্ঞ।"],
  "6:129": ["We thus match the wicked to be companions of each other, as a punishment for their transgressions.","আমরা এভাবে একে অন্যের সঙ্গী হিসেবে পাপীদের মিলিয়ে দেই, তাদের সীমাতিক্রমের শাস্তি হিসাবে।"],
  "6:130": ["O you jinns and humans, did you not receive messengers from among you, who narrated to you My revelations, and warned you about the meeting of this day? They will say, \"We bear witness against ourselves.\" They were totally preoccupied with the worldly life, and they will bear witness against themselves that they were disbelievers.","হে তোমরা জীন ও মানুষ, তোমরা কি তোমাদের মধ্য থেকে বার্তাবাহকদের পাওনি, যারা তোমাদের কাছে আমার প্রকাশনাবলি বর্ণনা করেছিল, এবং এই দিনের সাক্ষাতের ব্যাপারে তোমাদের সতর্ক করেছিল? তারা বলবে, “আমরা আমাদের নিজেদের বিরুদ্ধে সাক্ষী দেই”। তারা দুনিয়ার জীবন নিয়ে সম্পূর্ণ আচ্ছন্ন ছিল, এবং তারা তাদের নিজেদের বিরুদ্ধে সাক্ষী দেবে যে তারা অবিশ্বাসী ছিল।"],
  "6:131": ["This is to show that your Lord never annihilates any community unjustly, while its people are unaware.","এটি দেখাতে যে তোমাদের প্রভু কখনো কোন সম্প্রদায়কে অন্যায়ভাবে ধংস করেন না,যখন এর লোকেরা অনবগত।"],
  "6:132": ["Everyone will attain a rank commensurate with their deeds. Your Lord is never unaware of anything they do.","প্রত্যেকেই তাদের কর্মের সমানুপাতিক পদমর্যাদা অর্জন করবে। তোমাদের প্রভু কখনো অনবগত নন, যা কিছু তারা করে।"],
  "6:133": ["Your Lord is the Rich One; possessor of all mercy. If He wills, He can remove you, and substitute whomever He wills in your place, just as He produced you from the progeny of other people.","তোমাদের প্রভুই একমাত্র স্ব-সমৃদ্ধ; সকল করুনার অধিকারী। যদি তিনি চান, তিনি তোমাদের সরিয়ে দিতে, এবং তোমাদের জায়গায় যাকে ইচ্ছা প্রতিস্থাপন করতে পারেন, ঠিক যেমন তিনি তোমাদেরকে অন্য লোকদের বংশধর থেকে বানিয়েছিলেন।"],
  "6:134": ["What is promised to you will come to pass, and you can never evade it.","যা তোমাদেরকে অঙ্গীকার করা হয় তা ঘটবে,এবং তোমরা কখনো তা এড়াতে পার না।"],
  "6:135": ["Say, \"O my people, do your best, and so will I. You will surely find out who the ultimate victors are.\" Certainly, the wicked will never succeed.","বল, \"হে আমার লোকেরা , তোমাদের সেরাটা করো, এবং আমিও তা-ই করবো। তোমরা অবশ্যই জানতে পারবে কারা চুড়ান্ত বিজয়ী।” নিশ্চিতভাবে, মন্দরা কখনো সফল হবে না।"],
  "6:136": ["They even set aside a share of Allah's provisions of crops and livestock, saying, \"This share belongs to Allah,\" according to their claims, \"and this share belongs to our idols.\" However, what was set aside for their idols never reached Allah, while the share they set aside for Allah invariably went to their idols. Miserable indeed is their judgment.","তারা এমনকি আল্লাহর দেয়া শস্য এবং গবাদিপশুর একটি অংশ সরিয়ে রাখে, এই বলে, “এই অংশ আল্লাহর, ” , “এবং এই অংশ আমাদের উপাস্যদের”, তাদের দাবী অনুসারে। কিন্তু, যা তাদের উপাস্যদের জন্য সরিয়ে রেখেছিল তা কখনো আল্লাহর কাছে পৌঁছেনি, যখন আল্লাহর জন্য সরিয়ে রাখা অংশ সবসময় তাদের উপাস্যদের কাছে গিয়েছিল। তাদের সিদ্ধান্ত প্রকৃতপক্ষে দুঃখদায়ক।"],
  "6:137": ["Thus were the idol worshipers duped by their idols, to the extent of killing their own children. In fact, their idols inflict great pain upon them, and confuse their religion for them. Had Allah willed, they would not have done it. You shall disregard them and their fabrications.","এভাবে প্রতিমা উপাসকরা তাদের উপাস্যদের দ্বারা প্রতারিত হয়েছিল, এমনকি তাদের নিজেদের সন্তানদেরকে হত্যা করার পর্যন্ত।  আসলে, তাদের উপাস্যরা তাদের উপর অত্যধিক যন্ত্রণা আরোপ করে, এবং তাদের জন্য তাদের ধর্মকে বিভ্রান্ত করে দেয়। আল্লাহ যদি চাইতেন, তারা এটা করতো না। তোমরা তাদের এবং তাদের মিথ্যা উদ্ভাবনকে উপেক্ষা করবে।"],
  "6:138": ["They said, \"These are livestock and crops that are prohibited; no one shall eat them except whomever we permit,\" so they claimed. They also prohibited the riding of certain livestock. Even the livestock they ate, they never pronounced Allah's name as they sacrificed them. Such are innovations attributed to Him. He will surely requite them for their innovations.","তারা বলেছিল, ‘এইসব গৃহপালিত পশু এবং শস্য, যেগুলো নিষিদ্ধ; আমরা যাদেরকে অনুমতি দেই তারা ব্যতিত কেউ এগুলো খাবে না,” তা-ই তারা দাবি করেছিল। তারা এছাড়াও নির্দিষ্ট কিছু গৃহপালিত পশুর উপর চড়া নিষিদ্ধ করেছিল। এমনকি যে গৃহপালিত পশু তারা খেতো, যখন সেগুলো উৎসর্গ করতো তারা কখনো আল্লাহর নাম উচ্চারণ করতো না। এমন নতুন রীতিনীতি তাঁর প্রতি আরোপ করা হতো। তিনি অবশ্যই তাদের নতুন উদ্ভাবনের জন্য তাদের প্রতিশোধ নেবেন।"],
  "6:139": ["They also said, \"What is in the bellies of these livestock is reserved exclusively for the males among us, and prohibited for our wives.\" But if it was a stillbirth, they permitted their wives to share therein. He will certainly requite them for their innovations. He is Most Wise, Omniscient.","তারা আরও বলেছিল, “এই গৃহপালিত পশুগুলোর পেটে যা আছে তা কেবলমাত্র আমাদের মধ্যকার পুরুষদের জন্য সংরক্ষিত, এবং আমাদের স্ত্রীদের জন্য নিষিদ্ধ।” কিন্তু যদি এটা (গর্ভে জীবিত কিন্তু প্রসবের পর) মৃত হতো, তারা তাদের স্ত্রীদের তাতে অংশ নিতে অনুমতি দিত। তিনি অবশ্যই তাদের নতুন উদ্ভাবনের জন্য তাদের প্রতিশোধ নেবেন। তিনি সবচেয়ে জ্ঞানী,সর্বজ্ঞ।"],
  "6:140": ["Losers indeed are those who killed their children foolishly, due to their lack of knowledge, and prohibited what Allah has provided for them, and followed innovations attributed to Allah. They have gone astray; they are not guided.","প্রকৃতপক্ষে তারাই ক্ষতিগ্রস্ত যারা মূর্খের মতো তাদের সন্তানদের হত্যা করে, তাদের জ্ঞানের ঘাটতির কারনে, এবং নিষিদ্ধ করে যা আল্লাহ তাদেরকে দিয়েছেন, এবং আল্লাহর প্রতি আরোপিত নতুন রীতিনীতি অনুসরণ করে। তারা বিপথে গিয়েছে; তারা পথপ্রাপ্ত নয়।"],
  "6:141": ["He is the One who established gardens, trellised and untrellised, and palm trees, and crops with different tastes, and olives, and pomegranate —fruits that are similar, yet dissimilar. Eat from their fruits, and give the due alms on the day of harvest, and do not waste anything. He does not love the wasters.","তিনিই সে সত্ত্বা যিনি বাগানসমূহ স্থাপন করেছিলেন, মাচাবিশিষ্ট এবং মাচাবিহীন, এবং তাল গাছ এবং বিভিন্ন স্বাদবিশিষ্ট শস্যাদি, এবং জলপাই, এবং আনার- ফল যেগুলো একই রকম, তথাপি অন্যরকম। এদের ফল থেকে খাও, এবং ফসল সংগ্রহের দিন অবশ্য পরিশোধনীয় দান দিয়ে দাও, এবং কোন কিছু অপচয় করো না। তিনি অপচয়কারীদের ভালবাসেন না।"],
  "6:142": ["Some livestock supply you with transportation, as well as bedding materials. Eat from Allah's provisions to you, and do not follow the steps of Satan; he is your most ardent enemy.","কিছু গৃহপালিত পশু তোমাদের পরিবহনের কাজ করে, একই সাথে বিছানাপত্রের উপকরণ হিসেবে। তোমাদেরকে দেয়া আল্লাহর খাদ্যসামগ্রী থেকে খাও, এবং শয়তানের পদাঙ্ক অনুসরণ করো না; সে তোমাদের সবচেয়ে ঘোর শত্রু।"],
  "6:143": ["Eight kinds of livestock: regarding the two kinds of sheep, and the two kinds of goats, say, \"Is it the two males that He prohibited, or the two females, or the contents of the wombs of the two females? Tell me what you know, if you are truthful.\"","আট রকমের গৃহপালিত পশু: দুই রকমের ভেড়া, এবং দুই রকমের ছাগল সম্পর্কে,বলো, \"এটি কি দু'টি পুরুষ-জাতীয়, নাকি দু'টি নারী-জাতীয়, নাকি দু'টি নারী-জাতির জরায়ুর অভ্যন্তরস্থ বস্তু যা তিনি নিষেধ করেছিলেন? আমাকে বলো তোমরা কি জানো, যদি তোমরা সত্যবাদী হও?"],
  "6:144": ["Regarding the two kinds of camels, and the two kinds of cattle, say, \"Is it the two males that He prohibited, or the two females, or the contents of the wombs of the two females? Were you witnesses when Allah decreed such prohibitions for you? Who is more evil than those who invent such lies and attribute them to Allah? They thus mislead the people without knowledge. Allah does not guide such evil people.\"","দুই রকমের উট, এবং দুই রকমের গবাদিপশু সম্পর্কে, বলো, \"এটি কি সে দুইটি পুরুষ-জাতীয়, অথবা সে দু'টি নারী-জাতীয়, অথবা সে দু'টি নারী-জাতির জরায়ুর অভ্যন্তরস্থ বস্তু, যা তিনি নিষেধ করেছিলেন? তোমরা কি সাক্ষী ছিলে, যখন আল্লাহ তোমাদের জন্য এরকম নিষেধাজ্ঞা জারি করেছিলেন? তাদের চেয়ে কে বেশি মন্দ যে এরকম মিথ্যা উদ্ভাবন করে এবং সেগুলো আল্লাহর প্রতি আরোপ করে? তারা এভাবে লোকদের বিপথগামী করে জ্ঞান ছাড়া। আল্লাহ এরকম মন্দ লোকদের পথ-প্রদর্শন করেন না।\""],
  "6:145": ["Say, \"I do not find in the revelations given to me any food that is prohibited for any eater except: (1) carrion, (2) running blood, (3) the meat of pigs, for it is contaminated, and (4) the meat of animals blasphemously dedicated to other than Allah.\" If one is forced (to eat these), without being deliberate or malicious, then your Lord is Forgiver, Most Merciful.","বল, আমাকে দেয়া প্রকাশনাবলিতে আমি কোন ভক্ষনকারীর জন্য কোন খাদ্যের নিষেধ খুঁজে পাই না, এগুলো ব্যতীত: (১) মৃত প্রানীর গলিত মাংস, (২) প্রবাহিত রক্ত, (৩) শুকরের মাংস, কারন তা সংক্রামিত, এবং (৪) প্রানীর মাংস যা বানানো মিথ্যা ধর্মানুসারে আল্লাহ ছাড়া অন্য কারো প্রতি উৎসর্গকৃত।” যদি কেউ (এগুলো খেতে) বাধ্য  হয়, ইচ্ছাকৃত বা বিদ্বেষপরায়ন না হয়ে, তবে আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "6:146": ["For those who are Jewish we prohibited animals with undivided hoofs; and of the cattle and sheep we prohibited the fat, except that which is carried on their backs, or in the viscera, or mixed with bones. That was a retribution for their transgressions, and we are truthful.","যারা ইহুদী তাদের জন্য আমরা অবিভক্ত খুরওয়ালা পশু নিষিদ্ধ করেছিলাম; এবং গবাদিপশু ও ভেড়ার চর্বি নিষিদ্ধ করেছিলাম, শুধু সেগুলো ছাড়া যা তাদের পিঠে বহন করে, অথবা অন্ত:স্থিত অঙ্গে  অথবা হাড়ের সাথে মিশ্রিত থাকে। এটা ছিল তাদের সীমাতিক্রমের একটি শাস্তি, এবং আমরা সত্যবাদী।"],
  "6:147": ["If they disbelieve you, then say, \"Your Lord possesses infinite mercy, but His retribution is unavoidable for the guilty people.\"","যদি তারা তোমাকে অবিশ্বাস করে, তাহলে বল, “তোমাদের প্রভু অসীম দয়ার অধিকারী,কিন্তু তাঁর শাস্তি দোষী লোকদের জন্য অনিবার্য”।"],
  "6:148": ["The idol worshipers say, \"Had Allah willed, we would not practice idolatry, nor would our parents, nor would we prohibit anything.\" Thus did those before them disbelieve, until they incurred our retribution. Say, \"Do you have any proven knowledge that you can show us? You follow nothing but conjecture; you only guess.\"","প্রতিমা উপাসকেরা বলে, “আল্লাহ যদি চাইতেন, আমরা শিরক চর্চা করতাম না, না আমাদের পিতামাতারা, না আমরা কোনকিছু নিষিদ্ধ করতাম”। এভাবে তাদের পূর্বে যারা ছিল অবিশ্বাস করেছিল, যতক্ষণ না আমাদের শাস্তি তাদের উপর এসে যায়। বল, “তোমাদের কি কোন প্রমানিত জ্ঞান আছে যা তোমরা আমাদের দেখাতে পারো? তোমরা মিথ্যা ধারনা ছাড়া অন্যকিছুর অনুসরণ করো না; তোমরা শুধু অনুমান করো”।"],
  "6:149": ["Say, \"Allah possesses the most powerful argument; if He wills He can guide all of you.\"","বল, “আল্লাহ সবচেয়ে শক্তিশালী যুক্তির অধিকারী; তিনি যদি চান তিনি তোমাদের সকলকে পথপ্রদর্শন করতে পারেন”"],
  "6:150": ["Say, \"Bring your witnesses who would testify that Allah has prohibited this or that.\" If they testify, do not testify with them. Nor shall you follow the opinions of those who reject our revelations, and those who disbelieve in the Hereafter, and those who stray away from their Lord.","বল, “তোমাদের সাক্ষিদের আনো যারা সাক্ষ্য দেবে যে আল্লাহ এটা অথবা ঐটা নিষিদ্ধ করেছেন”। যদি তারা সাক্ষী দেয়, তাদের সাথে সাক্ষী দেবে না। না তোমরা তাদের মতামত অনুসরণ করবে যারা আমার প্রকাশনাবলী প্রত্যক্ষান করে, এবং যারা পরকালে অবিশ্বাস করে,এবং যারা তাদের প্রভু থেকে দূরে পপথভ্রষ্ট হয়।"],
  "6:151": ["Say, \"Come let me tell you what your Lord has really prohibited for you: You shall not set up idols besides Him. You shall honor your parents. You shall not kill your children from fear of poverty—we provide for you and for them. You shall not commit gross sins, obvious or hidden. You shall not kill—Allah has made life sacred—except in the course of justice. These are His commandments to you, that you may understand.\"","বল, \"আসো তোমাদেরকে আমি বলি তোমাদের প্রভু তোমাদের জন্য প্রকৃতপক্ষে কি নিষিদ্ধ করেছেন: তোমরা তাঁর পাশে উপাস্য স্থাপন করবে না। তোমরা তোমাদের পিতা-মাতাকে সম্মান করবে। দারিদ্র্যতার ভয়ে তোমরা তোমাদের সন্তানদের হত্যা করবে না- আমরা তোমাদের জন্য এবং তাদের জন্য প্রদান করি। তোমরা গুরুতর পাপসমূহ করবে না, প্রকাশিত অথবা গোপন। তোমরা হত্যা করবে না- আল্লাহ জীবনকে পবিত্র করেছেন- বিচার প্রক্রিয়া ছাড়া। এগুলো তোমাদের প্রতি তাঁর প্রত্যাদেশ, যাতে তোমরা বুঝতে পারো।\""],
  "6:152": ["You shall not touch the orphans' money except in the most righteous manner, until they reach maturity. You shall give full weight and a full measure when you trade, equitably. We do not burden any soul beyond its means. You shall be absolutely just when you bear witness, even against your relatives. You shall fulfill your covenant with Allah. These are His commandments to you, that you may take heed.","তোমরা সর্বোচ্চ ন্যায়পরায়ণ পন্থা ছাড়া এতিমদের অর্থ স্পর্শ করবে না, যতক্ষণ না তারা পরিপক্বতায় পৌঁছায়। যখন তোমরা ব্যবসা করো, তোমরা পূর্ণ ওজন এবং একটি পূর্ণ মাপ দিবে, ন্যয়সঙ্গতভাবে। আমরা কোন আত্মাকে এর ক্ষমতার অতিরিক্ত বোঝা চাপাই না। তোমরা পুরোপুরি ন্যায়পরায়ণ হবে যখন তোমরা সাক্ষ্য দাও, এমনকি তোমাদের আত্মীয় -স্বজনদের বিরুদ্ধে। তোমরা আল্লাহর সাথে তোমাদের অংগীকার পরিপূর্ণ করবে। এগুলো তোমাদের প্রতি তাঁর প্রত্যাদেশ, যাতে তোমরা সতর্ক হতে পারো।"],
  "6:153": ["This is My path—a straight one. You shall follow it, and do not follow any other paths, lest they divert you from His path. These are His commandments to you, that you may be saved.","এটি আমার পথ - সরল। তোমরা এটি অনুসরণ করবে, এবং অন্যকোন পথ অনুসরণ করো না, পাছে তারা তোমাদেরকে তাঁর পথ থেকে বিচ্যুত করে ফেলে। এগুলো তোমাদের প্রতি তাঁর প্রত্যাদেশ, যাতে তোমরা রক্ষা পেতে পারো।"],
  "6:154": ["And we gave Moses the scripture, complete with the best commandments, and detailing everything, and a beacon and mercy, that they may believe in meeting their Lord.","এবং আমরা মুসাকে ঐশীগ্রন্থ দিয়েছিলাম, সর্বোত্তম প্রত্যাদেশাবলি দিয়ে পূর্ন, এবং সবকিছু সবিস্তারে বর্ননা করে, এবং একটি আলোকবর্তিকা এবং দয়া, যাতে তারা তাদের প্রভুর সাথে সাক্ষাতে বিশ্বাস করতে পারে।"],
  "6:155": ["This too is a blessed scripture that we have revealed; you shall follow it and lead a righteous life, that you may attain mercy.","এটিও একটি মহিমান্বিত ঐশীগ্রন্থ যা আমরা প্রকাশিত করেছি ; তোমরা এটি অনুসরণ করবে এবং একটি সৎকর্মশীল জীবন যাপন করবে, যাতে তোমরা ক্ষমা অর্জন করতে পারো।"],
  "6:156": ["Now you can no longer say, \"The scripture was sent down to two groups before us, and we were unaware of their teachings.\"","তোমরা এখন আর বলতে পারবে না,“আমাদের পূর্বের দুই দলের কাছে ঐশীগ্রন্থ অবতীর্ণ হয়েছিল, এবং আমরা সেগুলোর শিক্ষাসমূহে অনবগত ছিলাম।"],
  "6:157": ["Nor can you say, \"If only a scripture could come down to us, we would be better guided than they.\" A proven scripture has now come to you from your Lord, and a beacon, and a mercy. Now, who is more evil than one who rejects these proofs from Allah, and disregards them? We will commit those who disregard our proofs to the worst retribution, for their heedlessness.","না তোমরা বলতে পারো, “যদি শুধু একটি ঐশীগ্রন্থ আমাদের কাছে অবতীর্ণ হতো, আমরা তাদের থেকে উত্তম পথপ্রদর্শিত হতাম”। “তোমাদের প্রভুর পক্ষ থেকে এখন তোমাদের কাছে এসেছে একটি প্রমানিত ঐশীগ্রন্থ, এবং একটি আলোকবর্তিকা, এবং একটি দয়া। এখন, কে তার চেয়ে অধিক মন্দ যে আল্লাহর পক্ষ থেকে আসা এই প্রমানাদি প্রত্যাক্ষান করে, এবং সেগুলো উপেক্ষা করে? যারা আমাদের প্রমানাদি উপেক্ষা করে আমরা তাদের নিকৃষ্টতম শাস্তি দেব, তাদের অমনোযোগিতার কারনে।"],
  "6:158": ["Are they waiting for the angels to come to them, or your Lord, or some physical manifestations of your Lord? The day this happens, no soul will benefit from believing if it did not believe before that, and did not reap the benefits of belief by leading a righteous life. Say, \"Keep on waiting; we too are waiting.\"","তারা কি অপেক্ষা করছে ফেরেশতাদের, অথবা তোমার প্রভুর, অথবা তোমার প্রভুর কিছু শারীরিক প্রকাশ তাদের কাছে আসার? যেদিন এটা ঘটবে, কোন আত্মার বিশ্বাস করায় লাভ হবে না, যদি আগে থেকে এটি বিশ্বাস না করে, এবং একটি সৎ জীবন যাপনের দ্বারা বিশ্বাসের উপকারিতা সমূহের ফল লাভ না করে থাকে। বল, “অপেক্ষা করতেই থাকো, আমরাও অপেক্ষা করছি”।"],
  "6:159": ["Those who divide themselves into sects do not belong with you. Their judgment rests with Allah, then He will inform them of everything they had done.","যারা নিজেদেরকে বিভিন্ন বর্ণে বিভক্ত করে তারা তোমার অন্তর্ভূক্ত নয়। তাদের বিচার আল্লাহর কাছে রয়েছে, তখন তিনি তাদেরকে জানাবেন সবকিছু যা তারা করেছিল।"],
  "6:160": ["Whoever does a righteous work receives the reward for ten, and the one who commits a sin is requited for only one. No one suffers the slightest injustice.","যে কেউ একটি সৎকর্ম করে সে দশটির পুরুস্কার লাভ করে, এবং যে একটি পাপ করে,  শুধু মাত্র একটির জন্য প্রতিফল ভোগ করে। কেউই সামান্যতম অবিচার ভোগ করে না।"],
  "6:161": ["Say, \"My Lord has guided me in a straight path—the perfect religion of Abraham, monotheism. He never was an idol worshiper.\"","বল, \"আমার প্রভু আমাকে প্রদর্শন করেছেন একটি সরল পথ - ইব্রাহিমের সঠিক ধর্ম, একেশ্বরবাদ। সে কখনো প্রতিমা উপাসক ছিল না।\""],
  "6:162": ["Say, \"My Contact Prayers (Salat), my worship practices, my life and my death, are all devoted absolutely to Allah alone, the Lord of the universe.","বল, \"আমার সংযোগ প্রার্থনাসমূহ (সালাত), আমার উপাসনা চর্চাসমূহ, আমার জীবন এবং আমার মৃত্যু, সবকিছু উৎসর্গকৃত একমাত্র আল্লাহর প্রতি, মহাবিশ্বের প্রভু।"],
  "6:163": ["\"He has no partner. This is what I am commanded to believe, and I am the first to submit.\"","\"তাঁর কোন অংশীদার নেই। এটিই আমাকে বিশ্বাস করতে আদেশ করা হয়েছে এবং আমি প্রথমেই আত্মসমর্পণ করি।\""],
  "6:164": ["Say, \"Shall I seek other than Allah as a lord, when He is the Lord of all things? No soul benefits except from its own works, and none bears the burden of another. Ultimately, you return to your Lord, then He informs you regarding all your disputes.\"","বল, \"আমি কি প্রভু হিসেবে আল্লাহ ছাড়া অন্য কাউকে খুঁজবো, যখন তিনি সবকিছুর প্রভু? কোন আত্মাই লাভবান হয় না এর নিজের কর্ম থেকে ছাড়া, এবং কেউই অন্যের বোঝা বহন করে না। অবশেষে, তোমরা তোমাদের প্রভুর কাছে ফিরে আসো, এরপর তিনি তোমাদের সকল বিবাদের বিষয়ে তোমাদেরকে জানান।\""],
  "6:165": ["He is the One who made you inheritors of the earth, and He raised some of you above others in rank, in order to test you in accordance with what He has given you. Surely, your Lord is efficient in enforcing retribution, and He is Forgiver, Most Merciful.","তিনিই সে সত্ত্বা যিনি তোমাদেরকে পৃথিবীর উত্তরাধিকারী করেছেন, এবং তিনি তোমাদের কাউকে কাউকে পদমর্যাদায় অন্যদের উপর উন্নীত করেছিলেন, তিনি তোমাদেরকে যা দিয়েছেন সে অনুসারে তোমাদেরকে পরীক্ষা করার জন্য। নিশ্চিতভাবে, তোমাদের প্রভু শাস্তি প্রয়োগে দক্ষ, এবং তিনি ক্ষমাকারী,পরম দয়ালু।"],
  "7:1": ["A. L. M. S.","অ, ল, ম, স"],
  "7:2": ["This scripture has been revealed to you—you shall not harbor doubt about it in your heart—that you may warn with it, and to provide a reminder for the believers.","এই ঐশীগ্রন্থ তোমার কাছে প্রকাশিত হয়েছে- এটি সম্পর্কে তুমি তোমার হৃদয়ে সন্ধেহ পোষণ করবে না- যাতে তুমি এটি দিয়ে সতর্ক করতে পারো,এবং বিশ্বাসীদের জন্য স্মরণ করার একটি মাধ্যম প্রদান করতে পার।"],
  "7:3": ["You shall all follow what is revealed to you from your Lord; do not follow any idols besides Him. Rarely do you take heed.","তোমরা সকলে অনুসরণ করবে তোমাদের প্রভুর পক্ষ থেকে তোমাদের কাছে যা প্রকাশিত হয়েছে;তাঁর পাশে কোন উপাস্য অনুসরণ করো না। তোমরা খুব কমই মনোযোগ দাও।"],
  "7:4": ["Many a community we annihilated; they incurred our retribution while they were asleep, or wide awake.","অনেক জনপদ আমরা ধ্বংস করেছিলাম; তারা আমাদের শাস্তি পেয়েছিল যখন তারা ঘুমন্ত ছিল, অথবা জেগে ছিল।"],
  "7:5": ["Their utterance when our retribution came to them was: \"Indeed, we have been transgressors.\"","যখন আমাদের শাস্তি তাদের কাছে এসেছিল, তাদের উক্তি ছিলঃ “প্রকৃতপক্ষে, আমরা সীমালংঘনকারী হয়েছি”।"],
  "7:6": ["We will certainly question those who received the message, and we will question the messengers.","আমরা অবশ্যই তাদেরকে প্রশ্ন করবো যারা বার্তা পেয়েছিল, এবং আমরা  প্রশ্ন করবো বার্তাবাহকদের।"],
  "7:7": ["We will inform them authoritatively, for we were never absent.","আমরা তাদেরকে প্রমান সহকারে জানাব, যেহেতু আমরা কখনো অনুপস্থিত ছিলাম না।"],
  "7:8": ["The scales will be set on that day, equitably. Those whose weights are heavy will be the winners.","সে দিন মাপযন্ত্র স্থাপন করা হবে, ন্যায়পরায়ণভাবে। যাদের ওজন ভারী হবে, তারা বিজয়ী হবে।"],
  "7:9": ["As for those whose weights are light, they will be the ones who lost their souls, as a consequence of disregarding our revelations, unjustly.","তাদের জন্য যাদের ওজন হাল্কা হবে, তারা হবে সেই লোক যারা তাদের আত্মা হারিয়েছে, আমাদের প্রকাশনাবলী উপেক্ষা করার ফলে,অন্যায়ভাবে।"],
  "7:10": ["We have established you on earth, and we have provided for you the means of support therein. Rarely are you appreciative.","আমরা তোমাদেরকে পৃথিবীর উপর প্রতিষ্ঠিত করেছি, এবং আমরা সেখানে তোমাদের ভরন-পোষনের জন্য উপায় দিয়েছি। তোমরা খুব কমই কৃতজ্ঞ হও।"],
  "7:11": ["We created you, then we shaped you, then we said to the angels, \"Fall prostrate before Adam.\" They fell prostrate, except Iblees (Satan); he was not with the prostrators.","আমরা তোমাদেরকে সৃষ্টি করেছিলাম, এরপর আমরা তোমাদের আকার দিয়েছিলাম, এরপর আমরা ফেরেশতাদের বলেছিলাম, \"আদমের সামনে সেজদাবনত হও।” তারা সেজদাবনত হয়েছিল, ই বলিস (শয়তান) ব্যতীত; সে সেজদাকারীদের সাথে ছিল না।"],
  "7:12": ["He said, \"What prevented you from prostrating when I ordered you?\" He said, \"I am better than he; You created me from fire, and created him from mud.\"","তিনি বলেছিলেন, \"কিসে তোমাকে সেজদা করা থেকে বিরত রেখেছিল, যখন আমি তোমাকে আদেশ করেছিলাম?” সে বলেছিল, \"আমি তার চেয়ে উত্তম; আপনি আমাকে আগুন থেকে সৃষ্টি করেছিলেন, এবং তাকে কাদামাটি থেকে সৃষ্টি করেছিলেন।\""],
  "7:13": ["He said, \"Therefore, you must go down, for you are not to be arrogant here. Get out; you are debased.\"","তিনি বলেছিলেন, \"এজন্য, তুমি অবশ্যই নিচে চলে যাবে, কারন তুমি এখানে উদ্ধত হবে না। বের হয়ে যাও; তুমি অধ:পতিত।\""],
  "7:14": ["He said, \"Grant me a respite, until the Day of Resurrection.\"","সে বলেছিল, \"আমাকে একটি অবকাশ মঞ্জুর করুন, পুন:রুত্থান দিবস পর্যন্ত।\""],
  "7:15": ["He said, \"You are granted a respite.\"","তিনি বলেছিলেন, \"তোমাকে একটি অবকাশ মঞ্জুর করা হলো।\""],
  "7:16": ["He said, \"Since You have willed that I go astray, I will skulk for them on Your straight path.","সে বলেছিল, “যেহেতু আপনি চেয়েছেন যে আমি বিপথে যাই,  আমি তাদের জন্য আপনার সরল পথের উপর গাপটি মেরে থাকব।"],
  "7:17": ["\"I will come to them from before them, and from behind them, and from their right, and from their left, and You will find that most of them are unappreciative.\"","“আমি তাদের কাছে আসব তাদের সামনে থেকে, এবং তাদের পেছন থেকে, এবং তাদের ডান দিক থেকে,এবং তাদের বাম দিক থেকে, এবং আপনি তাদের বেশির ভাগকে অকৃতজ্ঞ পাবেন”।"],
  "7:18": ["He said, \"Get out therefrom, despised and defeated. Those among them who follow you, I will fill Hell with you all.","তিনি বলেছিলেন, “সেখান থেকে বেরিয়ে যাও, ঘৃণিত এবং পরাজিত হয়ে। তাদের মধ্যে যারা তোমাকে অনুসরণ করে, আমি তোমাদের সকলকে দিয়ে নরক পূর্ণ করবো।"],
  "7:19": ["\"As for you, Adam, dwell with your wife in Paradise, and eat therefrom as you please, but do not approach this one tree, lest you fall in sin.\"","“তোমার ক্ষেত্রে, আদম, তোমার স্ত্রীর সাথে স্বর্গে বাস করো, এবং তা থেকে খাও যেমন তোমরা পছন্দ করো, কিন্তু এই একটি গাছের কাছে যেও না, পাছে তোমরা পাপে পতিত হও”।"],
  "7:20": ["The devil whispered to them, in order to reveal their bodies, which were invisible to them. He said, \"Your Lord did not forbid you from this tree, except to prevent you from becoming angels, and from attaining eternal existence.\"","শয়তান তাদের কাছে ফিসফিস করেছিল, তাদের শরীর প্রকাশ করার জন্য, যা তাদের কাছে অদৃশ্য ছিল। সে বলেছিল, “ফেরেশতা হয়ে যাওয়া থেকে,এবং চিরস্থায়ী অস্তিত্ব অর্জন করা থেকে তোমাদের বিরত করা ছাড়া, অন্য কোন কারনে তোমাদের প্রভু তোমাদেরকে এই গাছ নিষেধ করেননি।"],
  "7:21": ["He swore to them, \"I am giving you good advice.\"","সে তাদের কাছে শপথ করেছিল, \"আমি তোমাদেরকে ভাল উপদেশ দিচ্ছি।\""],
  "7:22": ["He thus duped them with lies. As soon as they tasted the tree, their bodies became visible to them, and they tried to cover themselves with the leaves of Paradise. Their Lord called upon them: \"Did I not enjoin you from that tree, and warn you that the devil is your most ardent enemy?\"","সে এভাবে তাদেরকে মিথ্যা বলে প্রতারিত করেছিল। যখনই তারা সে গাছের স্বাদ নিয়েছিল, তাদের দেহ তাদের কাছে দৃশ্যমান হয়ে পড়েছিল, এবং তারা তাদের নিজেদেরকে স্বর্গোদ্যানের পাতা দিয়ে ঢাকার চেষ্টা করেছিল। তাদের প্রভু তাদেরকে ডাকলেন: \"আমি কি তোমাদেরকে ঐ গাছ থেকে বিরত থাকার আদেশ দেইনি, এবং সতর্ক করিনি যে শয়তান তোমাদের সবচেয়ে ঘোর শত্রু?\""],
  "7:23": ["They said, \"Our Lord, we have wronged our souls, and unless You forgive us and have mercy on us, we will be losers.\"","তারা বলেছিল, \"আমাদের প্রভু,আমরা আমাদের আত্মার ক্ষতি করেছি, এবং যদি না আপনি আমাদের ক্ষমা করেন ও আমাদের উপর দয়া করেন, আমরা ক্ষতিগ্রস্ত হবো।\""],
  "7:24": ["He said, \"Go down as enemies of one another. On earth shall be your habitation and provision for awhile.\"","তিনি বলেছিলেন, \"একে অন্যের শত্রু হিসেবে নিচে নেমে যাও। পৃথিবীর উপর হবে তোমাদের বাসস্থান এবং জীবিকা কিছু কালের জন্য।\""],
  "7:25": ["He said, \"On it you will live, on it you will die, and from it you will be brought out.\"","তিনি বলেছিলেন, \"এর উপর তোমরা বাচবে, এর উপর তোমরা মরবে, এবং এর থেকে তোমাদের বের করে আনা হবে।\""],
  "7:26": ["O children of Adam, we have provided you with garments to cover your bodies, as well as for luxury. But the best garment is the garment of righteousness. These are some of Allah's signs, that they may take heed.","হে আদম সন্তানেরা, আমরা তোমাদেরকে পোশাক দিয়েছি তোমাদের শরীর আবৃত করতে, পাশাপাশি বিলাসিতার জন্য। কিন্তু সর্বোত্তম পোশাক হলো সৎকর্মশীলতার পোশাক। এগুলো আল্লাহর কিছু নিদর্শন, যাতে তারা মনোযোগ দিতে পারে।"],
  "7:27": ["O children of Adam, do not let the devil dupe you as he did when he caused the eviction of your parents from Paradise, and the removal of their garments to expose their bodies. He and his tribe see you, while you do not see them. We appoint the devils as companions of those who do not believe.","হে আদম সন্তানেরা, শয়তানকে তোমাদের ক্ষেত্রে তা করতে দিও না যেরকম সে করেছিল যখন সে স্বর্গোদ্যান থেকে তোমাদের পিতামাতার উচ্ছেদ ঘটিয়েছিল, এবং তাদের দেহ প্রকাশ করতে তাদের পোশাকের অপসারণ ঘটিয়েছিল। সে এবং তার জাতি তোমাদের দেখে, যখন তোমরা তাদেরকে দেখো না। আমরা শয়তানদের নিযুক্ত করি তাদের সঙ্গী হিসেবে যারা বিশ্বাস করে না।"],
  "7:28": ["They commit a gross sin, then say, \"We found our parents doing this, and Allah has commanded us to do it.\" Say, \"Allah never advocates sin. Are you saying about Allah what you do not know?\"","তারা একটি মহা পাপ করে, এরপর বলে, “আমরা আমাদের পিতামাতাকে এগুলো করতে দেখেছি,এবং আল্লাহ আমাদেরকে এটা করতে আদেশ করেছেন”। বল, “আল্লাহ কখনো পাপের উকালতি করেন না। তোমরা কি আল্লাহ সম্পর্কে বলছ যা তোমরা জানো না?”"],
  "7:29": ["Say, \"My Lord advocates justice, and to stand devoted to Him alone at every place of worship. You shall devote your worship absolutely to Him alone. Just as He initiated you, you will ultimately go back to Him.\"","বল, “আমার প্রভু উকালতি করেন ন্যায়পরায়ণতার, এবং প্রত্যেক উপাসনার স্থানে একমাত্র তাঁর প্রতি উৎসর্গকৃত হয়ে দাড়ানোর। তোমরা সম্পূর্ণরূপে একমাত্র তাঁর প্রতি তোমাদের উপাসনা উৎসর্গ করবে। ঠিক যেমন তিনি তোমাদের সূচনা করেছিলেন, তোমরা সবশেষে তাঁর কাছেই ফিরে যাবে”।"],
  "7:30": ["Some He guided, while others are committed to straying. They have taken the devils as their masters, instead of Allah, yet they believe that they are guided.","কাউকে কাউকে তিনি পথপ্রদর্শন করেছিলেন, যখন অন্যরা পথভ্রষ্টতায় লিপ্ত। তারা শয়তানদেরকে তাদের মনিব হিসাবে নিয়েছে, আল্লাহর বদলে, তা সত্ত্বেও তারা বিশ্বাস করে যে তারা পথপ্রাপ্ত।"],
  "7:31": ["O children of Adam, you shall be clean and dress nicely when you go to the masjid. And eat and drink moderately. Surely, He does not love the gluttons.","হে আদম সন্তানেরা, তোমরা পরিষ্কার হবে এবং সুন্দরভাবে পোষাক পরিধান করবে, যখন তোমরা মসজিদে যাও। এবং খাও ও পান করো পরিমিতভাবে। নিশ্চয়, তিনি অতিভোজীদের ভালোবাসেন না।"],
  "7:32": ["Say, \"Who prohibited the nice things Allah has created for His creatures, and the good provisions?\" Say, \"Such provisions are to be enjoyed in this life by those who believe. Moreover, the good provisions will be exclusively theirs on the Day of Resurrection.\" We thus explain the revelations for people who know.","বল, \"কে নিষিদ্ধ করে সুন্দর জিনিসগুলো যা আল্লাহ সৃষ্টি করেছেন তাঁর সৃষ্ট জীবের জন্য, এবং উত্তম জীবিকা?\" বল, \"এরকম জীবিকা এই জীবনে তাদের উপভোগ্য হবে, যারা বিশ্বাস করে। অধিকন্তু, ভালো জীবিকা সমূহ পুন:রুত্থান দিবসে কেবলমাত্র তাদের হবে।\" আমরা এভাবে লোকদের জন্য প্রকাশনাবলি ব্যাখ্যা করি, যারা জানে।"],
  "7:33": ["Say, \"My Lord prohibits only evil deeds, be they obvious or hidden, and sins, and unjustifiable aggression, and to set up beside Allah powerless idols, and to say about Allah what you do not know.\"","বল, \"আমার প্রভু নিষেধ করেন শুধু মন্দ কাজগুলো, সেগুলো প্রকাশ্য হোক অথবা গোপন, এবং পাপ, এবং অযৌক্তিক আগ্রাসন, এবং আল্লাহর পাশে ক্ষমতাহীন উপাস্য স্থাপন করা, এবং আল্লাহ সম্পর্কে বলা যা তোমরা জানো না।\""],
  "7:34": ["For each community, there is a predetermined life span. Once their interim comes to an end, they cannot delay it by one hour, nor advance it.","প্রত্যেক সম্প্রদায়ের জন্য, একটি পূর্বনির্ধারিত সময়কাল রয়েছে। যখনই তাদের অন্তবর্তী সময়কাল শেষ হয়ে আসে, তারা একে এক ঘন্টার জন্যও বিলম্ব করাতে পারে না, না তা আগাতে পারে।"],
  "7:35": ["O children of Adam, when messengers come to you from among you, and recite My revelations to you, those who take heed and lead a righteous life, will have nothing to fear, nor will they grieve.","হে আদম সন্তানেরা, যখন বার্তাবাহকরা তোমাদের কাছে আসে তোমাদের মধ্য থেকে, এবং আমার প্রকাশনাবলি তোমাদের কাছে আবৃতি করে, যারা মনোযোগ দেয় এবং একটি সৎকর্মশীল জীবন যাপন করে, তাদের ভয়ের কিছু থাকবে না, না তারা শোক করবে।"],
  "7:36": ["As for those who reject our revelations, and are too arrogant to uphold them, they have incurred Hell, wherein they abide forever.","তাদের জন্য যারা আমাদের প্রকাশনাবলী প্রত্যাখ্যান করে, এবং সেগুলো মেনে চলতে খুব দাম্ভিক হয়, তারা নরক টেনে এনেছে,যেখানে তারা চিরকাল বাস করে।"],
  "7:37": ["Who is more evil than those who invent lies about Allah, or reject His revelations? These will get their share, in accordance with the scripture, then, when our messengers come to terminate their lives, they will say, \"Where are the idols you used to implore beside Allah?\" They will say, \"They have abandoned us.\" They will bear witness against themselves that they were disbelievers.","তাদের থেকে কে বেশি মন্দ যে আল্লাহ সম্বন্ধে মিথ্যা উদ্ভাবন করে, অথবা তাঁর প্রকাশনাবলী প্রত্যাখ্যান করে? এরা তাদের অংশ পাবে, ঐশীগ্রন্থ অনুসারে, এরপর, যখন আমাদের বার্তাবাহকরা তাদের জীবন সমাপ্ত করতে আসে, তারা বলবে, “কোথায় সেই উপাস্যরা, আল্লাহর পাশে যাদের কাছে তোমরা মিনতি করতে?” তারা বলবে, “তারা আমাদের পরিত্যাগ করেছে”। তারা নিজেদের বিরুদ্ধে সাক্ষ্য দিবে যে, তারা অবিশ্বাসী ছিল।"],
  "7:38": ["He will say, \"Enter with the previous communities of jinns and humans into Hell.\" Every time a group enters, they will curse their ancestral group. Once they are all in it, the latest one will say of the previous one, \"Our Lord, these are the ones who misled us. Give them double the retribution of Hell.\" He will say, \"Each receives double, but you do not know.\"","তিনি বলবেন, “পূর্ববর্তী সম্প্রদায়ের জিন এবং মানুষদের সাথে নরকে প্রবেশ করো”। প্রত্যেকবার যখন একটি দল প্রবেশ করে, তারা তাদের পূর্বপুরুষের দলকে অভিশাপ দেবে। যখন তাদের সকলে এর ভিতর থাকবে, সর্বশেষ দলটি পূর্ববর্তী দল সম্পর্কে বলবে, “আমাদের প্রভু, এরা তারাই যারা আমাদের পথভ্রষ্ট করেছিল। তাদেরকে নরকের দিগুন শাস্তি দিন”। তিনি বলবেন, “প্রত্যেকে দিগুন পায়, কিন্তু তোমরা জানো না”।"],
  "7:39": ["The ancestral group will say to the later group, \"Since you had an advantage over us, taste the retribution for your own sins.\"","পূর্বপুরুষের দল পরবর্তী দলকে বলবে, “যেহেতু আমাদের চেয়ে তোমাদের সুবিধা বেশি ছিল , তোমাদের নিজেদের পাপের জন্য শাস্তি আস্বাদন করো”।"],
  "7:40": ["Surely, those who reject our revelations and are too arrogant to uphold them, the gates of the sky will never open for them, nor will they enter Paradise until the camel passes through the needle's eye. We thus requite the guilty.","নিশ্চয়, যারা আমাদের প্রকাশনাবলী প্রত্যাখ্যান করে এবং সেগুলো মেনে চলতে খুব উদ্ধত হয়, আকাশের দরজাগুলো কখনো তাদের জন্য খোলা হবে না, না তারা স্বর্গে প্রবেশ করবে যতক্ষণ না সূচের ছিদ্র দিয়ে উট প্রবেশ করে। আমরা এভাবে অপরাধিদের থেকে প্রতিশোধ গ্রহন করি।"],
  "7:41": ["They have incurred Hell as an abode; they will have barriers above them. We thus requite the transgressors.","তারা একটি আবাস হিসেবে নরক টেনে এনেছে; তাদের উপরে  সীমানা সমূহ থাকবে। আমরা এভাবে সীমালঙ্ঘনকারীদের থেকে প্রতিশোধ গ্রহন করি।"],
  "7:42": ["As for those who believe and lead a righteous life—we never burden any soul beyond its means—these will be the dwellers of Paradise. They abide in it forever.","তাদের জন্য যারা বিশ্বাস করে এবং একটি সৎকর্মশীল জীবন যাপন করে- আমরা কখনো কোন আত্মাকে এর ক্ষমতার অতিরিক্ত বোঝা চাপাই না- এরা হবে স্বর্গোদ্যানের বাসিন্দা। তারা এতে চিরকাল বাস করে।"],
  "7:43": ["We will remove all jealousy from their hearts. Rivers will flow beneath them, and they will say, \"Allah be praised for guiding us. We could not possibly be guided, if it were not that Allah has guided us. The messengers of our Lord did bring the truth.\" They will be called: \"This is your Paradise. You have inherited it, in return for your works.\"","আমরা তাদের অন্তর থেকে সকল ঈর্সা সরিয়ে নেবো। তাদের নিচ থেকে নদীসমূহ প্রবাহিত হবে,এবং তারা বলবে, \"আমাদের পথ-প্রদর্শনের জন্য প্রশংসা আল্লাহর। আমরা সম্ভবত পথপ্রাপ্ত হতে পারতাম না, যদি এটি না হতো যে আল্লাহ আমাদের পথপ্রদর্শন করেছেন। আমাদের প্রভুর বার্তাবাহকরা সত্য এনেছিল।” তাদেরকে ডাকা হবে: \"এটি তোমাদের স্বর্গোদ্যান। তোমরা এর উত্তরাধিকারী হয়েছ, তোমাদের কর্মসমূহের প্রতিদানে।\""],
  "7:44": ["The dwellers of Paradise will call the dwellers of Hell: \"We have found our Lord's promise to be the truth, have you found your Lord's promise to be the truth?\" They will say, \"Yes.\" An announcer between them will announce: \"Allah's condemnation has befallen the transgressors;","স্বর্গোদ্যানের অধিবাসীরা নরকের অধিবাসীদের ডাকবে: \"আমরা আমাদের প্রভুর অংগীকার সত্য পেয়েছি, তোমরা কি তোমাদের প্রভুর অংগীকার সত্য পেয়েছ?\" তারা বলবে, \"হ্যা\"। তাদের মধ্যে একজন ঘোষনাকারী ঘোষনা করবে : \"আল্লাহর শাস্তি সীমালঙ্ঘনকারীদের উপর পড়েছে;"],
  "7:45": ["\"who repel from the path of Allah, and strive to make it crooked, and, with regard to the Hereafter, they are disbelievers.\"","\"যারা আল্লাহর পথে বাধা দেয়, এবং একে বক্র করতে কঠোর চেষ্টা করে,এবং, পরকাল সম্পর্কে, তারা অবিশ্বাসী।\""],
  "7:46": ["A barrier separates them, while the Purgatory is occupied by people who recognize each side by their looks. They will call the dwellers of Paradise: \"Peace be upon you.\" They did not enter (Paradise) through wishful thinking.","একটি সীমানা তাদেরকে আলাদা করে, যখন শুদ্ধিস্থান (আরাফ)  এমন লোকেদের দখলে থাকে যারা তাদের চেহারা দ্বারা প্রতিটি পক্ষকে চিনতে পারে। তারা স্বর্গের বাসিন্দাদের ডাকবেঃ “তোমাদের উপর শান্তি হোক”। তারা মনোমতো চিন্তার ছলে (স্বর্গোদ্যানে) প্রবেশ করেনি।"],
  "7:47": ["When they turn their eyes towards the dwellers of Hell, they will say, \"Our Lord, do not put us with these wicked people.\"","যখন তারা তাদের চোখ নরকের বাসিন্দাদের দিকে ফেরায়, তারা বলবে, “আমাদের প্রভু, আমাদেরকে এই পাপপূর্ন লোকদের সাথে রেখো না”।"],
  "7:48": ["The dwellers of the Purgatory will call on people they recognize by their looks, saying, \"Your great numbers did not avail you in any way, nor did your arrogance.","শুদ্ধিস্থানের বাসিন্দারা জিজ্ঞেস করবে লোকদের, যাদেরকে তাদের চাহনি দেখে চিনবে, এই বলে যে, “তোমাদের বিশাল সংখ্যা কোন ভাবেই তোমাদের উপকারে আসেনি, না তোমাদের ঔদ্ধত্য।"],
  "7:49": ["\"Are those the people you swore that Allah will never touch them with mercy?\" (The people in the Purgatory will then be told,) \"Enter Paradise; you have nothing to fear, nor will you grieve.\"","ওরাই কি সেই লোক তোমরা শপথ করতে যে আল্লাহ কখনো তাদের দয়া করবেন না?”(শুদ্ধিস্থানের লোকদের তখন বলা হবে,) “স্বর্গোদ্যানে প্রবেশ করো; তোমাদের ভয়ের কিছু নেই, না তোমরা শোক করবে”।"],
  "7:50": ["The dwellers of Hell will call on the dwellers of Paradise: \"Let some of your water, or some of Allah's provisions to you flow towards us.\" They will say, \"Allah has forbidden them for the disbelievers.\"","নরকের বাসিন্দারা স্বর্গোদ্যানের বাসিন্দাদের সাথে সাক্ষাতে বলবেঃ “তোমাদের কিছু পানি, অথবা তোমাদেরকে আল্লাহর দেয়া কিছু জীবিকা আমাদের দিকে সরবরাহ করো”। তারা বলবে, “আল্লাহ সেগুলো অবিশ্বাসীদের জন্য নিষিদ্ধ করেছেন”।"],
  "7:51": ["Those who do not take their religion seriously, and are totally preoccupied with this worldly life, we forget them on that day, because they forgot that day, and because they spurned our revelations.","যারা তাদের ধর্মকে গুরুত্বের সাথে নেয় না, এবং দুনিয়ার জীবনে সম্পূর্ণ আচ্ছন্ন, আমরা তাদেরকে ঐ দিন ভুলে যাই, কারণ তারা ঐ দিনকে ভুলে গিয়েছিল, এবং কারণ তারা আমাদের প্রকাশনাবলি অবজ্ঞার সাথে প্রত্যাক্ষান করেছিল।"],
  "7:52": ["We have given them a scripture that is fully detailed, with knowledge, guidance, and mercy for the people who believe.","আমরা তাদেরকে একটি ঐশীগ্রন্থ দিয়েছি যা সম্পূর্ন বিস্তারিত, জ্ঞানে, পথ-প্রদর্শনে,এবং দয়ায়, সে লোকদের জন্য যারা বিশ্বাস করে।"],
  "7:53": ["Are they waiting until all (prophecies) are fulfilled? The day such fulfillment comes to pass, those who disregarded it in the past will say, \"The messengers of our Lord have brought the truth. Are there any intercessors to intercede on our behalf? Would you send us back, so that we change our behavior, and do better works than what we did?\" They have lost their souls, and their own innovations have caused their doom.","তারা কি অপেক্ষা করছে যতক্ষণ না সকল (ভবিষ্যৎবানী) পরিপূর্ণ হয়? সে দিন যখন এরকম পরিপূর্ণতা ঘটে, যারা অতীতে এটি উপেক্ষা করেছিল তারা বলবে, \"আমাদের প্রভুর বার্তাবাহকরা সত্য এনেছে। আমাদের পক্ষে সুপারিশ করতে কোন সুপারীশকারী আছে কি? আপনি কি আমাদের ফেরত পাঠাবেন, যাতে আমরা আমাদের ব্যবহার পরিবর্তন করি, এবং উত্তম কাজ করি তার চেয়ে যা আমরা করেছিলাম?” তারা তাদের আত্মা হারিয়েছে, এবং তাদের নিজেদের উদ্ভাবন তাদের ধ্বংসের কারণ হয়েছে।"],
  "7:54": ["Your Lord is the one Allah; who created the heavens and the earth in six days, then assumed all authority. The night overtakes the day, as it pursues it persistently, and the sun, the moon, and the stars are committed to serve by His command. Absolutely, He controls all creation and all commands. Most Exalted is Allah, Lord of the universe.","তোমাদের প্রভু এক আল্লাহ; যিনি আকাশমন্ডলী  ও পৃথিবী ছয় দিনে সৃষ্টি করেছিলেন,  এরপর সকল কর্তৃত্ব গ্রহন করেছিলেন। রাত নাগাল পায় দিনের, যেহেতু এটি নিরবচ্ছিন্নভাবে এর পেছনে ছোটে, এবং সূর্য, চন্দ্র, ও তারকারাজি তাঁর আদেশে চলতে নিয়োজিত। নি:সন্দেহে, তিনি সকল সৃষ্টি এবং সকল আদেশ নিয়ন্ত্রন করেন। আল্লাহ সবচেয়ে মর্যাদাসম্পন্ন, মহাবিশ্বের প্রভু।"],
  "7:55": ["You shall worship your Lord publicly and privately; He does not love the transgressors.","তোমরা তোমাদের প্রভুকে প্রকাশ্যে এবং গোপনে উপাসনা করবে; তিনি সীমালঙ্ঘনকারীদের ভালোবাসেন না।"],
  "7:56": ["Do not corrupt the earth after it has been set straight, and worship Him out of reverence, and out of hope. Surely, Allah's mercy is attainable by the righteous.","পৃথিবীকে কলুষিত করো না, এটিকে পরিশুদ্ধ করার পর এবং তাঁর উপাসনা করো ভক্তি-শ্রদ্ধা থেকে,এবং আশা নিয়ে। নিশ্চয়, আল্লাহর দয়া সৎ কর্মীদের দ্বারা অর্জনীয়।"],
  "7:57": ["He is the One who sends the wind with good omen, as a mercy from His hands. Once they gather heavy clouds, we drive them to dead lands, and send down water therefrom, to produce with it all kinds of fruits. We thus resurrect the dead, that you may take heed.","তিনিই একজন যিনি শুভ ইঙ্গিত সহ বায়ু পাঠান, তাঁর হাত থেকে একটি দয়া হিসাবে। একবার যখন তারা ভারী মেঘ জড়ো করে, আমরা এগুলোকে মৃত ভূমির দিকে চালনা করি,এবং তা থেকে পানি বর্ষন করি, তা দিয়ে সব রকমের ফল উৎপাদন করতে। আমরা এভাবে মৃতকে পুনরূজ্জীবিত করি, যাতে তোমরা খেয়াল করতে পার।"],
  "7:58": ["The good land readily produces its plants by the leave of its Lord, while the bad land barely produces anything useful. We thus explain the revelations for people who are appreciative.","ভালো জমি সহজে এর উদ্ভিদ উৎপাদন করে এর প্রভুর অনুমতিতে, যখন মন্দ জমি নামেমাত্র প্রয়োজনীয় কিছু উৎপাদন করে। আমরা এভাবে প্রকাশনাবলী ব্যাখ্যা করি লোকদের জন্য যারা কৃতজ্ঞ।"],
  "7:59": ["We sent Noah to his people, saying, \"O my people, worship Allah; you have no other god beside Him. I fear for you the retribution of an awesome day.\"","আমরা নুহকে তার লোকদের কাছে পাঠিয়েছিলাম, এই বলে,“হে আমার লোকেরা,আল্লাহর উপাসনা করো; তাঁর পাশে তোমাদের অন্য কোন উপাস্য নেই। আমি তোমাদের জন্য একটি ভয়াবহ দিনের শাস্তির ভয় করি”।"],
  "7:60": ["The leaders among his people said, \"We see that you are far astray.\"","তার লোকদের নেতারা বলেছিল, “আমরা দেখি যে তুমি বহুদূর পথভ্রষ্ট”।"],
  "7:61": ["He said, \"O my people, I am not astray; I am a messenger from the Lord of the universe.","সে বলেছিল, \"হে আমার লোকেরা,আমি পথভ্রষ্ট নই; আমি মহাবিশ্বের প্রভুর পক্ষ থেকে একজন বার্তাবাহক।"],
  "7:62": ["\"I deliver to you the messages of my Lord, and I advise you, and I know from Allah what you do not know.","\"আমি তোমাদের কাছে আমার প্রভুর বার্তা পৌঁছে দেই, এবং আমি তোমাদেরকে উপদেশ দেই, এবং আমি আল্লাহ থেকে জানি যা তোমরা জানো না।"],
  "7:63": ["\"Is it too much of a wonder that a reminder should come to you from your Lord, through a man like you, to warn you, and to lead you to righteousness, that you may attain mercy?\"","\"এটি কি খুব বেশি বিস্ময়ের যে স্মরণ করার একটি মাধ্যম তোমাদের প্রভুর পক্ষ থেকে আসা উচিত, তোমাদের মতো একজন মানুষের মাধ্যমে, তোমাদেরকে সতর্ক করতে, এবং তোমাদেরকে সৎকর্মশীলতার দিকে পরিচালিত করতে, যাতে তোমরা দয়া অর্জন করতে পারো?\""],
  "7:64": ["They rejected him. Consequently, we saved him and those with him in the ark, and we drowned those who rejected our revelations; they were blind.","তারা তাকে প্রত্যাক্ষান করেছিল। ফলস্বরুপ, আমরা রক্ষা করেছিলাম তাকে এবং যারা তার সাথে নৌকায় ছিল এবং আমরা তাদেরকে ডুবিয়ে ছিলাম যারা আমাদের প্রকাশনাবলি প্রত্যাক্ষান করেছিল; তারা ছিল অন্ধ ।"],
  "7:65": ["To 'Ãd we sent their brother Hûd. He said, \"O my people, worship Allah; you have no other god beside Him. Would you then observe righteousness?\"","আ'দের কাছে আমরা তাদের ভাই হুদকে পাঠিয়েছিলাম। সে বলেছিল, \"হে আমার লোকেরা, আল্লাহর উপাসনা করো ; তাঁর পাশে তোমাদের অন্য উপাস্য নেই। তবে কি তোমরা সৎকর্মশীল হবে?"],
  "7:66": ["The leaders who disbelieved among his people said, \"We see that you are behaving foolishly, and we think that you are a liar.\"","তার লোকেদের মধ্যে নেতারা যারা অবিশ্বাস করেছিল তারা বলেছিল, “আমরা দেখি যে তুমি বোকার মতো আচরণ করছ, এবং আমরা মনে করি যে তুমি একজন মিথ্যুক”।"],
  "7:67": ["He said, \"O my people, there is no foolishness in me; I am a messenger from the Lord of the universe.","সে বলেছিল, “হে আমার লোকেরা, আমার মধ্যে কোন বোকামি নেই; আমি মহাবিশ্বের প্রভুর পক্ষ থেকে একজন বার্তাবাহক”।"],
  "7:68": ["\"I deliver to you my Lord's messages, and I am honestly advising you.","“আমি তোমাদের কাছে আমার প্রভুর বার্তা পৌঁছে দিই, এবং আমি সততার সাথে তোমাদের উপদেশ দিচ্ছি।"],
  "7:69": ["\"Is it too much of a wonder that a message should come to you from your Lord, through a man like you, to warn you? Recall that He made you inheritors after the people of Noah, and multiplied your number. Remember Allah's blessings, that you may succeed.\"","“এটি কি খুব বেশি বিস্ময়ের যে একটি বার্তা তোমাদের প্রভুর পক্ষ থেকে এসেছে, তোমাদের মতো একজন মানুষের মাধ্যমে, তোমাদেরকে সতর্ক করতে? স্মরণ করো যে তিনি তোমাদেরকে নুহের লোকদের পর উত্তরাধিকারী করেছিলেন, এবং তোমাদের সংখ্যা বৃদ্ধি করেছিলেন। স্মরণ করো, আল্লাহর কৃপা, যাতে তোমরা সফলকাম হতে পারো।"],
  "7:70": ["They said, \"Did you come to make us worship Allah alone, and abandon what our parents used to worship? We challenge you to bring the doom you threaten us with, if you are truthful.\"","তারা বলেছিল, “তুমি কি এসেছ আমাদেরকে একমাত্র আল্লাহর উপাসনা করাতে,এ বং আমাদের মাতাপিতারা যা উপাসনা করতো তা পরিত্যাগ করাতে? আমরা তোমাকে সে অনিবার্য ধ্বংস চ্যালেঞ্জ করি যা দিয়ে তুমি আমাদের ভয় দেখাও, যদি তুমি সত্যবাদী হও।"],
  "7:71": ["He said, \"You have incurred condemnation and wrath from your Lord. Do you argue with me in defense of innovations you have fabricated— you and your parents—which were never authorized by Allah? Therefore, wait and I will wait along with you.\"","সে বলেছিল, \"তোমরা তোমাদের প্রভুর পক্ষ থেকে শাস্তি এবং ক্রোধ টেনে এনেছ। তোমরা কি আমার সাথে তর্ক করো তোমাদের বানানো বিষয় সমূহের সমর্থনে যা তোমরা মিথ্যা ভাবে গড়েছো- তোমরা এবং তোমাদের পিতা-মাতারা - যা কখনোই আল্লাহ দ্বারা অনুমোদিত ছিল না? সুতরাং, অপেক্ষা করো এবং আমি তোমাদের সাথে অপেক্ষা করবো।\""],
  "7:72": ["We then saved him and those with him, by mercy from us, and we annihilated those who rejected our revelations and refused to be believers.","আমরা তখন রক্ষা করেছিলাম তাকে এবং যারা তার সাথে ছিল, আমাদের পক্ষ থেকে দয়ার দ্বারা, এবং আমরা তাদেরকে ধ্বংস করেছিলাম যারা আমাদের প্রকাশনাবলি প্রত্যাক্ষান করেছিল এবং বিশ্বাসী হতে অস্বীকার করেছিল।"],
  "7:73": ["To Thamûd we sent their brother Sãleh. He said, \"O my people, worship Allah; you have no other god beside Him. Proof has been provided for you from your Lord: here is Allah's camel, to serve as a sign for you. Let her eat from Allah's land, and do not touch her with any harm, lest you incur a painful retribution.","সামুদের কাছে আমরা তাদের ভাই সালেহকে পাঠিয়েছিলাম। সে বলেছিল, \"হে আমার লোকেরা, আল্লাহর উপাসনা করো ; আল্লাহর পাশে তোমাদের অন্য কোন উপাস্য নেই।  তোমাদের জন্য তোমাদের প্রভুর পক্ষ থেকে প্রমান দেয়া হয়েছে: এই যে আল্লাহর উট, তোমাদের জন্য একটি নিদর্শন। একে আল্লাহর দেয়া জমি থেকে খেতে দাও, এবং কোনো ক্ষতির উদ্দেশ্যে একে স্পর্শ করো না, পাছে তোমরা এক যন্ত্রনাদায়ক শাস্তি টেনে আনো।"],
  "7:74": ["\"Recall that He made you inheritors after 'Ãd, and established you on earth, building mansions in its valleys, and carving homes from its mountains. You shall remember Allah's blessings, and do not roam the earth corruptingly.\"","\"স্মরন করো যে, তিনি আদের পর তোমাদের উত্তরাধিকারী করেছিলেন, এবং পৃথিবীর উপর তোমাদেরকে প্রতিষ্ঠিত করেছিলেন, এর উপত্যকায় অট্রালিকা তৈরী করে, এবং এর পাহাড়ে বাড়ি খোদাই করে। তোমরা আল্লাহর আশীর্বাদকে স্মরণ করবে, এবং পৃথিবীতে দূর্নীতি করে বেড়িও না।\""],
  "7:75": ["The arrogant leaders among his people said to the common people who believed, \"How do you know that Sãleh is sent by his Lord?\" They said, \"The message he brought has made us believers.\"","তার লোকদের মধ্যে উদ্ধত নেতারা সেসব সাধারন লোকদের বলেছিল যারা বিশ্বাস করেছিল, \"তোমরা কিভাবে জানো যে সালেহ তার প্রভুর পক্ষ থেকে প্রেরিত?” তারা বলেছিল, \"যে বার্তা সে এনেছিল, তা আমাদেরকে বিশ্বাসী করেছে।\""],
  "7:76": ["The arrogant ones said, \"We disbelieve in what you believe in.\"","উদ্ধত লোকেরা বলেছিল, “তোমরা যা বিশ্বাস করো  তা আমরা অবিশ্বাস করি”।"],
  "7:77": ["Subsequently, they slaughtered the camel, rebelled against their Lord's command, and said, \"O Sãleh, bring the doom you threaten us with, if you are really a messenger.\"","ফলস্বরূপ, তারা উটটি হত্যা করেছিল, তাদের প্রভুর হুকুমের বিরুদ্ধে বিদ্রোহ করেছিল, এবং বলেছিল, \"হে সালেহ, নিয়ে আসো সেই অনিবার্য ধ্বংস যা দিয়ে তুমি আমাদের ভয় দেখাও, যদি সত্যি তুমি একজন বার্তাবাহক হও”।"],
  "7:78": ["Consequently, the quake annihilated them, leaving them dead in their homes.","ফলস্বরূপ, ভূমিকম্প তাদের নির্মূল করেছিল, তাদেরকে তাদের বাড়িতে মৃত ফেলে রেখে।"],
  "7:79": ["He turned away from them, saying, \"O my people, I have delivered my Lord's message to you, and advised you, but you do not like any advisers.\"","সে তাদের থেকে মুখ ফিরিয়ে নিয়েছিল, এই বলে, “হে আমার লোকেরা, আমি আমার প্রভুর বার্তা তোমাদের কাছে পৌঁছিয়েছি, এবং তোমাদের উপদেশ দিয়েছি, কিন্তু তোমরা কোন উপদেশ প্রদানকারী পছন্দ করো না”।"],
  "7:80": ["Lot said to his people, \"You commit such an abomination; no one in the world has done it before!","লুত তার লোকদের বলেছিল, “তোমরা এমন নিদারুন ঘৃণ্য কাজে লিপ্ত; বিশ্বে কেউ আগে এটা করেনি!”"],
  "7:81": ["\"You practice sex with the men, instead of the women. Indeed, you are a transgressing people.\"","\"তোমরা মহিলাদের বদলে পুরুষদের সাথে যৌণ চর্চা করো। প্রকৃতপক্ষে, তোমরা একটি সীমালঙ্ঘনকারী সম্প্রদায়।"],
  "7:82": ["His people responded by saying, \"Evict them from your town. They are people who wish to be pure.\"","তার লোকেরা এই বলে সাড়া দিয়েছিল যে, \"তাদেরকে তোমার শহর থেকে তাড়াও। তারা এমন লোক যারা সচ্চরিত্রবান হতে চায়।\""],
  "7:83": ["Consequently, we saved him and his family, but not his wife; she was with the doomed.","ফলস্বরুপ, আমরা তাকে এবং তার পরিবারকে রক্ষা করেছিলাম, কিন্তু তার স্ত্রীকে নয়;  সে ধ্বংসপ্রাপ্তদের সাথে ছিল।"],
  "7:84": ["We showered them with a certain shower; note the consequences for the guilty.","আমরা একটি নির্দিষ্ট বর্ষন তাদের উপর বর্ষিত করেছিলাম; সেসব অপরাধীর পরিণতি লক্ষ্য করো।"],
  "7:85": ["To Midyan we sent their brother Shu'aib. He said, \"O my people, worship Allah; you have no other god beside Him. Proof has come to you from your Lord. You shall give full weight and full measure when you trade. Do not cheat the people out of their rights. Do not corrupt the earth after it has been set straight. This is better for you, if you are believers.","মাদিয়ানবাসীর কাছে আমরা তাদের ভাই শোয়েবকে পাঠিয়েছিলাম। সে বলেছিল, \"হে আমার লোকেরা, আল্লাহর উপাসনা করো; তাঁর পাশে তোমাদের অন্য কোন উপাস্য নেই। তোমাদের প্রভুর পক্ষ থেকে তোমাদের কাছে প্রমান এসেছে। তোমরা পূর্ণ ওজন এবং পূর্ণ মাপ দিবে, যখন তোমরা ব্যবসা করো। লোকদেরকে তাদের অধিকার থেকে ঠকিও না। পৃথিবীকে কলুষিত করো না, এটি পরিশুদ্ধ করার পর। এটি তোমাদের জন্য উত্তম, যদি তোমরা বিশ্বাসী হও।"],
  "7:86": ["\"Refrain from blocking every path, seeking to repel those who believe from the path of Allah, and do not make it crooked. Remember that you used to be few and He multiplied your number. Recall the consequences for the wicked.","“বিরত হও প্রত্যেক পথে বাঁধা দেয়া হতে , আল্লাহর পথ থেকে তাদেরকে তাড়িয়ে দেয়ার প্রয়াসে যারা বিশ্বাস করে, এবং একে বক্র করো না। স্মরণ করো যে, তোমরা সংখ্যায় কম ছিলে এবং তিনি তোমাদের সংখ্যা বৃদ্ধি করেছিলেন। স্মরণ করো, পাপীদের পরিণতি।"],
  "7:87": ["\"Now that some of you have believed in what I was sent with, and some have disbelieved, wait until Allah issues His judgment between us; He is the best judge.\"","“এখন যেহেতু তোমাদের কেউ কেউ বিশ্বাস করেছ তাতে যা নিয়ে আমি প্রেরিত  হয়েছি, এবং কেউ কেউ অবিশ্বাস করেছ, অপেক্ষা করো  যতক্ষণ পর্যন্ত না আল্লাহ আমাদের মধ্যে তাঁর রায় দেন; তিনি সর্বোত্তম বিচারক।"],
  "7:88": ["The arrogant leaders among his people said, \"We will evict you, O Shu'aib, together with those who believed with you, from our town, unless you revert to our religion.\" He said, \"Are you going to force us?\"","তার লোকদের মধ্যে উদ্ধত নেতারা বলেছিল, “আমরা তোমাকে উচ্ছেদ করবো, হে সোয়েব, তাদের সাথে একত্রে যারা তোমার সাথে বিশ্বাস করেছিল, আমাদের শহর থেকে, যদি না তোমরা আমাদের ধর্মে ফিরে আসো। “সে বলেছিল, “তোমরা কি আমাদের জোর করতে যাচ্ছ?"],
  "7:89": ["\"We would be blaspheming against Allah if we reverted to your religion after Allah has saved us from it. How could we revert back to it against the will of Allah our Lord? Our Lord's knowledge encompasses all things. We have put our trust in Allah. Our Lord, grant us a decisive victory over our people. You are the best supporter.\"","“আমরা আল্লাহর বিরুদ্ধে মিথ্যা আরোপকারী হয়ে যাব, যদি আমরা তোমাদের ধর্মে প্রত্যাবর্তন করি, আল্লাহ আমাদেরকে তা থেকে রক্ষা করার পর। আমাদের প্রভু আল্লাহর ইচ্ছার বিরুদ্ধে কেমন করে আমরা পুনরায় এতে প্রত্যাবর্তন করতে পারি? আমাদের প্রভুর জ্ঞান সকল বস্তুকে বেষ্টন করে আছে। আমরা আল্লাহর প্রতি আমাদের আস্থা রেখেছি। আমাদের প্রভু, আমাদেরকে আমাদের লোকদের উপর চূড়ান্ত বিজয় দিন। আপনি সর্বোত্তম সমর্থনকারী”।"],
  "7:90": ["The disbelieving leaders among his people said, \"If you follow Shu'aib, you will be losers.\"","তার লোকদের মধ্যে অবিশ্বাসী নেতারা বলেছিল, “যদি তোমরা সোয়েবকে অনুসরণ করো, তোমরা ক্ষতিগ্রস্ত হবে”।"],
  "7:91": ["The quake annihilated them, leaving them dead in their homes.","ভূমিকম্প তাদেরকে নির্মূল করেছিল, তাদেরকে তাদের বাড়িতে মৃত ফেলে রেখে।"],
  "7:92": ["Those who rejected Shu'aib vanished, as if they never existed. Those who rejected Shu'aib were the losers.","যারা শোয়েবকে প্রত্যাক্ষান করেছিল তারা বিলুপ্ত হয়েছিল, যেন কখনোই তাদের অস্তিত্ব ছিল না। যারা শোয়েবকে প্রত্যাক্ষান করেছিল তারা ছিল ক্ষতিগ্রস্ত।"],
  "7:93": ["He turned away from them, saying, \"O my people, I have delivered to you the messages of my Lord, and I have advised you. How can I grieve over disbelieving people.\"","সে তাদের থেকে মুখ ফিরিয়ে নিয়েছিল, এই বলে, \"হে আমার লোকেরা, আমি আমার প্রভুর বার্তা তোমাদের কাছে পৌছিঁয়েছি, এবং আমি তোমাদেরকে উপদেশ দিয়েছি। কিভাবে আমি অবিশ্বাসী লোকদের জন্য দু:খ করতে পারি।\""],
  "7:94": ["Whenever we sent a prophet to any community, we afflicted its people with adversity and hardship, that they may implore.","যখনই আমরা কোন সম্প্রদায়ের কাছে কোন নবী পাঠিয়েছিলাম, আমরা এর লোকদেরকে প্রতিকূলতা এবং কষ্ট দিয়ে দূর্দশাগ্রস্থ করেছিলাম, যাতে তারা মিনতি করে।"],
  "7:95": ["Then we substituted peace and prosperity in place of that hardship. But alas, they turned heedless and said, \"It was our parents who experienced that hardship before prosperity.\" Consequently, we punished them suddenly when they least expected.","এরপর আমরা ঐ কষ্টের জায়গায় শান্তি এবং সমৃদ্ধি প্রতিস্থাপিত করেছিলাম। কিন্তু হায়, তারা অমনোযোগী হয়ে পড়েছিল এবং বলেছিল, \"আমাদের মাতাপিতারাও সমৃদ্ধির পূর্বে ঐ কষ্ট ভোগ করেছিল।” ফলস্বরুপ, আমরা তাদের শাস্তি দিয়েছিলাম আকষ্মিকভাবে, যখন তারা খুব অল্পই এমনটা ভেবেছিল।"],
  "7:96": ["Had the people of those communities believed and turned righteous, we would have showered them with blessings from the heaven and the earth. Since they decided to disbelieve, we punished them for what they earned.","ঐসব সম্প্রদায়ের লোকরা যদি বিশ্বাস করতো এবং সৎকর্মশীলতে পরিনত হতো, আমরা আকাশ এবং পৃথিবী থেকে তাদের আশীর্বাদ বর্ষণ করতাম। যেহেতু তারা অবিশ্বাস করার সিদ্ধান্ত নিয়েছিল, আমরা তাদেরকে শাস্তি দিয়েছিলাম তার জন্য, যা তারা অর্জন করেছিল।"],
  "7:97": ["Did the people of the present communities guarantee that our retribution will not come to them in the night as they sleep?","বর্তমান সম্প্রদায়ের লোকেরা কি নিশ্চয়তা দেয় যে, আমাদের শাস্তি রাতে তাদের কাছে আসবে না, যখন তারা ঘুমন্ত?"],
  "7:98": ["Did the people of today's communities guarantee that our retribution will not come to them in the daytime while they play?","বর্তমান সম্প্রদায়ের লোকেরা কি নিশ্চয়তা দেয় যে আমাদের শাস্তি দিনে তাদের কাছে আসবে না, যখন তারা খেলায় মগ্ন?"],
  "7:99": ["Have they taken Allah's plans for granted? None takes Allah's plans for granted except the losers.","তারা কি আল্লাহর পরিকল্পনাকে আবজ্ঞা করেছে? দুর্ভাগারা ছাড়া কেউ আল্লাহর পরিকল্পনাকে আবজ্ঞা করে না।"],
  "7:100": ["Does it ever occur to those who inherit the earth after previous generations that, if we will, we can punish them for their sins, and seal their hearts, causing them to turn deaf?","যারা পূর্ববর্তী প্রজন্মের পর পৃথিবীকে উত্তরাধিকার করে কখনো কি এটা তাদের উপলব্ধি হয় যে, আমরা যদি চাই, আমরা তাদের পাপের জন্য তাদের শাস্তি দিতে পারি, এবং তাদের হৃদয়ে মোহর মেরে দিতে পারি, তাদেরকে বধির করে দিয়ে?"],
  "7:101": ["We narrate to you the history of those communities: their messengers went to them with clear proofs, but they were not to believe in what they had rejected before. Allah thus seals the hearts of the disbelievers.","আমরা তোমার কাছে সেসব সম্প্রদায়ের ইতিহাস বর্ননা করি: তাদের কাছে তাদের বার্তাবাহকেরা সুস্পষ্ট প্রমানাদি নিয়ে গিয়েছিল, কিন্তু তারা বিশ্বাস করার ছিল না তাতে, যা তারা পূর্বেই প্রত্যাক্ষান করেছিল। আল্লাহ এভাবে অবিশ্বাসীদের অন্তরে মোহর এটে দেন।"],
  "7:102": ["We found that most of them disregard their covenant; we found most of them wicked.","আমরা পেয়েছিলাম যে,তাদের বেশির ভাগ তাদের অংগীকার উপেক্ষা করে; আমরা তাদের বেশির ভাগকে পাপী পেয়েছিলাম।"],
  "7:103": ["After (those messengers,) we sent Moses with our signs to Pharaoh and his people, but they transgressed. Note the consequences for the wicked.","সেসব বার্তাবাহকদের) পর, আমরা ফেরাউন এবং তার লোকদের কাছে আমাদের নিদর্শনাবলি দিয়ে মুসাকে পাঠিয়েছিলাম, কিন্তু তারা সীমালঙ্ঘন করেছিল। লক্ষ্য করো,পাপীদের পরিণতি।"],
  "7:104": ["Moses said, \"O Pharaoh, I am a messenger from the Lord of the universe.","মূসা বলেছিল, \"হে ফেরাউন, আমি মহাবিশ্বের প্রভুর পক্ষ থেকে একজন বার্তাবাহক।"],
  "7:105": ["\"It is incumbent upon me that I do not say about Allah except the truth. I come to you with a sign from your Lord; let the Children of Israel go.\"","\"এটি আমার উপর অবশ্য পালনীয় যে,আমি আল্লাহ সম্পর্কে সত্য ছাড়া বলি না। আমি তোমাদের প্রভুর পক্ষ থেকে একটি নিদর্শন নিয়ে এসেছি; ইসরাইলের সন্তানদের যেতে দাও।"],
  "7:106": ["He said, \"If you have a sign, then produce it, if you are truthful.\"","সে বলেছিল, “যদি তোমার একটি নিদর্শন থাকে,তাহলে তা উপস্থাপন করো,যদি তুমি সত্যবাদী হও”।"],
  "7:107": ["He threw down his staff, and it turned into a tremendous serpent.","সে তার লাঠি নিক্ষেপ করেছিল, এবং এটি এক ভয়ানক সাপে পরিনত হয়েছিল।"],
  "7:108": ["He took out his hand, and it was white to the beholders.","সে তার হাত বের করেছিল, এবং এটি ছিল দর্শকদের কাছে সাদা।"],
  "7:109": ["The leaders among Pharaoh's people said, \"This is no more than a clever magician.","ফেরাউনের লোকদের নেতারা বলেছিল, \"সে একজন চতুর যাদুকর ছাড়া বেশি কিছু নয়।"],
  "7:110": ["\"He wants to take you out of your land; what do you recommend?\"","“সে তোমাদেরকে তোমাদের দেশ থেকে বের করে নিয়ে যেতে চায়; তোমরা কি পরামর্শ দাও?”"],
  "7:111": ["They said, \"Respite him and his brother, and send summoners to every city.","তারা বলেছিল, \"তাকে এবং তার ভাইকে অবকাশ দিন, এবং আহ্বানকারীদেরকে প্রত্যেক শহরে পাঠান।"],
  "7:112": ["\"Let them summon every experienced magician.\"","\"তাদেরকে সকল অভিজ্ঞ যাদুকরদের একত্র করতে দিন।\""],
  "7:113": ["The magicians came to Pharaoh and said, \"Do we get paid if we are the winners?\"","যাদুকররা ফেরাউনের কাছে এসেছিল এবং বলেছিল, \"যদি আমরা জয়ী হই, আমরা কি পারিশ্রমিক পাবো?\""],
  "7:114": ["He said, \"Yes indeed; you will even become close to me.\"","সে বলেছিল, \"হ্যা নিশ্চয়ই; তোমরা এমনকি আমার নিকটবর্তী হবে।\""],
  "7:115": ["They said, \"O Moses, either you throw, or we are throwing.\"","তারা বলেছিল, \"হে মূসা, হয় তুমি ছোড়ো, অথবা আমরা ছুড়ছি।\""],
  "7:116": ["He said, \"You throw.\" When they threw, they tricked the people's eyes, intimidated them, and produced a great magic.","সে বলল, “তোমরা ছোড়ো”। যখন তারা ছুঁড়ল, তারা লোকদের চোখকে ধোঁকা দিলো, তাদেরকে ভয় দেখালো, এবং একটি বিশাল যাদু উপস্থাপন করলো।"],
  "7:117": ["We then inspired Moses: \"Throw down your staff,\" whereupon it swallowed whatever they fabricated.","আমরা তখন মুসাকে উদ্বুদ্ধ করলামঃ “তোমার লাঠি ছোড়ে ফেলো,” যার ফলে তা গিলে ফেললো, যা কিছু তারা মিথ্যা বানিয়েছিল।"],
  "7:118": ["Thus, the truth prevailed, and what they did was nullified.","এভাবে, সত্য জয়ী হলো, এবং যা তারা করেছিল, তা অকার্যকর হলো।"],
  "7:119": ["They were defeated then and there; they were humiliated.","তারা তৎক্ষণাৎ পরাজিত হলো; তারা অপদস্ত হলো।"],
  "7:120": ["The magicians fell prostrate.","যাদুকরেরা সেজদায় পড়লো।"],
  "7:121": ["They said, \"We believe in the Lord of the universe.","তারা বলল, \"আমরা মহাবিশ্বের প্রভুকে বিশ্বাস করি।"],
  "7:122": ["\"The Lord of Moses and Aaron.\"","\"মূসা এবং হারুনের প্রভুকে।\""],
  "7:123": ["Pharaoh said, \"Did you believe in him without my permission? This must be a conspiracy you schemed in the city, in order to take its people away. You will surely find out.","ফেরাউন বলল, \"তোমরা কি আমার অনুমতি ছাড়া তাকে বিশ্বাস করলে? এটি অবশ্যই একটি ষড়যন্ত্র হবে, যা তোমরা শহরে পরিকল্পনা করেছিলে, এর লোকদেরকে সরিয়ে নিয়ে যেতে। তোমরা অবশ্যই দেখতে পাবে।"],
  "7:124": ["\"I will cut your hands and feet on alternate sides, then I will crucify you all.\"","“আমি তোমাদের হাত এবং পা বিপরীত দিক থেকে কাটবো, এরপর আমি তোমাদের সবাইকে ক্রুশবিদ্ধ করবো।\""],
  "7:125": ["They said, \"We will then return to our Lord.","তারা বলল, \"আমরা এরপর আমাদের প্রভুর নিকট ফিরে যাবো।"],
  "7:126": ["\"You persecute us simply because we believed in the proofs of our Lord when they came to us.\" \"Our Lord, grant us steadfastness, and let us die as submitters.\"","“তুমি আমাদেরকে শুধুমাত্র এ কারনে নির্যাতন করো যে আমরা আমাদের প্রভুর প্রমানে বিশ্বাস করেছি, যখন সেগুলো আমাদের কাছে এসেছে। “আমাদের প্রভু, আমাদের দৃড়তা প্রদান করুন, এবং আমাদেরকে আত্মসমর্পণকারী হিসেবে মৃত্যু দিন”।"],
  "7:127": ["The leaders among Pharaoh's people said, \"Will you allow Moses and his people to corrupt the earth, and forsake you and your gods?\" He said, \"We will kill their sons, and spare their daughters. We are much more powerful than they are.\"","ফেরাউনের লোকদের নেতারা বলল, “আপনি কি মুসা এবং তার লোকদের পৃথিবীকে কলুষিত করতে দেবেন, এবং আপনাকে এবং আপনার উপাস্যদেরকে পরিত্যাগ করতে দেবেন?” সে বলল, “আমরা তাদের পুত্রদের হত্যা করবো, এবং কন্যাদের নিষ্কৃতি দেবো। আমরা তাদের থেকে অনেক বেশি শক্তিশালী”।"],
  "7:128": ["Moses said to his people, \"Seek Allah's help, and steadfastly persevere. The earth belongs to Allah, and He grants it to whomever He chooses from among His servants. The ultimate victory belongs to the righteous.\"","মুসা তার লোকদের বলল, “আল্লাহর সাহায্য প্রার্থনা করো, এবং দৃড়তার সাথে অধ্যবসায়ী হও। পৃথিবী আল্লাহর, এবং তিনি এটি প্রদান করেন তাঁর দাসদের মধ্যে থেকে যাকে তিনি পছন্দ করেন। চূড়ান্ত বিজয় সৎকর্মশীলদের।"],
  "7:129": ["They said, \"We were persecuted before you came to us, and after you came to us.\" He said, \"Your Lord will annihilate your enemy and establish you on earth, then He will see how you behave.\"","তারা বলল, “আমরা নির্যাতিত ছিলাম - তুমি আমাদের কাছে আসার আগে, এবং তুমি আমাদের কাছে আসার পরে”। সে বলল, “তোমাদের প্রভু তোমাদের শত্রুকে সম্পূর্ন ধ্বংস করবেন এবং তোমাদেরকে পৃথিবীতে প্রতিষ্ঠিত করবেন, এরপর তিনি দেখবেন - তোমরা কেমন আচরণ করো”।"],
  "7:130": ["We then afflicted Pharaoh's people with drought, and shortage of crops, that they may take heed.","আমরা এরপর ফেরাউনের লোকদের খরা, এবং ফসলের ঘাটতি দিয়ে দুর্দশাগ্রস্থ করলাম, যাতে তারা সতর্ক হয়।"],
  "7:131": ["When good omens came their way, they said, \"We have deserved this,\" but when a hardship afflicted them, they blamed Moses and those with him. In fact, their omens are decided only by Allah, but most of them do not know.","যখন তাদের সামনে শুভ লক্ষনসমূহ আসতো, তারা বলতো, “আমরা এর উপযুক্ত হয়েছি,” কিন্তু যখন কোন কষ্ট তাদেরকে পীড়া দিতো, তারা মূসাকে এবং তার সাথে যারা ছিল তাদেরকে দোষী করতো। প্রকৃতপক্ষে, তাদের লক্ষনসমূহ শুধুমাত্র আল্লাহর দ্বারা সিদ্ধান্তকৃত, কিন্তু তাদের বেশির ভাগ জানে না।"],
  "7:132": ["They said, \"No matter what kind of sign you show us, to dupe us with your magic, we will not believe.\"","তারা বলল, “তুমি আমাদেরকে যে রকমের নিদর্শনই দেখাও না কেন, তোমার যাদু দিয়ে আমাদেরকে প্রতারিত করতে, আমরা বিশ্বাস করবো না।’’"],
  "7:133": ["Consequently, we sent upon them the flood, the locusts, the lice, the frogs, and the blood—profound signs. But they maintained their arrogance. They were evil people.","ফলস্বরূপ, আমরা তাদের উপর পাঠিয়েছিলাম বন্যা, পঙ্গপাল, উকুন, ব্যাঙ, এবং রক্ত- প্রগাড় নিদর্শনাবলি। কিন্তু তারা তাদের দাম্ভিকতা বজায় রাখলো। তারা মন্দ লোক ছিল।"],
  "7:134": ["Whenever a plague afflicted them, they said, \"O Moses, implore your Lord—you are close to Him. If you relieve this plague, we will believe with you, and will send the Children of Israel with you.\"","যখনই কোন মহামারি তাদের দূর্দশাগ্রস্থ করতো, তারা বলতো “হে মূসা, তোমার প্রভুর কাছে মিনতি করো- তুমি তাঁর নিকটবর্তী। যদি তুমি এই মহামারি দূর করো, আমরা তোমার সাথে বিশ্বাস করবো, এবং ইসরাইলের সন্তানদের তোমার সাথে পাঠাব।”"],
  "7:135": ["Yet, when we relieved the plague for any length of time, they violated their pledge.","এরপরও, যখন কিছু সময়ের জন্য আমরা মহামারী দূর করতাম, তারা তাদের অংগীকার ভঙ্গ করতো।"],
  "7:136": ["Consequently, we avenged their actions, and drowned them in the sea. That is because they rejected our signs, and were totally heedless thereof.","ফলস্বরূপ, আমরা তাদের কাজের প্রতিশোধ গ্রহণ করলাম, এবং তাদের সাগরে ডুবিয়ে দিলাম। এটা এ কারনে যে তারা আমাদের নিদর্শন প্রত্যাখ্যান করেছিল, এবং তা হতে পুরোপুরি অমনোযোগী ছিল।"],
  "7:137": ["We let the oppressed people inherit the land, east and west, and we blessed it. The blessed commands of your Lord were thus fulfilled for the Children of Israel, to reward them for their steadfastness, and we annihilated the works of Pharaoh and his people and everything they harvested.","আমরা নির্যাতিত লোকদের ভূমির উত্তরাধিকারী করলাম, পূর্ব এবং পশ্চিম, এবং আমরা একে মহিমান্বিত করলাম। তোমার প্রভুর পবিত্র হুকুম এভাবে ইসরাইলের সন্তানদের জন্য পরিপূর্ণ হয়েছিল, তাদেরকে তাদের ধৈর্য্যশীলতার জন্য পুরস্কৃত করতে, এবং আমরা নির্মূল করেছিলাম ফেরাউন ও তার লোকদের কাজ এবং তাদের ফলানো সবকিছু।"],
  "7:138": ["We delivered the Children of Israel across the sea. When they passed by people who were worshiping statues, they said, \"O Moses, make a god for us, like the gods they have.\" He said, \"Indeed, you are ignorant people.","আমরা ইসরাইলের সন্তানদের সাগর পার করালাম। যখন তারা পাশ দিয়ে যাচ্ছিলো সেই লোকদের, যারা মূর্তি পুজা করছিল, তারা বলল, “হে মুসা,তাদের উপাস্যের মতো আমাদের জন্য একটি উপাস্য বানাও”। সে বলল, “নিশ্চয়, তোমরা অজ্ঞ লোক।"],
  "7:139": ["\"These people are committing a blasphemy, for what they are doing is disastrous for them.","“এইসব  লোকেরা এক মিথ্যাচারে লিপ্ত, তারা যা করছে এর ফল  তাদের জন্য ধ্বংসাত্মক।"],
  "7:140": ["\"Shall I seek for you other than Allah to be your god, when He has blessed you more than anyone else in the world?\"","“আমি কি তোমাদের উপাস্য হতে আল্লাহ ছাড়া অন্য কাউকে খুঁজবো, যখন তিনি তোমাদেরকে বিশ্বের অন্য যে কারোর চেয়ে সৌভাগ্যবান করেছেন?”"],
  "7:141": ["Recall that we delivered you from Pharaoh's people, who inflicted the worst persecution upon you, killing your sons and sparing your daughters. That was an exacting trial for you from your Lord.","স্মরণ করো যে আমরা তোমাদেরকে ফেরাউনের লোকদের থেকে রক্ষা করেছিলাম, যারা তোমাদের উপর নির্মম অত্যাচার চালাতো,তোমাদের পূত্রদের হত্যা করতো আর কন্যাদের ছেড়ে দিতো। তোমাদের প্রভুর পক্ষ থেকে সেটা ছিল তোমাদের জন্য একটি কঠিন পরীক্ষা।"],
  "7:142": ["We summoned Moses for thirty nights, and completed them by adding ten. Thus, the audience with his Lord lasted forty nights. Moses said to his brother Aaron, \"Stay here with my people, maintain righteousness, and do not follow the ways of the corruptors.\"","আমরা মুসাকে ডেকেছিলাম ত্রিশ রাতের জন্য, এবং সেগুলোকে পূর্ন করেছিলাম দশ যোগ করে। এভাবে, তার প্রভুর সাথে শ্রবন চল্লিশ  রাতের জন্য স্থায়ী হয়েছিল। মূসা তার ভাই হারুনকে বলল, \"এখানে আমার লোকদের সাথে থাকো, সৎকর্মশীলতা বজায় রাখো, এবং দূর্নীতিগ্রস্থ লোকদের পথ অনুসরণ করো না।\""],
  "7:143": ["When Moses came at our appointed time, and his Lord spoke with him, he said, \"My Lord, let me look and see You.\" He said, \"You cannot see Me. Look at that mountain; if it stays in its place, then you can see Me.\" Then, his Lord manifested Himself to the mountain, and this caused it to crumble. Moses fell unconscious. When he came to, he said, \"Be You glorified. I repent to You, and I am the most convinced believer.\"","যখন মুসা আমাদের নির্ধারিত সময়ে আসল, এবং তার প্রভু তার সাথে কথা বললেন, সে বলেছিল, \"আমার প্রভু,আমাকে আপনার দিকে তাকাতে এবং দেখতে দিন।” তিনি বললেন, \"তুমি আমাকে দেখতে পারো না। ঐ পাহাড়ের দিকে তাকাও; যদি এটি এর জায়গায় স্থির থাকে, তাহলে তুমি আমাকে দেখতে পারো।\" এরপর, তার প্রভু নিজেকে পাহাড়ে স্পষ্ট প্রকাশ করলেন, এবং এটি একে ভেঙ্গে গুঁড়িয়ে দিলো। মুসা অচেতন হয়ে পড়লো। যখন সে চেতনা ফিরে পেল, সে বলল, \"আপনি মহিমান্বিত। আমি আপনার নিকট অনুশোচনা করি, এবং আমি সর্বোচ্চ প্রমানপ্রাপ্ত বিশ্বাসী।\""],
  "7:144": ["He said, \"O Moses, I have chosen you, out of all the people, with My messages and by speaking to you. Therefore, take what I have given you and be appreciative.\"","তিনি বললেন, \"হে মুসা,আমি তোমাকে পছন্দ করেছি,সব লোকের মধ্য থেকে, আমার বার্তা দিয়ে এবং তোমার সঙ্গে কথা বলার মাধ্যমে। সুতরাং, আমি তোমাকে যা দিয়েছি তা গ্রহন করো এবং কৃতজ্ঞ হও।\""],
  "7:145": ["We wrote for him on the tablets all kinds of enlightenments and details of everything: \"You shall uphold these teachings strongly, and exhort your people to uphold them—these are the best teachings. I will point out for you the fate of the wicked.\"","আমরা তার জন্য ফলকের উপর সব ধরনের শিক্ষা এবং সকল কিছু বিস্তারিত লিখলাম: \"তুমি দৃড়ভাবে এইসব শিক্ষা ধারণ করবে, এবং তোমার লোকদের সেগুলো ধারণ করতে উদ্বুদ্ধ করবে- এগুলো সর্বোত্তম শিক্ষা। আমি তোমাকে মন্দদের পরিণতি দেখাবো।"],
  "7:146": ["I will divert from My revelations those who are arrogant on earth, without justification. Consequently, when they see every kind of proof they will not believe. And when they see the path of guidance they will not adopt it as their path, but when they see the path of straying they will adopt it as their path. This is the consequence of their rejecting our proofs, and being totally heedless thereof.","আমার প্রকাশনাবলী থেকে আমি তাদেরকে সরিয়ে রাখবো যারা যথার্থ কারণ ছাড়া পৃথিবীতে উদ্ধত। ফলস্বরূপ, যখন তারা সব রকমের প্রমান দেখবে,তারা বিশ্বাস করবে না। এবং যখন তারা পথপ্রাপ্তির রাস্তা দেখবে তারা তাদের পথ হিসেবে এটি অবলম্বন করবে না,কিন্তু যখন তারা পথভ্রষ্টতার রাস্তা দেখবে তারা তাদের পথ হিসেবে এর অবলম্বন করবে। এটি হচ্ছে আমাদের প্রমানগুলোকে তাদের প্রত্যাক্ষান করার, এবং এতে সম্পূর্ণ অমনোযোগী থাকার ফল।"],
  "7:147": ["Those who reject our revelations and the meeting of the Hereafter, their works are nullified. Are they requited only for what they committed?","যারা প্রত্যাখ্যান করে আমাদের প্রকাশনাবলী এবং পরকালের সাক্ষাত, তাদের কাজ নিষ্ফল হয়। তারা যা করেছিল তারা কি শুধু তার জন্য প্রতিদানপ্রাপ্ত?"],
  "7:148": ["During his absence, Moses' people made from their jewelry the statue of a calf, complete with the sound of a calf. Did they not see that it could not speak to them, or guide them in any path? They worshiped it, and thus turned wicked.","তার অনুপস্থিতিতে, মুসার লোকেরা তাদের অলঙ্কার থেকে তৈরি করল একটি বাছুরের মূর্তি, যা একটি বাছুরের ডাক করতে সক্ষম। তারা কি দেখেনি যে,এ টা তাদের সাথে কথা বলতে পারে না,অথবা তাদেরকে কোন রাস্তায় পথপ্রদর্শন করে না? তারা এর উপাসনা করল, এবং এভাবে মন্দে পরিণত হলো।"],
  "7:149": ["Finally, when they regretted their action, and realized that they had gone astray, they said, \"Unless our Lord redeems us with His mercy, and forgives us, we will be losers.\"","অবশেষে,যখন তারা তাদের কাজের জন্য অনুতাপ করলো,এবং উপলব্ধি করলো যে তারা বিপথে গিয়েছে,তারা বলল, “যদি না আমাদের প্রভু আমাদের উদ্ধার করেন তাঁর দয়া দিয়ে,এবং ক্ষমা করেন, আমরা ক্ষতিগ্রস্ত হব”।"],
  "7:150": ["When Moses returned to his people, angry and disappointed, he said, \"What a terrible thing you have done in my absence! Could you not wait for the commandments of your Lord?\" He threw down the tablets, and took hold of his brother's head, pulling him towards himself. (Aaron) said, \"Son of my mother, the people took advantage of my weakness, and almost killed me. Let not my enemies rejoice, and do not count me with the transgressing people.\"","যখন মুসা তার লোকদের কাছে ফিরে আসল, রাগান্বিত ও হতাশ হল, সে বলল, “আমার অনুপস্থিতিতে তোমরা কি এক ভয়ানক জিনিস করেছ!” তোমরা কি তোমাদের প্রভুর প্রত্যাদেশের জন্য অপেক্ষা করতে পারনি?”সে ফলকগুলো ছুড়ে ফেলল, এবং তার ভাইয়ের মাথা ধরল, তাকে নিজের দিকে টেনে ধরে। (হারুন) বলল, “আমার মায়ের পুত্র, লোকেরা আমার দুর্বলতার সুযোগ নিয়েছিল, এবং প্রায় আমাকে মেরে ফেলেছিল। আমার শত্রুদের আনন্দিত হতে দিয়ো না, এবং আমাকে সীমাতিক্রমকারী লোকদের সাথে গণনা করো না”।"],
  "7:151": ["(Moses) said, \"My Lord, forgive me and my brother, and admit us into Your mercy. Of all the merciful ones, You are the Most Merciful.\"","(মূসা) বলল, \"আমার প্রভু,আমাকে এবং আমার ভাইকে ক্ষমা করুন, এবং আমাদেরকে প্রবেশ করান আপনার দয়ায়। সকল দয়াবানদের মধ্যে,আপনি সবচেয়ে দয়াবান।"],
  "7:152": ["Surely, those who idolized the calf have incurred wrath from their Lord, and humiliation in this life. We thus requite the innovators.","অবশ্যই, যারা বাছুরটির উপাসনা করলো তারা টেনে এনেছে তাদের প্রভুর তীব্র ক্রোধ, এবং এই জীবনে অবমাননা।  আমরা এভাবে নব-উদ্ভাবকদের থেকে প্রতিশোধ নেই।"],
  "7:153": ["As for those who committed sins, then repented thereafter and believed, your Lord—after this—is Forgiver, Most Merciful.","আর যারা পাপ করে,এরপর অনুশোচনা করে এবং বিশ্বাস করে, তোমাদের প্রভু - এরপর - ক্ষমাকারী,পরম দয়ালু।"],
  "7:154": ["When Moses' anger subsided, he picked up the tablets, containing guidance and mercy for those who reverence their Lord.","যখন মুসার রাগ প্রশমিত হলো,সে  তুলে নিলো ফলকগুলো,যা পথ-প্রদর্শন ও দয়া সমৃদ্ধ- তাদের জন্য যারা তাদের প্রভুকে ভক্তি-শ্রদ্ধা করে।"],
  "7:155": ["Moses then selected seventy men from among his people, to come to our appointed audience. When the quake shook them, he said, \"My Lord, You could have annihilated them in the past, together with me, if You so willed. Would You annihilate us for the deeds of those among us who are foolish? This must be the test that You have instituted for us. With it, You condemn whomever You will, and guide whomever You will. You are our Lord and Master, so forgive us, shower us with Your mercy; You are the best Forgiver.","মুসা এরপর তার লোকেদের মধ্য থেকে সত্তর জনকে নির্বাচন করলো,আমাদের নির্ধারিত বৈঠকে আসতে। যখন ভূ-কম্পন তাদেরকে কম্পিত করলো,সে বলল, \"আমার প্রভু,অতীতে আপনি তাদেরকে ধ্বংস করতে পারতেন, একই সাথে আমাকেও, যদি আপনি এমনই ইচ্ছা করতেন। আপনি কি আমাদেরকে ধ্বংস করবেন আমাদের মধ্যকার তাদের কাজের জন্য যারা বোকা? এটি অবশ্যই একটি পরীক্ষা যা আপনি আমাদের জন্য প্রবর্তন করেছেন। এটি দিয়ে,আপনি দন্ড বিধান করেন যাকে আপনি ইচ্ছা করেন, এবং পথ- প্রদর্শন করেন যাকে আপনি ইচ্ছা করেন। আপনি আমাদের প্রভু এবং মনিব, তাই আমাদেরকে ক্ষমা করুন, আমাদেরকে আপনার দয়া বর্ষন করুন; আপনি সর্বোত্তম ক্ষমাকারী।"],
  "7:156": ["\"And decree for us righteousness in this world, and in the Hereafter. We have repented to You. He said, \"My retribution befalls whomever I will. But My mercy encompasses all things. However, I will specify it for those who (1) lead a righteous life, (2) give the obligatory charity (Zakat), (3) believe in our revelations, and","“এবং আমাদের জন্য সৎকর্মশীলতা জারী করুন, এই দুনিয়ায়, এবং পরকালে। আমরা আপনার কাছে অনুশোচনা করেছি”। তিনি বললেন, “আমার শাস্তি পতিত হয় যার উপর আমি চাই । কিন্তু আমার দয়া সবকিছুকে পরিবেষ্টন করে আছে। তা সত্ত্বেও, আমি তা নির্দিষ্ট করবো তাদের জন্য যারা (১) সৎকর্মশীল জীবন যাপন করে,(২)বাধ্যতামূলক দান (যাকাত) দেয়, (৩) আমাদের প্রকাশনাবলিতে বিশ্বাস করে,এবং"],
  "7:157": ["\"(4) follow the messenger, the gentile prophet (Muhammad), whom they find written in their Torah and Gospel. He exhorts them to be righteous, enjoins them from evil, allows for them all good food, and prohibits that which is bad, and unloads the burdens and the shackles imposed upon them. Those who believe in him, respect him, support him, and follow the light that came with him are the successful ones.\"","“(৪) অনুসরণ করে বার্তাবাহককে,সেই উম্মী (যারা আগের ঐশীগ্রন্থ অনুসরণ করেনি) নবীকে(মুহাম্মাদ),যার ব্যাপারে তাদের তওরাত এবং ইঞ্জিলে লিখা আছে। সে তাদেরকে উৎসাহিত করে সৎকর্মশীল হতে,তাদেরকে মন্দ থেকে নিষেধ করে,সকল ভালো খাদ্য তাদের জন্য অনুমোদন করে,এবং নিষিদ্ধ করে যা কিছু মন্দ, এবং তাদের উপর আরোপিত বোঝা ও শৃঙ্খলসমূহের ভার মুক্ত করে। যারা তাকে বিশ্বাস করে,তাকে সন্মান করে,তাকে সমর্থন করে,এবং অনুসরণ করে সে আলো যা তার সাথে এসেছিল তারাই সফলকাম ব্যক্তি।"],
  "7:158": ["Say, \"O people, I am Allah's messenger to all of you. To Him belongs the sovereignty of the heavens and the earth. There is no god except He. He controls life and death.\" Therefore, you shall believe in Allah and His messenger, the gentile prophet, who believes in Allah and His words. Follow him, that you may be guided.","বল, “হে লোকেরা,আমি তোমাদের সকলের নিকট আল্লাহর বার্তাবাহক। আকাশমন্ডলী ও পৃথিবীর সার্বভৌম ক্ষমতা তাঁর। তিনি ব্যতিত কোন উপাস্য নেই। তিনি জীবন এবং মৃত্যু নিয়ন্ত্রন করেন”। অতএব, তোমরা বিশ্বাস করবে আল্লাহ এবং তাঁর বার্তাবাহককে,সেই উম্মী(যারা আগের ঐশীগ্রন্থ অনুসরণ করেনি) নবীকে,যে আল্লাহ এবং তাঁর বানী বিশ্বাস করে। তাকে অনুসরণ করো,যাতে তোমরা পথ প্রাপ্ত হতে পারো।"],
  "7:159": ["Among the followers of Moses there are those who guide in accordance with the truth, and the truth renders them righteous.","মুসার অনুসারীদের মধ্যে রয়েছে তারা যারা সত্য অনুসারে পথ প্রদর্শন করে,এবং সত্য তাদের সৎকর্মশীলতে পরিণত করে।"],
  "7:160": ["We divided them into twelve tribal communities, and we inspired Moses when his people asked him for water: \"Strike the rock with your staff,\" whereupon twelve springs gushed out therefrom. Thus, each community knew its water. And we shaded them with clouds, and sent down to them manna and quails: \"Eat from the good things we provided for you.\" It is not us that they wronged; it is they who wronged their own souls.","আমরা তাদেরকে বারটি গোত্রীয় সম্প্রদায়ে ভাগ করলাম, এবং আমরা মুসাকে অনুপ্রাণিত করলাম যখন তার লোকেরা তার কাছে পানি চেয়েছিলঃ “তোমার লাঠি দিয়ে পাথরটিতে আঘাত করো,”যার ফলে,সেখান থেকে বারটি ঝর্না প্রবলবেগে বের হয়ে এলো। এরুপে,প্রত্যেক সম্প্রদায় এর পানি চিনলো। এবং আমরা তাদেরকে মেঘমালা দিয়ে ছায়া দিয়েছিলাম, এবং তাদের কাছে নাজিল করেছিলাম মান্না ও কয়েলঃ “তোমাদের জন্য আমাদের দেয়া ভালো জিনিস থেকে খাও।’’ তারা আমাদের ক্ষতি করেনি; তারা তাদের নিজেদেরেই আত্মার ক্ষতি করেছিল।"],
  "7:161": ["Recall that they were told, \"Go into this town to live, and eat therefrom as you please, treat the people amicably, and enter the gate humbly. We will then forgive your transgressions. We will multiply the reward for the righteous.\"","স্মরণ করো যে তাদেরকে বলা হয়েছিল, \"বসবাস করতে এই শহরে ঢোক, এবং তোমাদের খুশিমতো তা থেকে খাও, লোকদের সাথে অমায়িক ব্যবহার করো,এবং দরজা দিয়ে বিনীতভাবে প্রবেশ করো। আমরা তাহলে তোমাদের সীমালঙ্ঘনগুলো ক্ষমা করবো। আমরা সৎকর্মশীলদের জন্য প্রতিদান বহুগুনে বৃদ্ধি করবো।\""],
  "7:162": ["But the evil ones among them substituted other commands for the commands given to them. Consequently, we sent upon them condemnation from the sky, because of their wickedness.","কিন্তু,তাদের মধ্যকার মন্দ লোকেরা তাদেরকে দেয়া নির্দেশাবলিকে অন্য  নির্দেশাবলি দিয়ে প্রতিস্থাপন করলো। ফলস্বরুপ, আমরা আকাশ থেকে তাদের উপর দন্ডাদেশ পাঠালাম, তাদের অপকর্মের কারণে।"],
  "7:163": ["Remind them of the community by the sea, who desecrated the Sabbath. When they observed the Sabbath, the fish came to them abundantly. And when they violated the Sabbath, the fish did not come. We thus afflicted them, as a consequence of their transgression.","তাদেরকে সাগর ধারের সম্প্রদায়ের বিষয়ে স্মরণ করাও, যারা সাব্বাথ (বিশ্রামের দিনকে) অপবিত্র করেছিল।  যখন তারা সাব্বাথ (বিশ্রামের দিন) পালন করতো,তাদের কাছে প্রচুর মাছ আসতো। এবং যখন তারা সাব্বাথ (বিশ্রামের দিন) লঙ্ঘন করতো,মাছ আসতো না। আমরা এভাবে তাদেরকে দুর্দশাগ্রস্থ করলাম, তাদের সীমালঙ্ঘনের ফলস্বরুপ।"],
  "7:164": ["Recall that a group of them said, \"Why should you preach to people whom Allah will surely annihilate or punish severely?\" They answered, \"Apologize to your Lord,\" that they might be saved.","স্মরণ করো যে তাদের এক দল বলল, “কেন তোমাদের সে লোকদের কাছে ধর্ম-প্রচার করা উচিত যাদের আল্লাহ অবশ্যই ধ্বংস করবেন বা কঠোর শাস্তি দিবেন?”তারা উত্তর দিলো,“তোমাদের প্রভুর কাছে ক্ষমা চাও, ”যাতে তারা রক্ষা পেতে পারে।"],
  "7:165": ["When they disregarded what they were reminded of, we saved those who prohibited evil, and afflicted the wrongdoers with a terrible retribution for their wickedness.","যখন তারা উপেক্ষা করলো যা তাদের স্মরণ করানো হয়েছিল, আমরা তাদের রক্ষা করলাম যারা মন্দ থেকে নিষিদ্ধ করেছিল, এবং মন্দকর্মীদের এক ভয়ানক শাস্তি দিয়ে দুদর্শাগ্রস্থ করলাম তাদের অপকর্মের জন্য।"],
  "7:166": ["When they continued to defy the commandments, we said to them, \"Be you despicable apes.\"","যখন তারা প্রত্যাদেশসমূহের বিরোধিতা করা অব্যাহত রাখলো,আমরা তাদের বললাম, “তোমরা ঘৃণ্য বানর হয়ে যাও”।"],
  "7:167": ["Additionally, your Lord has decreed that He will raise up against them people who will inflict severe persecution upon them, until the Day of Resurrection. Your Lord is most efficient in enforcing retribution, and He is certainly the Forgiver, Most Merciful.","এছাড়াও, তোমার প্রভু হুকুম করেছেন যে তিনি তাদের বিপক্ষে সে লোকদের উথিত করবেন যারা তাদের উপর কঠিন নির্যাতন আরোপ করবে,পুনুরুত্থান দিবস পর্যন্ত। তোমাদের প্রভু শাস্তি জোরদারে সবচেয়ে দক্ষ, এবং তিনি নিঃসন্দেহে ক্ষমাশীল, পরম দয়ালু।"],
  "7:168": ["We scattered them among many communities throughout the land. Some of them were righteous, and some were less than righteous. We tested them with prosperity and hardship, that they may return.","আমরা তাদেরকে সমগ্র স্থলের অনেক সম্প্রদায়ের মধ্যে ছড়িয়ে দিলাম। তাদের কেউ কেউ সৎকর্মশীল ছিল, এবং কেউ কেউ কম সৎকর্মশীল ছিল। আমরা তাদেরকে পরীক্ষা করেছিলাম সমৃদ্ধি এবং অসচ্ছলতা দিয়ে,যাতে তারা ফিরে আসতে পারে।"],
  "7:169": ["Subsequent to them, He substituted new generations who inherited the scripture. But they opted for the worldly life instead, saying, \"We will be forgiven.\" But then they continued to opt for the materials of this world. Did they not make a covenant to uphold the scripture, and not to say about Allah except the truth? Did they not study the scripture? Certainly, the abode of the Hereafter is far better for those who maintain righteousness. Do you not understand?","তাদের পরবর্তীতে,তিনি প্রতিস্থাপিত করেছিলেন নতুন প্রজন্ম যারা  ঐশীগ্রন্থ উত্তরাধিকার করেছিল। কিন্তু উলটো তারা দুনিয়ার জীবন পছন্দ করেছিল, এই বলে যে,“আমাদের ক্ষমা করা হবে”। কিন্তু তারা তখন এই দুনিয়ার বস্তু পছন্দ করাই অব্যাহত রেখেছিল। তারা কি ঐশীগ্রন্থ মেনে চলার, এবং আল্লাহ সম্পর্কে সত্য ছাড়া না বলার অঙ্গীকার করেনি? তারা কি ঐশীগ্রন্থ অধ্যয়ন করেনি? নিশ্চিতভাবে,যারা সৎকর্মশীলতা বজায় রাখে তাদের জন্য পরকালের বাসস্থান অনেক উত্তম। তোমরা কি বুঝো না?"],
  "7:170": ["Those who uphold the scripture, and observe the Contact Prayers (Salat), we never fail to recompense the pious.","তারা যারা ঐশীগ্রন্থ মেনে চলে,এবং সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করে,আমরা কখনো সৎকর্মশীলদের প্রতিদান দিতে ব্যর্থ হই না।"],
  "7:171": ["We raised the mountain above them like an umbrella, and they thought it was going to fall on them: \"You shall uphold what we have given you, strongly, and remember the contents thereof, that you may be saved.\"","আমরা একটি ছাতার মতো তাদের উপর পাহাড়টি তুলে ধরলাম, এবং তারা মনে করলো এটি তাদের উপর পড়তে যাচ্ছে  : “তোমরা মেনে চলবে যা আমরা তোমাদেরকে দিয়েছি,দৃঢভাবে এবং এর অভ্যন্তরস্থ বস্তু স্মরণ রাখবে,যাতে তোমরা রক্ষা পেতে পারো।”"],
  "7:172": ["Recall that your Lord summoned all the descendants of Adam, and had them bear witness for themselves: \"Am I not your Lord?\" They all said, \"Yes. We bear witness.\" Thus, you cannot say on the Day of Resurrection, \"We were not aware of this.\"","স্মরণ করো যে তোমার প্রভু আদমের সকল সন্তানদের একত্র করলেন, এবং তাদেরকে তাদের নিজেদের জন্য সাক্ষী করলেন: \"আমি কি তোমাদের প্রভু নই?”তারা সকলে বলল, \"হ্যা,আমরা সাক্ষ্য দিচ্ছি।”এভাবে,তোমরা পুনরুত্থান দিবসে বলতে পারবে না,\"আমরা এ বিষয়ে অবহিত ছিলাম না।\""],
  "7:173": ["Nor can you say, \"It was our parents who practiced idolatry, and we simply followed in their footsteps. Will You punish us because of what others have innovated?\"","না তোমরা বলতে পারবে,\"আমাদের মাতাপিতারাই তো শিরক চর্চা করতো,এবং আমরা শুধু তাদের পদাঙ্ক অনুসরণ করেছিলাম। আপনি কি অন্যরা যা প্রবর্তণ করেছে তার কারনে আমাদেরকে শাস্তি দিবেন?"],
  "7:174": ["We thus explain the revelations, to enable the people to redeem themselves.","আমরা এভাবে প্রত্যাদেশাবলি ব্যাখ্যা করি,লোকদের উদ্ধারপ্রাপ্ত হতে তাদের নিজেদের সক্ষম করতে।"],
  "7:175": ["Recite for them the news of one who was given our proofs, but chose to disregard them. Consequently, the devil pursued him, until he became a strayer.","তাদের জন্য আবৃত্তি করো সে ব্যক্তির সংবাদ যাকে আমাদের প্রমানাদি দেয়া হয়েছিল, কিন্তু সেগুলো উপেক্ষা করা পছন্দ করল। ফলস্বরুপ, শয়তান তার পিছনে লাগল, যতক্ষন না সে একজন পথভ্রষ্ট হলো।"],
  "7:176": ["Had we willed, we could have elevated him therewith, but he insisted on sticking to the ground, and pursued his own opinions. Thus, he is like the dog; whether you pet him or scold him, he pants. Such is the example of people who reject our proofs. Narrate these narrations, that they may reflect.","আমরা যদি ইচ্ছা করতাম, আমরা তাকে ঐ অবস্থা সত্ত্বেও তুলে আনতে পারতাম, কিন্তু সে নীচে এঁটে থাকাতেই অনঁড় রইল, এবং তার নিজের মত অনুসরণ করলো। এরূপে,সে ঐ কুকুরের মতো; তুমি তাকে আদর করো অথবা বকুনী দাও, সে হাঁপায়। এমনই লোকদের উদাহরন যারা আমাদের প্রমানাদি প্রত্যাখ্যান করে। বর্ননা করো এসব কাহিনী,যাতে তারা অনুধাবন করতে পারে।"],
  "7:177": ["Bad indeed is the example of people who reject our proofs; it is only their own souls that they wrong.","মন্দ নিশ্চয়ই সেই লোকদের উদাহরণ যারা আমাদের প্রমানাদি প্রত্যাখ্যান করে; তারা শুধু তাদের নিজের আত্মারই ক্ষতি করে।"],
  "7:178": ["Whomever Allah guides is the truly guided one, and whomever He commits to straying, these are the losers.","যাকে আল্লাহ পথপ্রদর্শন করেন সেই সত্যিকার পথপ্রাপ্ত ব্যক্তি,এবং যাকে তিনি পথভ্রষ্ট করেন, এরাই ক্ষতিগ্রস্ত।"],
  "7:179": ["We have committed to Hell multitudes of jinns and humans. They have minds with which they do not understand, eyes with which they do not see, and ears with which they do not hear. They are like animals; no, they are far worse—they are totally unaware.","আমরা বহু সংখ্যক জীন এবং মানুষকে নরকে সোপর্দ করেছি। তাদের আছে মন যা দিয়ে তারা বোঝে না,চোখ যা দিয়ে তারা দেখে না,এবং কান যা দিয়ে তারা শোনে না। তারা পশুর মতো,না,তারা আরও অধিক মন্দ- তারা সম্পূর্ণ অসচেতন।"],
  "7:180": ["To Allah belongs the most beautiful names; call upon Him therewith, and disregard those who distort His names. They will be requited for their sins.","সবচেয়ে সুন্দর নামগুলো আল্লাহর; তাঁকে সেগুলো ধরে ডাকো,এবং তাদেরকে উপেক্ষা করো যারা তাঁর নাম বিকৃত করে। তারা তাদের পাপের জন্য প্রতিফল প্রাপ্ত হবে।"],
  "7:181": ["Among our creations, there are those who guide with the truth, and the truth renders them righteous.","আমাদের সৃষ্টির মধ্যে,রয়েছে তারা যারা সত্য দিয়ে পথ-প্রদর্শন করে,এবং সত্য তাদের সৎকর্মশীলতে পরিনত করে।"],
  "7:182": ["As for those who reject our revelations, we lead them on without them ever realizing it.","আর তাদের জন্য যারা আমাদের প্রকাশনাবলি প্রত্যাক্ষান করে,আমরা তাদের পরিচালনা করি তাদেরকে কখনো তা বুঝতে না দিয়ে।"],
  "7:183": ["I will even encourage them; My scheming is formidable.","আমি এমনকি তাদের উৎসাহিত করবো,আমার পরিকল্পনা অজেয়।"],
  "7:184": ["Why do they not reflect upon their friend (the messenger)? He is not crazy. He is simply a profound warner.","কেন তারা তাদের বন্ধুর বিষয়ে (বার্তাবাহক) চিন্তা-ভাবনা করে না? সে উন্মাদ নয়। সে শুধু একজন স্পষ্ট সতর্ককারী।"],
  "7:185": ["Have they not looked at the dominion of the heavens and the earth, and all the things Allah has created? Does it ever occur to them that the end of their life may be near? Which Hadith, beside this, do they believe in?","তারা কি দেখে নি আকাশমন্ডলী  ও পৃথিবীর রাজত্য, এবং সে সবকিছু যা আল্লাহ সৃষ্টি করেছেন? এটা কখনো তাদের মনে হয় কী যে তাদের জীবনের সমাপ্তি হয়তো খুবই নিকটে? কোন হাদীস, এর পাশে,তারা বিশ্বাস করে?"],
  "7:186": ["Whomever Allah commits to straying, there is no way for anyone to guide him. He leaves them in their sins, blundering.","যাকে আল্লাহ পথভ্রষ্টতায় লিপ্ত করেন, কারো জন্য কোন পথ নেই তাকে পথপ্রদর্শন করার। তিনি তাদেরকে তাদের পাপে ছেড়ে দেন, ঘুরপাকরত অবস্থায়।"],
  "7:187": ["They ask you about the end of the world (the Hour), and when it will come to pass. Say, \"The knowledge thereof is with my Lord. Only He reveals its time. Heavy it is, in the heavens and the earth. It will not come to you except suddenly.\" They ask you as if you are in control thereof. Say, \"The knowledge thereof is with Allah,\" but most people do not know.","তারা তোমাকে জিজ্ঞাসা করে দুনিয়ার সমাপ্তি (সেই সময়) সম্পর্কে,এবং কখন তা সংঘটিত হবে। বল, “এর জ্ঞান আমার প্রভুর নিকট আছে। একমাত্র তিনি এর সময় প্রকাশ করেন। আকাশমন্ডলী  এবং পৃথিবীতে,এটি গুরুতর। হঠাৎ করে ছাড়া এটি তোমাদের কাছে আসবে না। তারা তোমাকে জিজ্ঞাসা করে,যেন তুমি এর নিয়ন্ত্রনে রয়েছ। বল, “এর জ্ঞান আল্লাহর নিকট আছে”,কিন্তু বেশির ভাগ মানুষ তা জানে না।"],
  "7:188": ["Say, \"I have no power to benefit myself, or harm myself. Only what Allah wills happens to me. If I knew the future, I would have increased my wealth, and no harm would have afflicted me. I am no more than a warner, and a bearer of good news for those who believe.\"","বল, “আমার কোন ক্ষমতা নেই আমার নিজের উপকার করার, অথবা আমার নিজের ক্ষতি করার। শুধু আল্লাহ যা ইচ্ছা করেন তা আমার সাথে ঘটে। যদি আমি ভবিষ্যৎ জানতাম, আমি আমার সম্পদ বৃদ্ধি করতাম, এবং কোন ক্ষতি আমাকে দুর্দশাগ্রস্ত করতো না। আমি একজন সতর্ককারীর চেয়ে বেশি কিছু নই, এবং তাদের জন্য একজন সুসংবাদ বহনকারী যারা বিশ্বাস করে”।"],
  "7:189": ["He created you from one person (Adam). Subsequently, He gives every man a mate to find tranquility with her. She then carries a light load that she can hardly notice. As the load gets heavier, they implore Allah their Lord: \"If You give us a good baby, we will be appreciative.\"","তিনি তোমাদের সৃষ্টি করেছেন এক ব্যক্তি (আদম) থেকে। পরবর্তীতে,তিনি প্রত্যেক  মানুষকে একজন সঙ্গীনী দিয়েছেন তার  সাথে শান্তি পেতে। সে (স্ত্রী) তখন একটি হালকা বোঝা বহন করে যা সে কমই  খেয়াল করতে পারে। যখন বোঝা ভারী হয়, তারা তাদের প্রভু আল্লাহর কাছে মিনতি করেঃ “যদি আপনি আমাদেরকে একটি ভালো শিশু দেন, আমরা কৃতজ্ঞ হব”।"],
  "7:190": ["But when He gives them a good baby, they turn His gift into an idol that rivals Him. Allah be exalted, far above any partnership.","কিন্তু যখন তিনি তাদের একটি ভালো শিশু  দেন, তারা তাঁর দানকে উপাস্যে পরিণত করে যা তাঁর প্রতিদ্বন্দ্বি হয়। আল্লাহ উচ্চপ্রশংসিত, কোন অংশীদারিত্বের অনেক উর্ধে।"],
  "7:191": ["Is it not a fact that they are idolizing idols who create nothing, and are themselves created?","এটা কি বাস্তব বিষয় নয় যে তারা উপাস্যদের উপাসনা করছে যারা কিছুই সৃষ্টি করে না,এবং নিজেরাই সৃষ্ট?"],
  "7:192": ["Idols that can neither help them, nor even help themselves?","উপাস্যরা যারা না পারে তাদেরকে সাহায্য করতে,না পারে নিজেদেরকে সাহায্য করতে?"],
  "7:193": ["When you invite them to the guidance, they do not follow you. Thus, it is the same for them whether you invite them, or remain silent.","যখন তুমি তাদেরকে পথপ্রাপ্তির দিকে আমন্ত্রন করো,তারা তোমাকে অনুসরণ করে না। এভাবে,তুমি তাদেরকে আমন্ত্রন করো,অথবা নীরব থাকো তা তাদের জন্য একই।"],
  "7:194": ["The idols you invoke besides Allah are creatures like you. Go ahead and call upon them; let them respond to you, if you are right.","আল্লাহর পাশে যে উপাস্যদের কাছে তোমরা সাহায্য প্রার্থনা করো তারা তোমাদের মতোই সৃষ্ট। তৎপর হও এবং তাদেরকে আহবান করো; তাদেরকে তোমাদের প্রতি সাড়া দিতে দাও, যদি তোমরা সঠিক হও।"],
  "7:195": ["Do they have legs on which they walk? Do they have hands with which they defend themselves? Do they have eyes with which they see? Do they have ears with which they hear? Say, \"Call upon your idols, and ask them to smite me without delay.","তাদের কি পা আছে যার উপর তারা হাঁটে? তাদের কি হাত আছে যা দিয়ে তারা নিজেদের রক্ষা করে? তাদের কি চোখ আছে যা দিয়ে তারা দেখে? তাদের কি কান আছে যা দিয়ে তারা শোনে? বল, “তোমাদের উপাস্যদের আহবান করো,এবং তাদেরকে অনতিবিলম্বে আমাকে আক্রমন করতে বলো।"],
  "7:196": ["\"Allah is my only Lord and Master; the One who revealed this scripture. He protects the righteous.","আল্লাহ আমার একমাত্র প্রভু এবং মনিব; সেই সত্বা যিনি এই ঐশীগ্রন্থ প্রকাশ করেছিলেন। তিনি সৎকর্মশীলদের রক্ষা করেন।"],
  "7:197": ["\"As for the idols you set up beside Him, they cannot help you, nor can they help themselves.\"","“তাঁর পাশে তোমরা যে উপাস্যদের স্থাপন করেছ, তারা তোমাদের সাহায্য করতে পারে না,না তারা নিজেদের সাহায্য করতে পারে।”"],
  "7:198": ["When you invite them to the guidance, they do not hear. And you see them looking at you, but they do not see.","যখন তুমি তাদেরকে সুপথে আহবান করো,তারা শোনে না। এবং তুমি তাদেরকে তোমার দিকে তাকাতে দেখো,কিন্তু তারা দেখে না।"],
  "7:199": ["You shall resort to pardon, advocate tolerance, and disregard the ignorant.","তুমি ক্ষমা অবলম্বন করবে,সহিষ্ণুতার উপদেশ দেবে,এবং অজ্ঞদের উপেক্ষা করবে।"],
  "7:200": ["When the devil whispers to you any whisper, seek refuge in Allah; He is Hearer, Omniscient.","যখন শয়তান তোমার কাছে ফিস ফিস করে কোন প্ররোচনা,আল্লাহর আশ্রয় খোঁজ, তিনি শ্রবণকারী,সর্বজ্ঞ।"],
  "7:201": ["Those who are righteous, whenever the devil approaches them with an idea, they remember, whereupon they become seers.","তারা যারা সৎকর্মশীল, যখনই শয়তান কোন ধারনা নিয়ে তাদের কাছে আসে,তারা স্মরণ করে,যার ফলে তারা অন্তর্দৃষ্টি সম্পন্ন হয়।"],
  "7:202": ["Their brethren ceaselessly entice them to go astray.","তাদের ভাইয়েরা বিরামহীনভাবে তাদেরকে পথভ্রষ্টতায় প্ররোচিত করে।"],
  "7:203": ["If you do not produce a miracle that they demand, they say, \"Why not ask for it?\" Say, \"I simply follow what is revealed to me from my Lord.\" These are enlightenments from your Lord, and guidance, and mercy for people who believe.","যদি তুমি একটি অলৌকিকতা না দেখাও যা তারা দাবি করে,তারা বলে,“কেন এটি চাও না?’’ বল, “আমি কেবলমাত্র অনুসরন করি যা আমার প্রভুর পক্ষ থেকে আমার কাছে প্রকাশিত হয়েছে।” এগুলো তোমার প্রভুর পক্ষ থেকে জ্ঞানালোক, এবং পথপ্রদর্শন, এবং লোকদের জন্য দয়া যারা বিশ্বাস করে।"],
  "7:204": ["When the Quran is recited, you shall listen to it and take heed, that you may attain mercy.","যখন কুরআন আবৃত্তি করা হয়, তোমরা তা শুনবে এবং মনোযোগ দিবে,যাতে তোমরা দয়া অর্জন করতে পারো।"],
  "7:205": ["You shall remember your Lord within yourself, publicly, privately, and quietly, day and night; do not be unaware.","তোমরা তোমাদের প্রভুর স্মরণ করবে নিজেদের অন্তরে,জনসমক্ষে,একান্তে,এবং প্রশান্তভাবে,দিনে ও রাতে;অসচেতন হইও না।"],
  "7:206": ["Those at your Lord are never too proud to worship Him; they glorify Him and fall prostrate before Him.","তোমার প্রভুর সান্নিধ্যে যারা রয়েছে তারা তাঁর উপাসনায় কখনো অহংকারী নয়। তারা তাঁর গুনকীর্তন করে এবং তাঁর সামনে সেজদাবনত হয়।"],
  "8:1": ["They consult you about the spoils of war. Say, \"The spoils of war belong to Allah and the messenger.\" You shall observe Allah, exhort one another to be righteous, and obey Allah and His messenger, if you are believers.","তারা তোমার সাথে পরামর্শ করে যুদ্ধলব্ধ মালের ব্যাপারে। বল, “যুদ্ধলব্ধ মাল আল্লাহ এবং তাঁর বার্তাবাহকের।”তোমরা আল্লাহকে মান্য করবে, একে অন্যকে সৎকর্মশীল হতে উৎসাহিত করবে, এবং আল্লাহ ও তাঁর বার্তাবাহকে মান্য করবে, যদি তোমরা বিশ্বাসী হও।"],
  "8:2": ["The true believers are those whose hearts tremble when Allah is mentioned, and when His revelations are recited to them, their faith is strengthened, and they trust in their Lord.","সত্যিকার বিশ্বাসী তারা যাদের হৃদয় কম্পিত হয় যখন আল্লাহর উল্লেখ করা হয়, এবং যখন তাঁর প্রকাশনাবলি তাদের কাছে পাঠ করা হয়, তাদের বিশ্বাস জোরদার হয়, এবং তারা তাদের প্রভুর প্রতি আস্থা রাখে।"],
  "8:3": ["They observe the Contact Prayers (Salat), and from our provisions to them, they give to charity.","তারা সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করে, এবং তাদেরকে দেয়া আমাদের জীবিকা থেকে, তারা দান করে।"],
  "8:4": ["Such are the true believers. They attain high ranks at their Lord, as well as forgiveness and a generous provision.","সত্যিকার বিশ্বাসীরা এমনই। তারা তাদের প্রভুর কাছে উচ্চ পদসমূহ অর্জন করে, সেই সাথে ক্ষমা এবং এক উদার জীবিকা।"],
  "8:5": ["When your Lord willed that you leave your home, to fulfill a specific plan, some believers became exposed as reluctant believers.","যখন তোমার প্রভু ইচ্ছা করলেন যে তোমরা তোমাদের ঘর ত্যাগ করো, একটি বিশেষ পরিকল্পনা পূর্ণ করতে, কিছু বিশ্বাসী অনিচ্ছুক বিশ্বাসী হিসাবে প্রকাশিত/আবির্ভূত হলো।"],
  "8:6": ["They argued with you against the truth, even after everything was explained to them. They acted as if they were being driven to certain death.","তারা সত্যের বিরুদ্ধে তোমার সাথে তর্ক করলো, এমনকি সবকিছু তাদের কাছে ব্যাখ্যা করার পরও। তারা  আচরণ করলো যেন তারা নিশ্চিত মৃত্যুর দিকে চালিত হচ্ছে।"],
  "8:7": ["Recall that Allah promised you victory over a certain group, but you still wanted to face the weaker group. It was Allah's plan to establish the truth with His words, and to defeat the disbelievers.","স্মরণ করো যে আল্লাহ তোমাদেরকে একটি নির্দিষ্ট দলের উপর বিজয়ের অঙ্গীকার করেছিলেন, কিন্তু তোমরা তবুও দুর্বল দলের মুখোমুখি হতে চাইলে। এটা ছিল আল্লাহর পরিকল্পনা সত্যকে প্রতিষ্ঠিত করা তাঁর বানী দিয়ে, এবং অবিশ্বাসীদের পরাজিত করা।"],
  "8:8": ["For He has decreed that the truth shall prevail, and the falsehood shall vanish, in spite of the evildoers.","তিনি জারি করেছেন যে সত্য জয়ী হবে, এবং মিথ্যা বিলুপ্ত হবে, মন্দকর্মীদের সত্ত্বেও।"],
  "8:9": ["Thus, when you implored your Lord to come to the rescue, He responded to you: \"I am supporting you with one thousand angels in succession.\"","এভাবে, যখন তোমরা তোমাদের প্রভুর কাছে সহায়তা প্রদান করতে মিনতি করেছিলে, তিনি তোমাদের প্রতি সাড়া দিলেনঃ “আমি ধারাবাহিকভাবে এক হাজার স্বর্গদুত দিয়ে তোমাদের সমর্থন করছি”।"],
  "8:10": ["Allah gave you this good news to strengthen your hearts. Victory comes only from Allah. Allah is Almighty, Most Wise.","আল্লাহ এই সুসংবাদ তোমাদেরকে দেন তোমাদের হৃদয়কে শক্তিশালী করতে। বিজয় শুধুমাত্র আল্লাহ থেকে আসে। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "8:11": ["He caused peaceful slumber to overtake you and pacify you, and He sent down water from the sky to clean you therewith. He protected you from the devil's curse, reassured your hearts and strengthened your foothold.","তিনি শান্তিময় তন্দ্রা দিলেন তোমাদের আচ্ছন্ন করতে এবং  তোমাদেরকে প্রশান্ত করতে, এবং তিনি আকাশ থেকে পানি পাঠালেন তোমাদের তা দিয়ে পরিষ্কার করতে। তিনি শয়তানের অভিশাপ থেকে তোমাদের রক্ষা করলেন, তোমাদের অন্তরকে পূনঃ আশ্বস্ত করলেন এবং তোমাদের অবস্থানকে সুদৃড় করলেন।"],
  "8:12": ["Recall that your Lord inspired the angels: \"I am with you; so support those who believed. I will throw terror into the hearts of those who disbelieved. You may strike them above the necks, and you may strike even every finger.\"","স্মরণ করো যে তোমাদের প্রভু ফেরেশতাদের অনুপ্রানিত করেছিলেন, \"আমি তোমাদের সাথে রয়েছি; সুতরাং তাদেরকে সমর্থন করো যারা বিশ্বাস করেছে। আমি তাদের অন্তরে আতঙ্ক ছুঁড়ে দিবো যারা অবিশ্বাস করেছে। তোমরা তাদের আঘাত করতে পারো ঘারের উপর,  এবং তোমরা এমনকি তাদের প্রত্যেক আঙ্গুলে আঘাত করতে পারো।"],
  "8:13": ["This is what they have justly incurred by fighting Allah and His messenger. For those who fight against Allah and His messenger, Allah's retribution is severe.","এটা হচ্ছে যা তারা আল্লাহ এবং তাঁর বার্তাবাহকের সাথে যুদ্ধ করে যথার্থই অর্জন করেছে। তাদের জন্য যারা আল্লাহ এবং তাঁর বার্তাবাহকের বিরুদ্ধে যুদ্ধ করে, আল্লাহর শাস্তি কঠোর।"],
  "8:14": ["This is to punish the disbelievers; they have incurred the retribution of Hell.","এটি অবিশ্বাসীদেরকে শাস্তি দিতে; তারা নরকের শাস্তি টেনে এনেছে।"],
  "8:15": ["O you who believe, if you encounter the disbelievers who have mobilized against you, do not turn back and flee.","হে তোমরা যারা বিশ্বাস করো, যদি তোমরা অবিশ্বাসীদের মুখোমুখি হও যারা তোমাদের বিরুদ্ধে একত্রিত হয়েছে, পিছু হটবে না এবং পালাবে না।"],
  "8:16": ["Anyone who turns back on that day, except to carry out a battle plan, or to join his group, has incurred wrath from Allah, and his abode is Hell; what a miserable destiny!","যেকেউ ঐ দিন পেছনে ফিরে আসে, কোন যুদ্ধ পরিকল্পনা সম্পন্ন করা, অথবা তার দলের সাথে যোগ দেয়া ছাড়া, সে টেনে এনেছে আল্লাহর ক্রোধ, এবং তার বাসস্থান নরক; কি এক শোচনীয় ভাগ্য!"],
  "8:17": ["It was not you who killed them; Allah is the One who killed them. It was not you who threw when you threw; Allah is the One who threw. But He thus gives the believers a chance to earn a lot of credit. Allah is Hearer, Omniscient.","এটা তুমি নও যে তাদের হত্যা করেছিল; আল্লাহই তাদেরকে হত্যা করেছিলেন। এটা তুমি নও যে ছুঁড়েছিল; আল্লাহই ছুঁড়েছিলেন। কিন্তু তিনি এভাবে বিশ্বাসীদের অনেক কৃতিত্ব অর্জন করার একটি সুযোগ দেন। আল্লাহ শ্রোতা, সর্বজ্ঞ।"],
  "8:18": ["Additionally, Allah thus nullifies the schemes of the disbelievers.","উপরন্তু, আল্লাহ এভাবে অবিশ্বাসীদের চক্রান্ত নস্যাৎ করে দেন।"],
  "8:19": ["You sought victory (O disbelievers), and victory did come; it belonged to the believers. If you refrain (from aggression) it would be better for you, but if you return, so will we. Your armies will never help you, no matter how great. For Allah is on the side of the believers.","(হে অবিশ্বাসীরা) তোমরা বিজয় চেয়েছিলে, এবং বিজয় এসেছিল; এটি ছিল বিশ্বাসীদের। যদি তোমরা (আগ্রাসন থেকে) বিরত হও এটা তোমাদের জন্য উত্তম হবে, কিন্তু যদি তোমরা ফিরে আসো, আমরা তা-ই করবো। তোমাদের সেনাবাহিনী কখনোই তোমাদের সাহায্য করবে না, যতো বিশালই হোক না কেন। কারন আল্লাহ বিশ্বাসীদের পাশে রয়েছেন।"],
  "8:20": ["O you who believe, obey Allah and His messenger, and do not disregard him while you hear.","হে তোমরা যারা বিশ্বাস করো, আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করো, এবং তাকে উপেক্ষা করো না যেহেতু তোমরা শোন।"],
  "8:21": ["Do not be like those who say, \"We hear,\" when they do not hear.","তাদের মতো হইও না যারা বলে, “আমরা শুনি,” যদিও তারা শুনে না।"],
  "8:22": ["The worst creatures in the sight of Allah are the deaf and dumb, who do not understand.","আল্লাহর দৃষ্টিতে সবচেয়ে নিকৃষ্ট সৃষ্টি হচ্ছে বধির এবং বোবারা, যারা বুঝে না।"],
  "8:23": ["Had Allah known of any good in them, He would have made them hearers. Even if He made them hearers, they still would turn away in aversion.","যদি আল্লাহ তাদের মধ্যে কোন ভাল জানতেন, তিনি তাদের শ্রোতা বানাতেন। এমনকি তিনি যদি তাদের শ্রোতা করতেন, এরপরও তারা বিদ্বেষে মুখ ফিরিয়ে নিতো।"],
  "8:24": ["O you who believe, you shall respond to Allah and to the messenger when he invites you to what gives you life. You should know that Allah is closer to you than your heart, and that before Him you will be summoned.","হে তোমরা যারা বিশ্বাস করো, তোমরা সাড়া দেবে আল্লাহ এবং বার্তাবাহকের প্রতি যখন সে তোমাদেরকে আমন্ত্রন করে তার প্রতি যা তোমাদেরকে প্রান দেয়। তোমাদের জানা উচিত যে আল্লাহ তোমাদের হ্রদয়ের চেয়েও তোমাদের নিকটবর্তী, এবং এটা যে তাঁর সামনে তোমরা একত্রিত হবে।"],
  "8:25": ["Beware of a retribution that may not be limited to the evildoers among you. You should know that Allah's retribution is severe.","সতর্ক হও একটি শাস্তির বিষয়ে যা হয়তো সীমাবদ্ধ থাকবে না তোমাদের মধ্যকার মন্দকর্মীদের মাঝে। তোমাদের জানা উচিত যে, আল্লাহর শাস্তি কঠোর।"],
  "8:26": ["Remember that you used to be few and oppressed, fearing that the people may snatch you, and He granted you a secure sanctuary, supported you with His victory, and provided you with good provisions, that you may be appreciative.","স্মরণ করো যে তোমরা অল্পসংখ্যক এবং নির্যাতিত ছিলে, ভয় করতে যে লোকেরা হয়তো তোমাদের ছিনিয়ে নিতে পারে, এবং তিনি তোমাদেরকে প্রদান করলেন একটি নিরাপদ আশ্রয়স্থল, তাঁর বিজয় দিয়ে তোমাদের সমর্থন করলেন, এবং তোমাদেরকে দিলেন ভালো জীবিকা, যাতে তোমরা কৃতজ্ঞ হতে পারো।"],
  "8:27": ["O you who believe, do not betray Allah and the messenger, and do not betray those who trust you, now that you know.","হে তোমরা যারা বিশ্বাস করো,আল্লাহ এবং তাঁর বার্তাবাহককের সাথে প্রতারণা করো না, এবং তাদের সাথে প্রতারণা করো না যারা তোমাদের প্রতি আস্থা রাখে,এখন যেহেতু তোমরা জানো।"],
  "8:28": ["You should know that your money and your children are a test, and that Allah possesses a great recompense.","তোমাদের জানা উচিত যে তোমাদের অর্থ এবং তোমাদের সন্তানরা একটি পরীক্ষা, এবং এটা যে আল্লাহর অধীনে আছে এক মহা প্রতিদান।"],
  "8:29": ["O you who believe, if you reverence Allah, He will enlighten you, remit your sins, and forgive you. Allah possesses infinite grace.","হে তোমরা যারা বিশ্বাস করো, যদি তোমরা আল্লাহকে ভক্তি শ্রদ্ধা করো, তিনি তোমাদেরকে আলোকিত করবেন, তোমাদের পাপ মার্জনা করবেন, এবং তোমাদের ক্ষমা করবেন। আল্লাহ অসীম অনুগ্রহের অধিকারী।"],
  "8:30": ["The disbelievers plot and scheme to neutralize you, or kill you, or banish you. However, they plot and scheme, but so does Allah. Allah is the best schemer.","অবিশ্বাসীরা চক্রান্ত এবং ফন্দী আঁটে তোমাকে নিষ্ক্রিয় করতে, অথবা তোমাকে হত্যা করতে, অথবা তোমাকে নির্বাসিত করতে।  যাই হোক, তারা চক্রান্ত এবং ফন্দী আঁটে, কিন্তু আল্লাহও তা-ই করেন, আল্লাহ শ্রেষ্ঠ পরিকল্পনাকারী।"],
  "8:31": ["When our revelations are recited to them, they say, \"We have heard. If we wanted to, we could have said the same things. These are no more than tales from the past!\"","যখন আমাদের প্রকাশনাবলি তাদের কাছে আবৃতি করা হয়, তারা বলে, “আমরা শুনেছি। যদি আমরা করতে চাইতাম, আমরা একই জিনিস বলতে পারতাম। এগুলো অতীতের গল্প ছাড়া বেশি কিছু নয়।!”"],
  "8:32": ["They also said, \"Our god, if this is really the truth from You, then shower us with rocks from the sky, or pour upon us a painful punishment.\"","তারা আরোও বলেছিল, “আমাদের উপাস্য, যদি এটি বাস্তবিকই আপনার পক্ষ থেকে সত্য হয়, তবে আকাশ থেকে আমাদের উপর পাথর বর্ষন করুন, অথবা আমাদের উপর একটি যন্ত্রনাদায়ক শাস্তি পতিত করুন।”"],
  "8:33": ["However, Allah is not to punish them while you are in their midst; Allah is not to punish them while they are seeking forgiveness.","তা সত্ত্বেও, আল্লাহ তাদের শাস্তি দেয়ার নয় যতক্ষন তুমি তাদের মধ্যে রয়েছ;  আল্লাহ তাদের শাস্তি দেয়ার নয় যতক্ষন তারা ক্ষমা প্রার্থনা করছে।"],
  "8:34": ["Have they not deserved Allah's retribution, by repelling others from the Sacred Masjid, even though they are not the custodians thereof? The true custodians thereof are the righteous, but most of them do not know.","তারা কি আল্লাহর শাস্তির উপযুক্ত হয় নি, অন্যদেরকে পবিত্র মসজিদ থেকে বাঁধা দানের দ্বারা, যদিও তারা সেখানকার তত্ত্বাবধায়ক নয়? সেখানকার প্রকৃত তত্ত্বাবধায়ক হচ্ছে সৎকর্মশীলরা, কিন্তু তাদের অধিকাংশ জানে না।"],
  "8:35": ["Their Contact Prayers (Salat) at the shrine (Ka'bah) were no more than a mockery and a means of repelling the people (by crowding them out). Therefore, suffer the retribution for your disbelief.","পূন্যস্থানে (কা’বা) তাদের সংযোগ প্রার্থনাসমূহ (সালাত) একটি উপহাস এবং (ভিড় করে বাইরে রেখে) লোকদের  বাধা দেয়ার একটি মাধ্যমের চেয়ে বেশি কিছু নয়। অতএব, তোমাদের অবিশ্বাসের জন্য শাস্তি ভোগ করো।"],
  "8:36": ["Those who disbelieve spend their money to repel others from the way of Allah. They will spend it, then it will turn into sorrow and remorse for them. Ultimately, they will be defeated, and all disbelievers will be summoned to Hell.","যারা অবিশ্বাস করে তারা তাদের অর্থ ব্যয় করে অন্যদেরকে আল্লাহর পথ থেকে প্রতিহত করতে। তারা তা ব্যয় করবে, এরপর এটা তাদের জন্য দুঃখ ও অনুতাপে পরিণত হবে। সব শেষে, তারা পরাজিত হবে, এবং সব অবিশ্বাসীদের নরকে ডাকা হবে।"],
  "8:37": ["Allah will sift away the bad from the good, then pile the bad on top of each other, all in one pile, then throw it in Hell. Such are the losers.","আল্লাহ মন্দকে ভালো থেকে আলাদা করবেন, এরপর মন্দকে একে অন্যের উপর স্তুপ করবেন, সকলকে এক স্তুপের ভিতর, তারপর একে নরকে নিক্ষেপ করবেন। ক্ষতিগ্রস্থরা এমনই।"],
  "8:38": ["Tell those who disbelieved: if they stop, all their past will be forgiven. But if they return, they will incur the same fate as their previous counterparts.","যারা অবিশ্বাস করেছে তাদেরকে বলঃ যদি তারা ক্ষান্ত হয়, তাদের সকল অতীত ক্ষমা করে দেয়া হবে। কিন্তু যদি তারা ফিরে যায়, তারা সেই একই ভাগ্য টেনে আনবে যেমন এনেছিল তাদের পূর্ববর্তী প্রতিরূপরা।"],
  "8:39": ["You shall fight them to ward off oppression, and to practice your religion devoted to Allah alone. If they refrain from aggression, then Allah is fully Seer of everything they do.","তুমি তাদের সাথে লড়াই করবে নিপীড়ন বন্ধ করতে, এবং তোমাদের ধর্ম একমাত্র আল্লাহকে উৎসর্গ করে চর্চা করতে। যদি তারা আগ্রাসন থেকে বিরত হয়, তবে আল্লাহ সবকিছুর পূর্ণ দ্রষ্টা যা তারা করে।"],
  "8:40": ["If they turn away, then you should know that Allah is your Lord and Master; the best Lord and Master, the best supporter.","যদি তারা মুখ ফিরিয়ে নেয়, তবে তোমাদের জানা উচিত যে আল্লাহ তোমাদের প্রভু এবং মনিব; সর্বশ্রেষ্ঠ প্রভু এবং মনিব, সর্বশ্রেষ্ঠ সহায়তাকারী।"],
  "8:41": ["You should know that if you gain any spoils in war, one-fifth shall go to Allah and the messenger, to be given to the relatives, the orphans, the poor, and the traveling alien. You will do this if you believe in Allah and in what we revealed to our servant on the day of decision, the day the two armies clashed. Allah is Omnipotent.","তোমাদের জানা উচিত যে যদি তোমরা যুদ্ধে কোন যুদ্ধলব্ধ মাল অর্জন করো, এক-পঞ্চমাংশ আল্লাহ এবং বার্তাবাহকের নিকট যাবে, আত্মীয়, এতিম, গরিব, এবং ভ্রমনরত ভিনদেশীকে দিতে। তোমরা এটি করবে যদি তোমরা বিশ্বাস করো আল্লাহতে এবং তাতে যা আমরা আমাদের দাসের নিকট প্রকাশ করেছি সিদ্ধান্তের দিনে, দুই সৈন্যবাহিনীর সংঘর্ষের দিন। আল্লাহ সর্বশক্তিমান।"],
  "8:42": ["Recall that you were on this side of the valley, while they were on the other side. Then their caravan had to move to lower ground. Had you planned it this way, you could not have done it. But Allah was to carry out a predetermined matter, whereby those destined to be annihilated were annihilated for an obvious reason, and those destined to be saved were saved for an obvious reason. Allah is Hearer, Omniscient.","Recall that you were on this side of the valley, while they were on the other side. Then their caravan had to move to lower ground. Had you planned it this way, you could not have done it. But GOD was to carry out a predetermined matter, whereby those destined to be annihilated were annihilated for an obvious reason, and those destined to be saved were saved for an obvious reason. GOD is Hearer, Omniscient."],
  "8:43": ["Allah made them appear in your dream (O Muhammad) fewer in number. Had He made them appear more numerous, you would have failed, and you would have disputed among yourselves. But Allah saved the situation. He is Knower of the innermost thoughts.","আল্লাহ তোমার (হে মুহাম্মদ) স্বপ্নে তাদেরকে অল্প সংখ্যক দেখিয়েছিলেন।  যদি তিনি তাদেরকে অধিকতর সংখ্যক দেখাতেন, তোমরা ব্যর্থ হতে, এবং তোমরা নিজেদের মধ্য বিবাদ করতে। কিন্তু আল্লাহ পরিস্থিতিটি নিয়ন্ত্রন করলেন। তিনি গভীরতম চিন্তাগুলো জানেন।"],
  "8:44": ["And when the time came and you faced them, He made them appear fewer in your eyes, and made you appear fewer in their eyes as well. For Allah willed to carry out a certain plan. All decisions are made by Allah.","এবং যখন সে সময় আসলো ও তোমরা তাদের সম্মুখীন হলে, তিনি তোমাদের চোখে তাদের অল্প সংখ্যক দেখালেন, এবং তোমাদেরকেও তাদের চোখে অল্প সংখ্যক দেখালেন। কারণ আল্লাহ একটি নির্দিষ্ট পরিকল্পনা সম্পন্ন করার ইচ্ছা করেছিলেন। সকল সিদ্ধান্ত আল্লাহর প্রনীত।"],
  "8:45": ["O you who believe, when you encounter an army, you shall hold fast and commemorate Allah frequently, that you may succeed.","হে যারা বিশ্বাস করো, যখন তোমরা কোন সৈন্য বাহিনীর মুখোমুখি হও, তোমরা সুদৃড় থাকবে এবং আল্লাহকে অনবরত স্মরণ করবে, যাতে তোমরা সফল হতে পারো।"],
  "8:46": ["You shall obey Allah and His messenger, and do not dispute among yourselves, lest you fail and scatter your strength. You shall steadfastly persevere. Allah is with those who steadfastly persevere.","তোমরা আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করবে, এবং নিজেদের মধ্যে বিবাদ করবে না, পাছে তোমরা ব্যর্থ হও এবং তোমাদের শক্তি ছিন্ন হয়। তোমরা দৃঢ়তার সাথে অধ্যবসায়ী হবে। আল্লাহ তাদের সাথে রয়েছেন যারা দৃঢ়তার সাথে অধ্যবসায়ী।"],
  "8:47": ["Do not be like those who left their homes grudgingly, only to show off, and in fact discouraged others from following the path of Allah. Allah is fully aware of everything they do.","তাদের মতো হইও না যারা অনিচ্ছায় তাদের ঘর ছেড়েছিল, শুধুমাত্র লোক দেখাতে, এবং বাস্তবিকপক্ষে অন্যদেরকে আল্লাহর পথ অনুসরণ করা থেকে অনুৎসাহিত করতো। তারা যা করে আল্লাহ সে সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "8:48": ["The devil had adorned their works in their eyes, and said, \"You cannot be defeated by any people today,\" and \"I will be fighting along with you.\" But as soon as the two armies faced each other, he turned back on his heels and fled, saying, \"I disown you. I see what you do not see. I am afraid of Allah. Allah's retribution is awesome.\"","শয়তান তাদের কাজকে তাদের চোখে সাজিয়ে দিল, এবং বলল, “তোমরা আজ কোন দল দ্বারা পরাজিত হতে পারো না”, এবং “আমি তোমাদের সাথে যুদ্ধ করতে থাকবো”কিন্তু যে মুহূর্তে দুই সৈন্যদল একে অন্যের মুখোমুখি হলো, সে পেছনে ফিরে গেল এবং পালাল, এই বলে যে, “আমি তোমাদের পরিত্যাগ করি। আমি দেখি যা তোমরা দেখো না। আমি আল্লাহকে ভয় করি। আল্লাহর শাস্তি ভয়াবহ।”"],
  "8:49": ["The hypocrites and those who harbored doubt in their hearts said, \"These people are deceived by their religion.\" However, if one puts his trust in Allah, then Allah is Almighty, Most Wise.","ভণ্ডরা এবং যারা তাদের হৃদয়ে সন্দেহ পোষণ করেছিল তারা বলল, “এই লোকেরা তাদের ধর্মের মাধ্যমে প্রতারিত”। কিন্তু, কেউ যদি তার আস্থা আল্লাহর প্রতি রাখে, তবে আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "8:50": ["If you could only see those who disbelieved when the angels put them to death! They will beat them on their faces and their rear ends: \"Taste the retribution of Hell.","যদি তুমি শুধু দেখতে পারতে তাদেরকে যারা অবিশ্বাস করেছিল যখন ফেরেশতারা তাদের হত্যা করে! তারা তাদের প্রহার করবে তাদের মুখে এবং তাদের পশ্চাৎপ্রান্তে “নরকের শাস্তি আস্বাদন করো।"],
  "8:51": ["\"This is a consequence of what your hands have sent forth. Allah is never unjust towards the creatures.\"","“যা তাদের হাত পুর্বে পাঠিয়েছে এটি তার একটি ফল। আল্লাহ সৃষ্টিজগতের  প্রতি কখনো অবিবেচক নন।”"],
  "8:52": ["This is the same fate as that of Pharaoh's people and those who disbelieved before them. They rejected Allah's revelations, and Allah punished them for their sins. Allah is powerful, and His retribution is severe.","ফেরাউনের লোক এবং তাদের পূর্বে যারা অবিশ্বাস করেছিল এটি তাদের মতো সে একই পরিনতি। তারা আল্লাহর প্রকাশনাবলি প্রত্যাক্ষান করেছিল, এবং আল্লাহ তাদেরকে তাদের পাপের জন্য শাস্তি দিয়েছিলেন। আল্লাহ ক্ষমতাবান, এবং তাঁর শাস্তি কঠোর।"],
  "8:53": ["Allah does not change a blessing He has bestowed upon any people unless they themselves decide to change. Allah is Hearer, Omniscient.","আল্লাহ কোন আশীর্বাদ পরিবর্তন করেন না যা তিনি কোন লোকের উপর আরোপ করেছেন যদি না তারা নিজেরা পরিবর্তনের সিদ্ধান্ত নেয়। আল্লাহ শ্রোতা, সর্বজ্ঞ।"],
  "8:54": ["Such was the case with the people of Pharaoh and others before them. They first rejected the signs of their Lord. Consequently, we annihilated them for their sins. We drowned Pharaoh's people; the wicked were consistently punished.","ফেরাউনের লোক এবং তাদের পূর্বের অন্যদের সাথে বিষয়টি এরকমই ছিল। তারা প্রথমে তাদের প্রভুর নিদর্শনাবলি প্রত্যাক্ষান করেছিল। ফলস্বরুপ, আমরা তাদেরকে তাদের পাপের জন্য ধ্বংস করলাম। আমরা ফেরাউনের লোকদের ডুবালাম; মন্দদেরকে উপযুক্তভাবে শাস্তি দেয়া হয়েছিল।"],
  "8:55": ["The worst creatures in the sight of Allah are those who disbelieved; they cannot believe.","আল্লাহর দৃষ্টিতে তারা সবচেয়ে নিকৃষ্ট সৃষ্টি যারা অবিশ্বাস করে; তারা বিশ্বাস করতে পারে না।"],
  "8:56": ["You reach agreements with them, but they violate their agreements every time; they are not righteous.","তোমরা তাদের সাথে চুক্তিতে পৌঁছাও, কিন্তু প্রতিবারই তারা তাদের চুক্তি ভাঙ্গে; এরা সৎকর্মশীল নয়।"],
  "8:57": ["Therefore, if you encounter them in war, you shall set them up as a deterrent example for those who come after them, that they may take heed.","অতএব, তোমরা যদি তাদের সাথে যুদ্ধে মুখোমুখি হও, তোমরা তাদের পরবর্তীদের জন্য একটি প্রতিরোধমূলক উদাহরণ হিসাবে স্থাপন করবে, যাতে তারা উপদেশ গ্রহণ করতে পারে।"],
  "8:58": ["When you are betrayed by a group of people, you shall mobilize against them in the same manner. Allah does not love the betrayers.","যখন তোমরা এক দল লোক দ্বারা প্রতারিত হয়েছ, তাদের বিরুদ্ধে তোমরা একই পন্থায় যুদ্ধের জন্য প্রস্তুত হবে।"],
  "8:59": ["Let not those who disbelieve think that they can get away with it; they can never escape.","যারা অবিশ্বাস করে তাদেরকে ভাবতে দিওনা যে তারা এটি করে পার পেয়ে যাবে; তারা কখনো পালাতে পারে না।"],
  "8:60": ["You shall prepare for them all the power you can muster, and all the equipment you can mobilize, that you may frighten the enemies of Allah, your enemies, as well as others who are not known to you; Allah knows them. Whatever you spend in the cause of Allah will be repaid to you generously, without the least injustice.","তোমরা তাদের জন্য সকল শক্তি প্রস্তুত করবে যা তোমরা সমবেত করতে পারো, এবং সকল সরঞ্জাম যা তোমরা একত্রিত করতে পারো, যাতে তোমরা আল্লাহর শত্রুদের ভয় দেখাতে পারো, তোমাদের শত্রু, একই সাথে অন্যদের যারা তোমাদের কাছে পরিচিত নয়; আল্লাহ তাদের জানেন।তোমরা আল্লাহর উদ্দেশ্যে যা কিছু ব্যয় করো তোমাদেরকে পুনরায় ফিরিয়ে দেয়া হবে উদারভাবে সামান্যতম অবিচার ছাড়াই।"],
  "8:61": ["If they resort to peace, so shall you, and put your trust in Allah. He is the Hearer, the Omniscient.","যদি তারা শান্তি অবলম্বন করে, তোমরাও তা-ই করবে, এবং আল্লাহর প্রতি তোমাদের আস্থা রাখো। তিনি শ্রোতা, সর্বজ্ঞ।"],
  "8:62": ["If they want to deceive you, then Allah will suffice you. He will help you with His support, and with the believers.","যদি তারা তোমাদের প্রতারিত করতে চায়, তবে আল্লাহ তোমাদের জন্য যথেষ্ট হবেন। তিনি তাঁর সমর্থণ দিয়ে, এবং বিশ্বাসীদের দিয়ে তোমাদের সাহায্য করবেন।"],
  "8:63": ["He has reconciled the hearts (of the believers). Had you spent all the money on earth, you could not reconcile their hearts. But Allah did reconcile them. He is Almighty, Most Wise.","তিনি (বিশ্বাসীদের) অন্তর পূনর্মিলিত করেছেন। যদি তুমি পৃথিবীর সমস্ত অর্থ ব্যয় করতে, তুমি তাদের অন্তরকে পূনর্মিলিত করাতে পারতে না। কিন্তু আল্লাহ তাদের পূনর্মিলিত করলেন। তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "8:64": ["O you prophet, sufficient for you is Allah and the believers who have followed you.","হে নবী, তোমার জন্য যথেষ্ট আল্লাহ এবং বিশ্বাসীরা যারা তোমার অনুসরণ করেছে।"],
  "8:65": ["O you prophet, you shall exhort the believers to fight. If there are twenty of you who are steadfast, they can defeat two hundred, and a hundred of you can defeat a thousand of those who disbelieved. That is because they are people who do not understand.","হে নবী, তুমি বিশ্বাসীদের যুদ্ধ করতে উৎসাহিত করবে। যদি তোমাদের বিশ জন থাকে যারা দৃড়, তারা দুই শত লোককে পরাজিত করতে পারে, এবং তোমাদের একশত জন পরাজিত করতে পারে তাদের এক হাজার জনকে যারা অবিশ্বাস করে। এর কারন হচ্ছে তারা এমন লোক যারা বোঝে না।"],
  "8:66": ["Now (that many new people have joined you) Allah has made it easier for you, for He knows that you are not as strong as you used to be. Henceforth, a hundred steadfast believers can defeat two hundred, and a thousand of you can defeat two thousand by Allah's leave. Allah is with those who steadfastly persevere.","এখন (যেহেতু অনেক নতুন লোক তোমাদের সাথে যুক্ত হয়েছে) আল্লাহ এটি তোমাদের জন্য সহজ করেছেন, কারন তিনি জানেন যে তোমরা ততটা শক্তিশালী নও যেমন তোমরা থাকতে। এখন থেকে, আল্লাহর অনুমতিক্রমে একশ দৃঢ় বিশ্বাসী দু’শ জনকে পরাজিত করতে পারবে, এবং তোমাদের এক হাজার জন দু’হাজার জনকে পরাজিত করতে পারবে। আল্লাহ তাদের সাথে রয়েছেন যারা দৃঢ়তার সাথে অধ্যবসায়ী।"],
  "8:67": ["No prophet shall acquire captives, unless he participates in the fighting. You people are seeking the materials of this world, while Allah advocates the Hereafter. Allah is Almighty, Most Wise.","কোন নবী বন্দীদের পাবে না, যদি না সে লড়াইয়ে অংশ নেয়। তোমরা লোকেরা এই দুনিয়ার বস্তুসামগ্রী খুঁজছ, যখন আল্লাহ পরকালের উকালতি করেন। আল্লাহ সর্ব শক্তিমান, সব থেকে জ্ঞানী।"],
  "8:68": ["If it were not for a predetermined decree from Allah, you would have suffered, on account of what you took, a terrible retribution.","যদি এটি আল্লাহর পক্ষ থেকে একটি পূর্ব নির্ধারিত হুকুম না হতো, তোমরা হয়তো ভুগতে, যা তোমরা নিয়েছিলে তার ফল হিসাবে, এক ভয়ানক শাস্তি।"],
  "8:69": ["Therefore, eat from the spoils you have earned that which is lawful and good, and observe Allah. Allah is Forgiver, Most Merciful.","অতএব, যুদ্ধলব্ধ মালের থেকে খাও যা তোমরা উপার্জন করেছ যা আইনসিদ্ধ এবং ভালো, এবং আল্লাহকে মান্য করো। আল্লাহ ক্ষমাশীল, সব থেকে দয়াময়।"],
  "8:70": ["O you prophet, tell the prisoners of war in your hands, \"If Allah knew of anything good in your hearts, He would have given you better than anything you have lost, and would have forgiven you. Allah is Forgiver, Most Merciful.\"","হে নবী, তোমাদের হাতে থাকা যুদ্ধ বন্দীদের বল, “যদি আল্লাহ তোমাদের হৃদয়ের এমন কিছু ভাল জানতেন, তিনি তোমাদেরকে দিতেন তোমরা যা কিছু হারিয়েছ তার চেয়ে উত্তম, এবং তোমাদের ক্ষমা করে দিতেন। আল্লাহ ক্ষমাকারী, সব থেকে দয়ালু।”"],
  "8:71": ["And if they want to betray you, they have already betrayed Allah. This is why He made them the losers. Allah is Omniscient, Most Wise.","এবং যদি তারা তোমাদের প্রতারিত করতে চায়, তারা ইতোমধ্যেই আল্লাহকে প্রতারনা করেছে। এ কারনেই তিনি তাদের পরাজিত করালেন। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "8:72": ["Surely, those who believed, and emigrated, and strove with their money and their lives in the cause of Allah, as well as those who hosted them and gave them refuge, and supported them, they are allies of one another. As for those who believe, but do not emigrate with you, you do not owe them any support, until they do emigrate. However, if they need your help, as brethren in faith, you shall help them, except against people with whom you have signed a peace treaty. Allah is Seer of everything you do.","নিশ্চিতভাবে, যারা বিশ্বাস করেছে, এবং দেশত্যাগ করেছে, এবং আল্লাহর উদ্দেশ্যে সংগ্রাম করেছে তাদের অর্থ এবং তাদের জীবন দিয়ে, একই সাথে যারা তাদেরকে আতিথিয়তা করেছে এবং তাদেরকে আশ্রয় দিয়েছে, এবং তাদেরকে সমর্থন করেছে, তারা একে অন্যের মিত্র। তাদের জন্য যারা বিশ্বাস করে, কিন্তু তোমাদের সাথে দেশত্যাগ করে না, তোমরা তাদেরকে কোন সমর্থন দিতে বাধ্য নও, যতক্ষন পর্যন্ত না তারা দেশত্যাগ করে। যাহোক, যদি তোমাদের সাহায্য তাদের দরকার হয়, বিশ্বাসী ভ্রাতা হিসেবে, তোমরা তাদের সাহায্য করবে, সে লোকদের বিরুদ্ধে না গিয়ে যারা তোমাদের সাথে একটি শান্তি চুক্তিতে সাক্ষর করেছে। আল্লাহ সবকিছুর দ্রষ্টা যা তোমরা করো।"],
  "8:73": ["Those who disbelieved are allies of one another. Unless you keep these commandments, there will be chaos on earth, and terrible corruption.","যারা অবিশ্বাস করেছে তারা একে অন্যের মিত্র। যদি না তোমরা এই প্রত্যাদেশাবলি রক্ষা করো, পৃথিবীতে বিশৃঙ্খলা, এবং ভয়ানক দূর্নীতি হবে।"],
  "8:74": ["Those who believed and emigrated, and strove in the cause of Allah, as well as those who hosted them and gave them refuge, and supported them, these are the true believers. They have deserved forgiveness and a generous recompense.","যারা বিশ্বাস করেছে এবং দেশত্যাগ করেছে, এবং আল্লাহর উদ্দেশ্যে সংগ্রাম করেছে, একই সাথে যারা তাদেরকে আতিথিয়তা করেছে এবং তাদেরকে আশ্রয় দিয়েছে, এবং তাদেরকে সমর্থন করেছে, এরাই প্রকৃত বিশ্বাসী। তারা ক্ষমা এবং এক উদার প্রতিদানের উপযুক্ত হয়েছে।"],
  "8:75": ["Those who believed afterwards, and emigrated, and strove with you, they belong with you. Those who are related to each other shall be the first to support each other, in accordance with Allah's commandments. Allah is fully aware of all things.","যারা এরপর বিশ্বাস করেছে, এবং দেশত্যাগ করেছে, এবং তোমাদের সাথে সংগ্রাম করেছে, তারা তোমাদের অন্তর্ভূক্ত। যারা একে অন্যের সাথে সম্পর্কিত সমর্থণ করার ক্ষেত্রে তারা একে অন্যকে  প্রাধান্য দিবে, আল্লাহর প্রত্যাদেশাবলি অনুসারে। আল্লাহ সবকিছুর বিষয়েই পূর্ন সচেতন।"],
  "9:1": ["An ultimatum is herein issued from Allah and His messenger to the idol worshipers who enter into a treaty with you.","আল্লাহ এবং তাঁর বার্তাবাহকের পক্ষ থেকে এখানে একটি চুড়ান্ত শর্ত জারি করা হলো প্রতিমা উপাসকদের প্রতি যারা তোমাদের সাথে একটি চুক্তিতে আসে।"],
  "9:2": ["Therefore, roam the earth freely for four months, and know that you cannot escape from Allah, and that Allah humiliates the disbelievers.","অতএব, চার মাসের জন্য পৃথিবীতে মুক্তভাবে ঘুড়ে বেড়াও, এবং জানো যে তোমরা আল্লাহ থেকে পালাতে পারো না, এবং যে আল্লাহ অবিশ্বাসীদের লাঞ্ছিত করেন।"],
  "9:3": ["A proclamation is herein issued from Allah and His messenger to all the people on the great day of pilgrimage, that Allah has disowned the idol worshipers, and so did His messenger. Thus, if you repent, it would be better for you. But if you turn away, then know that you can never escape from Allah. Promise those who disbelieve a painful retribution.","আল্লাহ এবং তাঁর বার্তাবাহকের পক্ষ থেকে সকল লোকদের প্রতি এখানে একটি ঘোষণা জারি করা হলো তীর্থযাত্রার সেই মহান দিনে, যে আল্লাহ প্রতিমা উপাসকদের পরিত্যাগ করেছেন, এবং তাঁর বার্তাবাহকও তা-ই করেছে। সুতরাং, যদি তোমরা অনুশোচনা করো, এটা তোমাদের জন্য উত্তম হবে। কিন্তু যদি তোমরা মুখ ফিরিয়ে নাও, তবে জানো যে তোমরা কখনোই আল্লাহ থেকে পালাতে পারো না। যারা অবিশ্বাস করে তাদেরকে একটি যন্ত্রণাদায়ক শাস্তির অঙ্গীকার করো।"],
  "9:4": ["If the idol worshipers sign a peace treaty with you, and do not violate it, nor band together with others against you, you shall fulfill your treaty with them, until the expiration date. Allah loves the righteous.","যদি প্রতিমা উপাসকেরা তোমাদের সাথে একটি শান্তি চুক্তিতে সাক্ষর করে, এবং না এর লঙ্ঘন করে, না সংঘবদ্ধ হয় অন্যদের সাথে তোমাদের বিরুদ্ধে, তোমরা তাদের সাথে তোমাদের চুক্তি পরিপূর্ণ করবে, মেয়াদ উত্তির্ণের তারিখ পর্যন্ত।"],
  "9:5": ["Once the Sacred Months are past, (and they refuse to make peace) you may kill the idol worshipers when you encounter them, punish them, and resist every move they make. If they repent and observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), you shall let them go. Allah is Forgiver, Most Merciful.","একবার পবিত্র মাসসমূহ পার হলে, (এবং তারা শান্তি স্থাপন করা প্রত্যাখ্যান করলে) তোমরা প্রতিমা উপাসকদের হত্যা করতে পারো যখন তোমরা তাদের সম্মুখিন হও, তাদের শাস্তি দিতে পারো, এবং তাদের তৈরী করা প্রত্যেক পদক্ষেপ প্রতিহত করতে পারো। যদি তারা অনুশোচনা করে এবং সংযোগ প্রার্থনাসমূহ (সালাত) প্রতিষ্ঠা করে এবং বাদ্ধতামূলক দান (যাকাত) দেয়, তোমরা তাদের ছেড়ে দেবে। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "9:6": ["If one of the idol worshipers sought safe passage with you, you shall grant him safe passage, so that he can hear the word of Allah, then send him back to his place of security. That is because they are people who do not know.","যদি কোন প্রতিমা উপাসক তোমাদের সাথে নিরাপদে অবস্থান করতে চায়, তোমরা তাকে নিরাপদ প্রস্থান করতে দিবে, যাতে সে আল্লাহর বানী শুনতে পারে, এরপর তাকে তার নিরাপত্তার স্থানে ফেরত পাঠাও। এটা এ কারনে যে তারা এমন লোক যারা জানে না।"],
  "9:7": ["How can the idol worshipers demand any pledge from Allah and from His messenger? Exempted are those who have signed a peace treaty with you at the Sacred Masjid. If they honor and uphold such a treaty, you shall uphold it as well. Allah loves the righteous.","কেমন করে প্রতিমা উপাসকরা আল্লাহ থেকে এবং তাঁর বার্তাবাহক থেকে কোন অঙ্গীকার দাবী করতে পারে? তারা নিষ্কৃতিপ্রাপ্ত যারা পবিত্র মসজিদে তোমাদের সাথে একটি শান্তি চুক্তি স্বাক্ষর করেছে। যদি তারা এরকম একটি চুক্তিকে সম্মান করে এবং বহাল রাখে, তোমরাও একই ভাবে তা বহাল রাখবে। আল্লাহ সৎকর্মশীলদের ভালোবাসেন।"],
  "9:8": ["How can they (demand a pledge) when they never observed any rights of kinship between you and them, nor any covenant, if they ever had a chance to prevail. They pacified you with lip service, while their hearts were in opposition, and most of them are wicked.","কেমন করে তারা (একটি প্রতিশ্রুতি দাবী করতে) পারে যখন তারা  কখনোই তোমাদের এবং তাদের মাঝে কোন আত্মীয়তার অধিকার পালন করতো না, না কোন অঙ্গীকার, যদি কখনো তাদের জয়ী হবার সুযোগ থাকতো। তারা মুখের কথা দিয়ে তোমাকে প্রশান্ত করলো, যখন তাদের হৃদয়ে বিরোধিতা ছিল, এবং তাদের বেশির ভাগ মন্দ।"],
  "9:9": ["They traded away Allah's revelations for a cheap price. Consequently, they repulsed the people from His path. Miserable indeed is what they did!","তারা সস্তা মূল্যে আল্লাহর প্রকাশনাবলির বিকিয়ে দিলো। পরিনামে, তারা লোকদেরকে তাঁর পথ থেকে বিতাড়িত করলো। নিশ্চয়ই শোচনীয় যা তারা করেছিল।"],
  "9:10": ["They never observe any rights of kinship towards any believer, nor do they uphold their covenants; these are the real transgressors.","তারা কখনোই কোন বিশ্বাসীর প্রতি আত্মীয়তার কোন অধিকার পালন করেনি, না তারা মেনে চলে তাদের অঙ্গীকারগুলো; এরাই আসল সীমালঙ্ঘনকারী।"],
  "9:11": ["If they repent and observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), then they are your brethren in religion. We thus explain the revelations for people who know.","যদি তারা অনুশোচনা করে এবং সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করে ও বাদ্ধতামুলক (যাকাত)দান করে, তবে তারা তোমাদের ধর্ম ভাই। আমরা এভাবে লোকদের জন্য প্রকাশনাবলী ব্যাখ্যা করি যারা জানে।"],
  "9:12": ["If they violate their oaths after pledging to keep their covenants, and attack your religion, you may fight the leaders of paganism—you are no longer bound by your covenant with them—that they may refrain.","যদি তারা তাদের শপথ ভঙ্গ করে তাদের অঙ্গীকার রাখার প্রতিশ্রুতি দেবার পর, এবং তোমাদের ধর্মকে আক্রমণ করে, তোমরা পৌত্তলিকতার নেতাদের সাথে লড়াই করতে পারো- তোমরা তাদের সাথে তোমাদের অঙ্গীকার দ্বারা আর আবদ্ধ নও-যাতে তারা বিরত থাকতে পারে।"],
  "9:13": ["Would you not fight people who violated their treaties, tried to banish the messenger, and they are the ones who started the war in the first place? Are you afraid of them? Allah is the One you are supposed to fear, if you are believers.","তোমরা কি সে লোকদের সাথে লড়াই করবে না যারা তাদের চুক্তি সমূহ ভঙ্গ করেছে, বার্তাবাহককে বিতাড়িত করার চেষ্টা করেছে, এবং তারাই তো সেই লোক যারা প্রথমে যুদ্ধ শুরু করেছে? তোমরা কি তাদেরকে ভয় করো? একমাত্র আল্লাহকে ভয় করাই তোমাদের কাছে প্রত্যাশিত, যদি তোমরা বিশ্বাসী হও।"],
  "9:14": ["You shall fight them, for Allah will punish them at your hands, humiliate them, grant you victory over them, and cool the chests of the believers.","তোমরা তাদের সাথে যুদ্ধ করবে, কারন আল্লাহ তোমাদের হাতে তাদের শাস্তি দেবেন, তাদেরকে অপদস্ত করবেন, তাদের উপর তোমাদের বিজয় দেবেন, এবং বিশ্বাসীদের বক্ষ শীতল করবেন।"],
  "9:15": ["He will also remove the rage from the believers' hearts. Allah redeems whomever He wills. Allah is Omniscient, Most Wise.","তিনি এছাড়াও বিশ্বাসীদের হৃদয় থেকে ক্রোধ অপসারণ করবেন। আল্লাহ উদ্ধার করেন যাকে তিনি ইচ্ছা করেন। আল্লাহ সর্বজ্ঞ, সব থেকে জ্ঞানী।"],
  "9:16": ["Did you think that you will be left alone without Allah distinguishing those among you who strive, and never ally themselves with Allah's enemies, or the enemies of His messenger, or the enemies of the believers? Allah is fully Cognizant of everything you do.","তোমরা কি ভেবেছে যে তোমাদেরকে এমনি এমনি ছেড়ে দেয়া হবে আল্লাহ তোমাদের মধ্যে তাদেরকে আলাদা না করেই যারা সংগ্রাম করে, এবং কখনো নিজেদেরকে মিত্র করে না আল্লাহর শত্রুদের সাথে, অথবা তাঁর বার্তাবাহকের শত্রুদের সাথে, অথবা বিশ্বাসীদের শত্রুদের সাথে? আল্লাহ পূর্ণ জ্ঞাত সবকিছু সম্পর্কে যা তোমরা করো।"],
  "9:17": ["The idol worshipers are not to frequent the masjids of Allah, while confessing their disbelief. These have nullified their works, and they will abide forever in Hell.","প্রতিমা উপাসকরা আল্লাহর মসজিদে নিয়মিত হয় না, যখন তাদের অবিশ্বাস স্বীকার করছে। এরা তাদের কাজ বিনষ্ট করেছে, এবং তারা চিরকাল নরকে বাস করবে।"],
  "9:18": ["The only people to frequent Allah's masjids are those who believe in Allah and the Last Day, and observe the Contact Prayers (Salat), and give the obligatory charity (Zakat), and do not fear except Allah. These will surely be among the guided ones.","শুধু সেই লোকেরা আল্লাহর মসজিদে নিয়মিত হয় যারা আল্লাহতে এবং শেষ দিনে বিশ্বাস করে, এবং সংযোগ প্রার্থনাসমূহ (সালাত) প্রতিষ্ঠা করে, এবং বাদ্ধতামূলক (যাকাত) দান করে, এবং আল্লাহ ছাড়া কাউকে ভয় করে না। এরা অবশ্যই পথপ্রাপ্তদের অন্তর্ভুক্ত হবে।"],
  "9:19": ["Have you considered the watering of the pilgrims and caring for the Sacred Masjid a substitute for believing in Allah and the Last Day, and striving in the cause of Allah? They are not equal in the sight of Allah. Allah does not guide the wicked people.","তোমরা কি তীর্থযাত্রীদের পানি পান করানো এবং পবিত্র মসজিদের পরিচর্যা করাকে আল্লাহ এবং শেষ দিনে বিশ্বাস করার, এবং আল্লাহর পথে সংগ্রাম করার বিকল্প বিবেচনা করো? তারা আল্লাহর দৃষ্টিতে সমান নয়।  আল্লাহ মন্দ লোকদের পথ প্রদর্শন করেন না।"],
  "9:20": ["Those who believe, and emigrate, and strive in the cause of Allah with their money and their lives, are far greater in rank in the sight of Allah. These are the winners.","যারা বিশ্বাস করে,এবং দেশ ত্যাগ করে, এবং তাদের অর্থ এবং তাদের জীবন দিয়ে আল্লাহর পথে সংগ্রাম করে, তারা পদমর্যাদায় আল্লাহর দৃষ্টিতে অনেক বড়। এরাই বিজয়ী।"],
  "9:21": ["Their Lord gives them good news: mercy and approval from Him, and gardens where they rejoice in everlasting bliss.","তাদের প্রভু তাদের সু-সংবাদ দেনঃ তার পক্ষ থেকে দয়া এবং অনুমোদন, এবং বাগানসমূহ যেখানে তারা চিরস্থায়ী স্বর্গসুখে আনন্দ করে।"],
  "9:22": ["Eternally they abide therein. Allah possesses a great recompense.","চিরদিন তারা সেখানে বসবাস করে। আল্লাহ এক মহা প্রতিদানের অধিকারী।"],
  "9:23": ["O you who believe, do not ally yourselves even with your parents and your siblings, if they prefer disbelieving over believing. Those among you who ally themselves with them are transgressing.","হে তোমরা যারা বিশ্বাস করো, নিজেদেরকে তোমাদের মাতা-পিতা এবং তোমাদের ভাই-বোনদের মিত্র করো না, যদি তারা বিশ্বাসের উপর অবিশ্বাসকে পছন্দ করে। তোমাদের মধ্যে যারা নিজেদেরকে তাদের মিত্র করে তারা সীমালঙ্গনকারী।"],
  "9:24": ["Proclaim: \"If your parents, your children, your siblings, your spouses, your family, the money you have earned, a business you worry about, and the homes you cherish are more beloved to you than Allah and His messenger, and the striving in His cause, then just wait until Allah brings His judgment.\" Allah does not guide the wicked people.","ঘোষনা করঃ “যদি তোমাদের পিতা-মাতারা, তোমাদের সন্তানেরা, তোমাদের ভাই-বোনেরা, তোমাদের পতি-পত্নীরা, তোমাদের পরিবার, অর্থ যা তোমরা উপার্জন করেছ, ব্যবসা যা নিয়ে তোমরা শঙ্কা করো, এবং ঘর যা তোমরা যত্নে আগলে রাখো আল্লাহ ও তাঁর বার্তাবাহকের চেয়ে প্রিয় হয়, এবং তার উদ্দেশ্যে সংগ্রাম করার চেয়ে, তবে শুধু অপেক্ষা করো যতক্ষণ না আল্লাহ তার রায় দেন।”আল্লাহ মন্দ লোকদের পথপ্রদর্শন করেন না।"],
  "9:25": ["Allah has granted you victory in many situations. But on the day of Hunayn, you became too proud of your great number. Consequently, it did not help you at all, and the spacious earth became so straitened around you, that you turned around and fled.","আল্লাহ অনেক পরিস্থিতিতে তোমাদের বিজয় দিয়েছেন। কিন্তু হুনাইনের দিনে, তোমরা তোমাদের বিশাল সংখ্যা নিয়ে অতিরিক্ত গর্বিত হয়ে পড়লে। ফলস্বরুপ, এটি তোমাদের কোন কাজেই আসেনি। প্রশস্ত পৃথিবী তোমাদের চারপাশে এতো সংকীর্ণ হয়ে পড়লো, যে তোমরা ঘুরে দাঁড়ালে এবং পলায়ন করলে।"],
  "9:26": ["Then Allah sent down contentment upon His messenger and upon the believers. And He sent down invisible soldiers; He thus punished those who disbelieved. This is the requital for the disbelievers.","এরপর আল্লাহ অবতীর্ণ করলেন সন্তুষ্টি তাঁর বার্তাবাহকের উপর এবং বিশ্বাসীদের উপর। এবং তিনি অবতীর্ণ করলেন অদৃশ্য সৈন্যদের; তিনি এভাবে তাদেরকে শাস্তি দেন যারা অবিশ্বাস করে। এটা অবিশ্বাসীদের জন্য প্রতিফল।"],
  "9:27": ["Ultimately, Allah redeems whomever He wills. Allah is Forgiver, Most Merciful.","চূড়ান্তপর্যায়ে, আল্লাহ উদ্ধার করেন যাকে তিনি ইচ্ছা করেন। আল্লাহ ক্ষমাকারী, সবথেকে দয়ালু।"],
  "9:28": ["O you who believe, the idol worshipers are polluted; they shall not be permitted to approach the Sacred Masjid after this year. If you fear loss of income, Allah will shower you with His provisions, in accordance with His will. Allah is Omniscient, Most Wise.","হে তোমরা যারা বিশ্বাস করো, প্রতিমা উপাসকরা দূষিত; তারা এই বছরের পর পবিত্র মসজিদের নিকট আসতে অনুমতি প্রাপ্ত হবে না। যদি তোমরা উপার্জন হারানোর ভয় করো, আল্লাহ তোমাদেরকে তাঁর অফুরন্ত জীবিকা থেকে দেবেন, তাঁর ইচ্ছা অনুসারে। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "9:29": ["You shall fight back against those who do not believe in Allah, nor in the Last Day, nor do they prohibit what Allah and His messenger have prohibited, nor do they abide by the religion of truth among those who received the scripture, until they pay the due tax, willingly or unwillingly.","তোমরা তাদের বিরুদ্ধে পালটা লড়াই করবে যারা না বিশ্বাস করে আল্লাহতে, না শেষ দিনে, না তারা নিষেধ করে যা আল্লাহ এবং তাঁর বার্তাবাহক নিষিদ্ধ করেছেন, না তারা সত্য ধর্ম মেনে চলে যারা তাদের মধ্যে ঐশীগ্রন্থ গ্রহণ করেছে, যতক্ষণ না তারা পরিশোধনীয় কর দেয়, ইচ্ছায় অথবা অনিচ্ছায়।"],
  "9:30": ["The Jews said, \"Ezra is the son of Allah,\" while the Christians said, \"Jesus is the son of Allah!\" These are blasphemies uttered by their mouths. They thus match the blasphemies of those who have disbelieved in the past. Allah condemns them. They have surely deviated.","ইহুদিরা বলেছিল, “ওজাইর আল্লাহর পুত্র”,যখন খ্রিষ্টানরা বলেছিল, “যীশু আল্লাহর পুত্র!”এগুলো তাদের মুখে উচ্চারিত আল্লাহ নিন্দা। তারা এভাবে আল্লাহনিন্দাগুলো ওদের সাথে মিলিয়ে নেয় যারা অতীতে অবিশ্বাস করেছিল। আল্লাহ তাদের নিন্দা করেন। তারা অবশ্যই পথচ্যুত হয়েছে।"],
  "9:31": ["They have set up their religious leaders and scholars as lords, instead of Allah. Others deified the Messiah, son of Mary. They were all commanded to worship only one god. There is no god except He. Be He glorified, high above having any partners.","তারা তাদের ধর্মীয় নেতা এবং পন্ডিতদেরকে প্রভু হিসেবে স্থাপন করেছে, আল্লাহর বদলে। অন্যরা মরিয়মের পুত্র, মূসার প্রতি আল্লাহত্ব আরোপ করলো। তাদের সকলকে আদেশ দেয়া হয়েছিল শুধু এক উপাস্যের উপাসনা করতে। তিনি ছাড়া অন্য কোন উপাস্য নেই। তিনি মহিমান্বিত, কোন অংশীদার থাকা থেকে অনেক উর্ধ্বে।"],
  "9:32": ["They want to put out Allah's light with their mouths, but Allah insists upon perfecting His light, in spite of the disbelievers.","তারা তাদের মুখ দিয়ে আল্লাহর আলো নিভিয়ে দিতে চায়, কিন্তু আল্লাহ তাঁর আলো যথার্থ করানোয়় জোড় দেন, অবিশ্বাসীদের সত্ত্বেও।"],
  "9:33": ["He is the One who sent His messenger with the guidance and the religion of truth, and will make it dominate all religions, in spite of the idol worshipers.","তিনিই সে সত্ত্বা যিনি তাঁর বার্তাবাহককে  পথনির্দেশনা এবং সত্য ধর্ম দিয়ে পাঠালেন, এবং একে সকল ধর্মের উপর আধিপত্যশীল করবেন, প্রতিমা উপাসকদের সত্তেও।"],
  "9:34": ["O you who believe, many religious leaders and preachers take the people's money illicitly, and repel from the path of Allah. Those who hoard the gold and silver, and do not spend them in the cause of Allah, promise them a painful retribution.","হে তোমরা যারা বিশ্বাস করো, অনেক ধর্মীয় নেতা এবং প্রচারকরা লোকদের অর্থ অবৈধভাবে নেয়, এবং আল্লাহর পথ থেকে প্রতিহত করে। যারা স্বর্ন ও রূপা জমা করে, এবং সেগুলো আল্লাহর উদ্দেশ্যে ব্যয় না করে, তাদেরকে এক যন্ত্রনাদায়ক শাস্তির প্রতিশ্রুতি দাও।"],
  "9:35": ["The day will come when their gold and silver will be heated in the fire of Hell, then used to burn their foreheads, their sides, and their backs: \"This is what you hoarded for yourselves, so taste what you have hoarded.\"","সে দিন আসবে যখন তাদের স্বর্ন ও রূপা নরকের আগুনে উত্তপ্ত করা হবে, এরপর তাদের কপাল, তাদের পার্শ্ব, এবং তাদের পশ্চাৎভাগ পোড়ানো হবেঃ “এটা হচ্ছে যা তোমরা নিজেদের জন্য জমা করেছিলে, সুতরাং স্বাদ নাও যা তোমরা জমা করেছ।”"],
  "9:36": ["The count of months, as far as Allah is concerned, is twelve. This has been Allah's law, since the day He created the heavens and the earth. Four of them are sacred. This is the perfect religion; you shall not wrong your souls (by fighting) during the Sacred Months. However, you may declare all-out war against the idol worshipers (even during the Sacred Months), when they declare all-out war against you, and know that Allah is on the side of the righteous.","আল্লাহর দৃষ্টিভঙ্গি থেকে গননায় মাস বারটি। এটি আল্লাহর আইন, যেদিন থেকে তিনি আকাশমন্ডলী  ও পৃথিবী সৃষ্টি করেছেন। এগুলোর চারটি পবিত্র। এটাই যথার্থ ধর্ম; তোমরা পবিত্র মাসগুলোতে (লড়াই করে) তোমাদের আত্মার ক্ষতি করবে না। কিন্তু, তোমরা প্রতিমা উপাসকদের বিরুদ্ধে পূর্ণমাত্রায় যুদ্ধ ঘোষণা করতে পারো (এমনকি পবিত্র মাসগুলোতেও), যখন তারা পূর্ণমাত্রায় তোমাদের বিরুদ্ধে যুদ্ধ ঘোষণা করে, এবং জানো যে আল্লাহ সৎকর্মশীলদের পাশে রয়েছেন।"],
  "9:37": ["Altering the Sacred Months is a sign of excessive disbelief; it augments the straying of those who have disbelieved. They alternate the Sacred Months and the regular months, while preserving the number of months consecrated by Allah. They thus violate what Allah has consecrated. Their evil works are adorned in their eyes. Allah does not guide the disbelieving people.","পবিত্র মাসগুলোর পরিবর্তন করা অত্যধিক অবিশ্বাসের একটি চিহ্ন; এটি তাদের পথভ্রষ্টতা বাড়িয়ে দেয় যারা অবিশ্বাস করেছে। তারা পবিত্র মাসগুলো এবং সাধারন মাসগুলোতে অদল-বদল করে, যদিও আল্লাহর পবিত্র করা মাসগুলোর সংখ্যা ঠিক রাখে। তারা এভাবে তা ভঙ্গ করে যা আল্লাহ পবিত্র করেছেন। তাদের মন্দ কাজগুলো তাদের চোখে সু-সজ্জিত করা হয়েছে। আল্লাহ অবিশ্বাসী লোকদের পথ দেখান না।"],
  "9:38": ["O you who believe, when you are told, \"Mobilize in the cause of Allah,\" why do you become heavily attached to the ground? Have you chosen this worldly life in place of the Hereafter? The materials of this world, compared to the Hereafter, are nil.","হে তোমরা যারা বিশ্বাস করো, যখন তোমাদের বলা হয়, “আল্লাহর উদ্দেশ্যে যুদ্ধের জন্য একত্রিত হও, ”কেন তোমরা তীব্রভাবে মাটির সাথে আঁকড়ে থাকো? তোমরা কি পরকালের জায়গায় এই দুনিয়াবি জীবন পছন্দ করেছ? এই দুনিয়ার উপকরন, পরকালের তুলনায়, শূন্য।"],
  "9:39": ["Unless you mobilize, He will commit you to painful retribution and substitute other people in your place; you can never hurt Him in the least. Allah is Omnipotent.","যদি না তোমরা যুদ্ধের জন্য একত্রিত হও, তিনি তোমাদেরকে যন্ত্রণাদায়ক শাস্তিতে পতিত করবেন এবং তোমাদের জায়গায় অন্য লোকদের প্রতিস্থাপন করবেন; তোমরা কখনো তাঁর সামান্যতম ক্ষতিও করতে পারো না। আল্লাহ সর্বশক্তিমান।"],
  "9:40": ["If you fail to support him (the messenger), Allah has already supported him. Thus, when the disbelievers chased him, and he was one of two in the cave, he said to his friend, \"Do not worry; Allah is with us.\" Allah then sent down contentment and security upon him, and supported him with invisible soldiers. He made the word of the disbelievers lowly. Allah's word reigns supreme. Allah is Almighty, Most Wise.","যদি তোমরা তাকে (বার্তাবাহককে) সমর্থন দিতে ব্যর্থ হও, আল্লাহ তাকে ইতোমধ্যেই সমর্থন দিয়েছেন। তাই, যখন অবিশ্বাসীরা তাকে ধাওয়া করলো, এবং গুহায় সে দুজনের একজন ছিল, সে তার বন্ধুকে বলল, “দুশ্চিন্তা করো না; আল্লাহ আমাদের সাথে আছেন।”আল্লাহ তখন তার উপর সন্তুষ্টি এবং নিরাপত্তা অবতীর্ণ করলেন, এবং অদৃশ্য সৈন্য দিয়ে তাকে সমর্থন করলেন। তিনি অবিশ্বাসীদের কথার অবমূল্যায়ন করলেন। আল্লাহর বানী সর্বোচ্চ প্রভাব বিস্তার করে। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "9:41": ["You shall readily mobilize, light or heavy, and strive with your money and your lives in the cause of Allah. This is better for you, if you only knew.","তোমরা তৎক্ষনাৎ যুদ্ধের জন্য একত্রিত হবে, অল্প অথবা অধিক (সজ্জিত), এবং আল্লাহর উদ্দেশ্যে সংগ্রাম করো তোমাদের অর্থ এবং তোমাদের জীবন দিয়ে। এটা তোমাদের জন্য উত্তম, যদি শুধু তোমরা জানতে।"],
  "9:42": ["If there were a quick material gain, and a short journey, they would have followed you. But the striving is just too much for them. They will swear by Allah: \"If we could, we would have mobilized with you.\" They thus hurt themselves, and Allah knows that they are liars.","যদি কোন আশু পার্থিব অর্জন, এবং কোন সংক্ষিপ্ত যাত্রা থাকতো, তারা তোমার অনুসরণ করতো। কিন্তু সংগ্রাম করাটাই তাদের জন্য অত্যধিক। তারা আল্লাহর নামে শপথ করবেঃ “যদি আমরা পারতাম, আমরা তোমাদের সাথে যুদ্ধের জন্য একত্রিত হতাম।”তারা এভাবে নিজেদের আঘাত করে, এবং আল্লাহ জানেন যে তারা মিথ্যাবাদী।"],
  "9:43": ["Allah has pardoned you: why did you give them permission (to stay behind), before you could distinguish those who are truthful from the liars?","আল্লাহ তোমাকে ক্ষমা করেছেনঃ কেন তুমি তাদেরকে (পিছনে থাকার) অনুমতি দিলে, তুমি আগে মিথ্যাবাদীদের থেকে যারা সত্যবাদী তাদেরকে আলাদা করতে পারতে?"],
  "9:44": ["Those who truly believe in Allah and the Last Day do not ask your permission to evade the opportunity to strive with their money and their lives. Allah is fully aware of the righteous.","যারা প্রকৃতই আল্লাহ এবং শেষ দিনে বিশ্বাস করে তারা তাদের অর্থ এবং তাদের জীবন দিয়ে সংগ্রাম করার সুযোগটি এড়াতে তোমার কাছে অনুমতি চায় না। আল্লাহ সৎকর্মশীলদের সম্পর্কে পূর্ন সচেতন।"],
  "9:45": ["The only people who wish to be excused are those who do not really believe in Allah and the Last Day. Their hearts are full of doubt, and their doubts cause them to waver.","একমাত্র সে লোকেরাই অব্যহতি পেতে চায় যারা প্রকৃতই আল্লাহ এবং শেষ দিনে বিশ্বাস করে না। তাদের হৃদয় সন্দেহে পূর্ন, এবং তাদের সন্দেহ তাদেরকে দ্বিধাগ্রস্থ করে।"],
  "9:46": ["Had they really wanted to mobilize, they would have prepared for it thoroughly. But Allah disliked their participation, so He discouraged them; they were told, \"Stay behind with those who are staying behind.\"","তারা যদি সত্যিই যুদ্ধের জন্য একত্রিত হতে চাইতো, তারা পুরোপুরিভাবে এরজন্য প্রস্তুত হতো। কিন্তু আল্লাহ তাদের অংশগ্রহণ অপছন্দ করলেন, তাই তিনি তাদের নিরুৎসাহিত করলেন; তাদেরকে বলা হলো, “তাদের সাথে পেছনে থাকো যারা পেছনে থাকছে”।"],
  "9:47": ["Had they mobilized with you, they would have created confusion, and would have caused disputes and divisions among you. Some of you were apt to listen to them. Allah is fully aware of the transgressors.","তারা যদি তোমাদের সাথে যুদ্ধের জন্য একত্রিত হতো, তারা বিভ্রান্তি সৃষ্টি করতো, এবং তোমাদের মাঝে দ্বন্দ এবং বিভাজনের কারন ঘটাতো। তোমাদের কারো কারো মধ্যে তাদের কথা শুনার প্রতি প্রবনতা ছিল। আল্লাহ সীমালঙ্ঘনকারীদের ব্যাপারে সম্পূর্ণ অবগত।"],
  "9:48": ["They sought to spread confusion among you in the past, and confounded the matters for you. However, the truth ultimately prevails, and Allah's plan is carried out, in spite of them.","অতীতে তারা তোমাদের মাঝে বিভ্রান্তি ছড়ানোর সুযোগ খুঁজত, এবং তোমাদের জন্য বিষয়গুলোকে বিভ্রান্তিময় করতো, কিন্তু, সত্য সবশেষে বিজয়ী হয়, এবং আল্লাহর পরিকল্পনা বাস্তবায়িত হয়, তাদের সত্ত্বেও।"],
  "9:49": ["Some of them would say, \"Give me permission (to stay behind); do not impose such a hardship on me.\" In fact, they have thus incurred a terrible hardship; Hell is surrounding the disbelievers.","তাদের কেউ কেউ বলবে, “আমাকে (থেকে যাওয়ার) অনুমতি দিন; আমার উপর এরকম একটি কষ্ট আরোপ করবেন না”। আসলে, তারা এভাবে এক ভয়াবহ কষ্ট টেনে এনেছে; নরক অবিশ্বাসীদের ঘিরে ফেলছে।"],
  "9:50": ["If something good happens to you, they hurt, and if an affliction befalls you, they say, \"We told you so,\" as they turn away rejoicing.","যদি তোমাদের ভালোকিছু হয়, তারা কষ্ট পায়, এবং যদি কোন দুর্দশা তোমাদের উপর আসে, তারা বলে, “আমরা তোমাদেরকে এটাই বলেছিলাম, ”যদিও তারা আনন্দে পিছনে চলে যায়।"],
  "9:51": ["Say, \"Nothing happens to us, except what Allah has decreed for us. He is our Lord and Master. In Allah the believers shall trust.\"","বল, \"আমাদের কিছুই হয় না, আল্লাহ আমাদের জন্য যা জারি করেছেন তা ছাড়া। তিনি আমাদের প্রভু এবং মনিব। বিশ্বাসীরা আল্লাহর প্রতি আস্থা রাখবে।\""],
  "9:52": ["Say, \"You can only expect for us one of two good things (victory or martyrdom), while we expect for you condemnation from Allah and retribution from Him, or at our hands. Therefore, wait, and we will wait along with you.\"","বল, \"তোমরা আমাদের জন্য কেবল দু’টো ভাল জিনিস (বিজয় অথবা শহীদত্ব) থেকে একটি আশা করতে পারো, পক্ষান্তরে আমরা তোমাদের জন্য আশা করি আল্লাহর পক্ষ থেকে নিন্দা এবং তাঁর পক্ষ থেকে অথবা আমাদের হাতে শাস্তি। অতএব, অপেক্ষা করো, এবং আমরাও তোমাদের সাথে অপেক্ষা করবো।"],
  "9:53": ["Say, \"Spend, willingly or unwillingly. Nothing will be accepted from you, for you are evil people.\"","বল, “ব্যয় করো,ইচ্ছায় অথবা অনিচ্ছায়। তোমাদের কাছ থেকে কিছুই গ্রহন করা হবে না, কারণ তোমরা মন্দ লোক।”"],
  "9:54": ["What prevented the acceptance of their spending is that they disbelieved in Allah and His messenger, and when they observed the Contact Prayers (Salat), they observed them lazily, and when they gave to charity, they did so grudgingly.","তাদের ব্যয় গ্রহনযোগ্য হতে যা বাধা দিয়েছিল তা হচ্ছে তারা আল্লাহ এবং তাঁর বার্তাবাহককে অবিশ্বাস করেছে, এবং যখন তারা সংযোগ প্রার্থনাসমূহ (সালাত) পালন করতো, তারা সেগুলো অলসতার সাথে পালন করতো, এবং যখন তারা দান করতো, তারা তা করতো অনিচ্ছায়।"],
  "9:55": ["Do not be impressed by their money, or their children. Allah causes these to be sources of retribution for them in this life, and (when they die) their souls depart while they are disbelievers.","তাদের অর্থ, অথবা তাদের সন্তানাদি দ্বারা অভিভূত হইও না। আল্লাহ এই জীবনে এগুলোকে তাদের জন্য শাস্তির উৎস করেছেন, এবং (যখন তারা মারা যায়) তাদের আত্মা বেড়িয়ে যায় যে সময় তারা অবিশ্বাসী।"],
  "9:56": ["They swear by Allah that they belong with you, while they do not belong with you; they are divisive people.","তারা আল্লাহর নামে শপথ করে যে তারা তোমাদের সাথে আছে, যদিও তারা তোমাদের সাথে নেই; তারা বিভেদকারী লোক।"],
  "9:57": ["If they could find a refuge, or caves, or a hiding place, they would go to it, rushing.","যদি তারা কোন আশ্রয়, অথবা গুহা, অথবা কোন লুকানোর স্থান পেতো, তারা তাতে যেতো, দ্রুতবেগে।"],
  "9:58": ["Some of them criticize your distribution of the charities; if they are given therefrom, they become satisfied, but if they are not given therefrom, they become objectors.","তাদের কেউ কেউ তোমার দান বণ্টনের সমালোচনা করে; যদি তাদেরকে তা থেকে দেয়া হয়, তারা সন্তুষ্ট হয়, কিন্তু তাদেরকে যদি তা থেকে না দেয়া হয়, তারা অভিযোগকারী হয়।"],
  "9:59": ["They should be satisfied with what Allah and His messenger have given them. They should have said, \"Allah suffices us. Allah will provide for us from His bounties, and so will His messenger. We are seeking only Allah.\"","তাদের উচিত আল্লাহ এবং তাঁর বার্তাবাহক তাদেরকে যা দিয়েছেন তাতে সন্তুষ্ট হওয়া। তাদের বলা উচিত ছিল, “আল্লাহ আমাদের জন্য যথেষ্ট। আল্লাহ তাঁর অনুগ্রহ থেকে আমাদের জন্য দেবেন, এবং তাঁর বার্তাবাহকও তা-ই করবেন। আমরা একমাত্র আল্লাহর অন্বেষণ করছি”।"],
  "9:60": ["Charities shall go to the poor, the needy, the workers who collect them, the new converts, to free the slaves, to those burdened by sudden expenses, in the cause of Allah, and to the traveling alien. Such is Allah's commandment. Allah is Omniscient, Most Wise.","দানসমূহ যাবে দরিদ্র, অভাবী, সে শ্রমিকদের কাছে যারা এগুলো সংগ্রহ করে, নতুন ধর্মান্তরিতদের কাছে, দাসদের মুক্ত করতে, তাদের কাছে যারা ভারগ্রস্ত অপ্রত্যাশিত খরচ দ্বারা, আল্লাহর উদ্দেশ্যে, এবং ভ্রমণকারী ভিনদেশীদের জন্য। এমনই আল্লাহর প্রত্যাদেশ। আল্লাহ সর্বজ্ঞ, সব থেকে জ্ঞানী।"],
  "9:61": ["Some of them hurt the prophet by saying, \"He is all ears!\" Say, \"It is better for you that he listens to you. He believes in Allah, and trusts the believers. He is a mercy for those among you who believe.\" Those who hurt Allah's messenger have incurred a painful retribution.","তাদের কেউ কেউ নবীকে এই বলে আঘাত করে, “সে সবকিছুতে কান দেয়!”বল, “এটা তোমাদের জন্য উত্তম যে সে তোমাদের কথা শোনে। সে আল্লাহতে বিশ্বাস করে, এবং বিশ্বাসীদের প্রতি আস্থা রাখে। সে তোমাদের মধ্যে যারা বিশ্বাস করে তাদের জন্য একটি দয়া।”যারা আল্লাহর বার্তাবাহককে আঘাত করে তারা এক যন্ত্রনাদায়ক শাস্তি টেনে এনেছে।"],
  "9:62": ["They swear by Allah to you, to please you, when Allah and His messenger are more worthy of pleasing, if they are really believers.","তারা তোমাদের কাছে আল্লাহর নামে শপথ করে, তোমাদেরকে সন্তুষ্ট করতে, যখন আল্লাহ এবং তাঁর বার্তাবাহককে সন্তুষ্ট করা অধিক উপযুক্ত, যদি তারা সত্যিই বিশ্বাসী হয়।"],
  "9:63": ["Did they not know that anyone who opposes Allah and His messenger has incurred the fire of Hell forever? This is the worst humiliation.","তারা কি জানে না যে যেকেউ আল্লাহ এবং তাঁর বার্তাবাহকের বিরোধিতা করে সে অনন্তকালের জন্য নরকের আগুন টেনে এনেছে? এটি হচ্ছে নিকৃষ্টতম অবমাননা।"],
  "9:64": ["The hypocrites worry that a sura may be revealed exposing what is inside their hearts. Say, \"Go ahead and mock. Allah will expose exactly what you are afraid of.\"","ভন্ডরা আশঙ্কা করে যে তাদের হৃদয়ের ভেতরে যা আছে তা প্রকাশ করে একটি সূরা প্রকাশিত হতে পারে। বল, “চালিয়ে যাও এবং উপহাস করো। আল্লাহ ঠিক সে বিষয়টিই প্রকাশ করবেন যাতে তোমরা ভীত।"],
  "9:65": ["If you ask them, they would say, \"We were only mocking and kidding.\" Say, \"Do you realize that you are mocking Allah, and His revelations, and His messenger?\"","যদি তুমি তাদেরকে জিজ্ঞাসা করো, তারা বলবে, \"আমরা শুধু ব্যঙ্গ এবং মজা করছিলাম।”বল, \"তোমরা কি উপলব্ধি করো যে তোমরা ব্যঙ্গ করছো আল্লাহকে, এবং তাঁর প্রকাশনাবলিকে, এবং তাঁর বার্তাবাহককে?”"],
  "9:66": ["Do not apologize. You have disbelieved after having believed. If we pardon some of you, we will punish others among you, as a consequence of their wickedness.","ক্ষমা  চে-ও না। তোমরা অবিশ্বাস করেছো বিশ্বাস করার পর। যদি আমরা তোমাদের কাউকে কাউকে ক্ষমা করি, আমরা তোমাদের ভেতর অন্যদের শাস্তি দেবো, তাদের পাপের ফলস্বরূপ।"],
  "9:67": ["The hypocrite men and the hypocrite women belong with each other—they advocate evil and prohibit righteousness, and they are stingy. They forgot Allah, so He forgot them. The hypocrites are truly wicked.","ভণ্ড পুরুষ এবং ভণ্ড নারীরা একে অপরের সাথে রয়েছে- তারা মন্দের ওকালতি করে এবং নিষেধ করে সৎকর্মশীলতা, এবং তারা কৃপণ। তারা আল্লাহকে ভুলে গিয়েছে, তাই তিনি তাদের ভুলে গিয়েছেন। ভণ্ডরা সত্যই মন্দ।"],
  "9:68": ["Allah promises the hypocrite men and the hypocrite women, as well as the disbelievers, the fire of Hell, wherein they abide forever. It suffices them. Allah has condemned them; they have incurred an everlasting retribution.","আল্লাহ ভণ্ড পুরুষ এবং ভণ্ড নারীদের, একই সাথে অবিশ্বাসীদের অঙ্গীকার দেন, নরকাগ্নির, যেখানে তারা চিরকাল বাস করবে। এটা তাদের জন্য যথেষ্ট। আল্লাহ তাদের নিন্দা করেন; তারা টেনে এনেছে চিরস্থায়ী শাস্তি।"],
  "9:69": ["Some of those before you were stronger than you, and possessed more money and children. They became preoccupied with their material possessions. Similarly, you have become preoccupied with your material possessions, just like those before you have become preoccupied. You have become totally heedless, just as they were heedless. Such are the people who nullify their works, both in this world and in the Hereafter; they are the losers.","তোমাদের আগে তাদের কেউ কেউ তোমাদের চেয়ে শক্তিশালী ছিল, এবং অধিক অর্থ ও সন্তানের অধিকারী ছিল। তারা তাদের পার্থিব সম্পদে আচ্ছন্ন হয়েছিল। একইভাবে, তোমরা তোমাদের পার্থিব সম্পদে আচ্ছন্ন হয়ে পড়েছো, তোমাদের পূর্বের ঠিক তাদের মতো যারা আচ্ছন্ন হয়ে পড়েছিল। তোমরা সম্পূর্ণ অমনোযোগী হয়ে পড়েছো, ঠিক যেমন তারা  অমনোযোগী  ছিল। এমনই হচ্ছে সেসব লোক যারা তাদের কাজগুলো নষ্ট করেছে, এই দুনিয়া এবং পরকাল উভয় স্থানে; তারাই ক্ষতিগ্রস্থ।"],
  "9:70": ["Have they not learned anything from the previous generations; the people of Noah, 'Ãd, Thamûd, the people of Abraham, the dwellers of Midyan, and the evildoers (of Sodom and Gomorrah)? Their messengers went to them with clear proofs. Allah never wronged them; they are the ones who wronged their own souls.","তারা কি পূর্ববর্তী প্রজন্মগুলো থেকে কিছুই শেখেনি; নূহ, আদ সামুদের লোক, ইবরাহীমের লোক, মাদিয়ানের অধিবাসী, এবং (সদম ও গমরার) সেই মন্দকর্মীদের থেকে? তাদের বার্তাবাহকরা তাদের কাছে সুস্পষ্ট প্রমান নিয়ে গিয়েছিলো। আল্লাহ কখনো তাদের প্রতি অন্যায় করেননি, তারাই তাদের নিজেদের আত্মার প্রতি অন্যায় করেছিল।"],
  "9:71": ["The believing men and women are allies of one another. They advocate righteousness and forbid evil, they observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), and they obey Allah and His messenger. These will be showered by Allah's mercy. Allah is Almighty, Most Wise.","বিশ্বাসী পুরুষ এবং নারীরা একে অন্যের মিত্র। তারা সৎকর্মশীলতার ওকালতি করে এবং মন্দে নিষেধ করে, তারা সংযোগ প্রার্থনা (সালাত) পালন করে এবং বাধ্যতামূলক দান (যাকাত) দেয়, এবং তারা আল্লাহ ও তাঁর বার্তাবাহককে মান্য করে। এদের প্রতি আল্লাহর দয়া বর্ষিত হবে। আল্লাহ সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "9:72": ["Allah promises the believing men and the believing women gardens with flowing streams, wherein they abide forever, and magnificent mansions in the gardens of Eden. And Allah's blessings and approval are even greater. This is the greatest triumph.","আল্লাহ বিশ্বাসী পুরুষ এবং বিশ্বাসী নারীদের প্রবাহিত ঝর্নাসহ বাগানসমূহের প্রতিশ্রুতি দেন, যেখানে তারা চিরকাল বসবাস করে, এবং ইডেনের বাগানগুলোর জাঁকজমকময় অট্রালিকাসমূহ। এবং আল্লাহর আশীর্বাদ ও অনুমোদন আরো বড়। এটি শ্রেষ্ঠ বিজয়।"],
  "9:73": ["O you prophet, strive against the disbelievers and the hypocrites, and be stern in dealing with them. Their destiny is Hell; what a miserable abode!","হে নবী, অবিশ্বাসী এবং ভন্ডদের বিরুদ্ধে সংগ্রাম করো, এবং তাদের সাথে কার্যকলাপে কঠোর হও। তাদের নিয়তি নরক; কি এক শোচনীয় আবাস!"],
  "9:74": ["They swear by Allah that they never said it, although they have uttered the word of disbelief; they have disbelieved after becoming submitters. In fact, they gave up what they never had. They have rebelled even though Allah and His messenger have showered them with His grace and provisions. If they repent, it would be best for them. But if they turn away, Allah will commit them to painful retribution in this life and in the Hereafter. They will find no one on earth to be their lord and master.","তারা আল্লাহর নামে শপথ করে যে তারা কখনো তা বলেনি, যদিও তারা অবিশ্বাসমূলক শব্দ উচ্চারণ করেছে; তারা আত্মসমর্পণকারী হবার পর অবিশ্বাস করেছে।  আসলে, তারা ত্যাগ করলো  যা তাদের কখনো ছিল না। তারা বিদ্রোহ করেছে যদিও আল্লাহ এবং তাঁর বার্তাবাহক তাদেরকে তাঁর দয়া ও জীবিকা বর্ষণ করেছেন।  যদি তারা অনুতপ্ত হয়, এটি হবে তাদের জন্য সর্বোত্তম।  কিন্তু যদি তারা মুখ ফিরিয়ে নেয়, আল্লাহ তাদেরকে এই জীবনে এবং পরকালে যন্ত্রনাদায়ক শাস্তি দিবেন।  তারা পৃথিবীতে তাদের প্রভু ও মনিব হিসেবে কাউকে পাবে না।"],
  "9:75": ["Some of them even pledged: \"If Allah showered us with His grace, we would be charitable, and would lead a righteous life.\"","তাদের কেউ কেউ এমনকি অঙ্গীকার করেছিলঃ “যদি আল্লাহ আমাদেরকে তাঁর দয়া বর্ষণ করেন, আমরা দানশীল হবো, এবং সৎকর্মশীল জীবন-যাপন করবো।”"],
  "9:76": ["But when He did shower them with His provisions, they became stingy, and turned away in aversion.","কিন্তু যখন তিনি তাদেরকে তাঁর জীবিকা বর্ষণ করলেন, তারা কৃপণ হয়ে গেলো, এবং অনীহায় মুখ ফিরিয়ে নিল।"],
  "9:77": ["Consequently, He plagued them with hypocrisy in their hearts, till the day they meet Him. This is because they broke their promises to Allah, and because of their lying.","ফলস্বরূপ, তিনি তাদের হৃদয়ে ভন্ডামী দিয়ে তাদেরকে করলেন মহামারীগ্রস্থ, তাঁর সাথে সাক্ষাতের দিন পর্যন্ত। এটা এ কারনে যে তারা আল্লাহর সাথে করা অঙ্গীকার ভঙ্গ করলো, এবং তাদের মিথ্যা বলার কারনে।"],
  "9:78": ["Do they not realize that Allah knows their secrets, and their conspiracies, and that Allah is the Knower of all secrets?","তারা কি উপলব্ধি করে না যে, আল্লাহ জানেন তাদের গোপন বিষয়গুলো, এবং তাদের চক্রান্তগুলো, এবং যে আল্লাহ সকল গোপন বিষয়ই জানেন।"],
  "9:79": ["Those who criticize the generous believers for giving too much, and ridicule the poor believers for giving too little, Allah despises them. They have incurred a painful retribution.","যারা উদার বিশ্বাসীদের সমালোচনা করে খুব বেশি দেয়ার জন্য, এবং গরিব বিশ্বাসীদের উপহাস করে খুব কম দেয়ার জন্য, আল্লাহ তাদেরকে ঘৃণা করেন। তারা টেনে এনেছে একটি যন্ত্রণাদায়ক শাস্তি।"],
  "9:80": ["Whether you ask forgiveness for them, or do not ask forgiveness for them—even if you ask forgiveness for them seventy times—Allah will not forgive them. This is because they disbelieve in Allah and His messenger. Allah does not guide the wicked people.","তুমি তাদের জন্য ক্ষমা প্রার্থনা করো, অথবা ক্ষমা প্রার্থনা না করো- এমনকি যদি তুমি সত্তর বার তাদের জন্য ক্ষমা প্রার্থনা করো- আল্লাহ তাদেরকে ক্ষমা করবেন না। এটা এ কারনে যে তারা আল্লাহ এবং তাঁর বার্তাবাহককে অবিশ্বাস করে। আল্লাহ মন্দ লোকদের পথ-প্রদর্শন করেন না।"],
  "9:81": ["The sedentary rejoiced in their staying behind the messenger of Allah, and hated to strive with their money and their lives in the cause of Allah. They said, \"Let us not mobilize in this heat!\" Say, \"The fire of Hell is much hotter,\" if they could only comprehend.","বসে থাকা লোকেরা আল্লাহর বার্তাবাহকের পিছনে থেকে যাওয়ায় আনন্দ করেছিলো, এবং আল্লাহর উদ্দেশ্যে তাদের অর্থ ও তাদের জীবন দিয়ে সংগ্রাম করাকে ঘৃনা করেছিল। তারা বলেছিল, “আমাদেরকে এই উত্তাপে যুদ্ধের জন্য একত্রিত করো না!”বল, “নরকের আগুন অধিক উত্তপ্ত, ”যদি তারা শুধু অনুধাবন করতে পারতো।"],
  "9:82": ["Let them laugh a little, and cry a lot. This is the requital for the sins they have earned.","তাদেরকে একটু হাসতে দাও, এবং অনেক কাঁদতে দাও। এটি হচ্ছে তাদের অর্জন করা পাপের প্রতিদান।"],
  "9:83": ["If Allah returns you to a situation where they ask your permission to mobilize with you, you shall say, \"You will never again mobilize with me, nor will you ever fight with me against any enemy. For you have chosen to be with the sedentary in the first place. Therefore, you must stay with the sedentary.\"","যদি আল্লাহ তোমাকে এমন অবস্থায় ফিরিয়ে নেন যেখানে তারা তোমার সাথে যুদ্ধের জন্য একত্রিত হতে অনুমতি চায়। তুমি বলবে, \"তোমরা আবার কখনো আমার সাথে যুদ্ধের জন্য একত্রিত হবে না, না তোমরা কখনো কোন শত্রুর বিরুদ্ধ্বে আমার সাথে লড়াই করবে। কারণ তোমরাই প্রথমে বসে থাকা লোকদের সাথে থাকা পছন্দ করেছো। সেজন্য, তোমরা অবশ্যই বসে থাকা লোকদের সাথে থাকবে।”"],
  "9:84": ["You shall not observe the funeral prayer for any of them when he dies, nor shall you stand at his grave. They have disbelieved in Allah and His messenger, and died in a state of wickedness.","তুমি তাদের কারো জন্য দাফনপূর্ব প্রার্থনা করবে না যখন সে মারা যায়, না তুমি তার কবরে দাঁড়াবে। তারা আল্লাহ ও তাঁর বার্তাবাহককে অবিশ্বাস করেছে, এবং মরেছে পাপী অবস্থায়।"],
  "9:85": ["Do not be impressed by their money or their children; Allah causes these to be sources of misery for them in this world, and their souls depart as disbelievers.","তাদের অর্থ অথবা তাদের সন্তানদের দ্বারা অভিভূত হইও না। এই দুনিয়াতে আল্লাহ এগুলোকে তাদের জন্য দুর্দশার উৎস করেন, এবং তাদের আত্মা অবিশ্বাসী হিসেবে বেরিয়ে যায়।"],
  "9:86": ["When a sura is revealed, stating: \"Believe in Allah, and strive with His messenger,\" even the strong among them say, \"Let us stay behind!\"","যখন কোন সুরা প্রকাশিত হয়, বলে যেঃ “আল্লাহতে বিশ্বাস করো, এবং তাঁর বার্তাবাহকের সাথে সংগ্রাম করো”তখন এমনকি তাদের মধ্যকার বলবানরা বলে, “আমাদের থাকতে দিন”।"],
  "9:87": ["They chose to be with the sedentary. Consequently, their hearts were sealed, and thus, they cannot comprehend.","তারা বসে থাকাদের সাথে থাকতে পছন্দ করলো। পরিনামে, তাদের হৃদয়ে মোহর এঁটে দেয়া হয়েছিল, এবং এ কারনে, তারা হৃদয়ঙ্গম করতে পারে না।"],
  "9:88": ["As for the messenger and those who believed with him, they eagerly strive with their money and their lives. These have deserved all the good things; they are the winners.","আর বার্তাবাহক এবং যারা তার সাথে বিশ্বাস করেছে, তারা আগ্রহের সাথে তাদের অর্থ এবং তাদের জীবন দিয়ে সংগ্রাম করে। এরা সকল ভালো জিনিসের যোগ্য হয়েছে; এরাই জয়ী।"],
  "9:89": ["Allah has prepared for them gardens with flowing streams, wherein they abide forever. This is the greatest triumph.","আল্লাহ তাদের জন্য প্রবাহিত ঝর্নাসহ বাগান প্রস্তুত করেছেন, যেখানে তারা চিরকাল বসবাস করে। এটাই সবচেয়ে বড় বিজয়।"],
  "9:90": ["The Arabs made up excuses, and came to you seeking permission to stay behind. This is indicative of their rejection of Allah and His messenger—they stay behind. Indeed, those who disbelieve among them have incurred a painful retribution.","আরবরা অজুহাত বানিয়েছিল, এবং তোমার কাছে এসেছিল পেছনে থেকে যাবার অনুমতি চাইতে। এটি নির্দেশ করে আল্লাহ এবং তাঁর বার্তাবাহককে তাদের প্রত্যাখ্যান- তারা পেছনে থেকে যায়। নিশ্চয়, তাদের মধ্যে যারা অবিশ্বাস করে তারা টেনে এনেছে যন্ত্রণাদায়ক শাস্তি।"],
  "9:91": ["Not to be blamed are those who are weak, or ill, or do not find anything to offer, so long as they remain devoted to Allah and His messenger. The righteous among them shall not be blamed. Allah is Forgiver, Most Merciful.","তারা দোষী হবে না যারা দূর্বল, অথবা অসুস্থ, অথবা উৎসর্গ করার জন্য কোনকিছু পায় না, যতক্ষণ পর্যন্ত তারা আল্লাহ ও তাঁর বার্তাবাহকের প্রতি নিবেদিত থাকে। তাদের মধ্যকার সৎকর্মশীলরা দোষী হবে না। আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "9:92": ["Also excused are those who come to you wishing to be included with you, but you tell them, \"I do not have anything to carry you on.\" They then turn back with tears in their eyes, genuinely saddened that they could not afford to contribute.","এছাড়াও তারা অব্যাহতিপ্রাপ্ত যারা তোমার কাছে আসে তোমার সাথে অন্তর্ভুক্ত হবার ইচ্ছায়, কিন্তু তুমি তাদেরকে বলো, \"তোমাদেরকে চালিয়ে নিতে আমার কিছুই করার নেই।”তারা তখন তাদের চোখে অশ্রু নিয়ে ফিরে যায়, সত্যই দু:খ পেয়ে যে তারা অবদান রাখতে সমর্থ হয়নি।"],
  "9:93": ["The blame is on those who ask your permission to stay behind, even though they have no excuse. They have chosen to be with the sedentary. Consequently, Allah has sealed their hearts, and thus, they do not attain any knowledge.","দোষ হচ্ছে তাদের যারা তোমার কাছে পেছনে থেকে যাওয়ার অনুমতি চায়, এমনকি যদিও তাদের কোন অজুহাত নেই। তারা বসে থাকাদের সাথে থাকতে পছন্দ করেছে। পরিনামে, আল্লাহ তাদের হৃদয়ে মোহর এঁটে দিয়েছেন, এবং এ কারণে, তারা কোন জ্ঞান অর্জন করে না।"],
  "9:94": ["They apologize to you when you return to them (from battle). Say, \"Do not apologize; we no longer trust you. Allah has informed us about you.\" Allah will see your works, and so will the messenger, then you will be returned to the Knower of all secrets and declarations, then He will inform you of everything you had done.","তারা তোমার কাছে ক্ষমা চায় যখন তুমি (যুদ্ধ থেকে) তাদের কাছে ফিরে আসো। বল, “ক্ষমা চেও না; তোমাদেরকে আমরা আর বিশ্বাস করি না। আল্লাহ আমাদেরকে তোমাদের সম্পর্কে অবগত করেছেন।”আল্লাহ তোমাদের কাজ দেখবেন, এবং বার্তাবাহকও, এরপর তোমরা সকল গোপন এবং প্রকাশ্য বিষয়ের জ্ঞাতার নিকট ফিরে যাবে, এরপর তিনি তোমাদেরকে সবকিছু জানাবেন যা তোমরা করেছিলে।"],
  "9:95": ["They will swear by Allah to you, when you return to them, that you may disregard them. Do disregard them. They are polluted, and their destiny is Hell, as a requital for the sins they have earned.","যখন তুমি তাদের কাছে ফিরে আসো, তারা তোমার কাছে আল্লাহর নামে শপথ করবে, কারণ হয়তো তুমি তাদের উপেক্ষা করতে পারো। তাদেরকে উপেক্ষা করো। তারা দূষিত, এবং তাদের নিয়তি নরক, তাদের অর্জিত পাপের প্রতিফল হিসেবে।"],
  "9:96": ["They swear to you, that you may pardon them. Even if you pardon them, Allah does not pardon such wicked people.","তারা তোমার কাছে শপথ করে, যাতে তুমি তাদেরকে ক্ষমা করে দাও। যদি তুমি তাদেরকে ক্ষমা করেও দাও, আল্লাহ এমন মন্দ লোকদের ক্ষমা করেন না।"],
  "9:97": ["The Arabs are the worst in disbelief and hypocrisy, and the most likely to ignore the laws that Allah has revealed to His messenger. Allah is Omniscient, Most Wise.","আরবরা অবিশ্বাস এবং ভণ্ডামিতে নিকৃষ্টতম। এবং আল্লাহ তাঁর বার্তাবাহকের কাছে যে আইন প্রকাশ করেছেন তা উপেক্ষা করার প্রবণতা সবচেয়ে বেশি। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "9:98": ["Some Arabs consider their spending (in the cause of Allah) to be a loss, and even wait in anticipation that a disaster may hit you. It is they who will incur the worst disaster. Allah is Hearer, Omniscient.","কিছু আরব (আল্লাহর উদ্দেশে) তাদের ব্যায়কে ক্ষতি হিসেবে গন্য করে, এমনকি প্রত্যাশায় অপেক্ষা করতে থাকে যে তোমার উপর কোন বিপর্যয় আঘাত হানবে। এরাই নিকৃষ্টতম বিপর্যয় টেনে আনবে। আল্লাহ শ্রোতা, সর্বজ্ঞ।"],
  "9:99": ["Other Arabs do believe in Allah and the Last Day, and consider their spending to be a means towards Allah, and a means of supporting the messenger. Indeed, it will bring them nearer; Allah will admit them into His mercy. Allah is Forgiver, Most Merciful.","অন্যান্য আরবরা আল্লাহ এবং শেষ দিবসে বিশ্বাস করে, এবং তাদের ব্যয়কে আল্লাহর নৈকট্য লাভের একটি উপায় হিসেবে গন্য করে, এবং বার্তাবাহককে সমর্থনের একটি উপায় হিসেবে গন্য করে। নিশ্চয়ই, এটি তাদেরকে অধিকতর নিকটে আনবে; আল্লাহ তাদেরকে তাঁর দয়ার অন্তর্ভুক্ত করবেন। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "9:100": ["As for the early vanguards who immigrated (Muhãjerin), and the supporters who gave them refuge (Ansãr) and those who followed them in righteousness, Allah is pleased with them, and they are pleased with Him. He has prepared for them gardens with flowing streams, wherein they abide forever. This is the greatest triumph.","প্রথম অগ্রণীদল যারা দেশান্তরিত হয়েছে (মুহাজারিন), এবং সমর্থনকারীরা (আনসার) যারা তাদেরকে আশ্রয় দিয়েছিল, এবং যারা তাদেরকে সৎকর্মশীলতায় অনুসরণ করেছিল, আল্লাহ তাদের প্রতি সন্তুষ্ট, এবং তারা তাঁর প্রতি সন্তুষ্ট। তিনি তাদের জন্য প্রস্তুত করেছেন প্রবাহিত ঝর্না সহ বাগান, যেখানে তারা চিরকাল থাকবে। এটাই সর্বশ্রেষ্ঠ বিজয়।"],
  "9:101": ["Among the Arabs around you, there are hypocrites. Also, among the city dwellers, there are those who are accustomed to hypocrisy. You do not know them, but we know them. We will double the retribution for them, then they end up committed to a terrible retribution.","তোমাদের চারপাশের আরবদের মধ্যে রয়েছে ভন্ডরা। আরও, শহরের অধিবাসীদের মধ্যে তারা রয়েছে, যারা ভণ্ডামিতে অভ্যস্ত। তুমি তাদের জানো না, কিন্তু আমরা তাদেরকে জানি। আমরা তাদের জন্য শাস্তি দ্বিগুন করবো, এরপর পরিশেষে তারা এক ভয়ানক শাস্তিতে পতিত হয়।"],
  "9:102": ["There are others who have confessed their sins; they have mixed good deeds with bad deeds. Allah will redeem them, for Allah is Forgiver, Most Merciful.","অন্যান্যরা আছে যারা তাদের পাপ স্বীকার করেছে; তারা ভাল কাজের সাথে মন্দ কাজ মিশিয়েছে। আল্লাহ তাদেরকে উদ্ধার করবেন, কারণ আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "9:103": ["Take from their money a charity to purify them and sanctify them. And encourage them, for your encouragement reassures them. Allah is Hearer, Omniscient.","তাদের অর্থ থেকে দান নাও তাদেরকে পরিশুদ্ধ করতে এবং তাদেরকে পবিত্র করতে। এবং তাদেরকে উৎসাহিত করো, কারণ তোমার উৎসাহ তাদেরকে আশ্বস্ত করে। আল্লাহ শ্রোতা, সর্বজ্ঞ।"],
  "9:104": ["Do they not realize that Allah accepts the repentance of His worshipers, and takes the charities, and that Allah is the Redeemer, Most Merciful?","তারা কি উপলব্ধি করে না যে আল্লাহ তাঁর উপাসনাকারীদের অনুশোচনা গ্রহন করেন, এবং দান নেন, এবং যে আল্লাহ উদ্ধারকারী, পরম দয়ালু?"],
  "9:105": ["Say, \"Work righteousness; Allah will see your work, and so will His messenger and the believers. Ultimately, you will be returned to the Knower of all secrets and declarations, then He will inform you of everything you had done.\"","বল, “সৎকর্ম করো; আল্লাহ তোমাদের কাজ দেখবেন, এবং তাঁর বার্তাবাহক এবং বিশ্বাসীরাও। অবশেষে, তোমরা সকল গোপন এবং প্রকাশ্য বিষয়ের জ্ঞাতার নিকট ফিরে যাবে, এরপর তিনি তোমাদেরকে সবকিছু জানাবেন যা তোমরা করেছিলে।”"],
  "9:106": ["Others are waiting for Allah's decision; He may punish them, or He may redeem them. Allah is Omniscient, Most Wise.","অন্যান্যরা অপেক্ষায় আছে আল্লাহর সিদ্ধান্তের জন্য; তিনি হয়তো তাদের শাস্তি দেবেন, অথবা হয়তো তিনি তাদের উদ্ধার করবেন। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "9:107": ["There are those who abuse the masjid by practicing idol worship, dividing the believers, and providing comfort to those who oppose Allah and His messenger. They solemnly swear: \"Our intentions are honorable!\" Allah bears witness that they are liars.","আর যারা মসজিদের অপব্যবহার করে অংশীদার উপাসনা চর্চা করে, বিশ্বাসীদের বিভক্ত করে, এবং তাদেরকে স্বস্তি দিয়ে যারা আল্লাহ এবং তাঁর বার্তাবাহকের বিরোধিতা করে। তারা দৃড়তার সাথে শপথ করেঃ “আমাদের উদ্দেশ্য সম্মানজনক!”আল্লাহ সাক্ষ্য দেন যে তারা মিথ্যুক।"],
  "9:108": ["You shall never pray in such a masjid. A masjid that is established on the basis of righteousness from the first day is more worthy of your praying therein. In it, there are people who love to be purified. Allah loves those who purify themselves.","তুমি এমন মসজিদে কখনো প্রার্থনা করবে না। যে মসজিদ প্রথম দিন থেকেই ন্যায়পরায়ণতার ভিত্তির উপর প্রতিষ্ঠিত সে স্থান তোমার প্রার্থনার অধিক উপযুক্ত। এখানে আছে লোকেরা, যারা শুদ্ধ হতে ভালবাসে। আল্লাহ তাদেরকে ভালবাসেন যারা নিজেদের শুদ্ধ করে।"],
  "9:109": ["Is one who establishes his building on the basis of reverencing Allah and to gain His approval better, or one who establishes his building on the brink of a crumbling cliff, that falls down with him into the fire of Hell? Allah does not guide the transgressing people.","যে ব্যক্তি তার ইমারত আল্লাহ ভক্তি এবং তাঁর সম্মতি অর্জনের ভিত্তির উপর প্রতিষ্ঠা করে সে উত্তম, নাকি সে ব্যক্তি যে তার ইমারত একটি ক্ষয়প্রাপ্ত পর্বতগাত্রের কিনারে প্রতিষ্ঠা করে, যা তাকে নিয়ে নরকের আগুনে পতিত হয়? আল্লাহ সীমাতিক্রকারি লোকদের পথ-প্রদর্শন করেন না।"],
  "9:110": ["Such a building that they have established remains a source of doubt in their hearts, until their hearts are stilled. Allah is Omniscient, Most Wise.","এমন ইমারত যা তারা স্থাপন করেছে তা তাদের হৃদয়ে সন্দেহের একটি উৎস হয়ে থাকে, যতক্ষণ না তাদের হৃদয় স্থির হয়ে যায়। আল্লাহ সর্বজ্ঞ, সবথেকে জ্ঞানী।"],
  "9:111": ["Allah has bought from the believers their lives and their money in exchange for Paradise. Thus, they fight in the cause of Allah, willing to kill and get killed. Such is His truthful pledge in the Torah, the Gospel, and the Quran—and who fulfills His pledge better than Allah? You shall rejoice in making such an exchange. This is the greatest triumph.","আল্লাহ স্বর্গোদ্যানের বিনিময়ে বিশ্বাসীদের কাছ থেকে তাদের জীবন এবং তাদের অর্থ কিনে নিয়েছেন। এ কারনে, তারা আল্লাহর উদ্দেশ্যে লড়াই করে, মারতে এবং মরতে সম্মত। এমনই হচ্ছে তওরাত, ইঞ্জিল, এবং কুরআনে তাঁর সত্য অঙ্গীকার– এবং কে অঙ্গীকার পূরণে আল্লাহর চেয়ে উত্তম? তোমরা এমন বিনিময়ে আনন্দ করবে। এটিই শ্রেষ্ঠ বিজয়।"],
  "9:112": ["They are the repenters, the worshipers, the praisers, the meditators, the bowing and prostrating, the advocators of righteousness and forbidders of evil, and the keepers of Allah's laws. Give good news to such believers.","তারা অনুশোচনাকারী, উপাসনাকারী, প্রশংসাকারী, ধ্যানকারী, অবনত হয় ও সেজদা করে, সৎকর্মশীলতার উকালতি করে এবং মন্দের নিষেধকারী, এবং আল্লাহর আইন রক্ষাকারী। এমন বিশ্বাসীদের সুসংবাদ দাও।"],
  "9:113": ["Neither the prophet, nor those who believe shall ask forgiveness for the idol worshipers, even if they were their nearest of kin, once they realize that they are destined for Hell.","না নবী, না তারা যারা বিশ্বাস করে প্রতিমা উপাসকদের জন্য ক্ষমা প্রার্থনা করবে, এমনকি যদিও তারা তাদের নিকটতম আত্মীয়স্বজন হয়, যখন তারা উপলব্ধি করে যে তারা নরকের জন্য নির্ধারিত।"],
  "9:114": ["The only reason Abraham asked forgiveness for his father was that he had promised him to do so. But as soon as he realized that he was an enemy of Allah, he disowned him. Abraham was extremely kind, clement.","ইব্রাহিম তার পিতার জন্য ক্ষমা চেয়েছিল শুধু একারনে যে, সে তাকে এমন অঙ্গীকার দিয়েছিল। কিন্তু, যখনই সে উপলব্ধি করলো যে সে আল্লাহর শত্রু, সে তাকে ত্যাগ করলো। ইব্রাহিম ছিল অত্যন্ত দয়ালু, সহিষ্ণু।"],
  "9:115": ["Allah does not send any people astray, after He had guided them, without first pointing out for them what to expect. Allah is fully aware of all things.","আল্লাহ কোন লোকদের পথভ্রষ্ট করেন না, তিনি তাদের পথ-প্রদর্শন করার পর, প্রথমে তাদের জন্য নির্দেশ না করে যে কি প্রত্যাশা করা হয়। আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "9:116": ["To Allah belongs the sovereignty of the heavens and the earth. He controls life and death. You have none beside Allah as a Lord and Master.","আকাশমন্ডলী এবং পৃথিবীর সার্বভৌমত্ব আল্লাহর। তিনি জীবন এবং মৃত্যু নিয়ন্ত্রন করেন। আল্লাহর পাশে প্রভু এবং মনিব হিসাবে তোমাদের অন্য কেউ নেই।"],
  "9:117": ["Allah has redeemed the prophet, and the immigrants (Muhãjireen) and the supporters who hosted them and gave them refuge (Ansãr), who followed him during the difficult times. That is when the hearts of some of them almost wavered. But He has redeemed them, for He is Compassionate towards them, Most Merciful.","আল্লাহ উদ্ধার করেছেন নবীকে, এবং অভিবাসীদের (মুহাজিরিন) এবং সমর্থকদের যারা তাদের আতিথিয়তা করেছে এবং তাদেরকে আশ্রয় দিয়েছে (আনসার), যারা তাকে কঠিন সময়ে অনুসরণ করেছে। সে সময় তাদের কারো কারো হৃদয় প্রায় দোদুল্যমান ছিল। কিন্তু তিনি তাদেরকে উদ্ধার করেছিলেন, কারন তিনি তাদের প্রতি করুনাময়, পরম দয়ালু।"],
  "9:118": ["Also (redeemed were) the three who stayed behind. The spacious earth became so straitened for them, that they almost gave up all hope for themselves. Finally, they realized that there was no escape from Allah, except to Him. He then redeemed them that they may repent. Allah is the Redeemer, Most Merciful.","আরো (ক্ষমা করা হয়েছে) সে তিনজনকে যারা পেছনে থেকে গিয়েছিল। বিস্তৃত পৃথিবী তাদের জন্য এতো সঙ্কুচিত হয়ে গিয়েছিল যে, তারা তাদের নিজেদের জন্য প্রায় সকল আশা ত্যাগ করেছিল। পরিশেষে, তারা উপলব্ধি করলো যে আল্লাহর থেকে পালানো যায় না, তাঁর দিকে ছাড়া। তিনি তখন তাদের উদ্ধার করলেন যাতে তারা অনুশোচনা করতে পারে। আল্লাহ উদ্ধারকারী, সবচেয়ে দয়াময়।"],
  "9:119": ["O you who believe, you shall reverence Allah, and be among the truthful.","হে তোমরা যারা বিশ্বাস করো, তোমরা আল্লাহকে ভক্তি করবে, এবং সত্যবাদীদের মধ্যে থাকবে।"],
  "9:120": ["Neither the dwellers of the city, nor the Arabs around them, shall seek to stay behind the messenger of Allah (when he mobilizes for war). Nor shall they give priority to their own affairs over supporting him. This is because they do not suffer any thirst, or any effort, or hunger in the cause of Allah, or make a single step that enrages the disbelievers, or inflict any hardship upon the enemy, without having it written down for them as a credit. Allah never fails to recompense those who work righteousness.","না এই শহরের বাসিন্দারা, না তাদের চারদিকের আরবরা, আল্লাহর বার্তাবাহকের পেছনে থেকে যাওয়ার পথ খুঁজবে (যখন সে যুদ্ধের জন্য একত্রিত হয়)। না তারা তাদের নিজেদের বিষয়কে প্রাধান্য দেবে তাকে সমর্থন দেয়ার চেয়ে। এটা এই কারনে যে, তারা আল্লাহর উদ্দেশ্যে কোন তৃষ্ণা , অথবা কোন উদ্যোগ, অথবা ক্ষুধা, অথবা কোন একটি পদক্ষেপ নেয়া যা অবিশ্বাসীদের ক্ষুদ্ধ করে, অথবা শত্রুদের উপর কোন কষ্ট আরোপ করা- এগুলোর কোনটাই করেনা,  যার কৃতিত্ব তাদের জন্য লেখা হয় না। যারা সৎকর্ম করে তাদেরকে আল্লাহ কখনো পুরস্কৃত করতে ব্যর্থ হন না।"],
  "9:121": ["Nor do they incur any expense, small or large, nor do they cross any valley, without having the credit written down for them. Allah will surely reward them generously for their works.","না তারা নিজের উপর কোন ব্যয় টেনে আনে, ছোট অথবা বড়, না তারা কোন উপত্যকা পার হয়, যার কৃতিত্ব তাদের জন্য লেখা না হয়। আল্লাহ অবশ্যই তাদের কাজের জন্য তাদেরকে উদারভাবে পুরস্কৃত করবেন।"],
  "9:122": ["When the believers mobilize, not all of them shall do so. A few from each group shall mobilize by devoting their time to studying the religion. Thus, they can pass the knowledge on to their people when they return, that they may remain religiously informed.","যখন বিশ্বাসীরা যুদ্ধের জন্য প্রস্তুতি নেয়, তাদের সকলে নিবে না। প্রত্যেক দল থেকে কিছু লোক ধর্ম অধ্যয়নে তাদের সময় উৎসর্গ করতে সমবেত হবে। এভাবে, তারা তাদের লোকদের কাছে জ্ঞান ছড়িয়ে দিতে পারে যখন তারা ফিরে আসে, যাতে তারা ধর্মীয়ভাবে অবগত থাকতে পারে।"],
  "9:123": ["O you who believe, you shall fight the disbelievers who attack you—let them find you stern—and know that Allah is with the righteous.","হে যারা তোমরা বিশ্বাস করো, তোমরা লড়াই করবে অবিশ্বাসীদের সাথে যারা তোমাদের আক্রমণ করে- যেন তারা তোমাদের কঠোরতা বুঝতে পারে-এবং জানে যে আল্লাহ সৎকর্মশীলদের সাথে আছেন।"],
  "9:124": ["When a sura was revealed, some of them would say, \"Did this sura strengthen the faith of anyone among you?\" Indeed, it did strengthen the faith of those who believed, and they rejoice in any revelation.","যখন কোন সুরা প্রকাশিত হতো, তাদের কেউ কেউ বলতো, “এই সুরা কি তোমাদের কারো বিশ্বাস মজবুত করেছে?” নিশ্চয়ই, এটা তাদের বিশ্বাসকে মজবুত করেছিল যারা বিশ্বাস করেছে, এবং তারা যেকোন প্রকাশনাতেই আনন্দ পায়।"],
  "9:125": ["As for those who harbored doubts in their hearts, it actually added unholiness to their unholiness, and they died as disbelievers.","আর তাদের জন্য যারা তাদের হৃদয়ে সন্দেহ পোষণ করতো, এটা আসলে তাদের অপবিত্রতায় অপবিত্রতা যোগ করেছিল, এবং তারা অবিশ্বাসী হিসাবে মৃত্যুবরণ করলো।"],
  "9:126": ["Do they not see that they suffer from exacting trials every year once or twice? Yet, they consistently fail to repent, and fail to take heed?","তারা কি খেয়াল করে না যে প্রতি বছর এক বা দু'বার তারা কঠোর পরীক্ষার সম্মুখীন হয়? এরপরও, তারা প্রতিবার অনুশোচনা করতে ব্যর্থ হয়, এবং ব্যর্থ হয় সতর্ক হতে।"],
  "9:127": ["Whenever a sura was revealed, some of them would look at each other as if to say: \"Does anyone see you?\" Then they left. Thus, Allah has diverted their hearts, for they are people who do not comprehend.","যখনি কোন সুরা প্রকাশিত হতো, তাদের কেউ কেউ একে অন্যের দিকে এমনভাবে তাকাতো যেন বলতে চায়ঃ “কেউ কি তোমাদের দেখছে?”এরপর তারা স্থান ত্যাগ করে। এভাবে, আল্লাহ তাদের হৃদয়কে বিমুখ করেন, কারন তারা এমন লোক যারা হৃদয়ঙ্গম করে না।"],
  "9:128": ["There certainly has come to you a messenger from among yourselves. He is concerned by your suffering, anxious for your well-being, and gracious and merciful to the believers.","তোমাদের কাছে এসেছে তোমাদের মধ্য থেকেই একজন রসূল। তোমাদের দুঃখ-কষ্ট তার পক্ষে দুঃসহ। তিনি তোমাদের মঙ্গলকামী, মুমিনদের প্রতি স্নেহশীল, দয়াময়।"],
  "9:129": ["But if they turn away, then say, ˹O Prophet,˺ “Allah is sufficient for me. There is no god ˹worthy of worship˺ except Him. In Him I put my trust. And He is the Lord of the Mighty Throne.”","এ সত্ত্বেও যদি তারা বিমুখ হয়ে থাকে, তবে বলে দাও, আল্লাহই আমার জন্য যথেষ্ট, তিনি ব্যতীত আর কারো বন্দেগী নেই। আমি তাঁরই ভরসা করি এবং তিনিই মহান আরশের অধিপতি।"],
};
